window.QUESTIONS =
[
  {id:"q150s", topic:"SQL vs NoSQL", diff:"basic", level:"Mid", type:"single",
    q:"What is the strongest single reason to reach for a NoSQL store like Cassandra/DynamoDB over Postgres?",
    options:["Lower latency on every query regardless of access pattern","Very high write throughput when access is by a known primary key","Richer multi-table JOINs and ad-hoc query support","Stronger out-of-the-box consistency than a single-node SQL DB"],
    correct:[1],
    why:"The real differentiator is the access pattern plus write profile, not ACID. NoSQL shines for huge write throughput and queries by a known key; SQL wins for complex ad-hoc queries, joins, and transactions.", more:"Cassandra and DynamoDB are tuned for partition-key access; ask the wrong question (joins, ranges across keys) and they get awkward or slow."},
  {id:"q132o", topic:"SQL vs NoSQL", diff:"tricky", level:"Senior", type:"single",
    q:"You're designing a billing/ledger system at massive scale. Which is the better default and why?",
    options:["NoSQL, because horizontal write scaling outweighs other concerns","SQL: multi-row transactions, integrity, and ad-hoc queries matter even at the cost of raw scale.","NoSQL, modeling balances as a key-value map with atomic counters","SQL or NoSQL: at sufficient scale the trade-offs between them roughly even out"],
    correct:[1],
    why:"Finance and billing are the classic 'SQL despite scale' case: transactions, joins, and auditability matter more than raw write throughput. NoSQL fits activity feeds, telemetry, and chat, not ledgers.", more:"You can scale SQL for ledgers via partitioning and read replicas; you cannot easily bolt multi-row ACID transactions onto an eventually-consistent store."},
  {id:"q1l7t", topic:"SQL vs NoSQL", diff:"tricky", level:"Senior", type:"multi",
    q:"Which workloads are natural fits for NoSQL? (select all)",
    options:["Activity / news feed","Double-entry accounting ledger","Device telemetry and time-series data","Chat message history"],
    correct:[0,2,3],
    why:"Feeds, telemetry, and chat are high-volume, key-accessed, and tolerant of eventual consistency. Double-entry accounting needs multi-row transactions, so it belongs in SQL."},
  {id:"q14ds", topic:"Sharding", diff:"basic", level:"Mid", type:"single",
    q:"What problem does sharding primarily solve?",
    options:["Making cross-node reads strongly consistent by default","Horizontal scaling of data and load beyond one node's capacity","Removing the need for replication and failover","Automatically detecting and rebalancing hot keys"],
    correct:[1],
    why:"Sharding is horizontal partitioning to scale past a single node. It does not remove the need for replication, and a bad shard key can create hotspots rather than eliminate them."},
  {id:"q10dm", topic:"Sharding", diff:"tricky", level:"Senior", type:"multi",
    q:"Which are genuine pains introduced by sharding? (select all)",
    options:["Hot shards from a celebrity or otherwise skewed key","Cross-shard queries and distributed transactions","The operational cost of resharding and rebalancing","Losing the ability to build indexes on the data"],
    correct:[0,1,2],
    why:"The three big pains are hotspots, cross-shard joins and transactions, and the cost of resharding. Indexes still exist; they are just maintained per shard rather than globally."},
  {id:"qh29l", topic:"Sharding", diff:"tricky", level:"Senior", type:"single",
    q:"You shard by user_id with a hash. A few celebrity users overwhelm their shard. Best first mitigation?",
    options:["Convert the entire dataset to range sharding instead of hashing","Isolate or split the hot key with sub-sharding, dedicated handling, or a cache","Raise the replication factor across every shard in the cluster","Drop sharding and consolidate back onto a single large node"],
    correct:[1],
    why:"Hotspots are handled by isolating or splitting the hot key (dedicated shard, key-splitting, caching the celebrity), not by re-architecting the whole scheme."},
  {id:"qx9pl", topic:"Replication", diff:"tricky", level:"Senior", type:"single",
    q:"What defines MULTI-leader replication (vs single-leader)?",
    options:["A standby replica is promoted to accept writes only after failover","Multiple nodes accept writes simultaneously, often one per data center","One node exclusively serves reads while another exclusively serves writes","Clients send each write to a quorum of replicas with no fixed leader"],
    correct:[1],
    why:"Multi-leader means several nodes accept writes at once, common across data centers; its core pain is write-conflict resolution. A standby promoted on failover describes single-leader."},
  {id:"q1tvi", topic:"Replication", diff:"tricky", level:"Senior", type:"single",
    q:"In leaderless replication (Dynamo/Cassandra), how is consistency tuned?",
    options:["By electing a dedicated leader for each partition","By tuning quorums so that writes plus reads exceed replicas (W + R > N)","By coordinating writes through two-phase commit","By reading from a single replica to avoid conflicts"],
    correct:[1],
    why:"Leaderless systems have clients write and read multiple replicas; you get strong-ish consistency when the write quorum plus the read quorum exceed the replica count (W + R > N)."},
  {id:"qvqce", topic:"Replication", diff:"tricky", level:"Senior", type:"single",
    q:"'Read-after-write consistency' guarantees that…",
    options:["The system blocks reads until a write has fully replicated everywhere","A user is guaranteed to see their own just-completed write","All users observe a given write at the same instant","Every read is routed to the leader to avoid stale data"],
    correct:[1],
    why:"Read-your-writes means a user sees their own just-made write even if other replicas lag. It does not imply global synchronization or that everyone sees the write instantly."},
  {id:"q1jab", topic:"Replication", diff:"basic", level:"Senior", type:"single",
    q:"Single-leader replication handles a leader crash via…",
    options:["By resolving write conflicts between the competing leaders","By promoting a replica to leader through failover and election","By satisfying reads from a quorum until a leader returns","By resharding the data across the surviving nodes"],
    correct:[1],
    why:"In single-leader replication all writes go to one node; on a crash a replica is promoted to leader via failover and leader election."},
  {id:"q1tib", topic:"CAP / PACELC", diff:"basic", level:"Mid", type:"single",
    q:"What do the three letters in CAP stand for?",
    options:["Cache, Availability, Performance","Consistency, Availability, Partition tolerance","Consistency, Atomicity, Persistence","Concurrency, Availability, Parallelism"],
    correct:[1],
    why:"CAP stands for Consistency, Availability, and Partition tolerance. It is easy to blank on the A and the P under pressure, so anchor them."},
  {id:"q1vto", topic:"CAP / PACELC", diff:"tricky", level:"Staff", type:"single",
    q:"The 'real' CAP choice in practice is between…",
    options:["Consistency versus Partition tolerance in steady state","Availability versus Partition tolerance during normal operation","Consistency versus Availability while a partition is happening","Read latency versus Consistency in the common case"],
    correct:[2],
    why:"Partitions are inevitable, so you cannot trade away P. The actual decision is C versus A when a partition occurs: a CP system refuses to answer, an AP system answers but may be stale.", accept:"Option 3 (latency vs consistency) is the real everyday trade-off, but that is the PACELC 'Else' case, not the CAP question being asked here."},
  {id:"qv7zr", topic:"CAP / PACELC", diff:"tricky", level:"Staff", type:"single",
    q:"What does PACELC add beyond CAP?",
    options:["A third consistency tier between strong and eventual","That even with no partition you still trade Latency versus Consistency","A mechanism to prevent network partitions from occurring","A standard protocol for detecting partitions quickly"],
    correct:[1],
    why:"PACELC says if there is a Partition choose A or C, Else (normal operation) choose Latency or Consistency. It captures the everyday latency cost of strong consistency that CAP ignores."},
  {id:"qxb1q", topic:"Caching", diff:"basic", level:"Mid", type:"single",
    q:"In cache-aside, who writes to the cache on a miss?",
    options:["The database pushes the value into the cache after the query","The application code populates the cache after reading from the DB","The cache fetches and loads the value from the DB itself","A background warming job is the only thing that fills it"],
    correct:[1],
    why:"In cache-aside (lazy loading) the app checks the cache, and on a miss it reads the DB and then populates the cache. Write-through writes cache and DB synchronously; write-back defers the DB write."},
  {id:"q17el", topic:"Caching", diff:"tricky", level:"Senior", type:"single",
    q:"A popular key expires and thousands of requests hit the DB at once to rebuild it. This is…",
    options:["Cache stampede, also called the thundering herd","Cache-aside lazy loading working as designed","A hot shard caused by a skewed partition key","Write amplification from repeated cache updates"],
    correct:[0],
    why:"This is a cache stampede or thundering herd. Mitigate it with a lock or single-flight so only one request rebuilds, TTL jitter, or refresh-ahead."},
  {id:"q111r", topic:"Caching", diff:"tricky", level:"Senior", type:"multi",
    q:"Which mitigate a cache stampede? (select all)",
    options:["A lock or single-flight so only one request rebuilds the key","TTL jitter so popular keys do not all expire at the same moment","Refresh-ahead that rebuilds the value just before it expires","Bypassing the cache entirely while the system is under load"],
    correct:[0,1,2],
    why:"A lock or single-flight, TTL jitter, and refresh-ahead all either spread out or collapse the rebuild. Bypassing the cache just sends every request straight to the DB."},
  {id:"q14pg", topic:"Caching", diff:"tricky", level:"Senior", type:"single",
    q:"Beyond eviction, the two hard cache problems are staleness/invalidation and…",
    options:["Choosing an efficient value compression scheme","Cache stampede, the thundering herd on rebuild","Picking a fast serialization format for entries","Designing a consistent key-naming convention"],
    correct:[1],
    why:"Beyond eviction, invalidation/staleness and cache stampede are the two cache problems that bite hardest in interviews."},
  {id:"q1qfn", topic:"CDN / Blob", diff:"basic", level:"Mid", type:"single",
    q:"You store user-uploaded videos. What goes in the relational DB?",
    options:["The raw file bytes stored in a binary BLOB column","Only the object-store key or URL referencing the file","A base64-encoded copy of the file contents","A thumbnail plus the inline binary for fast access"],
    correct:[1],
    why:"Keep binaries in object storage like S3 or GCS and store only the URL or reference in the DB. Stuffing binaries into rows wrecks index and cache efficiency."},
  {id:"q1t2q", topic:"CDN / Blob", diff:"basic", level:"Mid", type:"single",
    q:"A CDN's main job is to…",
    options:["Run your application's business logic close to the user","Geo-cache static content near users to cut latency and offload origin","Act as the primary datastore for dynamic application data","Encrypt all traffic between the client and the origin server"],
    correct:[1],
    why:"A CDN is a geographically distributed edge cache for static assets that reduces latency and origin load. It often sits in front of blob storage.", accept:"Edge compute (option 1) does run logic at the edge, but that is an add-on; geo-caching static content is the CDN's defining job."},
  {id:"q1prk", topic:"Redis", diff:"tricky", level:"Senior", type:"single",
    q:"Redis command execution model is…",
    options:["Multi-threaded execution with one lock acquired per key","Single-threaded command execution, so a heavy command blocks the whole instance","A separate OS process forked for each client connection","Lock-free parallel execution spread across all CPU cores"],
    correct:[1],
    why:"Redis executes commands single-threaded, which gives atomicity for free, but an expensive command such as KEYS or a big SORT stalls everything else.", more:"Networking I/O can be threaded in modern Redis, but the command-execution model itself is single-threaded."},
  {id:"q1f9d", topic:"Redis", diff:"tricky", level:"Senior", type:"single",
    q:"A single-node Redis is best described as…",
    options:["Consistent but not durable by default","Durable on disk but not internally consistent","Both strongly consistent and durable out of the box","Neither consistent nor durable in practice"],
    correct:[0],
    why:"A single node is consistent (one copy, atomic ops) but not durable by default since it is in-memory. The common miss is saying it sacrifices consistency, when it actually sacrifices durability."},
  {id:"qbp3s", topic:"Redis", diff:"tricky", level:"Senior", type:"single",
    q:"How does Redis Cluster map keys to nodes?",
    options:["A consistent-hashing ring with virtual nodes","16384 fixed hash slots, slot equals CRC16(key) mod 16384","Range partitioning based on the key prefix","Random slot assignment rebalanced periodically"],
    correct:[1],
    why:"Redis Cluster uses 16384 fixed hash slots (CRC16 mod 16384), not a consistent-hashing ring. Slots move between nodes on rebalance, and clients follow MOVED and ASK redirects."},
  {id:"q12db", topic:"Redis", diff:"tricky", level:"Senior", type:"single",
    q:"What is the DEFAULT eviction policy in Redis?",
    options:["allkeys-lru, evicting the least recently used key","volatile-ttl, evicting the key with the nearest expiry","noeviction, so writes return an error once memory is full","allkeys-random, evicting an arbitrary key"],
    correct:[2],
    why:"The default is noeviction: once maxmemory is hit, writes fail rather than silently dropping data. You must opt into an LRU or LFU policy to use Redis as a pure cache."},
  {id:"q1e2g", topic:"Redis", diff:"tricky", level:"Senior", type:"multi",
    q:"Which give Redis durability options? (select all)",
    options:["RDB point-in-time snapshots","AOF append-only command log","Single-threaded command execution","MemoryDB for true multi-AZ durability"],
    correct:[0,1,3],
    why:"RDB snapshots and the AOF log both add durability (AOF everysec loses about a second, AOF always loses nothing but is slower), and MemoryDB provides true durability. Single-threading is about execution, not durability."},
  {id:"q196r", topic:"Redis", diff:"tricky", level:"Senior", type:"single",
    q:"How do you make a multi-step Redis operation (e.g. a rate-limiter check-and-decrement) atomic?",
    options:["Wrap the steps in a server-side Lua script or a MULTI/EXEC block","Run a two-phase commit transaction across the cluster nodes","Rely on each separate command already running single-threaded","Hold a client-side mutex around the sequence of calls"],
    correct:[0],
    why:"A Lua script runs atomically on the server, and MULTI/EXEC with WATCH also works. Separate commands are not atomic relative to each other even though each individual command is."},
  {id:"q1i5v", topic:"Redis", diff:"tricky", level:"Senior", type:"single",
    q:"Redis Pub/Sub vs Redis Streams — the key difference?",
    options:["Streams deliver messages with lower latency than Pub/Sub","Pub/Sub is at-most-once with no persistence; Streams persist messages and add consumer groups","Pub/Sub persists messages while Streams are fire-and-forget","They are functionally equivalent with different command names"],
    correct:[1],
    why:"Pub/Sub is fire-and-forget and at-most-once, so offline subscribers miss messages. Streams persist the log and support consumer groups and replay, making them a Kafka-lite."},
  {id:"qqqvm", topic:"Redis", diff:"tricky", level:"Staff", type:"single",
    q:"Redlock (distributed lock across Redis nodes) — what's the nuance a senior should mention?",
    options:["It provides safe mutual exclusion under all failure conditions","Kleppmann showed it's unsafe under GC pauses and clock skew; use fencing tokens or consensus.","It only ever functions correctly when run on a single node","Backing it with MemoryDB makes the lock durable and safe, so fencing tokens are unnecessary"],
    correct:[1],
    why:"Redlock works for efficiency locks, but Kleppmann showed it is not safe for correctness under pauses or clock issues. Mention fencing tokens or a consensus store like ZooKeeper or etcd for hard locks."},
  {id:"q1awb", topic:"Load balancing", diff:"tricky", level:"Senior", type:"single",
    q:"Key difference between an L4 and an L7 load balancer?",
    options:["L4 inspects HTTP headers and cookies, which makes it slower than content-blind L7","L4 routes by IP/port and is content-blind; L7 reads URL, headers, and cookies for content routing and stickiness","L7 operates purely at the TCP transport layer, exactly like an L4 balancer does","L4 can inspect cookies and URLs to make sticky-session routing decisions"],
    correct:[1],
    why:"L4 is transport-layer (TCP/UDP), fast but content-blind. L7 is application-layer and can route by URL, header, or cookie, terminate TLS, and do sticky sessions."},
  {id:"q1ibb", topic:"Load balancing", diff:"basic", level:"Mid", type:"multi",
    q:"Which are valid load-balancing algorithms? (select all)",
    options:["Round-robin across the backend pool","Least-connections to the busiest-aware backend","Consistent hashing keyed on the client or request","Two-phase commit across the backends"],
    correct:[0,1,2],
    why:"Round-robin, least-connections, weighted, and consistent hashing are all load-balancing strategies. Two-phase commit is a distributed-transaction protocol, not a routing algorithm."},
  {id:"qfjwz", topic:"Kafka vs Queues", diff:"tricky", level:"Senior", type:"single",
    q:"The defining property of Kafka vs a traditional broker queue (SQS/RabbitMQ)?",
    options:["Messages are deleted as soon as a consumer acknowledges them","An append-only log: messages are retained and replayable; consumers track their own offset","Only a single consumer can ever read from a given topic","Messages arrive in no guaranteed order within a topic"],
    correct:[1],
    why:"Kafka is a distributed append-only log: messages are retained and replayable, consumers track offsets, multiple consumer groups read the same data independently, and order is preserved within a partition.", more:"Since Kafka 4.x (KIP-932 share groups) Kafka can also offer queue-style per-message delivery, so the log-vs-queue line is blurrier than it used to be."},
  {id:"q96zq", topic:"Kafka vs Queues", diff:"tricky", level:"Senior", type:"single",
    q:"In SQS/RabbitMQ, what happens to a message after a consumer acks it?",
    options:["It is retained on the queue for later replay by others","It is deleted from the queue and not redelivered","It is moved to a different partition for archival","It is broadcast to every other registered consumer"],
    correct:[1],
    why:"Broker queues delete a message on ack, typically with one consumer and no replay. They are good for simple background tasks and decoupling, not stream replay or analytics."},
  {id:"q17in", topic:"Kafka vs Queues", diff:"basic", level:"Mid", type:"multi",
    q:"Why put a message queue between services at all? (select all)",
    options:["Decoupling producers from consumers in time and deployment","Smoothing load by buffering bursts of incoming work","Providing strong cross-service transactional consistency","Throttling and protecting slower downstream consumers"],
    correct:[0,1,3],
    why:"Queues decouple services, smooth and buffer bursts, and throttle downstream load. They do not provide strong consistency and generally push you toward eventual consistency."},
  {id:"qkc73", topic:"Kafka vs Queues", diff:"tricky", level:"Senior", type:"single",
    q:"You need 3 independent teams to each process the same event stream their own way. Best fit?",
    options:["SQS, where each message is deleted once one consumer processes it","Kafka with a separate consumer group for each team","A single shared RabbitMQ queue all three teams drain","A database table that each team polls and deletes rows from"],
    correct:[1],
    why:"Kafka's multiple consumer groups each keep their own offset over the same retained log, which is exactly the multi-consumer fan-out case."},
  {id:"qymnv", topic:"Fan-out", diff:"tricky", level:"Senior", type:"single",
    q:"Fan-out-on-write (push) for a social timeline means…",
    options:["Assemble each user's timeline on demand at read time","On each post, write the item into every follower's precomputed timeline","Pull a user's followees' posts when they open the app","Cache the rendered home page at the CDN edge"],
    correct:[1],
    why:"Fan-out-on-write (push) fans each post into every follower's feed on write. Reads are fast but writes are expensive, and it breaks down for celebrities with millions of followers."},
  {id:"qsq2d", topic:"Fan-out", diff:"tricky", level:"Staff", type:"single",
    q:"Why is pure fan-out-on-write a disaster for a celebrity with 100M followers?",
    options:["Per-follower read latency becomes unacceptably slow","A single post triggers 100 million timeline writes","Post ordering across followers can no longer be preserved","The resulting timelines become impossible to cache"],
    correct:[1],
    why:"One celebrity post means 100 million writes. That is why the standard answer is a hybrid: push for normal users and pull (fan-out-on-read) for celebrities."},
  {id:"q1mb7", topic:"Fan-out", diff:"basic", level:"Staff", type:"single",
    q:"The standard production answer for a Twitter-style timeline is…",
    options:["Always fan-out-on-write into every follower's feed","Always fan-out-on-read by assembling feeds on request","Hybrid: push for normal users and pull for celebrities","Recompute every timeline from scratch on each request"],
    correct:[2],
    why:"The hybrid balances write cost and read latency: precompute feeds for the many normal users and compute on read for the few huge accounts."},
  {id:"q1p1p", topic:"Rate limiting", diff:"basic", level:"Mid", type:"single",
    q:"How does the token-bucket algorithm work?",
    options:["It counts requests per fixed window and resets the counter each window","It holds N tokens refilled at a steady rate; each request takes one, and an empty bucket rejects","It delays every request by a fixed interval to pace traffic","It admits requests but drops every Nth one to shed load"],
    correct:[1],
    why:"Token bucket keeps a bucket of N tokens refilled at a steady rate; a request consumes a token and an empty bucket rejects. It allows bursts up to the bucket size."},
  {id:"qp96x", topic:"Rate limiting", diff:"tricky", level:"Senior", type:"single",
    q:"Where should a rate limiter usually live?",
    options:["Inside the database, enforced per query","At the edge in the API gateway or load balancer, keyed per user, IP, or API key","In the client application before requests are sent","In the message queue between the services"],
    correct:[1],
    why:"Put the limiter at the edge (gateway or load balancer) so abuse is rejected before reaching downstream services, keyed per user, IP, or API key for fairness and DDoS protection."},
  {id:"qhcyc", topic:"Rate limiting", diff:"tricky", level:"Senior", type:"single",
    q:"Which limiter property does token bucket give that a fixed-window counter struggles with?",
    options:["Lower memory footprint than a simple counter","Smooth handling of short bursts up to the bucket size","Perfect counting accuracy right at the window boundary","Operation without any persistent state at all"],
    correct:[1],
    why:"Token bucket allows controlled bursts and avoids the fixed-window edge problem of double traffic at the boundary. A sliding-window log or counter also fixes that edge issue."},
  {id:"qbbw1", topic:"Idempotency", diff:"basic", level:"Mid", type:"single",
    q:"An idempotent operation is one where…",
    options:["It is guaranteed to execute exactly one time, ever","Applying it many times yields the same result as applying it once","It is designed so that it can never return an error","It completes successfully without any network round trip"],
    correct:[1],
    why:"Idempotent means repeating an operation has the same effect as doing it once. This matters because retries are inevitable: a timeout leaves the client unsure whether the call succeeded."},
  {id:"qnktr", topic:"Idempotency", diff:"tricky", level:"Senior", type:"single",
    q:"A payment API must avoid double-charging on client retries. Standard mechanism?",
    options:["Acquire an exclusive lock on the user's account during the charge","Have the client send an idempotency key the server dedupes on","Permit the client to retry the request at most one time","Disable client retries so a charge is only ever sent once"],
    correct:[1],
    why:"The client sends a unique idempotency key; the server records it and returns the original result on retries instead of charging again."},
  {id:"qqjqq", topic:"Idempotency", diff:"tricky", level:"Senior", type:"multi",
    q:"Where is idempotency essential? (select all)",
    options:["Payment and other write APIs that clients may retry","At-least-once queue consumers that must dedupe redeliveries","Pure read-only GET endpoints with no side effects","Any operation traveling over an unreliable network"],
    correct:[0,1,3],
    why:"Retryable writes, at-least-once consumers, and anything over flaky networks all need idempotency. Pure GETs are already naturally idempotent and need nothing extra."},
  {id:"qe6oh", topic:"Distributed Txns", diff:"tricky", level:"Staff", type:"single",
    q:"The core problem distributed transactions solve is preserving which ACID property across nodes?",
    options:["Isolation, preventing concurrent transactions from interfering","Durability, ensuring committed data survives a crash","Atomicity, so all participants commit or none do across services","Consistency, keeping invariants valid after each transaction"],
    correct:[2],
    why:"It is primarily Atomicity across nodes: all participants commit or none do. A common miss is saying A and I, but Saga in particular deliberately drops isolation."},
  {id:"qcz22", topic:"Distributed Txns", diff:"tricky", level:"Senior", type:"single",
    q:"Two-phase commit (2PC) is best characterized as…",
    options:["Optimistic and lock-free, settling to eventual consistency","Pessimistic prepare-and-commit phases that hold locks; CP and blocking with a coordinator SPOF.","Asynchronous compensation that undoes steps after the fact","A messaging pattern layered on a durable broker queue with asynchronous acknowledgements"],
    correct:[1],
    why:"Two-phase commit is pessimistic and coordinator-driven with prepare and commit phases, holds locks, and is CP and blocking; the coordinator is a single point of failure (mitigated but real). It underpins Spanner and XA."},
  {id:"q1ho5", topic:"Distributed Txns", diff:"tricky", level:"Staff", type:"single",
    q:"A Saga undoes a partially-completed workflow using…",
    options:["A rollback of the global ACID transaction across all services","Compensating transactions that semantically undo each prior step","A two-phase commit coordinated at the final commit point","A database savepoint the engine rewinds to on failure"],
    correct:[1],
    why:"A Saga is a sequence of local transactions; on failure it runs compensating transactions to semantically undo prior steps. It trades isolation for availability and eventual consistency.", more:"There is no single global transaction to roll back; each service already committed its local work, so the only way back is a forward-running compensation per completed step."},
  {id:"q1l48", topic:"Distributed Txns", diff:"tricky", level:"Staff", type:"single",
    q:"Saga CHOREOGRAPHY (vs orchestration) means…",
    options:["A central orchestrator service explicitly drives every step in order","Services react to each other's events via pub/sub with no central coordinator","Services run two-phase commit between each other to stay consistent","A single monolithic service performs every step internally"],
    correct:[1],
    why:"Choreography is decentralized and event-driven: each service listens and reacts, with no central brain. Orchestration is the opposite, where a central coordinator explicitly drives the steps.", more:"Easy to reverse, so anchor it: choreography = events fan out, orchestration = one conductor calls each step."},
  {id:"qzxr7", topic:"Distributed Txns", diff:"tricky", level:"Staff", type:"multi",
    q:"Which are Saga isolation/robustness countermeasures a Staff candidate might name? (select all)",
    options:["Semantic locks that mark records as in-progress until the saga completes","A transactional outbox that publishes events atomically with the local commit","Idempotent compensations so re-running an undo step is safe","A pivot transaction placed first so later steps need no compensation"],
    correct:[0,1,2],
    why:"Semantic locks, transactional outbox, and idempotent compensations recover the isolation a Saga gives up. The pivot transaction is the go/no-go step and is placed at the boundary, not first, and does not by itself eliminate compensation for steps before it.", more:"A real pivot transaction is a legitimate Saga concept, but it is the point after which the saga can only roll forward; it is not a robustness countermeasure that removes the need to compensate earlier steps, so it is the wrong pick here."},
  {id:"qxw9w", topic:"Real-time transport", diff:"basic", level:"Mid", type:"single",
    q:"Server-Sent Events (SSE) are best described as…",
    options:["A full-duplex bidirectional channel over a single TCP connection","A one-way server-to-client stream over one long-lived HTTP connection with auto-reconnect","A client-to-server-only upload stream over chunked HTTP","A repeated client polling loop that simulates pushing"],
    correct:[1],
    why:"SSE is one-way server-to-client over one persistent HTTP connection, with built-in auto-reconnect. Great for notifications and feeds, but not for bidirectional chat.", more:"SSE is text-only (UTF-8) and rides on plain HTTP, so it passes through proxies easily, unlike WebSocket's upgrade handshake."},
  {id:"qjz31", topic:"Real-time transport", diff:"tricky", level:"Senior", type:"single",
    q:"You're building a chat app needing low-latency two-way messaging. Best transport?",
    options:["Short polling on a fast interval to approximate real time","Server-Sent Events with a side channel for client messages","WebSocket, giving full-duplex messaging over one connection","Long polling that reopens after each server response"],
    correct:[2],
    why:"WebSocket is full-duplex over a single persistent connection, which is right for chat and games. The cost is that it is stateful and harder to scale than stateless HTTP.", more:"SSE plus a POST channel can fake two-way, but it adds latency and complexity versus a true bidirectional socket."},
  {id:"qaenv", topic:"Real-time transport", diff:"basic", level:"Mid", type:"single",
    q:"Order these from least to most efficient for server-push: polling, long-polling, SSE. Which is the most efficient of the three?",
    options:["Short polling, since each fresh request gets the newest data","Long polling, since it holds requests open until data arrives","SSE, since it streams events over one held-open connection","Long polling and SSE are effectively equal for one-way push"],
    correct:[2],
    why:"Short polling wastes requests, long polling is better, and SSE holds one connection and streams events, making it the most efficient of the three for one-way push.", more:"Long polling still incurs a full request/response cycle per message; SSE reuses one connection for many events, so per-message overhead is far lower."},
  {id:"q4nkf", topic:"Observability", diff:"basic", level:"Mid", type:"multi",
    q:"What are the three pillars of observability? (select all)",
    options:["Metrics, the aggregate numeric time-series of system health","Logs, the timestamped record of discrete events","Traces, the end-to-end path of a request across services","Backups, the periodic snapshots used for disaster recovery"],
    correct:[0,1,2],
    why:"The three pillars are metrics, logs, and traces. Backups are a durability and disaster-recovery concern, not an observability pillar.", more:"Layering SLO/SLI and error-budget vocabulary on top of the three pillars signals operational maturity."},
  {id:"qda92", topic:"Observability", diff:"tricky", level:"Senior", type:"single",
    q:"An 'error budget' is…",
    options:["A reserve fund the team draws on to pay for incident response","The allowed amount of unreliability, equal to 100 percent minus the SLO","The headcount of on-call engineers budgeted per rotation","A circuit-breaker threshold that trips after too many errors"],
    correct:[1],
    why:"The error budget is one minus the SLO. It quantifies acceptable failure and governs the release-versus-risk trade-off, which is a strong operational signal.", more:"When the budget is spent, teams typically freeze risky feature launches and redirect effort to reliability until the budget recovers."},
  {id:"q1525", topic:"Observability", diff:"tricky", level:"Senior", type:"multi",
    q:"Which protect a system under partial failure / overload? (select all)",
    options:["A circuit breaker that trips open to stop calling a failing dependency","Backpressure that slows or rejects intake when downstream is saturated","Graceful degradation that serves reduced functionality under load","Removing client and server timeouts so requests are never dropped"],
    correct:[0,1,2],
    why:"Circuit breakers, backpressure, and graceful degradation all contain cascading failure. Removing timeouts is the opposite: it lets slow calls pile up and makes cascades worse.", more:"Timeouts are what let a caller give up on a stuck dependency and free resources; without them, thread pools and connections exhaust system-wide."},
  {id:"q1gh5", topic:"SPOF / Reliability", diff:"basic", level:"Mid", type:"single",
    q:"The cleanest mental test for a single point of failure is…",
    options:["Does this component add measurable latency to the request path","If this component dies, does the entire system stop serving","Does this component cost more than its redundant alternative","Does this component sit in front of or behind the cache"],
    correct:[1],
    why:"Walk every component and ask whether the system stops if it dies. Eliminate SPOFs via redundancy: multiple instances, replicas, multi-AZ, and auto-failover with no un-backed shared resource.", more:"Latency, cost, and caching are real design concerns but none of them define a single point of failure."},
  {id:"qmaky", topic:"SPOF / Reliability", diff:"tricky", level:"Senior", type:"multi",
    q:"Which genuinely remove a SPOF? (select all)",
    options:["Multiple stateless instances spread behind a load balancer","Multi-AZ replicas with automatic failover on primary loss","A single shared NFS mount that every node depends on","Active-active deployment across multiple regions"],
    correct:[0,1,3],
    why:"Redundancy at every layer removes SPOFs. A single shared NFS mount that everything needs is itself a SPOF, not a fix, since its failure takes down all dependents.", more:"The mount could be made redundant (replicated/clustered storage), but as described, one mount everything depends on is the textbook SPOF."},
  {id:"qf68d", topic:"Estimation", diff:"tricky", level:"Senior", type:"single",
    q:"Rough QPS for 100M daily active users each making ~10 requests/day (uniform)?",
    options:["About 1,150 QPS on average across the day","About 11,500 QPS on average across the day","About 115,000 QPS on average across the day","About 1,150,000 QPS on average across the day"],
    correct:[1],
    why:"100M users times 10 requests is 1e9 requests per day. A day is about 86,400 seconds, roughly 1e5, so 1e9 divided by 1e5 is about 10,000, giving roughly 11.5k average QPS.", more:"Multiply by about 2 to 3 for peak traffic above the daily average."},
  {id:"qz62n", topic:"Estimation", diff:"basic", level:"Mid", type:"single",
    q:"Roughly how many seconds are in a day (the number to memorize for QPS math)?",
    options:["About 3,600 seconds, roughly 10 to the 3.5","About 86,400 seconds, roughly 10 to the 5","About 604,800 seconds, roughly 10 to the 5.8","About 1,000,000 seconds, roughly 10 to the 6"],
    correct:[1],
    why:"A day is 86,400 seconds, which is about 10 to the 5. Memorize it: daily count divided by 1e5 is roughly average QPS.", more:"3,600 is seconds in an hour; 604,800 is seconds in a week, both common distractors to avoid."},
  {id:"q185g", topic:"Estimation", diff:"tricky", level:"Senior", type:"single",
    q:"You store 500M records × 2 KB each. Approximate raw storage?",
    options:["About 10 GB of raw storage before overhead","About 100 GB of raw storage before overhead","About 1 TB of raw storage before overhead","About 10 TB of raw storage before overhead"],
    correct:[2],
    why:"500M records times 2 KB is 5e8 times 2e3 bytes, which equals 1e12 bytes, about 1 TB. Then add overhead for indexes and replication, roughly times 3 at RF=3.", more:"Keep the unit math explicit: 2 KB is 2e3 bytes, so the product lands in terabytes, not gigabytes."},
  {id:"q1wgr", topic:"API design", diff:"tricky", level:"Senior", type:"single",
    q:"For high-throughput internal service-to-service calls, what's a common reason to prefer gRPC over REST/JSON?",
    options:["Its plaintext JSON is easier to inspect with curl and browser tools","Binary protobuf over HTTP/2 gives lower latency, multiplexing, and typed contracts","It is schema-free, so services can evolve payloads without coordination","It runs natively in every browser without any proxy layer"],
    correct:[1],
    why:"gRPC uses protobuf over HTTP/2: compact binary payloads, request multiplexing, bidirectional streaming, and codegen-enforced contracts. REST and JSON win for public, human-debuggable, browser-facing APIs.", more:"gRPC actually requires a schema (the .proto) and browsers need grpc-web plus a proxy, so the schema-free and native-browser claims are reversed."},
  {id:"q14kw", topic:"API design", diff:"basic", level:"Mid", type:"single",
    q:"For a list endpoint returning millions of rows, the right pattern is…",
    options:["Return the full result set in one response and let the client trim it","Paginate, preferring cursor or keyset over large numeric offsets","Push filtering to the client so the server stays simple and stateless","Stream the whole table over a WebSocket as one long message"],
    correct:[1],
    why:"Paginate the endpoint. Cursor and keyset pagination scale better than OFFSET, which degrades on deep pages because the database still scans and discards the skipped rows.", more:"Keyset pagination uses the last-seen sort key as a WHERE bound, so each page is an index seek rather than a growing offset scan."},
  {id:"q1ffp", topic:"Redis", diff:"tricky", level:"Senior", type:"single",
    q:"HI Redis deep dive: out of the box, what does Redis do when it hits its memory limit?",
    options:["It evicts the least-recently-used keys automatically by default","It rejects new writes by default; you must set an eviction policy for a cache","It begins spilling cold keys to disk and continues accepting writes","It samples and evicts random keys until memory drops below the limit"],
    correct:[1],
    why:"The default is noeviction: writes return errors once memory is full. TTL handles staleness, not memory pressure, so for a cache you set a policy like allkeys-lru.", more:"allkeys-lru is approximate: Redis samples a handful of keys and evicts the oldest of the sample rather than maintaining an exact global LRU order."},
  {id:"ql0ep", topic:"Redis", diff:"tricky", level:"Staff", type:"single",
    q:"HI: in Redis Cluster, what happens if a client asks the wrong node for a key?",
    options:["The node transparently forwards the request to the owner and returns the result","The node replies MOVED with the right node, and the client refreshes its slot map","The node creates the key locally and serves future reads from itself","The cluster triggers an immediate rebalance to bring the slot to that node"],
    correct:[1],
    why:"Each key hashes to one of 16384 slots and clients cache the slot-to-node map. Ask the wrong node and it returns a MOVED reply rather than forwarding, so clients learn to aim at the right node.", more:"Nodes gossip the full slot map so any node knows the owner, but they redirect rather than proxy; a transient ASK redirect is used only during slot migration."},
  {id:"qao6s", topic:"Redis", diff:"tricky", level:"Staff", type:"single",
    q:"HI: how do you force two related Redis keys (user:123:posts and user:123:likes) into the same slot?",
    options:["Keys sharing a common prefix always land in the same slot by default","Use hash tags so only the substring inside braces is hashed for slot placement","Issue both operations inside one MULTI block so they colocate automatically","Pin both keys with a manual CLUSTER SETSLOT command on the client"],
    correct:[1],
    why:"Only the substring inside braces is hashed, so {user:123}:posts and {user:123}:likes share a slot and can be used together in a MULTI transaction. Cluster multi-key ops only work within one slot.", more:"A shared textual prefix without braces does not guarantee colocation; the hash tag is what forces identical slot computation."},
  {id:"q128q", topic:"Redis", diff:"tricky", level:"Senior", type:"single",
    q:"HI: why is single-node Redis NOT a system of record, even with a replica?",
    options:["A single node cannot hold a large enough working set to be authoritative","Replication is asynchronous, so failover can drop the last acknowledged writes","Redis keeps everything in memory only and never persists to disk at all","Read throughput is too low for a system that must serve as source of truth"],
    correct:[1],
    why:"Async replication means the primary acks before the replica sees the write, so a promoted replica may never have the last acknowledged writes. Combined with RDB/AOF loss windows, acked writes can vanish.", more:"Redis does persist (RDB snapshots and AOF), but the persistence windows plus async replication together leave gaps where durability is not guaranteed."},
  {id:"q1451", topic:"Redis", diff:"tricky", level:"Senior", type:"single",
    q:"HI: a Redis fixed-window rate limiter does INCR then EXPIRE. What's the subtle bug to avoid?",
    options:["INCR is not atomic, so concurrent requests can lose increments","Calling EXPIRE every request keeps pushing the reset forward; set TTL only on the first","EXPIRE must run before INCR or the counter starts without a TTL","Each request needs its own key, so one EXPIRE cannot cover the window"],
    correct:[1],
    why:"If you EXPIRE on every call, steady traffic never gets a fresh window. Set expiry only when INCR returns 1, and run INCR and EXPIRE as one Lua script so a crash between them cannot leave a counter that never resets.", more:"INCR is in fact atomic; the bug is the repeated EXPIRE resetting the window, not a race inside INCR itself."},
  {id:"q1u7b", topic:"Redis", diff:"tricky", level:"Senior", type:"single",
    q:"HI: the correct way to RELEASE a Redis lock (SET key token NX EX 30) is…",
    options:["Issue a plain DEL on the key as soon as the work is done","Verify the key still holds your token, then DEL, as one atomic Lua script","Never delete it and rely solely on the EX timeout to release the lock","Overwrite the key with an unlocked sentinel value using SET"],
    correct:[1],
    why:"Your lock may have expired and been re-acquired by someone else, so a blind DEL would delete their lock. Check-token-then-DEL must run atomically via Lua on Redis's single thread.", more:"Relying only on expiry is safe but releases late, holding the lock for the full TTL even after work finishes; the check-and-delete frees it promptly and safely."},
  {id:"qw5la", topic:"Redis", diff:"tricky", level:"Staff", type:"single",
    q:"HI: the standard defense against a paused client acting after its Redis lock expired is…",
    options:["Configure a much longer TTL so the lock never expires mid-operation","Use a monotonic fencing token the storage layer checks; Redis has no built-in for this","Adopt the Redlock multi-node algorithm as the sole correctness guarantee","Add more replicas so the lock state survives a primary failure"],
    correct:[1],
    why:"Treat a Redis lock as an efficiency tool that occasionally fails. For correctness use fencing tokens or a consensus system like ZooKeeper or etcd; often a DB row lock or conditional update replaces the distributed lock entirely.", more:"Longer TTLs and more replicas reduce the odds of a stale holder but do not prevent it; only a fencing check at the resource rejects the late writer deterministically."},
  {id:"qsa76", topic:"Redis", diff:"tricky", level:"Staff", type:"single",
    q:"HI: the old 'Redis Pub/Sub doesn't scale in a cluster' complaint is outdated because…",
    options:["Pub/Sub now persists undelivered messages so subscribers can replay them","Sharded Pub/Sub since Redis 7 routes each channel to the shard that owns its slot","Pub/Sub now opens a dedicated connection per channel to spread the load","The scaling complaint was never accurate even in older cluster versions"],
    correct:[1],
    why:"Classic cluster Pub/Sub broadcast every message to every node, adding no capacity. Sharded Pub/Sub via SPUBLISH and SSUBSCRIBE since Redis 7 hashes each channel to a slot, so capacity scales with shards.", more:"Pub/Sub still does not persist messages, and connections are per node rather than per channel; only the routing model changed."},
  {id:"qqwok", topic:"Redis", diff:"tricky", level:"Senior", type:"multi",
    q:"HI: remediations for a Redis hot-key problem? (select all)",
    options:["Client-side caching of the hottest keys with a short TTL","Key copies stored as product:123:1..10 so copies hash to different nodes","Read replicas, provided clients are configured to read from replicas","Read replicas pointed at a write-hot key to spread the write load"],
    correct:[0,1,2],
    why:"Client-side caching, key copies, and replica reads all spread read load. But replicas do nothing for a write-hot key, since every write still lands on the one primary that owns the slot.", more:"Key copies trade consistency and write amplification for read spread; choose a copy at random on read to fan out across nodes."},
  {id:"qww1x", topic:"Redis", diff:"tricky", level:"Senior", type:"single",
    q:"HI: a Redis Stream work queue can process an item twice. Why, and what's the fix?",
    options:["A bug in XADD duplicates entries, so upgrading Redis resolves it","Redis cannot distinguish a slow worker from a dead one, so XCLAIM may re-run an entry","Streams do not persist entries, so add RDB snapshots to stop replays","Pub/Sub would avoid this, so replace the stream with Pub/Sub channels"],
    correct:[1],
    why:"Consumer groups track pending entries by idle time; when a worker looks dead another XCLAIMs the entry, but a slow worker looks identical to a dead one, so delivery is at-least-once. Make consumers idempotent.", more:"Pub/Sub is fire-and-forget with no pending list, so it does not duplicate but also gives no delivery guarantee at all, which is worse for a work queue."},
  {id:"q8yds", topic:"Networking", diff:"basic", level:"Mid", type:"single",
    q:"In the OSI model as framed by HI, which protocol lives at the Transport Layer (Layer 4)?",
    options:["IP, which routes packets between hosts across networks","TCP, which provides reliable ordered byte streams between endpoints","HTTP, which structures request and response messages for the web","DNS, which resolves human-readable names to addresses"],
    correct:[1],
    why:"TCP, UDP, and QUIC sit at Layer 4 (Transport). IP is Layer 3 (Network), while HTTP, WebSockets, DNS, and WebRTC are Layer 7 (Application).", more:"QUIC is often called Layer 4 even though it runs over UDP, because it provides the transport-level reliability and ordering TCP normally would."},
  {id:"q6zk8", topic:"Networking", diff:"tricky", level:"Senior", type:"single",
    q:"HI Networking deep dive: a New York to London round trip (~5,600 km) has a theoretical minimum latency of roughly…",
    options:["About 6ms round trip at the speed of light in fiber","About 56ms round trip at the speed of light in fiber","About 200ms round trip at the speed of light in fiber","About 500ms round trip at the speed of light in fiber"],
    correct:[1],
    why:"Light in fiber travels at about two-thirds of c, roughly 200,000 km/s, so the 5,600 km round trip floors near 56ms before any processing, versus under 1ms to a nearby server.", more:"This is a physical floor; real-world latency adds router hops, queuing, and TLS handshakes on top of the propagation delay."},
  {id:"q6pna", topic:"Networking", diff:"tricky", level:"Senior", type:"single",
    q:"HI: why are L4 load balancers generally preferred for WebSocket connections over L7?",
    options:["L4 can inspect HTTP headers and route each frame by cookie value","L4 keeps one persistent TCP connection through to the server, as if directly connected","L4 terminates the client connection and opens a fresh one to the backend","L4 does more per-packet CPU work, which makes the path more reliable"],
    correct:[1],
    why:"L4 maintains persistent TCP connections, which suits long-lived WebSockets. L7 terminates connections and inspects content, the opposite behavior.", more:"Because L4 does not parse HTTP, it cannot route by cookie or header; that capability belongs to L7, which is exactly why L7 must terminate the connection."},
  {id:"qarv8", topic:"Networking", diff:"tricky", level:"Senior", type:"multi",
    q:"Per HI, which statements about failures and retries are accurate? (select all)",
    options:["Retry with exponential backoff is the phrase interviewers are listening for","Backoff should add jitter so many clients do not retry in the same instant","Idempotent APIs make retries safe, often via an idempotency key","Circuit breakers should retry immediately and keep retrying until recovery"],
    correct:[0,1,2],
    why:"Retry with exponential backoff is the key phrase, jitter spreads retry storms, and idempotency keys make write retries safe. Circuit breakers do the opposite of retrying: they trip open and fail fast.", more:"A tripped breaker periodically lets a single trial request through (half-open) rather than hammering the dependency continuously."},
  {id:"qw0x3", topic:"Networking", diff:"basic", level:"Mid", type:"single",
    q:"What does HI say about QUIC for interviews?",
    options:["It fully supersedes TCP and should be the default for every connection","Treat it as a better TCP, but without TCP's broad baseline of adoption","It is a Layer 3 routing protocol that replaces IP for path selection","It is used only for peer-to-peer video via STUN and TURN servers"],
    correct:[1],
    why:"Consider QUIC a better TCP that still lacks TCP's broad adoption. Some performance-minded interviewers value QUIC and HTTP/3 knowledge, but most want your time spent elsewhere.", more:"QUIC reduces handshake round trips and avoids head-of-line blocking across streams, but operational and middlebox support still trails TCP."},
  {id:"qer9f", topic:"API design", diff:"basic", level:"Mid", type:"single",
    q:"Per HI, which HTTP API style is your go-to default unless you have a specific reason otherwise?",
    options:["GraphQL, to let clients shape exactly the fields they fetch","REST, which covers the vast majority of use cases by default","gRPC, for its typed contracts and binary efficiency","WebSockets, for a persistent connection to the client"],
    correct:[1],
    why:"Default to REST; it covers about 90 percent of use cases. If unsure, say you will use REST APIs and move on.", more:"Reach for GraphQL, gRPC, or WebSockets only when a specific requirement (flexible client queries, internal high-throughput RPC, or real-time push) justifies it."},
  {id:"qhzjs", topic:"API design", diff:"tricky", level:"Senior", type:"multi",
    q:"Per HI, which HTTP methods are idempotent? (select all)",
    options:["GET, since repeating a read leaves server state unchanged","PUT, since replacing a resource with the same body is repeatable","DELETE, since deleting an already-deleted resource is a no-op","POST, since each call typically creates a new distinct resource"],
    correct:[0,1,2],
    why:"GET, PUT, and DELETE are idempotent. POST and PATCH are not guaranteed idempotent, which matters when networks fail and clients retry, since you do not want duplicate bookings.", more:"Idempotency is about the end state after repeats, not the response code; DELETE may return 404 on the second call yet still be idempotent."},
  {id:"q2llq", topic:"API design", diff:"tricky", level:"Senior", type:"single",
    q:"HI's biggest GraphQL gotcha: a client queries 100 events each with its venue. What goes wrong?",
    options:["Over-fetching, where the response returns far more data than the client needs","The N+1 problem, where you run about 101 queries instead of 2","Under-fetching, where the client must make 100 follow-up round trips","Schema drift, where 100 stale type versions collide on read"],
    correct:[1],
    why:"This is the N+1 problem: 1 query for events plus N for each venue equals 101 instead of 2. Fix it with batching via a dataloader.", more:"A dataloader coalesces the per-venue lookups within a tick into one batched query, collapsing N+1 back toward 2."},
  {id:"q1374", topic:"API design", diff:"tricky", level:"Senior", type:"single",
    q:"HI: path parameter vs query parameter — when to use which?",
    options:["Path for optional filters and query parameters for required identifiers","Path when the value is required to identify the resource, query for optional filters","Always use query parameters since they are simpler to test and cache","Use path parameters only to carry POST request body fields"],
    correct:[1],
    why:"Tie it to required versus optional: use a path or nested resource when the value is required, like /events/{id}/tickets, and query parameters for optional filters like /tickets?event_id=123&section=VIP.", more:"The path identifies which resource; query parameters refine, sort, or filter a collection of them."},
  {id:"qiuxi", topic:"API design", diff:"basic", level:"Mid", type:"single",
    q:"HI's recommendation on API versioning in interviews?",
    options:["Header versioning, which keeps URLs clean and content-negotiable","URL versioning like /v1/events, widely understood and quick to explain","Semantic version fields embedded in the request body payload","Skip versioning entirely and evolve the schema in place"],
    correct:[1],
    why:"URL versioning is the safer interview choice because it is widely understood and fast to explain. Breakdowns omit it only because most interviewers do not probe versioning, not because it is unimportant.", more:"Header versioning is legitimate in production, but it is harder to demonstrate and reason about quickly under interview time pressure.", accept:"Header versioning is a defensible real-world choice (cleaner URLs, content negotiation), but URL versioning is recommended for interviews because it communicates intent instantly."},
  {id:"q1xeu", topic:"Data Modeling", diff:"basic", level:"Mid", type:"single",
    q:"HI Data Modeling: default database recommendation in an interview?",
    options:["A graph database like Neo4j for relationship-heavy domains","A relational database, specifically PostgreSQL, unless requirements signal otherwise","A document database like MongoDB for flexible evolving schemas","A key-value store like Redis serving as the system of record"],
    correct:[1],
    why:"Resist exotic databases; most of the time the right answer is relational, and PostgreSQL is the recommended default unless you have strong opinions otherwise.", more:"Postgres also supports JSONB, full-text search, and geo extensions, so reaching for a specialized store is rarely justified at interview scope."},
  {id:"qhxhz", topic:"Data Modeling", diff:"tricky", level:"Senior", type:"single",
    q:"HI warns graph databases are a common mistake. What point does it make?",
    options:["Neo4j cannot represent many-to-many relationships cleanly","Even Facebook models its social graph on MySQL, so SQL is enough for your interview","Graph databases are unable to enforce foreign-key constraints","Graph databases are slower than key-value stores at multi-hop traversals"],
    correct:[1],
    why:"Even Facebook models its social graph on MySQL, and LinkedIn and Twitter use SQL for core relationship data, so graph databases usually add needless complexity.", more:"Facebook's TAO is a graph-aware caching and serving layer built on top of sharded MySQL, not a native graph database."},
  {id:"qxper", topic:"Data Modeling", diff:"tricky", level:"Senior", type:"single",
    q:"HI: why is time-range sharding usually an anti-pattern for write-heavy systems?",
    options:["Time values are not valid partition keys for a sharded table","All current writes hit the latest-range shard, creating a hot shard","It makes querying for recent posts effectively impossible","Foreign-key relationships break across time-based shard boundaries"],
    correct:[1],
    why:"Time-range sharding sends all current writes to the latest-range shard, creating a hot shard. It works better for archival or analytics where writes spread across ranges.", more:"Recent-data reads can also concentrate on that same shard, so both write and read hotspots tend to land on the newest range."},
  {id:"q3eq1", topic:"Data Modeling", diff:"tricky", level:"Senior", type:"multi",
    q:"Per HI, the three factors that drive schema design decisions? (select all)",
    options:["Data volume, how much will be stored and how fast it grows","Access patterns, which queries and writes dominate the workload","Consistency requirements, how fresh and correct reads must be","Backend language, which framework and ORM the team will use"],
    correct:[0,1,2],
    why:"Everything flows from data volume, access patterns (the most important), and consistency requirements. The backend programming language is an implementation detail, not a schema driver.", more:"Access patterns dominate: model the data to make the queries you run most often cheap, even at the cost of some normalization."},
  {id:"q14bk", topic:"Data Modeling", diff:"basic", level:"Mid", type:"single",
    q:"HI advice on primary keys when defining entities?",
    options:["Use business data like email so keys stay human-readable","Use system-generated IDs like user_id, which stay stable as business rules change","Always build composite primary keys spanning several columns","Omit explicit primary keys and rely on row insertion order"],
    correct:[1],
    why:"Use system-generated IDs such as user_id and post_id over business data like email, because system keys stay stable even when business rules change.", more:"A business value like email can change or be reassigned, which would cascade into every foreign key referencing it."},
  {id:"q1gw6", topic:"Database Indexing", diff:"basic", level:"Mid", type:"single",
    q:"HI: how is main table data typically stored on disk before any index is added?",
    options:["A balanced B-tree ordered by the primary key","A heap file, holding rows in no particular order","A hash table bucketed by the primary key value","An LSM tree kept sorted by insertion timestamp"],
    correct:[1],
    why:"The main table is a heap file: a collection of rows in no particular order, like a notebook where you write entries as they arrive.", more:"An index adds the ordered structure on top; the heap itself just appends rows wherever there is free space."},
  {id:"q1hic", topic:"Database Indexing", diff:"tricky", level:"Senior", type:"single",
    q:"HI: the classic case where indexes hurt more than help?",
    options:["Frequent reads with infrequent writes, like a reporting view","Frequent writes with infrequent reads, like a logging table","Any table once it grows past roughly a million rows","A table that is only ever queried by its primary key"],
    correct:[1],
    why:"Write-heavy, read-light tables like logs are the classic case where index maintenance overhead is not justified. Tiny tables are similar, where a sequential scan beats traversing an index.", more:"Every insert must also update each index, so on a write-dominated table indexes tax the hot path while rarely paying off on reads."},
  {id:"qra8i", topic:"Database Indexing", diff:"tricky", level:"Senior", type:"multi",
    q:"Per HI, which statements about B-tree indexes are correct? (select all)",
    options:["Nodes can have hundreds of children, unlike a binary tree's two","Each node is sized to fit one disk page, about 8KB in Postgres","Finding id=350 in Postgres might read only 2 to 3 pages from disk","B-trees support only equality lookups, never range scans"],
    correct:[0,1,2],
    why:"B-tree nodes have hundreds of children, fit a roughly 8KB page, and a lookup may read only 2 to 3 pages (root, maybe an internal node, then leaf). B-trees handle both equality and range, so the last statement is false.", more:"The high fan-out is what keeps the tree shallow, so even large tables resolve in a handful of page reads."},
  {id:"qne40", topic:"Database Indexing", diff:"tricky", level:"Senior", type:"single",
    q:"HI: random vs sequential access on modern SSDs?",
    options:["Modern NVMe SSDs have made random and sequential access essentially equal","Random access is still meaningfully slower than sequential, even on SSDs","Sequential access on SSDs is actually slower than sequential on HDDs","On SSDs the access pattern only matters for writes, not reads"],
    correct:[1],
    why:"HI flags as a misconception that SSDs equalize access; random is still meaningfully slower than sequential (far worse on HDDs), making proper indexing critical."},
  {id:"qkfz9", topic:"Database Indexing", diff:"basic", level:"Mid", type:"single",
    q:"HI: what cost does every index impose on writes?",
    options:["Writes are blocked entirely while any index on the table exists","A single write may trigger several disk writes, since every index must also be updated","Indexes cost extra disk space but add no write-time overhead","Writes speed up because the index already holds a copy of the row"],
    correct:[1],
    why:"HI: on insert/update the DB updates the main table plus every index, so multiple indexes mean a single write triggers several disk writes, plus extra disk space."},
  {id:"q1on2", topic:"Caching", diff:"basic", level:"Mid", type:"single",
    q:"Per HI, roughly what latency win does reading a profile from Redis give over Postgres?",
    options:["About 5x faster, roughly 10ms down to 2ms","About 50x faster, roughly 50ms down to 1ms","About 2x faster, roughly 4ms down to 2ms","About 500x faster, roughly 50ms down to 0.1ms"],
    correct:[1],
    why:"HI: Postgres ~50ms vs Redis ~1ms, a 50x improvement, because memory sits closer to the CPU and avoids disk."},
  {id:"q1vdu", topic:"Caching", diff:"tricky", level:"Senior", type:"single",
    q:"HI: the primary risk of write-behind (write-back) caching?",
    options:["Writes get slow because both the cache and the DB must confirm each write","If the cache crashes before flushing to the DB, recent writes can be lost","The cache fills with entries that are written but never actually read","Each read must first consult a directory to locate the data"],
    correct:[1],
    why:"Write-behind writes only to cache and flushes to the DB asynchronously, giving fast writes but data loss if the cache crashes before flushing. Suits workloads tolerant of occasional loss."},
  {id:"q45qu", topic:"Caching", diff:"tricky", level:"Senior", type:"single",
    q:"HI: cache warming only prevents stampedes under which condition?",
    options:["Only when reads are deduplicated via request coalescing","Only when expiration is TTL-based, not invalidation triggered on writes","Only when the cache runs in-process within the application","Only when hot keys are replicated across multiple cache nodes"],
    correct:[1],
    why:"HI: warming refreshes popular keys before they expire, which only helps with TTL-based expiration. If you invalidate on writes instead, warming does not prevent stampedes."},
  {id:"qw18x", topic:"Caching", diff:"basic", level:"Mid", type:"single",
    q:"HI: the single most effective way to handle a cache stampede?",
    options:["Raise the TTL to several hours so entries expire far less often","Request coalescing or single-flight, where one request rebuilds while others wait","Switch to a write-through cache so entries are refreshed on every write","Shard the cache across more nodes to spread the load on a miss"],
    correct:[1],
    why:"HI calls request coalescing (single-flight) the most effective fix: one request rebuilds the entry while the rest wait, instead of hundreds hitting the DB.", accept:"Raising the TTL reduces stampede frequency but does not prevent the thundering herd when an entry finally expires, so coalescing is the better answer."},
  {id:"qx7el", topic:"Caching", diff:"tricky", level:"Senior", type:"multi",
    q:"Per HI, which statements about caching patterns/layers are correct? (select all)",
    options:["Cache-aside is the sensible interview default for most reads","Redis supports write-through natively, no application code required","CDNs are essentially a form of read-through cache","In-process caching is an optimization layer added after an external cache"],
    correct:[0,2,3],
    why:"HI: cache-aside is the default, CDNs are read-through, and in-process caching comes after an external cache. It explicitly says Redis does NOT natively support write-through; application or framework code is needed."},
  {id:"q1tmp", topic:"Sharding", diff:"basic", level:"Mid", type:"single",
    q:"HI: even powerful cloud databases max out around a storage ceiling that forces sharding. What number does HI cite for Amazon Aurora?",
    options:["Around 256 GiB","Around 2.5 TB","Around 256 TiB","Around 16 TB"],
    correct:[2],
    why:"HI: even Aurora maxes out around 256 TiB, the kind of ceiling that forces splitting data across machines."},
  {id:"q15lp", topic:"Sharding", diff:"tricky", level:"Senior", type:"single",
    q:"HI: what distinguishes partitioning from sharding?",
    options:["Partitioning splits data across many machines while sharding stays on one instance","Partitioning splits data within a single DB instance while sharding splits across machines","They mean exactly the same thing with no practical distinction","Partitioning applies only to NoSQL stores while sharding applies only to SQL"],
    correct:[1],
    why:"HI: partitioning usually means splitting within one instance (ranges or hash); sharding means across machines. Terms are used loosely; what matters is one machine vs many."},
  {id:"q9zs9", topic:"Sharding", diff:"tricky", level:"Senior", type:"single",
    q:"HI: why is is_premium (a boolean) a bad shard key?",
    options:["Boolean columns cannot be fed into a hash function reliably","Two possible values cap you at two shards with badly uneven load","Each request would require an extra directory lookup to route it","The value flips when a user upgrades, forcing constant resharding"],
    correct:[1],
    why:"HI's canonical bad shard key: low cardinality (two values) caps you at two shards, and if most users are free, one shard is overloaded. Good keys need high cardinality plus even distribution."},
  {id:"qznlo", topic:"Sharding", diff:"basic", level:"Mid", type:"single",
    q:"HI: which sharding strategy will interviewers assume unless you say otherwise?",
    options:["Range-based sharding on a natural ordering key","Hash-based sharding on the partition key","Directory-based sharding via a lookup service","Vertical partitioning by splitting columns across tables"],
    correct:[1],
    why:"HI labels hash-based sharding the default and most common; it is what your interviewer assumes unless you explicitly state otherwise."},
  {id:"q1del", topic:"Sharding", diff:"tricky", level:"Staff", type:"multi",
    q:"Per HI, which are valid ways to handle hot spots or cross-shard problems? (select all)",
    options:["Isolate a hot key onto its own dedicated shard","Use compound shard keys such as hash of user_id plus date","Route every cross-shard write through two-phase commit by default","Denormalize related data so it stays together on one shard"],
    correct:[0,1,3],
    why:"HI recommends isolating hot keys, compound keys, and denormalizing. It warns AGAINST 2PC as the go-to (slow, fragile); prefer sagas or avoiding cross-shard transactions."},
  {id:"qu89t", topic:"Consistent Hashing", diff:"basic", level:"Mid", type:"single",
    q:"HI: what core problem does consistent hashing solve vs simple modulo hashing?",
    options:["It spreads hot keys so popular items never overload one node","It minimizes how much data must be moved when a node is added or removed","It removes the need for a hash function by mapping keys directly","It provides strong consistency across all replicas of a key"],
    correct:[1],
    why:"HI: modulo hashing (going from %3 to %4) remaps almost every key; consistent hashing moves only a bounded fraction when membership changes."},
  {id:"quto9", topic:"Consistent Hashing", diff:"tricky", level:"Senior", type:"single",
    q:"HI hash-ring example: how do you find which database an event maps to?",
    options:["Compute hash of the event ID modulo the current node count","Hash the event ID to a point on the ring, then move clockwise to the next node","Look the event ID up in a directory table that maps it to a node","Assign the event to whichever node currently reports the lowest load"],
    correct:[1],
    why:"HI: place nodes on the ring, hash the event ID to a point, then move clockwise to the next node, avoiding modulo and limiting movement on membership change."},
  {id:"qcqpp", topic:"Consistent Hashing", diff:"tricky", level:"Senior", type:"single",
    q:"HI: what problem do virtual nodes specifically solve?",
    options:["Hot keys created by a single piece of extremely popular content","A failed node dumping its entire load onto its one clockwise neighbor","The need to replicate each key for durability and availability","Extending the ring beyond the 2^32 address space when nodes grow"],
    correct:[1],
    why:"HI: without virtual nodes a failed node's load shifts entirely to one neighbor (doubling it). Virtual nodes place each DB at many ring points so failure load spreads evenly."},
  {id:"qpk9k", topic:"Consistent Hashing", diff:"tricky", level:"Staff", type:"multi",
    q:"Per HI, which statements about consistent hashing in real systems are correct? (select all)",
    options:["Virtual nodes fix structural imbalance while replication or key-salting fix workload imbalance","Redis Cluster implements consistent hashing using virtual nodes per master","Redis Cluster uses fixed hash slots, 16,384 of them via CRC16(key) mod 16384","DynamoDB replicates each partition across 3 AZs, so a primary failure promotes a replica with no data movement"],
    correct:[0,2,3],
    why:"HI: virtual nodes fix key-distribution imbalance while replication or salting fix traffic imbalance; Redis Cluster uses fixed slots (NOT consistent hashing); DynamoDB replicates partitions across 3 AZs so failover moves no data."},
  {id:"q1muv", topic:"CAP / PACELC", diff:"basic", level:"Staff", type:"single",
    q:"HI: CAP theorem practically reduces to which single choice?",
    options:["Whether to build on a SQL or a NoSQL datastore","Whether to favor consistency or availability when a network partition occurs","Whether to scale by sharding the data or by replicating it","Whether to guarantee strong or eventual durability of writes"],
    correct:[1],
    why:"HI: partition tolerance is non-negotiable in any distributed system, so CAP boils down to one choice: prioritize consistency or availability when a partition occurs."},
  {id:"q1lty", topic:"CAP / PACELC", diff:"tricky", level:"Staff", type:"single",
    q:"HI USA/Europe profile example during a partition: which choice and why?",
    options:["Consistency, because showing a stale display name is unacceptable","Availability, because showing the old name beats showing an error","Consistency, because profile fields are treated as financial data","Availability, but only by rejecting writes while still serving reads"],
    correct:[1],
    why:"HI: for the profile example the answer is clear, show the stale old name (availability) rather than an error, since a stale name beats no name."},
  {id:"q1yuh", topic:"CAP / PACELC", diff:"tricky", level:"Staff", type:"multi",
    q:"Per HI, which should prioritize CONSISTENCY over availability? (select all)",
    options:["Ticket and seat booking, to prevent double-booking the same seat","Viewing a Yelp restaurant's posted opening hours","E-commerce inventory counts, to prevent overselling stock","Stock trading order books matching buyers and sellers"],
    correct:[0,2,3],
    why:"HI lists ticket booking, inventory, and financial/trading as consistency-required. Yelp showing slightly outdated hours is an availability example; brief staleness is fine."},
  {id:"q1qg1", topic:"CAP / PACELC", diff:"tricky", level:"Staff", type:"single",
    q:"HI: the model where users always see their own updates immediately, but others may see older versions, is…",
    options:["Causal consistency, where related operations are seen in order","Strong consistency, where every reader sees the latest write at once","Read-your-own-writes, where you see your updates but others may lag","Eventual consistency, where all replicas converge given enough time"],
    correct:[2],
    why:"HI: read-your-own-writes is common in social media so users see their own profile edits right away, even if others briefly see stale data."},
  {id:"q6wvd", topic:"CAP / PACELC", diff:"basic", level:"Staff", type:"single",
    q:"HI: the default consistency model of most distributed databases when prioritizing availability?",
    options:["Strong consistency, where reads always reflect the newest write","Causal consistency, preserving the order of related operations","Eventual consistency, where replicas converge over time","Read-your-own-writes, guaranteeing you see your own updates"],
    correct:[2],
    why:"HI: eventual consistency is the most relaxed model and the default of most distributed databases, what you implicitly choose when prioritizing availability."},
  {id:"qjc2e", topic:"Numbers to Know", diff:"basic", level:"Mid", type:"single",
    q:"HI: a common giveaway that a candidate has only book knowledge is…",
    options:["Being unable to state the CAP theorem when asked","Doing scale math with outdated hardware numbers that underestimate modern systems","Never bringing up sharding as a scaling option","Reaching for Redis whenever caching comes up"],
    correct:[1],
    why:"HI: relying on outdated hardware constraints leads to over-engineered designs, one of the biggest tells of book-only knowledge."},
  {id:"q19qq", topic:"Numbers to Know", diff:"tricky", level:"Senior", type:"single",
    q:"HI 2026 numbers: roughly how much RAM does a high-memory instance like AWS U-24tb1.metal provide?",
    options:["Around 512 GiB of RAM","Around 4 TB of RAM","Around 24 TB of RAM","Around 60 TB of RAM"],
    correct:[2],
    why:"HI cites U-24tb1.metal at 24 TB RAM (X1e.32xlarge at 4 TB, M6i.32xlarge at 512 GiB); many apps that once needed distributed systems now fit on one machine."},
  {id:"qpzry", topic:"Numbers to Know", diff:"tricky", level:"Senior", type:"single",
    q:"HI network latency tiers: approximate latency across availability zones within the same region?",
    options:["Under 1ms","Roughly 1-2ms","Roughly 50-150ms","Roughly 250-300ms"],
    correct:[1],
    why:"HI: under 1ms within a single AZ, 1-2ms across AZs in a region, and 50-150ms cross-region."},
  {id:"q1eap", topic:"Numbers to Know", diff:"basic", level:"Mid", type:"single",
    q:"HI: how is object storage like S3 characterized as a constraint?",
    options:["A hard ceiling of roughly 60 TB per bucket","Effectively unlimited, with petabyte-scale considered standard practice","Capped near 256 TiB, the same ceiling as Amazon Aurora","Suitable only for cold, rarely accessed archival data"],
    correct:[1],
    why:"HI: S3 is effectively unlimited (petabyte-scale is standard); the days of storage being a primary constraint are largely behind us."},
  {id:"q8pxe", topic:"Numbers to Know", diff:"tricky", level:"Senior", type:"multi",
    q:"Which 2026 hardware figures does HI specifically cite? (select all)",
    options:["i3en.24xlarge offers roughly 60 TB of local SSD","D3en.12xlarge offers roughly 336 TB of HDD","Within a datacenter, 25 Gbps networking is common","A single Postgres instance should be sharded once it reaches 100GB"],
    correct:[0,1,2],
    why:"HI cites i3en.24xlarge at 60 TB SSD, D3en.12xlarge at 336 TB HDD, and 25 Gbps datacenter networking. It explicitly criticizes the textbook split-at-100GB rule as obsolete."},
  {id:"q1jo6", topic:"Elasticsearch", diff:"basic", level:"Mid", type:"single",
    q:"HI: what core problem is Elasticsearch presented as solving?",
    options:["Durable streaming of messages between decoupled services","Full-text search and querying over large volumes of data","Strongly consistent transactional writes across records","Distributed locking and coordination among nodes"],
    correct:[1],
    why:"HI frames Elasticsearch around search and querying over big data via inverted indexes, not as a queue, lock service, or transactional store."},
  {id:"q1qho", topic:"Elasticsearch", diff:"basic", level:"Mid", type:"single",
    q:"HI: the relationship between an Elasticsearch index, shards, and Lucene?",
    options:["An index is one Lucene file that every node opens and shares","An index is split into shards, and each shard is a self-contained Lucene index","Shards are read replicas pointing at a single master Lucene instance","Index and shard are two interchangeable names for the same unit"],
    correct:[1],
    why:"HI: an index is partitioned into shards for horizontal scaling, and each shard is itself a complete Lucene index that can live on a different node."},
  {id:"qlbk2", topic:"Elasticsearch", diff:"tricky", level:"Senior", type:"single",
    q:"HI: why must you choose the number of primary shards carefully up front?",
    options:["Primary shard count is fixed at creation; changing it means reindexing into a new index","Adding primary shards later triggers an automatic rebalance at no real cost","Primary shard count influences only read latency, never write throughput","Elasticsearch sets the shard count automatically and it cannot be configured"],
    correct:[0],
    why:"HI: primary shard count is fixed at index creation; changing it requires reindexing into a new index, a common gotcha interviewers probe."},
  {id:"qcgjh", topic:"Elasticsearch", diff:"tricky", level:"Senior", type:"single",
    q:"HI: the common anti-pattern with Elasticsearch is using it as…",
    options:["As a search layer running alongside a separate primary database","As the single primary datastore and source of truth for the system","As a tool for autocomplete, fuzzy matching, and relevance ranking","As a store backed by inverted indexes kept in sync from the DB"],
    correct:[1],
    why:"HI: Elasticsearch should generally not be your source of truth; keep a separate primary DB and sync ES as a secondary search index."},
  {id:"q1dit", topic:"Elasticsearch", diff:"tricky", level:"Senior", type:"multi",
    q:"Which approaches keep Elasticsearch in sync with a primary DB WITHOUT hitting the dual-write problem? (select all)",
    options:["Change Data Capture (CDC) streaming the DB's commit log into Elasticsearch","A transactional outbox: write the change + an outbox row in one DB transaction, then relay to ES","Application-level dual writes that update Postgres and ES in two separate calls","A periodic full reindex used as the ONLY real-time sync mechanism"],
    correct:[0,1],
    why:"CDC and the transactional outbox both tie the ES update to the committed DB state without needing an atomic write across two systems. Application-level dual writes are the classic dual-write problem: with no shared transaction, one store can succeed while the other fails, silently desyncing ES from the source of truth. A periodic full reindex is a backfill/reconciliation tool, not real-time sync.",
    more:"This is the same dual-write problem the CDC/Outbox topic covers. Prefer CDC (e.g. Debezium tailing the WAL) or an outbox relay; keep a periodic reindex only as a safety-net to repair drift. HelloInterview mentions dual writes, but at Staff level you should name its failure mode and reach for the outbox instead.", src:"https://www.hellointerview.com/learn/system-design/deep-dives/elasticsearch"},
  {id:"qd3nz", topic:"Elasticsearch", diff:"basic", level:"Mid", type:"single",
    q:"HI: which structure makes Elasticsearch efficient for full-text search?",
    options:["A B-tree keyed on document ID for fast point lookups","An inverted index mapping each term to the documents containing it","A consistent hash ring spreading documents across nodes","A skip list ordered by document timestamp for range scans"],
    correct:[1],
    why:"HI: the inverted index maps each term to the documents containing it, enabling fast full-text search, unlike a B-tree keyed on IDs."},
  {id:"q8gnc", topic:"Kafka vs Queues", diff:"basic", level:"Mid", type:"single",
    q:"HI Kafka deep dive: how is a topic distinguished from a partition?",
    options:["A topic is the physical storage while a partition is just a logical label","A topic is a logical grouping while a partition is the physical ordered append-only log","Topic and partition describe the same underlying unit of storage","A single partition can span and serve several different topics"],
    correct:[1],
    why:"HI: a topic is a logical grouping of messages; a partition is the physical, ordered, immutable append-only log. A topic can have many partitions across brokers."},
  {id:"q1x5l", topic:"Kafka vs Queues", diff:"basic", level:"Mid", type:"single",
    q:"HI: how does a Kafka consumer group ensure each event is normally processed once?",
    options:["Every consumer reads every partition and deduplicates the overlap","Each partition is assigned to exactly one consumer within the group","Kafka load-balances each individual message randomly across consumers","The producer decides which consumer in the group handles each message"],
    correct:[1],
    why:"HI: within a consumer group each partition is assigned to exactly one consumer, so under normal operation each event goes to a single consumer."},
  {id:"qk2e8", topic:"Kafka vs Queues", diff:"tricky", level:"Senior", type:"single",
    q:"HI single-broker capacity estimate on good hardware?",
    options:["Around 100GB of data and 100K messages per second","Around 1TB of data and roughly 1M messages per second","Around 10TB of data and 10M messages per second","Around 500GB of data and 50K messages per second"],
    correct:[1],
    why:"HI's hand-wavy but useful estimate: a single broker stores ~1TB and handles up to ~1M messages per second, used to decide whether scaling is even needed."},
  {id:"qp353", topic:"Kafka vs Queues", diff:"tricky", level:"Senior", type:"single",
    q:"HI: how is a Kafka message routed to a partition by default?",
    options:["partition equals hash(key) mod num_partitions using the murmur2 hash","Round-robin across partitions, ignoring the message key entirely","By the message timestamp taken modulo the partition count","By routing to whichever broker currently reports the lowest load"],
    correct:[0],
    why:"HI: partition equals hash(key) mod num_partitions with murmur2 by default. A bad key causes hot partitions."},
  {id:"q9zg0", topic:"Kafka vs Queues", diff:"tricky", level:"Staff", type:"multi",
    q:"Per HI, strategies for handling a hot partition (e.g. the Nike LeBron ad)? (select all)",
    options:["Random salting appended to the partition key to spread load","A compound key such as ad ID combined with region","Storing the full event payload blob directly inside Kafka","Applying back pressure to slow the producer down"],
    correct:[0,1,3],
    why:"HI lists no-key default partitioning, random salting, compound keys, and back pressure. Storing large blobs in Kafka is an anti-pattern, not a fix."},
  {id:"q7ktc", topic:"Kafka vs Queues", diff:"tricky", level:"Senior", type:"single",
    q:"HI: which feature does Kafka NOT natively support that AWS SQS does?",
    options:["Strict message ordering within a single partition","Built-in consumer retries with automatic dead-letter queues","Durable replication of messages across multiple brokers","Per-consumer offset tracking to resume from a position"],
    correct:[1],
    why:"With classic consumer groups Kafka has no out-of-the-box retry/DLQ support; you build a retry topic plus DLQ yourself (the Web Crawler breakdown chose SQS for this). Note: Kafka 4.x share groups (KIP-932) add broker-level redelivery, narrowing this gap."},
  {id:"q1owz", topic:"API Gateway", diff:"basic", level:"Mid", type:"single",
    q:"HI: the core, primary function of an API Gateway that candidates often forget?",
    options:["Authenticating and authorizing each incoming request","Routing each request to the appropriate backend service","Caching responses to reduce backend load","Terminating SSL and managing certificates"],
    correct:[1],
    why:"HI: candidates emphasize middleware but forget the core reason, request routing, deciding which backend handles each incoming request."},
  {id:"qf2z8", topic:"API Gateway", diff:"basic", level:"Mid", type:"single",
    q:"HI request flow: when does the gateway perform request validation?",
    options:["After routing, once the backend has accepted the request","Up front, as the first step before routing or other work","Only after a cached response has been checked or stored","Never at the gateway; validation is left to each backend"],
    correct:[1],
    why:"HI lists validation first, so malformed requests (bad JSON, missing API key) are rejected early without wasting backend resources."},
  {id:"qjopq", topic:"API Gateway", diff:"tricky", level:"Senior", type:"single",
    q:"HI: the two load-balancing dimensions around an API Gateway?",
    options:["Client-to-gateway uses a dedicated LB like ELB or NGINX; gateway-to-service is done by the gateway","The gateway handles client-to-gateway balancing internally, no separate LB needed","Load balancing is generally unrelated to API gateways in practice","Backend services balance among themselves; the gateway never load-balances"],
    correct:[0],
    why:"HI separates client-to-gateway balancing (a dedicated LB such as ELB or NGINX in front) from gateway-to-service balancing (the gateway distributing across backend instances)."},
  {id:"q19vp", topic:"API Gateway", diff:"tricky", level:"Senior", type:"single",
    q:"HI: what responses are appropriate to cache at the API Gateway?",
    options:["Highly user-specific responses, to personalize output per user","Frequently accessed data that changes rarely and is not user specific","Essentially every response, since gateway caching is always safe","Only error responses, to avoid re-running failed backend calls"],
    correct:[1],
    why:"HI: gateway caching fits frequently accessed, infrequently changing, non-user-specific data where the same input returns the same result."},
  {id:"qebq4", topic:"API Gateway", diff:"basic", level:"Mid", type:"single",
    q:"HI bottom line: when to introduce an API Gateway?",
    options:["Always, even for a simple single-client client-server app","For microservices; skip it for a simple monolithic or single-client design","Only once you also need a dedicated database caching layer","Only for very small systems with fewer than three services"],
    correct:[1],
    why:"HI: use a gateway with microservices, but it is overkill for simple monolithic or single-client systems."},
  {id:"qbgy3", topic:"API Gateway", diff:"tricky", level:"Senior", type:"single",
    q:"HI: how should you handle the API Gateway when speaking in an interview?",
    options:["Walk through its full middleware pipeline in detail","Briefly note it handles routing plus basic middleware, then move on","Replace it conceptually with a message queue for decoupling","Model it as the system's source of truth for request state"],
    correct:[1],
    why:"HI stresses the gateway is thin and not the interesting part; the bigger risk is over-spending time, so note routing plus middleware and move on."},
  {id:"q1j4u", topic:"Cassandra", diff:"basic", level:"Mid", type:"single",
    q:"HI: what storage structure gives Cassandra its high write throughput, replacing the B-tree?",
    options:["A skip list ordered for fast in-memory range scans","A Log Structured Merge tree using Memtables and immutable SSTables","An inverted index mapping terms to the rows that contain them","A balanced B-plus tree updated in place on each write"],
    correct:[1],
    why:"Cassandra uses an LSM tree instead of a B-tree, favoring write speed by treating most writes as append-only (Memtable then immutable SSTable)."},
  {id:"q1diu", topic:"Cassandra", diff:"basic", level:"Mid", type:"single",
    q:"HI: the purpose of a clustering key within a Cassandra primary key?",
    options:["It selects which node and partition the row is stored on","It defines the sorted order of rows within a single partition","It enforces referential integrity between related tables","It declares which columns are encrypted at rest"],
    correct:[1],
    why:"A primary key is partition key(s) plus clustering key(s). The partition key picks the partition; the clustering key sets sorted order within it (e.g. Discord ORDER BY message_id DESC)."},
  {id:"q1t70", topic:"Cassandra", diff:"tricky", level:"Senior", type:"single",
    q:"HI: with replication factor 3, why does QUORUM for both reads and writes guarantee a read sees the latest write?",
    options:["QUORUM waits for all 3 replicas to acknowledge every operation","QUORUM needs a majority each, so read and write sets always overlap on a node","QUORUM routes all reads and writes through one elected leader replica","QUORUM turns off hinted handoff so no replica can fall behind"],
    correct:[1],
    why:"QUORUM = majority (n/2+1). For 3 nodes that is 2, so a write touches 2 and a read touches 2 of 3, guaranteeing at least one overlapping node that has seen the write."},
  {id:"qcwkm", topic:"Cassandra", diff:"tricky", level:"Staff", type:"single",
    q:"HI: why did Discord add a bucket (fixed 10-day window) to the partition key of their Cassandra messages table?",
    options:["To let messages be joined to channel and author rows efficiently","To cap partition size so busy channels avoid large-partition problems","To make recent-message reads strongly consistent across replicas","To reduce the number of SSTables produced during compaction"],
    correct:[1],
    why:"Partitioning only by channel_id let busy channels grow monotonically into large-partition problems. The 10-day bucket caps partition size and rolls over, while recent reads still hit one partition."},
  {id:"q7602", topic:"Cassandra", diff:"tricky", level:"Staff", type:"multi",
    q:"HI: which are true about how Cassandra handles writes and deletes? (select all)",
    options:["A delete writes a tombstone marker rather than removing data in place","Writes hit the commit log, then the Memtable, then flush to an immutable SSTable","Each write edits the existing row in place inside the on-disk SSTable","Compaction merges SSTables together and purges tombstoned rows"],
    correct:[0,1,3],
    why:"Deletes are tombstones; writes hit the commit log (WAL) then the Memtable, later flushed to an immutable SSTable. SSTables are immutable (no in-place updates); compaction merges SSTables and purges tombstones."},
  {id:"q90lo", topic:"Cassandra", diff:"basic", level:"Staff", type:"single",
    q:"HI: how do Cassandra nodes share cluster state (which nodes are alive, the schema)?",
    options:["A central ZooKeeper ensemble holding the authoritative cluster state","A peer-to-peer gossip protocol biased toward designated seed nodes","An elected primary that broadcasts state changes to its followers","A shared system table polled by every node for membership info"],
    correct:[1],
    why:"Cassandra uses peer-to-peer gossip with a bias toward seed nodes (guaranteed hotspots) so info reaches the whole cluster and no sub-clusters form. No single coordinator."},
  {id:"qsvbq", topic:"DynamoDB", diff:"basic", level:"Mid", type:"single",
    q:"HI: maximum size of a single DynamoDB item, including all attributes?",
    options:["64KB per item across all attributes","256KB per item across all attributes","400KB per item across all attributes","1MB per item across all attributes"],
    correct:[2],
    why:"Each item has a primary key and can hold up to 400KB of data including all attributes."},
  {id:"q4zal", topic:"DynamoDB", diff:"tricky", level:"Senior", type:"single",
    q:"HI: how do you choose eventual vs strong consistency for a DynamoDB read?",
    options:["A consistency mode fixed for the whole table at creation time","A per-request flag, ConsistentRead=true, on the individual read call","Automatically inferred from the size of the item being read","A single setting applied uniformly across the whole AWS region"],
    correct:[1],
    why:"Not table-level. Set ConsistentRead=true per GetItem/Query/Scan. Strong reads hit the leader, cost 2x the RCU (1 RCU per 4KB vs 0.5), and are not supported on GSIs."},
  {id:"qjac3", topic:"DynamoDB", diff:"tricky", level:"Senior", type:"multi",
    q:"HI: which correctly distinguish a GSI from an LSI in DynamoDB? (select all)",
    options:["A GSI can use a different partition key; an LSI shares the base table partition key","GSIs support only eventually consistent reads; LSIs also support strong reads","LSIs can be added or dropped at any time; GSIs must be created with the table","An LSI is co-located on the base table's partitions; a GSI lives on separate partitions"],
    correct:[0,1,3],
    why:"GSIs use a different partition key, live on separate partitions, eventual-only. LSIs share the partition key, are co-located, support strong reads, but must be defined at table creation (the reversed claim is wrong)."},
  {id:"q1foo", topic:"DynamoDB", diff:"tricky", level:"Senior", type:"single",
    q:"HI: using ProjectionExpression to return only a few attributes primarily saves what?",
    options:["RCU cost, since only the projected attributes are read from storage","Network bandwidth only; the full item is still read and full RCU is charged","Storage cost, since unprojected attributes are never persisted to disk","Write cost, since projected reads avoid touching the leader replica"],
    correct:[1],
    why:"Unlike SQL column selection, ProjectionExpression only cuts network bandwidth. The full item is still read and you pay full RCU on its total size, which is why large items should be normalized."},
  {id:"q158k", topic:"DynamoDB", diff:"basic", level:"Mid", type:"single",
    q:"HI: roughly how many read/write capacity units does a single DynamoDB partition support?",
    options:["About 3,000 RCUs and about 1,000 WCUs per partition","About 1,000 RCUs and about 3,000 WCUs per partition","About 10,000 RCUs and about 10,000 WCUs per partition","About 500 RCUs and about 500 WCUs per partition"],
    correct:[0],
    why:"About 3,000 RCUs and 1,000 WCUs per partition (~12MB/s reads, ~1MB/s writes), useful for back-of-envelope partition-count math."},
  {id:"q9r3m", topic:"DynamoDB", diff:"tricky", level:"Senior", type:"single",
    q:"HI: an important caveat about DAX (DynamoDB Accelerator) and stale data?",
    options:["DAX serves only eventually consistent reads, so cached data is never stale","DAX auto-invalidates only writes routed through DAX; direct DynamoDB writes stay stale until TTL","DAX caches strongly consistent reads as well, and those entries drift stale fastest","DAX is fully transparent and needs no client SDK change to start using it"],
    correct:[1],
    why:"DAX is read-through/write-through but only invalidates for writes through DAX. Direct DynamoDB writes bypass it, so entries stay stale until TTL/eviction. DAX also does not cache strong reads and needs the DAX client SDK."},
  {id:"q1ssx", topic:"PostgreSQL", diff:"basic", level:"Mid", type:"single",
    q:"HI: what index type does PostgreSQL create by default, including on a primary key?",
    options:["A hash index optimized for equality lookups","A B-tree index, also auto-created on the primary key","A GIN index for multi-value and full-text columns","An LSM tree index tuned for write-heavy tables"],
    correct:[1],
    why:"Postgres defaults to B-tree indexes (auto-created on the primary key), good for exact matches, range queries, and sorting when ORDER BY columns match the index order."},
  {id:"qxq5m", topic:"PostgreSQL", diff:"basic", level:"Mid", type:"single",
    q:"HI: why is read performance the first focus when evaluating Postgres for a social platform?",
    options:["Writes require an extension, so reads are all the engine handles natively","In most apps reads vastly outnumber writes, since users browse far more than they create","Postgres cannot maintain indexes efficiently on write-heavy tables","Read operations are metered and billed separately from writes"],
    correct:[1],
    why:"Reads vastly outnumber writes in most apps; users spend far more time browsing than creating, making read performance critical."},
  {id:"qlouw", topic:"PostgreSQL", diff:"tricky", level:"Senior", type:"single",
    q:"HI: a common interview trap with Postgres indexes?",
    options:["Adding an index to every column to be safe","Choosing a B-tree index for range and ORDER BY queries","Letting the primary key be backed by an index","Building multi-column indexes for common query patterns"],
    correct:[0],
    why:"Indexing every column is a trap: each index slows writes, consumes disk, and may not even be used if the planner prefers a sequential scan."},
  {id:"q39sj", topic:"PostgreSQL", diff:"tricky", level:"Senior", type:"multi",
    q:"HI social-media example: which operations have which consistency/integrity needs? (select all)",
    options:["Creating a DM thread with its participants and first message must be atomic","Like counts can lag a few seconds and remain eventually consistent","Comments and follows need referential integrity to their parent rows","Follower counts must be identical on every replica the instant they change"],
    correct:[0,1,2],
    why:"DM-thread creation must be atomic, like counts can be eventually consistent (a few seconds lag is fine), comments/follows need referential integrity. It does not claim follower counts need instant strong consistency everywhere."},
  {id:"q1ryg", topic:"PostgreSQL", diff:"tricky", level:"Senior", type:"single",
    q:"HI warns candidates against which kind of statement about Postgres?",
    options:["Noting that Postgres supports several index types like B-tree and GIN","Sweeping claims like 'NoSQL scales better than Postgres' made without nuance","Observing that reads usually outnumber writes in typical workloads","Pointing out that the right index can speed up read queries"],
    correct:[1],
    why:"Candidates get tripped up either diving too deep (MVCC, WAL) or making broad claims like 'NoSQL scales better than Postgres' without nuance. Interviewers want informed trade-offs."},
  {id:"q1o6g", topic:"Flink", diff:"basic", level:"Mid", type:"single",
    q:"HI: what fundamentally changes when you count clicks per user over the last 5 minutes vs processing each click independently?",
    options:["You introduce state, since each event must remember prior counts in its window","You no longer need Kafka as the source feeding the job","You can revert to a simple stateless transform-and-write to a database","You remove the need for windowing over the event stream"],
    correct:[0],
    why:"The 5-minute window introduces state because each message depends on previous ones, unlike the trivial stateless transform-and-write case."},
  {id:"q19ll", topic:"Flink", diff:"basic", level:"Mid", type:"single",
    q:"HI: before reaching for a stream processor like Flink, what should you first ask?",
    options:["Do I actually need real-time latencies, or would batch suffice?","Can my budget cover the extra Kafka partitions this needs?","Is the incoming data structured or unstructured in shape?","Should the sink be backed by Spark or by Hadoop?"],
    correct:[0],
    why:"HI stresses asking 'do I really need real-time latencies?' Many seeming stream problems reduce to batch problems (Spark/Hadoop), saving an ops headache."},
  {id:"qhdbu", topic:"Flink", diff:"tricky", level:"Senior", type:"multi",
    q:"HI: problems from holding 5-minute click counts as in-memory counters in your own service? (select all)",
    options:["A crash loses all state, forcing a slow re-read of the entire Kafka topic","Scaling out demands complicated redistribution of state to new instances","Out-of-order or late-arriving events can quietly corrupt the counts","Kafka cannot deliver messages to the service fast enough to keep up"],
    correct:[0,1,2],
    why:"HI enumerates crash-losing-state, state redistribution on scaling, and late/out-of-order events as the motivation for Flink. Kafka throughput is not cited."},
  {id:"q1k4l", topic:"Flink", diff:"tricky", level:"Staff", type:"single",
    q:"HI: the role of the Job Manager relative to Task Managers in Flink?",
    options:["The Job Manager coordinates and schedules work; Task Managers run the actual tasks","The Job Manager only persists checkpoints, which Task Managers read on startup","Task Managers coordinate the cluster while the Job Manager just stores state","Both components run identical roles with no central coordinator at all"],
    correct:[0],
    why:"The coordinating Job Manager schedules work; Task Managers run it in task slots, which is where parallelism comes from."},
  {id:"q12zw", topic:"Flink", diff:"tricky", level:"Staff", type:"single",
    q:"HI: the basis for Flink's exactly-once processing guarantee?",
    options:["Periodic checkpointing of operator state into a state backend","Re-reading the entire Kafka topic from the start on every failure","Disabling watermarks so that no event is ever treated as late","Keeping all counters in volatile memory and never persisting them"],
    correct:[0],
    why:"HI ties exactly-once to checkpointing state into a state backend, letting Flink recover after failure rather than replaying everything from scratch."},
  {id:"q1ym1", topic:"Flink", diff:"basic", level:"Staff", type:"single",
    q:"HI: why do watermarks matter in a Flink job?",
    options:["They let Flink track event-time progress and handle late, out-of-order events","They encrypt the data stream as it passes between operators","They take over coordination duties from the Job Manager","They set how many task slots each Task Manager is allocated"],
    correct:[0],
    why:"Watermarks track event-time progress so windows correctly account for late and out-of-order events."},
  {id:"q1xg9", topic:"ZooKeeper", diff:"basic", level:"Mid", type:"single",
    q:"HI: what core problem was ZooKeeper (2008) designed to solve?",
    options:["Coordinating distributed systems: leader election, config, failure detection","Storing and serving large media blobs cheaply and efficiently","Acting as a high-throughput message queue to replace Kafka","Running batch analytics queries over large historical datasets"],
    correct:[0],
    why:"HI frames ZooKeeper as distributed coordination: electing leaders, keeping consistent config, and detecting failures in real time."},
  {id:"q96j9", topic:"ZooKeeper", diff:"basic", level:"Mid", type:"multi",
    q:"HI: which primitives does ZooKeeper use to solve coordination problems? (select all)",
    options:["A hierarchical namespace of paths, like a filesystem tree","Data nodes (znodes) that hold small pieces of coordination state","Watches that notify clients when a znode changes","A SQL query engine for ad-hoc reads over stored state"],
    correct:[0,1,2],
    why:"ZooKeeper coordinates via a hierarchical namespace, data nodes (znodes), and watches. It has no SQL query engine."},
  {id:"q1usl", topic:"ZooKeeper", diff:"tricky", level:"Senior", type:"single",
    q:"HI: which universal distributed-systems problems does ZooKeeper teach you to solve?",
    options:["Consensus, leader election, and configuration management","Image resizing, CDN routing, and payload compression","Garbage collection, JIT compilation, and thread scheduling","Sharding keys, hash rings, and bloom-filter membership"],
    correct:[0],
    why:"Learning ZooKeeper gives insight into consensus, leader election, and configuration management, the canonical coordination problems."},
  {id:"q1bgc", topic:"ZooKeeper", diff:"tricky", level:"Staff", type:"single",
    q:"HI chat-app example: why does a single-server deployment need no coordination?",
    options:["Both users connect to the same server, so delivery is in-memory and fast","ZooKeeper ships embedded inside the single server by default","The lone server still runs ZAB consensus even with one node","Messages are batched and processed offline by a background job"],
    correct:[0],
    why:"When both users are on the same server, delivery is in-memory with low latency; coordination only appears once you scale out."},
  {id:"qy005", topic:"ZooKeeper", diff:"tricky", level:"Staff", type:"single",
    q:"HI: which consensus protocol underlies ZooKeeper's strong consistency?",
    options:["ZAB, the ZooKeeper Atomic Broadcast protocol","Raft, the log-replication consensus protocol","Two-phase commit (2PC) across the ensemble","Gossip-based eventual propagation between nodes"],
    correct:[0],
    why:"HI's 'Consensus with ZAB' section indicates ZooKeeper relies on the ZAB protocol for its strong consistency guarantees."},
  {id:"qv0vy", topic:"ZooKeeper", diff:"basic", level:"Mid", type:"single",
    q:"HI: ZooKeeper's place in today's landscape?",
    options:["Aged with newer alternatives, but still common in the Apache ecosystem, though Kafka moved to KRaft in 4.0","The newest and fastest coordination service currently available","Fully removed from every major distributed system in use today","Repositioned mainly as a general-purpose relational database"],
    correct:[0],
    why:"ZooKeeper (2008) has aged and faces alternatives (etcd, Consul, Kafka's own KRaft from 4.0), yet remains common in the Apache ecosystem."},
  {id:"q5vyf", topic:"Pattern: Real-time", diff:"basic", level:"Mid", type:"single",
    q:"HI frames real-time updates as two distinct hops. What are they?",
    options:["Client to load balancer, and load balancer to the app server","The first hop (server to client) and the second hop (source to server)","Browser to DNS resolver, and DNS resolver to the origin","Read replica to cache, and cache back out to the client"],
    correct:[1],
    why:"HI splits it into the first hop (server to client) and the second hop (source to server), each with different trade-offs."},
  {id:"q11b6", topic:"Pattern: Real-time", diff:"basic", level:"Mid", type:"single",
    q:"HI: why does standard HTTP break down for real-time systems?",
    options:["HTTP cannot carry binary payloads, only text content","HTTP is request-response and closes, so a server cannot proactively push","HTTP transfers are always slower than the equivalent over UDP","HTTP forces a fresh DNS resolution on every single request"],
    correct:[1],
    why:"Standard HTTP is request-response; it works for browsing but breaks when servers need to proactively push updates."},
  {id:"qs1pd", topic:"Pattern: Real-time", diff:"tricky", level:"Senior", type:"single",
    q:"HI OSI layering: which protocol/layer/property pairing is correct?",
    options:["IP sits at Layer 4 and guarantees ordered, reliable delivery","TCP sits at Layer 4 and is connectionless, spray-and-pray delivery","UDP sits at Layer 4 and is connectionless with no delivery or ordering guarantees","WebSockets sit at Layer 3 and handle raw packet routing"],
    correct:[2],
    why:"UDP is a connectionless Transport (L4) protocol with no delivery/ordering guarantees (spray-and-pray); TCP is connection-oriented; IP sits at L3."},
  {id:"q1nj6", topic:"Pattern: Real-time", diff:"tricky", level:"Senior", type:"multi",
    q:"HI: which client-server approaches does the first-hop section explicitly cover? (select all)",
    options:["Long Polling held open until data is ready","Server-Sent Events (SSE) streaming server to client","WebSockets providing full-duplex channels","GraphQL subscriptions tunneled over gRPC"],
    correct:[0,1,2],
    why:"HI covers Simple Polling, Long Polling, SSE, WebSockets, and WebRTC. GraphQL subscriptions over gRPC is not one of the named protocols."},
  {id:"qq1df", topic:"Pattern: Real-time", diff:"tricky", level:"Staff", type:"single",
    q:"HI: for the second hop (source to the server holding the connection), which two PUSH approaches are contrasted?",
    options:["Pushing via consistent hashing and pushing via pub/sub","Two-phase commit and gossip-based propagation","Write-ahead logging and change data capture","Leader election and quorum-based reads"],
    correct:[0],
    why:"HI details pushing via consistent hashes and via pub/sub (plus pulling via polling) as ways to route an update to the specific server holding a client's connection."},
  {id:"q1wdz", topic:"Pattern: Real-time", diff:"basic", level:"Mid", type:"single",
    q:"HI: how is SSE characterized relative to WebSockets?",
    options:["SSE is full-duplex, matching WebSockets in both directions","SSE is an efficient one-way server-to-client stream; WebSockets are full-duplex","SSE is peer-to-peer while WebSockets always route through a server","SSE runs over UDP whereas WebSockets require a TCP connection"],
    correct:[1],
    why:"HI titles SSE 'The Efficient One-Way Street' (server-to-client) and WebSockets 'The Full-Duplex Champion'; WebRTC is the peer-to-peer option."},
  {id:"qjtxc", topic:"Pattern: Contention", diff:"basic", level:"Mid", type:"single",
    q:"HI: how is contention defined?",
    options:["When a database server exhausts its available disk space","When multiple processes compete for the same resource at the same time","When a network partition splits a cluster into isolated halves","When a cache and the database hold conflicting values for a key"],
    correct:[1],
    why:"Contention is multiple processes competing for the same resource at once (the last concert ticket), causing race conditions, double-bookings, and inconsistent state if unhandled."},
  {id:"qlseq", topic:"Pattern: Contention", diff:"tricky", level:"Senior", type:"single",
    q:"HI Alice and Bob ticket example: why does the naive read-check-decrement oversell the seat?",
    options:["The index on concert_id was missing, so the read scanned stale rows","Bob reads the same count Alice read before she writes, so both decrement","The UPDATE statement contained a syntax error that silently failed","The seat count was served from a stale CDN cache during the read"],
    correct:[1],
    why:"Alice reads one seat, then Bob reads the same count before Alice writes; both check what they read, both decrement, dropping the count to negative one."},
  {id:"qkm1j", topic:"Pattern: Contention", diff:"tricky", level:"Senior", type:"multi",
    q:"HI: which approaches to contention are covered as distinct named solutions? (select all)",
    options:["Conditional Writes guarded by an expected-value check","Pessimistic Locking that holds a lock during the operation","Optimistic Concurrency Control using a version check on write","Eventual consistency reconciled with vector clocks"],
    correct:[0,1,2],
    why:"HI enumerates Conditional Writes, Pessimistic Locking, Optimistic Concurrency Control, Isolation Levels, and Distributed Locks. Vector-clock eventual consistency is not listed."},
  {id:"qp10c", topic:"Pattern: Contention", diff:"tricky", level:"Senior", type:"single",
    q:"HI deep dive: the classic gotcha with optimistic concurrency is…",
    options:["The thundering herd problem of simultaneous retries","The ABA problem, where a value changes and reverts between read and write","The split-brain problem of two active primaries","The dining philosophers problem of cyclic resource waits"],
    correct:[1],
    why:"HI calls out the ABA problem: a value changes from A to B and back to A between read and write, defeating a naive version check."},
  {id:"q1nwn", topic:"Pattern: Contention", diff:"basic", level:"Mid", type:"single",
    q:"HI: which failure mode is a deep-dive concern specific to pessimistic locking?",
    options:["Lost updates from concurrent overwrites","Deadlocks from processes waiting on each other's locks","Cache stampedes when many keys expire at once","Clock drift between nodes skewing timestamps"],
    correct:[1],
    why:"HI has a dedicated deep dive on preventing deadlocks with pessimistic locking; holding locks across multiple resources can make processes wait on each other in a cycle.", accept:"Lost updates is a real contention failure, but HI's pessimistic-locking deep dive specifically targets deadlocks; pessimistic locking actually prevents lost updates."},
  {id:"qrzl4", topic:"Pattern: Contention", diff:"tricky", level:"Senior", type:"single",
    q:"HI's stance on when to reach for heavy contention machinery?",
    options:["Always reach for distributed locks to stay on the safe side","It warns, in a 'When NOT to overcomplicate' section, against over-engineering low contention","It recommends making pessimistic locking the default in every service","It argues contention can only be solved by a dedicated coordination service"],
    correct:[1],
    why:"HI's 'When NOT to overcomplicate' section signals you should match the solution to the actual level of contention rather than always reaching for distributed locks/OCC."},
  {id:"q18xc", topic:"Pattern: Multi-step", diff:"basic", level:"Staff", type:"single",
    q:"HI: which solutions does the multi-step article present?",
    options:["Sagas, workflow systems, and durable execution","Sharding, replication, and read-through caching","Load balancing, autoscaling, and rate limiting","Indexing, partitioning, and denormalization"],
    correct:[0],
    why:"HI centers multi-step processes on sagas, workflow systems, and durable execution (Single Server Orchestration, Event Sourcing, Workflows)."},
  {id:"q1ldb", topic:"Pattern: Multi-step", diff:"tricky", level:"Staff", type:"single",
    q:"HI: the core design problem of naive multi-step orchestration?",
    options:["It burns too much disk space writing verbose operation logs","It tangles system concerns like crashes and retries with business logic, growing brittle","It cannot distribute read load across multiple replicas","It demands a synchronous HTTP call for every individual step"],
    correct:[1],
    why:"Organically patching processes interweaves system-level concerns like crashes/retries with business logic, making the design complex and brittle."},
  {id:"qv3cn", topic:"Pattern: Multi-step", diff:"basic", level:"Mid", type:"single",
    q:"HI: which example workflow motivates the multi-step pattern?",
    options:["Fanning out a new post across a social media feed","E-commerce order fulfillment: charge, reserve inventory, ship, confirm","Transcoding an uploaded video into multiple resolutions","Streaming a real-time stock ticker to many subscribers"],
    correct:[1],
    why:"HI uses e-commerce order fulfillment: charge payment, reserve inventory, create a shipping label, wait for a human pickup, send confirmation; any step can fail or time out."},
  {id:"q1vl8", topic:"Pattern: Multi-step", diff:"tricky", level:"Staff", type:"single",
    q:"HI: when inventory can't be found AFTER payment is charged, what mechanism undoes prior steps?",
    options:["A storage-engine rollback segment unwinds the committed transaction","Compensating actions, like issuing a refund to reverse the charge","A two-phase-commit coordinator aborts and rolls back all participants","A read-repair pass reconciles the divergent replicas"],
    correct:[1],
    why:"Add compensating actions (like refunds when inventory can't be found) to undo already-completed steps — the core idea behind the saga pattern.", more:"Rollback segments and 2PC abort only help inside a single ACID database; once payment was charged in a separate service, the only way back is a semantic compensating transaction."},
  {id:"qlqc1", topic:"Pattern: Multi-step", diff:"tricky", level:"Staff", type:"multi",
    q:"HI: which deep-dive challenges does it raise about running workflows in production? (select all)",
    options:["Applying updates, versioning, and migrations to an already-running workflow","Keeping the accumulated workflow state from growing without bound","Guaranteeing a given step executes exactly once despite retries","Compressing and resizing media before it is uploaded"],
    correct:[0,1,2],
    why:"The deep dives cover workflow versioning/migrations, keeping state size in check, handling external events, and exactly-once steps. Media compression belongs to the blob-upload pattern, not workflow execution."},
  {id:"q19uk", topic:"Pattern: Multi-step", diff:"tricky", level:"Senior", type:"single",
    q:"HI references a talk to show how hard reliable multi-step processes are. Which?",
    options:["Martin Kleppmann's 'Turning the Database Inside Out' on stream processing","Jimmy Bogard's 'Six Little Lines of Fail' on the hidden difficulty of a short step sequence","Adam Wiggins' 'The Twelve-Factor App' on building stateless services","Kleppmann's 'Designing Data-Intensive Applications' chapter on consistency"],
    correct:[1],
    why:"HI cites Jimmy Bogard's 'Six Little Lines of Fail', whose premise is that distributed systems make even a short sequence of steps surprisingly hard to do reliably."},
  {id:"q10i2", topic:"Pattern: Scaling Reads", diff:"basic", level:"Mid", type:"single",
    q:"HI: the typical starting read-to-write ratio for many apps (often climbing higher for content-heavy ones)?",
    options:["Roughly 1:1, with reads and writes growing in lockstep","Around 10:1, often climbing far higher for content-heavy apps","About 2:1, since most users both read and post","Already 100:1 from day one for nearly every product"],
    correct:[1],
    why:"The standard ratio starts near 10:1 but often reaches 100:1+ for content-heavy apps like Instagram or YouTube.", more:"100:1 is real for mature content apps, but it is the destination, not the typical starting point."},
  {id:"qxone", topic:"Pattern: Scaling Reads", diff:"basic", level:"Mid", type:"single",
    q:"HI frames the core read-scaling difficulty as ultimately a question of what?",
    options:["Mostly bad software you can debug and refactor your way out of","Ultimately physics — CPU instructions per second, memory limits, disk I/O bounds","Largely a poor programming-language or framework choice for the hot path","Usually insufficient logging and observability hiding the real bottleneck"],
    correct:[1],
    why:"It is usually not a software bug you can debug away; it is physics, where CPU, memory, and disk I/O hit hard constraints that more code cannot overcome."},
  {id:"q19t8", topic:"Pattern: Scaling Reads", diff:"tricky", level:"Senior", type:"single",
    q:"HI: the natural read-scaling progression?",
    options:["Add external caching first, then shard the data, then tune the database","Optimize within the DB, scale it horizontally with replicas and sharding, then add external caching","Buy a CDN first, then attach read replicas, then revisit indexing","Shard the database first, denormalize the schema, then upgrade to bigger hardware"],
    correct:[1],
    why:"First optimize within the DB (indexing, hardware, denormalization), then scale horizontally (read replicas, sharding), then add external caching layers (application cache + CDN)."},
  {id:"q10or", topic:"Pattern: Scaling Reads", diff:"tricky", level:"Senior", type:"multi",
    q:"HI: which techniques are in the first bucket — optimizing reads WITHIN your database? (select all)",
    options:["Adding and tuning indexes for the hot query paths","Upgrading the database server hardware (CPU, memory, disk)","Applying denormalization strategies to cut joins","Serving responses from a CDN and edge caches"],
    correct:[0,1,2],
    why:"Indexing, hardware upgrades, and denormalization are the in-database optimizations. CDN and edge caching are a later external layer, not work done within the database."},
  {id:"qj2d4", topic:"Pattern: Scaling Reads", diff:"tricky", level:"Senior", type:"single",
    q:"HI deep dive: many requests rebuild the SAME expired cache entry at once. What's this called?",
    options:["Replication lag delaying reads on the database replicas","A thundering herd or cache stampede where many simultaneous misses hit the DB","A hot partition key overloading one shard on the write path","CDN cache poisoning serving a corrupted cached response"],
    correct:[1],
    why:"This is the cache stampede or thundering herd: when a popular entry expires, many requests miss at once and hammer the backing database to rebuild it."},
  {id:"q1duo", topic:"Pattern: Scaling Writes", diff:"basic", level:"Mid", type:"single",
    q:"HI: why is the write side often harder than the read side?",
    options:["Reads bypass the database entirely, so only writes touch it","Bursty, high-throughput writes with heavy contention are hard to design around","Writes are served from cache by default, hiding their true cost","Writes avoid disk I/O, so they scale linearly with more CPU"],
    correct:[1],
    why:"Read-side tools like replicas and caching are familiar, but bursty high-throughput writes with contention are genuinely hard, and many design choices make them worse."},
  {id:"qgmxp", topic:"Pattern: Scaling Writes", diff:"tricky", level:"Senior", type:"multi",
    q:"HI: which strategies does it combine to scale writes? (select all)",
    options:["Vertical scaling together with deliberate database engine choices","Sharding and partitioning to spread the write load across nodes","Absorbing bursts with queues and shedding load when overwhelmed","Batching writes and using hierarchical aggregation to reduce volume"],
    correct:[0,1,2,3],
    why:"HI combines exactly these four: vertical scaling plus DB choices, sharding plus partitioning, burst handling via queues plus load shedding, and batching plus hierarchical aggregation."},
  {id:"qkm6m", topic:"Pattern: Scaling Writes", diff:"basic", level:"Mid", type:"single",
    q:"HI: before throwing more hardware at writes, where should you first try to scale?",
    options:["Spread the data across hundreds of shards from the outset","Stay within a single-server, single-database setup and optimize it first","Push writes to a global CDN edge before they reach origin","Add read replicas to take pressure off the primary"],
    correct:[1],
    why:"First scale within a single-server, single-database setup using vertical scaling and write optimization before reaching for more hardware or distribution.", more:"Read replicas help reads, not writes — writes still funnel to the primary."},
  {id:"q6mf8", topic:"Pattern: Scaling Writes", diff:"tricky", level:"Senior", type:"single",
    q:"HI: what does vertical partitioning primarily do (vs horizontal sharding)?",
    options:["Splits rows across many machines using a partition key","Splits a table by columns so different attributes live in separate stores","Replicates the entire table to every node for read locality","Buffers writes in Redis before persisting them to the database"],
    correct:[1],
    why:"Horizontal sharding splits rows by key; vertical partitioning splits a table by columns or attributes so different fields can live and scale separately."},
  {id:"q1syk", topic:"Pattern: Scaling Writes", diff:"tricky", level:"Senior", type:"multi",
    q:"HI deep dive: a hot key too popular for even a single shard. Which two approaches are named? (select all)",
    options:["Pre-split every key across multiple sub-partitions up front","Split only the hot keys dynamically as they emerge","Apply backpressure and shed writes to the hot key under load","Replicate the hot key to read replicas to absorb the traffic"],
    correct:[0,1],
    why:"The hot-key deep dive offers two remedies: split all keys (pre-split) and split hot keys dynamically. Shedding writes or leaning on read replicas does not solve a write-side hot key.", more:"Replicas only help reads, so they cannot relieve a write hot key; load shedding drops data rather than scaling the key."},
  {id:"q9oxw", topic:"Pattern: Large Blobs", diff:"basic", level:"Mid", type:"single",
    q:"HI rule of thumb: when should data live in blob storage rather than a database?",
    options:["Anything over about 1KB that is read only occasionally","Anything over about 10MB that does not need SQL queries","Every image, regardless of how small or how it is queried","Only very large files above roughly 1GB in size"],
    correct:[1],
    why:"If something is over ~10MB and doesn't need SQL queries, it should probably live in blob storage like S3 rather than in the database."},
  {id:"qit8m", topic:"Pattern: Large Blobs", diff:"tricky", level:"Senior", type:"single",
    q:"HI: the durability figure it cites for object stores like S3?",
    options:["99.9 percent durability, about three nines","99.99 percent durability, about four nines","99.999999999 percent durability, about eleven nines","100 percent durability, contractually guaranteed against any loss"],
    correct:[2],
    why:"S3 advertises 99.999999999% (eleven nines) of durability, with effectively unlimited capacity and per-object pricing."},
  {id:"q16gk", topic:"Pattern: Large Blobs", diff:"basic", level:"Mid", type:"single",
    q:"HI: the core anti-pattern for large-file transfers?",
    options:["Keeping file metadata in a relational database alongside the blob","Routing the file bytes through your application servers as a proxy","Serving downloads through a CDN sitting in front of blob storage","Compressing files on the client before they are uploaded"],
    correct:[1],
    why:"The 'server as a proxy' anti-pattern routes bytes client to server to S3 and back; it works for small files but breaks down as files grow large."},
  {id:"qnzsp", topic:"Pattern: Large Blobs", diff:"tricky", level:"Senior", type:"multi",
    q:"HI: which mechanisms avoid proxying bytes through your servers? (select all)",
    options:["Presigned URLs so clients upload directly to blob storage","CDN-based downloads that pull from blob storage, not your servers","Resumable uploads with parallel transfers and progress tracking","Storing the whole file as a BLOB column inside Postgres"],
    correct:[0,1,2],
    why:"Presigned URLs (direct-to-blob), CDN downloads, and resumable parallel uploads all keep bytes off your servers. Storing the file as a DB BLOB is the opposite — it wrecks query, backup, and replication performance."},
  {id:"q16af", topic:"Pattern: Large Blobs", diff:"tricky", level:"Senior", type:"single",
    q:"HI deep dive 'What if the upload fails at 99 percent?' — which feature addresses it?",
    options:["Provision a larger application server to hold the partial upload","Use resumable multipart or chunked uploads so a failure does not restart from zero","Move the file metadata into a SQL database for durability","Disable the CDN so uploads take a more direct network path"],
    correct:[1],
    why:"The 'fails at 99%' case is solved by resumable uploads: chunked or multipart transfers let an upload resume from the last good part rather than restart entirely."},
  {id:"q1lhw", topic:"Pattern: Long-Running Tasks", diff:"basic", level:"Mid", type:"single",
    q:"HI: the two phases the long-running-tasks pattern splits a request into?",
    options:["A read phase followed by a separate write phase","Immediate acknowledgment followed by background processing","An authentication step followed by an authorization step","A compression step followed by an encryption step"],
    correct:[1],
    why:"The pattern splits the request into immediate acknowledgment (validate, enqueue, return a job ID in milliseconds) and background processing done by separate workers."},
  {id:"qfagc", topic:"Pattern: Long-Running Tasks", diff:"basic", level:"Mid", type:"single",
    q:"HI: why does synchronous processing of a 45-second PDF report fail, beyond poor UX?",
    options:["The database eventually runs out of rows to write","Web servers and load balancers enforce ~30-60s timeouts, so the request may never complete","Browsers abort any request that takes longer than ten seconds","Server-side code is unable to generate PDF documents at all"],
    correct:[1],
    why:"Beyond the spinner, the 45s report often won't finish synchronously because servers and load balancers enforce ~30-60s timeout limits and cut the request off."},
  {id:"qsm0y", topic:"Pattern: Long-Running Tasks", diff:"tricky", level:"Senior", type:"single",
    q:"HI: in the immediate-acknowledgment phase, what does the web server return almost instantly?",
    options:["The fully rendered PDF document in the response body","A job ID, after validating the request and pushing the job to a queue","A connection string pointing the client at a read replica","The raw queue offset together with the assigned worker's IP"],
    correct:[1],
    why:"The web server validates, pushes a job to a queue (Redis or RabbitMQ), and returns a job ID within milliseconds while workers do the heavy lifting and update status."},
  {id:"qeh15", topic:"Pattern: Long-Running Tasks", diff:"tricky", level:"Senior", type:"multi",
    q:"HI: which are listed as common deep dives in the long-running-tasks article? (select all)",
    options:["Recovering gracefully from repeated job failures","Preventing the same job from being processed twice","Managing queue backpressure when work arrives faster than workers drain it","Choosing which CDN region should serve the output"],
    correct:[0,1,2],
    why:"The deep dives cover repeated failures, preventing duplicate work, queue backpressure, mixed workloads, and job dependencies. CDN region selection belongs to the large-blobs pattern."},
  {id:"qg5sa", topic:"Pattern: Long-Running Tasks", diff:"tricky", level:"Senior", type:"single",
    q:"HI: how is the worker side described?",
    options:["A single background thread running inside the web server process","Separate worker processes that poll the queue, grab pending jobs, run them, and update status","The client browser executing the long-running task locally","A read replica that picks up and auto-executes queued jobs"],
    correct:[1],
    why:"Separate worker processes continuously poll the queue, grab pending jobs, run the time-consuming work, and update job status in a database — fully decoupled from the web server."},
  {id:"q1c3k", topic:"Design: Bitly", diff:"tricky", level:"Senior", type:"single",
    q:"HI Bitly: preferred way to generate the short code, and why?",
    options:["Hash the long URL and take the first seven characters as the code","Encode a unique counter in Base62 so every code is unique by construction","Generate random seven-character strings and retry whenever they collide","Use the long URL itself, URL-encoded, as the short code"],
    correct:[1],
    why:"Prefer counter + Base62: uniqueness is guaranteed and no collision handling is needed.", accept:"Hash-and-truncate is workable but requires a UNIQUE constraint plus collision retries; keep that constraint anyway as a safety net even with the counter approach."},
  {id:"qyps8", topic:"Design: Bitly", diff:"tricky", level:"Senior", type:"single",
    q:"HI Bitly: how do you make the global counter fast and not a per-request bottleneck?",
    options:["A SQL AUTO_INCREMENT column incremented on every single write","A single Redis atomic INCR, with each server claiming ~1000 IDs at a time","A UUID generated independently on each application server","A millisecond timestamp combined with a server identifier"],
    correct:[1],
    why:"Redis INCR is atomic and fast; batching ID ranges (grab ~1000 at once) cuts network round-trips so the counter isn't a per-request bottleneck.", more:"Losing a few counter values on failover is fine — you only need uniqueness, not a gap-free sequence."},
  {id:"q1cys", topic:"Design: Bitly", diff:"tricky", level:"Senior", type:"single",
    q:"HI Bitly: 301 vs 302 redirect — which does HI prefer and why?",
    options:["301 permanent, since browsers cache it and that lowers server load","302 temporary, so requests keep flowing through your server and you can add analytics","301 permanent, primarily because it is better for search-engine ranking","Either one, since the redirect type has no practical impact"],
    correct:[1],
    why:"HI prefers 302: the browser keeps hitting your server, so you retain control and can later add click analytics.", accept:"301 is defensible when minimizing load matters more than visibility, but the browser caches it and you lose per-click insight."},
  {id:"q1631", topic:"Design: Dropbox", diff:"tricky", level:"Senior", type:"single",
    q:"HI Dropbox: where should large files be chunked, and via what mechanism?",
    options:["On the server, after the client streams up one large upload","On the client, using S3 Multipart Upload with a presigned URL per part","Inside the database, storing each chunk as a BLOB row","Not at all, since chunking is unnecessary for files under 50GB"],
    correct:[1],
    why:"Chunk on the client (~5-10MB parts) and use S3 Multipart Upload: CreateMultipartUpload, a presigned URL per part, then CompleteMultipartUpload.", more:"Server-side chunking defeats the purpose — the big file still flows through your servers first."},
  {id:"qbucr", topic:"Design: Dropbox", diff:"tricky", level:"Senior", type:"single",
    q:"HI Dropbox: what should identify a file/chunk for dedup and resumable uploads?",
    options:["The original filename supplied by the client","A combination of the user ID and an upload timestamp","A SHA-256 hash of the content, used as a fingerprint","A database auto-increment ID assigned on upload"],
    correct:[2],
    why:"Use a fingerprint — a SHA-256 hash of the content. It enables dedup (same content already stored) and resumability (which chunks are present), neither of which a filename or timestamp can provide."},
  {id:"qdaqq", topic:"Design: Dropbox", diff:"tricky", level:"Staff", type:"single",
    q:"HI Dropbox: fixed-size chunks re-upload the whole file when you insert a byte near the start. The fix?",
    options:["Switch to larger fixed-size chunks to reduce the number of boundaries","Use content-defined chunking with a rolling hash, as in Rabin fingerprinting","Restrict large uploads to off-peak overnight windows","Turn off chunking entirely for any file that has been edited"],
    correct:[1],
    why:"With fixed offsets an early insert shifts every boundary so all chunks look changed. Content-defined chunking sets boundaries from a rolling hash of the content, so only the edited region's chunks change."},
  {id:"q1awh", topic:"Design: Ticketmaster", diff:"tricky", level:"Senior", type:"single",
    q:"HI Ticketmaster: how to hold a seat for ~10 min during checkout without double-booking?",
    options:["A long-running database transaction holding a row lock for the duration","A Redis distributed lock with a TTL that auto-expires if the user abandons checkout","A boolean reserved column flipped on hold with no expiration","Optimistic concurrency with retries and no explicit hold"],
    correct:[1],
    why:"The strong answer is a Redis lock keyed by seat with a ~10 minute TTL so abandoned holds auto-release.", accept:"A status-plus-expiration column scanned by a cron job is a defensible 'good' fallback, but the final DB write under ACID is what actually guarantees no double-booking."},
  {id:"q1g7u", topic:"Design: Ticketmaster", diff:"tricky", level:"Staff", type:"single",
    q:"HI Ticketmaster: the staff-level differentiator for a 10M-users-on-one-event on-sale is…",
    options:["Provisioning much larger database instances for the on-sale window","A virtual waiting queue that admits users into the booking flow in a controlled trickle","Caching the seat map more aggressively at the edge","Sharding the seat inventory by seat ID across nodes"],
    correct:[1],
    why:"A virtual waiting queue protects the booking path from the thundering herd by admitting users in controlled batches — the move that signals senior or staff level."},
  {id:"qwqgk", topic:"Design: Ticketmaster", diff:"tricky", level:"Senior", type:"single",
    q:"HI Ticketmaster: why not implement event search with SQL LIKE '%term%'?",
    options:["LIKE with wildcards is not valid SQL syntax for text columns","A leading-wildcard LIKE forces a full table scan, so use Elasticsearch instead","LIKE quietly returns incorrect or partial result sets","LIKE only operates on numeric columns, not on text"],
    correct:[1],
    why:"A leading-wildcard LIKE can't use a B-tree index, so it scans the whole table — too slow at scale. Elasticsearch's inverted index is the right tool; add query-result and edge caching."},
  {id:"q1yt4", topic:"Design: News Feed", diff:"tricky", level:"Staff", type:"single",
    q:"HI News Feed: the standard answer for mixing normal users and celebrities is…",
    options:["Pure fan-out-on-write, precomputing every follower's feed for all authors","Pure fan-out-on-read, recomputing every viewer's feed from raw posts on request","Hybrid: precompute feeds for normal users, pull celebrity posts at read time, merge","Store no feeds at all and fully recompute from scratch on every request"],
    correct:[2],
    why:"The strong solution precomputes (pushes) into per-user feed tables for normal accounts but pulls celebrity posts at read time and merges, avoiding the millions-of-writes-per-celebrity-post explosion."},
  {id:"q1sie", topic:"Design: News Feed", diff:"tricky", level:"Senior", type:"single",
    q:"HI News Feed: a few hot posts get hammered and your DynamoDB feed cache develops a hot key. Fix?",
    options:["Increase the cache TTL so the hot entry is recomputed less often","Replicate the hot entry across several cache nodes to spread the read load","Consolidate onto a single, much larger cache node with more memory","Stop caching the hottest posts and read them straight from the source"],
    correct:[1],
    why:"DynamoDB and single cache nodes struggle with hot keys. Replicating the hot post across multiple cache nodes spreads reads instead of concentrating them on one partition."},
  {id:"qsoqs", topic:"Design: WhatsApp", diff:"tricky", level:"Senior", type:"single",
    q:"HI WhatsApp: sender and receiver are connected to different chat servers. How do you route the message?",
    options:["A dedicated Kafka topic per user that the receiver's server consumes","Redis Pub/Sub with one channel per user, so the receiver's server is subscribed","A shared database table that both chat servers continuously poll","Consistent hashing so both users always pin to the same chat server"],
    correct:[1],
    why:"The strong answer is Redis Pub/Sub with one channel per user, which sidesteps consistent-hashing complexity.", more:"A Kafka topic per user is an anti-pattern — Kafka isn't built for hundreds of millions of topics."},
  {id:"qhggv", topic:"Design: WhatsApp", diff:"tricky", level:"Senior", type:"single",
    q:"HI WhatsApp: Pub/Sub is at-most-once and stores nothing. How is delivery still guaranteed?",
    options:["Force every client onto raw TCP and rely on its delivery guarantees","Persist to a durable Inbox before publishing, require client acks, and use sequence numbers","Publish each message twice so a dropped copy is unlikely to lose the message","Let the load balancer detect failed deliveries and automatically retry them"],
    correct:[1],
    why:"Persist undelivered messages in an Inbox (deleted on ack) and have clients detect gaps via per-chat sequence numbers piggybacked on heartbeats, with a polling backstop, covering Pub/Sub's dropped messages."},
  {id:"q5imy", topic:"Design: WhatsApp", diff:"tricky", level:"Senior", type:"single",
    q:"HI WhatsApp: how should message ordering be handled?",
    options:["Enforce a single global total order across every chat","Enforce strict per-chat ordering using server-side locks","Stamp NTP-synced server receipt times and let clients sort, tolerating rare pop-in","Order messages by each sending device's local clock"],
    correct:[2],
    why:"Don't pay for strict ordering. Stamp messages with NTP-synced server receipt time and let clients sort; users tolerate rare reordering. Client device clocks can't be trusted."},
  {id:"q1pnf", topic:"Design: WhatsApp", diff:"tricky", level:"Senior", type:"single",
    q:"HI WhatsApp: how do you detect a silently-dead WebSocket connection?",
    options:["Wait until the user's next message reveals the connection is gone","Use application-level heartbeats, since TCP keepalive reacts too slowly","Periodically ping the database to infer whether the client is alive","Proactively close and re-establish all connections every minute"],
    correct:[1],
    why:"TCP keepalive intervals are too coarse, so use application-level heartbeats to spot dead connections quickly and derive 'last seen' from active connections rather than per-heartbeat DB writes."},
  {id:"qmlp8", topic:"Design: Uber", diff:"tricky", level:"Senior", type:"single",
    q:"HI Uber: 10M drivers pinging location every few seconds (~2M writes/sec). Where do you store it?",
    options:["DynamoDB with on-demand capacity absorbing the write spikes","An in-memory geospatial store like Redis using geohashing or a quadtree","A Postgres table with a B-tree index on the latitude and longitude columns","One S3 object per driver, overwritten on each location update"],
    correct:[1],
    why:"That write rate in DynamoDB would cost a fortune (>$200k/day), and a B-tree can't answer 2D proximity queries. Redis with geohashing handles high-frequency writes and radius queries in memory; add adaptive client-side update intervals."},
  {id:"qvwjg", topic:"Design: Uber", diff:"tricky", level:"Staff", type:"single",
    q:"HI Uber: a driver doesn't respond to a ride offer. What's the robust way to handle the multi-step timeout/retry flow?",
    options:["A simple delay queue that re-enqueues the offer after a timeout","Durable execution such as Temporal or Cadence driving the offer-timeout-reoffer flow","A cron job that periodically scans rides for unanswered offers","Client-side timers on the driver app that trigger the next offer"],
    correct:[1],
    why:"This is the multi-step-process pattern. Durable execution (Uber authored Cadence) survives crashes and reliably advances offer to 10s timeout to next driver, which a fragile delay queue can't guarantee."},
  {id:"q1hws", topic:"Design: Uber", diff:"tricky", level:"Senior", type:"single",
    q:"HI Uber: which values must NOT be trusted from the client?",
    options:["Only the user's display name needs to be re-derived server-side","userId, timestamps, and the fare estimate — derive each from the session, server, or DB","Nothing needs re-checking once the client is authenticated","Only the payment token should be re-validated server-side"],
    correct:[1],
    why:"Never trust client-supplied identity or money fields: pull userId from the session or JWT, set timestamps server-side, and re-read the fare from the DB by fareId."},
  {id:"q1ez7", topic:"Design: Ad Click Aggregator", diff:"tricky", level:"Senior", type:"single",
    q:"HI Ad Click Aggregator: the recommended real-time processing pipeline is…",
    options:["Write every click to Postgres and run GROUP BY aggregations at query time","Stream into Kafka or Kinesis, aggregate in Flink, write to an OLAP store like ClickHouse or Druid","Have a cron job periodically aggregate clicks accumulated in a CSV file","Count clicks on the client and report rolled-up totals to the server"],
    correct:[1],
    why:"Ingest into a stream, aggregate in Flink, and write to an OLAP database optimized for analytical queries. Using one transactional DB for both ingest and analytics is the anti-pattern."},
  {id:"q19yd", topic:"Design: Ad Click Aggregator", diff:"tricky", level:"Staff", type:"single",
    q:"HI Ad Click Aggregator: a viral ad creates a hot partition. The standard fix?",
    options:["Stop tracking the viral ad until its traffic subsides","Append a random suffix to the partition key (AdId:0..N) and SUM the parts after stripping it","Provision a single much larger Kafka broker to absorb the hot ad","Switch the aggregation pipeline to a fan-out-on-read model"],
    correct:[1],
    why:"Salt the key with a random suffix so the hot ad's events spread across partitions; the aggregator strips the suffix and sums per AdId. This is classic hot-shard remediation."},
  {id:"qupqu", topic:"Design: Ad Click Aggregator", diff:"tricky", level:"Staff", type:"single",
    q:"HI Ad Click Aggregator: how do you guarantee correctness against the fast-but-lossy stream path?",
    options:["Trust the streaming path, since a well-tuned stream does not drop events","Lambda architecture: also dump raw events to S3 and run a nightly Spark batch as source of truth","Re-run the same streaming job a second time and compare the outputs","Extend the cache TTL so aggregated results survive transient loss"],
    correct:[1],
    why:"Use a speed layer (Flink) for near-real-time plus a batch layer (Spark over an S3 data lake) as the authoritative recompute. Reconciling the two catches drift and loss in the streaming path."},
  {id:"qgxya", topic:"Design: Ad Click Aggregator", diff:"tricky", level:"Senior", type:"single",
    q:"HI Ad Click Aggregator: how do you make click tracking idempotent (dedupe retries)?",
    options:["Dedupe on userId so each user's repeated clicks collapse into one","Mint a unique impression ID when the ad is served and dedupe clicks on it","Keep only the first click per user per one-minute tumbling window","Dedupe on the ad creative ID so the same ad counts only once"],
    correct:[1],
    why:"Mint a unique impression ID when the ad is served and carry it on the click event, so retried or duplicate clicks collapse to one. userId or creative ID is too coarse and drops legitimate distinct clicks."},
  {id:"qz8nm", topic:"Design: Web Crawler", diff:"tricky", level:"Senior", type:"single",
    q:"HI Web Crawler: which queue does HI pick for the frontier, and what goes in it?",
    options:["Kafka holding the raw HTML, so the parser reads pages directly off the log","A Redis list holding the URL, with workers popping entries via BRPOP","SQS holding just the URL, with visibility timeout giving easy backoff plus a DLQ","A SQL table of pending URLs that workers poll and mark as claimed"],
    correct:[2],
    why:"SQS is picked because its visibility timeout makes retries, exponential backoff, and dead-letter queues easy. Store a small URL pointer, not raw HTML, and keep the message in-flight until the HTML is confirmed stored in S3."},
  {id:"q15fr", topic:"Design: Web Crawler", diff:"tricky", level:"Senior", type:"single",
    q:"HI Web Crawler: a surprising bottleneck when crawling billions of pages is…",
    options:["CPU spent parsing, tokenizing, and extracting links from each downloaded HTML page","DNS resolution, cited at up to ~70% of per-thread time; fix with caching and multiple providers","Disk I/O writing and reading the frontier queue under high fan-out","Network bandwidth saturating the link to the blob store on writes"],
    correct:[1],
    why:"Per the Mercator paper, DNS can dominate thread time. Cache DNS results and round-robin multiple DNS providers. Crawling is I/O-bound, so a handful of network-optimized machines suffices for the 5-day target."},
  {id:"q1bh1", topic:"Design: Web Crawler", diff:"tricky", level:"Senior", type:"multi",
    q:"HI Web Crawler: which are part of being a 'polite' crawler? (select all)",
    options:["Parse and respect robots.txt, honoring both Disallow rules and Crawl-delay","Rate-limit to roughly 1 request/sec per domain via a per-domain Redis SET NX lock","Add jitter to request timing to avoid synchronized retry storms against a host","Crawl each domain from many IPs at once to maximize throughput per host"],
    correct:[0,1,2],
    why:"Politeness means respecting robots.txt including Crawl-delay, throttling per domain to ~1 rps via a per-domain lock, and adding jitter. Hammering one host from many IPs is the opposite of polite."},
  {id:"qyykt", topic:"Design: Web Crawler", diff:"tricky", level:"Senior", type:"single",
    q:"HI Web Crawler: how do you avoid re-storing the same content and getting stuck in crawler traps?",
    options:["Maintain a global visited-URL set and skip any URL already fetched once","Dedupe by content hash, not just URL, and cap crawl depth at ~15-20 hops from seed","Cap the crawl at a fixed total page count to bound the work per run","Detect traps by limiting the number of path segments in any single URL"],
    correct:[1],
    why:"URL-level dedup misses mirror and duplicate content, so also hash page content. Cap depth as hops from the seed (not path segments) to escape infinite trap pages."},
  {id:"q156k", topic:"Design: Top K", diff:"tricky", level:"Staff", type:"single",
    q:"HI Top-K: the headline data structure when exact counts can be relaxed to approximate is…",
    options:["A B-tree keyed by item, giving sorted exact counts with logarithmic updates","A Bloom filter per item to test membership before incrementing its counter","A Count-Min Sketch for approximate per-item counts, plus a heap for the top-K","A sorted set per item in Redis, ranked by its running exact count"],
    correct:[2],
    why:"A Count-Min Sketch estimates per-item counts in megabytes instead of a hundreds-of-GB exact hash table; feed the estimates into a heap to keep the top-K. Only valid when precise counts can be relaxed."},
  {id:"qoz3n", topic:"Design: Top K", diff:"tricky", level:"Senior", type:"single",
    q:"HI Top-K: 70B views/day (~810k TPS) far exceeds one DB. How do you keep results exact?",
    options:["Sample 1% of views and multiply the resulting counts back up by 100","Ingest via Kafka, shard counts across many DBs, take each shard's top-K, and merge","Round each counter to the nearest thousand to shrink the per-item write load","Count only logged-in users so the per-key write rate fits one database"],
    correct:[1],
    why:"Buffer with Kafka and shard counters; each shard's local top-K, when merged, is mathematically guaranteed to contain the global top-K, so it stays exact without a single hot DB."},
  {id:"qpc0m", topic:"Design: Top K", diff:"tricky", level:"Senior", type:"single",
    q:"HI Top-K: why does HI restrict the problem to tumbling (non-overlapping) windows?",
    options:["Sliding windows require continuously re-aggregating overlapping ranges; tumbling stays tractable","Tumbling windows are inherently less accurate, and that lower accuracy is acceptable here","Tumbling windows need no stored state because each window is recomputed on read","Real users only ever request non-overlapping windows in practice anyway"],
    correct:[0],
    why:"Sliding windows force continuous re-aggregation of overlapping ranges; tumbling windows let you keep one simple per-window aggregate (precomputed and cached per minute)."},
  {id:"q16wy", topic:"Design: Rate Limiter", diff:"tricky", level:"Senior", type:"single",
    q:"HI Rate Limiter: why does a per-gateway in-memory counter fail?",
    options:["In-memory increments are not atomic, so concurrent requests corrupt the counter","The load balancer spreads a client across gateways, so each sees only part of the count; centralize in Redis","Holding counters in RAM at this scale is too expensive versus a disk-backed store","An in-memory counter can only key on IP, which breaks user-based and API-key limits"],
    correct:[1],
    why:"With traffic spread across gateway instances, no single instance has the true count. Centralize the counter in Redis (sharded by client key) so the limit is enforced globally."},
  {id:"q124l", topic:"Design: Rate Limiter", diff:"tricky", level:"Senior", type:"single",
    q:"HI Rate Limiter: how do you make the read-modify-write of a token bucket race-free in Redis?",
    options:["Run the check, refill, and decrement as one atomic unit via Lua or MULTI/EXEC, plus EXPIRE","Read the token count first, then issue a separate write to decrement it","Take a global lock on the whole Redis instance around each bucket update","Use WATCH on the key and simply retry the whole operation whenever it conflicts"],
    correct:[0],
    why:"Bundle the read of tokens, the refill, and the decrement into one atomic transaction or Lua script so concurrent requests cannot both spend the last token; set EXPIRE so idle buckets do not leak memory.", accept:"WATCH/retry (optimistic) is a real Redis pattern, but at high contention it spins and retries; a single atomic Lua script is the cleaner, contention-free choice HI uses."},
  {id:"qymk2", topic:"Design: Rate Limiter", diff:"tricky", level:"Senior", type:"single",
    q:"HI Rate Limiter: if the Redis backing the limiter goes down, does HI fail open or fail closed (for a social API)?",
    options:["Fail open and allow all requests, since blocking legitimate users is the worse outcome","Fail closed and reject requests, since outages often coincide with spikes and failing open can collapse the backend","Fall back to a per-instance in-memory limiter until Redis recovers","Serve every request from cache and skip the limit check entirely during the outage"],
    correct:[1],
    why:"HI calls both fail-open and fail-closed defensible but picks fail-closed for social media: limiter failures tend to coincide with traffic surges, so failing open could let a flood cascade into a backend collapse.", accept:"Fail open is genuinely defensible (it prioritizes availability), but for a social API a coincident spike makes fail-closed the safer default."},
  {id:"q1vxf", topic:"Design: Google Docs", diff:"tricky", level:"Staff", type:"single",
    q:"HI Google Docs: which concurrency-control approach does HI choose, and what's the alternative?",
    options:["A per-paragraph lock so only one editor mutates a region; the alternative is last-write-wins","Operational Transformation, as Google uses; CRDTs are the alternative for P2P or huge collaborator counts","Two-phase commit across editor sessions; the alternative is a saga of compensating edits","Last-write-wins on the whole document; the alternative is first-write-wins on conflict"],
    correct:[1],
    why:"OT transforms concurrent INSERT/DELETE ops against each other on a central server so all clients converge, with low memory and great fit for text. CRDTs suit peer-to-peer or very large collaboration but cost more memory."},
  {id:"q1igd", topic:"Design: Google Docs", diff:"tricky", level:"Senior", type:"single",
    q:"HI Google Docs: what should clients send over the WebSocket?",
    options:["The full document content on every keystroke, letting the server diff it server-side","Edits as operations, such as INSERT or DELETE at a given character position","A periodic snapshot of the visible page so the server can reconstruct changes","Only the final document state when the user explicitly saves the file"],
    correct:[1],
    why:"Transmit compact operations (insert/delete at offsets), not the whole doc. That is what OT transforms and what Cassandra stores append-only, partitioned by documentId."},
  {id:"qinys", topic:"Design: Google Docs", diff:"tricky", level:"Senior", type:"single",
    q:"HI Google Docs: how do you ensure all editors of one document hit the same WebSocket server at scale?",
    options:["Pin each user to a server by sticky session on their source IP address","Consistent hashing by documentId with a ZooKeeper-maintained ring; clients upgrade to WS there","Route every editor of every document to a single global stateful WebSocket server","Random load balancing, then have servers gossip edits to each other"],
    correct:[1],
    why:"Route by documentId via consistent hashing so collaborators converge on one stateful server; ZooKeeper keeps the ring consistent as servers join and leave. Snapshot and compact operations to bound storage and transfer."},
  {id:"qddm0", topic:"Design: Payment System", diff:"tricky", level:"Staff", type:"single",
    q:"HI Payment System: a request times out after charging. How do you avoid double-charging on retry?",
    options:["Treat the timeout as a failure and reissue the charge until one succeeds","Use idempotency keys plus reconciliation against the payment network, never assuming a timeout equals failure","Charge again immediately and issue a refund later if it turns out to be a duplicate","Block all automatic retries and require the user to resubmit the payment manually"],
    correct:[1],
    why:"A timeout is ambiguous because the charge may have succeeded. An idempotency key makes the retry a no-op if it already went through, and reconciliation against the network catches any mismatch."},
  {id:"q1tjr", topic:"Design: Payment System", diff:"tricky", level:"Staff", type:"single",
    q:"HI Payment System: what storage approach gives the durability/audit trail payments require?",
    options:["Store only the current balance and status in a single mutable table","Event sourcing: an append-only immutable event log, captured via CDC, not just current state","Write current state to the DB and export daily CSV snapshots for the audit trail","Keep authoritative state in Redis and periodically flush it to durable storage"],
    correct:[1],
    why:"An append-only event log is the foundation for audits, chargebacks, reconciliation, and fraud detection; storing only current state loses the history that regulators and disputes require."},
  {id:"q1e8a", topic:"Design: Payment System", diff:"tricky", level:"Senior", type:"single",
    q:"HI Payment System: how is raw card data handled for PCI compliance?",
    options:["Encrypt the card number at rest in your primary database with a managed key","Tokenization: the card is exchanged for a token so your backend never stores or handles the raw number","Hash the card number with SHA-256 before persisting it alongside the order","Keep the raw card number only in append-only logs, never in the live database"],
    correct:[1],
    why:"Tokenize card data (e.g. via the provider's client-side SDK) so raw card numbers never reach your servers, keeping you out of PCI scope. Pair it with API keys and request signing for security."},
  {id:"q1a3d", topic:"Architecture", diff:"basic", level:"Mid", type:"multi",
    q:"For a typical read-heavy product (social app, marketplace), which components belong in the baseline high-level design? (select all)",
    options:["An API gateway or load balancer as the request entry point","A primary database holding the core entities","A cache such as Redis in front of hot reads","A CDN for static assets like images, JS, and video","A graph database as the primary store for every entity"],
    correct:[0,1,2,3],
    why:"The standard product-design skeleton is clients to an API gateway/LB to stateless services to a primary DB, with a cache for hot reads and a CDN for static media. A graph DB is situational, not baseline.", more:"A graph database is NOT a default — HI explicitly warns it's a common over-engineering mistake (even Facebook models its social graph on MySQL). Reach for specialized stores (graph, search, OLAP) only when a requirement demands it.", src:"https://www.hellointerview.com/learn/system-design/in-a-hurry/key-technologies"},
  {id:"q1yv1", topic:"Architecture", diff:"basic", level:"Mid", type:"single",
    q:"What is HI's delivery-framework order for driving a design?",
    options:["Start from the data model, then derive APIs and services from the schema","Requirements (functional and non-functional), then core entities, API, high-level design, then deep dives","Sketch the full architecture upfront, then back-fill the justification for each piece","Do capacity estimation first, then let the numbers dictate every component choice"],
    correct:[1],
    why:"HI's framework: nail requirements (functional plus non-functional), define core entities, sketch the API, build the high-level design, then go deep on the hard parts and trade-offs.", more:"Estimation isn't an opening ritual — do back-of-envelope math when a decision needs it (e.g. 'do we need to shard?'). Skipping requirements is the #1 way candidates burn time on the wrong problem.", src:"https://www.hellointerview.com/learn/system-design/in-a-hurry/delivery"},
  {id:"q1dt5", topic:"Architecture", diff:"basic", level:"Mid", type:"multi",
    q:"Which non-functional requirements should you pin down early in almost any design? (select all)",
    options:["The availability-versus-consistency priority for the system","Latency targets for the key user operations","Expected scale and throughput for both reads and writes","Durability needs for the data the system holds","The programming language and framework the team will build in"],
    correct:[0,1,2,3],
    why:"Non-functional requirements (the -ilities) shape every later decision: availability-versus-consistency, latency, throughput/scale, and durability. Language choice rarely changes the architecture.", more:"Programming language is almost never relevant in a system-design interview — naming it signals you're focused on the wrong layer. Frame NFRs as measurable targets ('p99 < 200ms', '10k writes/sec').", src:"https://www.hellointerview.com/learn/system-design/in-a-hurry/delivery"},
  {id:"q150a", topic:"Architecture", diff:"tricky", level:"Senior", type:"multi",
    q:"Which cross-cutting concerns should a senior+ candidate proactively address in any distributed design? (select all)",
    options:["Observability through metrics, logs, and traces","Fault tolerance and elimination of single points of failure","Security and authentication across the system","Horizontal scalability of each tier under load","The team's choice of editor and local tooling"],
    correct:[0,1,2,3],
    why:"Beyond the happy path, name observability, fault tolerance and SPOF removal, security, and how each tier scales horizontally. These are the operational signals interviewers look for at senior+.", more:"A clean test for SPOFs: walk every component and ask 'if this dies, does the system stop?' Eliminate via redundancy (multiple instances, replicas, multi-AZ, auto-failover).", src:"https://www.hellointerview.com/learn/system-design/in-a-hurry/key-technologies"},
  {id:"qev8x", topic:"Architecture", diff:"basic", level:"Mid", type:"single",
    q:"A requirement says 'users worldwide need fast loading of images and video'. Which component directly addresses it?",
    options:["Add read replicas to the primary database to spread out read load","A CDN caching static assets at edge locations close to users","A message queue to decouple the asset-serving path from the origin","Geo-sharding the primary database by the user's home region"],
    correct:[1],
    why:"A CDN caches static content at edge locations near users, cutting latency and offloading the origin. It is the standard answer for fast global static delivery.", more:"CDNs commonly sit in front of blob storage (S3): upload to S3 as origin, serve via CDN with signed URLs. They can also cache cacheable dynamic content/API responses.", src:"https://www.hellointerview.com/learn/system-design/in-a-hurry/key-technologies"},
  {id:"q1ri0", topic:"Architecture", diff:"basic", level:"Mid", type:"single",
    q:"A requirement says 'video encoding takes minutes and must not block the upload request'. Which pattern fits?",
    options:["Process the encoding synchronously inside the upload request and return when done","Ack the upload immediately, enqueue a job, and have a worker pool process it in the background","Stream the raw upload to a read replica and encode it there off the write path","Hold the connection open and send progress chunks until encoding finishes"],
    correct:[1],
    why:"This is the managing-long-running-tasks pattern: validate, enqueue, and return a job ID in milliseconds while separate workers do the heavy processing and update status asynchronously.", more:"Don't queue SHORT jobs — synchronous responses give clearer back-pressure and simpler UX. Add job-status tracking, retries, and a dead-letter queue for poison messages.", src:"https://www.hellointerview.com/learn/system-design/patterns/long-running-tasks"},
  {id:"qrgx5", topic:"Architecture", diff:"tricky", level:"Senior", type:"single",
    q:"You need full-text search over millions of posts. Which component, and why not just the primary DB?",
    options:["Run SQL LIKE with a leading wildcard against the posts table in Postgres","Add Elasticsearch, whose inverted index makes full-text search fast; a leading-wildcard LIKE full-scans","Add a Postgres GIN trigram index and serve all search from read replicas","Cache each query result in Redis so repeated searches avoid the database"],
    correct:[1],
    why:"Full-text search needs an inverted index from term to documents. Elasticsearch is the go-to; a leading-wildcard LIKE cannot use a B-tree index and scans the whole table.", more:"Keep your primary DB as the source of truth and sync ES as a secondary index via CDC — the search index lags slightly, which is fine for search. Postgres GIN can do lighter full-text in-DB.", accept:"Postgres GIN trigram indexes do enable real text search and can suffice at smaller scale, but a dedicated search cluster is the standard answer for millions of posts with ranking and relevance.", src:"https://www.hellointerview.com/learn/system-design/deep-dives/elasticsearch"},
  {id:"q1dkn", topic:"Design: Bitly", diff:"basic", level:"Mid", type:"multi",
    q:"Which subsystems are essential for a URL shortener? (select all)",
    options:["A write/create service that generates the unique short code","A read/redirect service that resolves a code to its long URL","A key-value store mapping short code to long URL","A cache, since reads dominate writes roughly 1000 to 1","A video transcoding pipeline for uploaded media"],
    correct:[0,1,2,3],
    why:"Bitly decomposes into a write path (generate a unique code, store the mapping), a read/redirect path, a KV store for the mapping, and a cache because reads vastly outnumber writes.", more:"Because write volume is tiny (~1/sec) and reads huge, the interesting work is fast redirects (cache/CDN) and unique code generation (counter + Base62), not the database choice — any DB works.", src:"https://www.hellointerview.com/learn/system-design/problem-breakdowns/bitly"},
  {id:"q2d9z", topic:"Design: Dropbox", diff:"basic", level:"Mid", type:"multi",
    q:"Which subsystems are essential for a file storage/sync service like Dropbox? (select all)",
    options:["Blob storage such as S3 for the file contents","A metadata database for files, versions, and ownership","A presigned-URL service for direct client upload and download","A sync and notification service to propagate changes to devices","A full-text search cluster indexing the contents of every file"],
    correct:[0,1,2,3],
    why:"Core pieces: blob storage for bytes, a metadata DB for file/version/share info, presigned URLs so clients transfer directly to S3, and a sync/notification path to keep devices consistent.", more:"Full-text search over contents isn't a core requirement of file sync — adding it would be scope creep unless asked. The hard parts are chunking (client-side), fingerprinting (SHA-256), and delta sync (content-defined chunking).", src:"https://www.hellointerview.com/learn/system-design/problem-breakdowns/dropbox"},
  {id:"q1bet", topic:"Design: Ticketmaster", diff:"tricky", level:"Senior", type:"multi",
    q:"Which subsystems are essential for Ticketmaster? (select all)",
    options:["An event and search service backed by Elasticsearch for browsing events","A booking service on an ACID database to prevent double-booking","A seat-reservation mechanism using a distributed lock with a TTL","A payment integration to charge for confirmed bookings","A real-time ML pipeline that retrains seat-recommendation models continuously"],
    correct:[0,1,2,3],
    why:"Ticketmaster needs search (ES), a transactional booking service (ACID prevents double-booking), a reservation hold (Redis lock with TTL), and a payment integration. Continuous model retraining is not core.", more:"The ACID final write is what truly guarantees no double-book; the distributed lock is for UX (holding a seat ~10 min). For huge on-sales, add a virtual waiting queue — the staff-level move.", src:"https://www.hellointerview.com/learn/system-design/problem-breakdowns/ticketmaster"},
  {id:"q755g", topic:"Design: News Feed", diff:"tricky", level:"Senior", type:"multi",
    q:"Which subsystems are essential for a social news feed? (select all)",
    options:["A post service plus a durable post store","A follow/social-graph store, with a reverse index for follower lookups","A feed-generation path using fan-out workers or precomputed feeds","A feed cache to serve hot reads quickly","A distributed lock service to serialize feed writes"],
    correct:[0,1,2,3],
    why:"Feed systems need posts, the follow graph (with a reverse index), feed generation (fan-out on write or read or a hybrid), and a feed cache. A distributed lock is not part of the core feed path.", more:"The signature decision is fan-out: precompute per-user feeds for normal accounts, pull at read time for celebrities, and merge (hybrid). A distributed lock isn't part of a feed.", src:"https://www.hellointerview.com/learn/system-design/problem-breakdowns/fb-news-feed"},
  {id:"q1glx", topic:"Design: WhatsApp", diff:"tricky", level:"Senior", type:"multi",
    q:"Which subsystems are essential for a chat app like WhatsApp? (select all)",
    options:["Stateful WebSocket chat servers holding persistent client connections","A pub/sub routing layer to reach the right server, e.g. Redis Pub/Sub per user","An inbox or message store for delivering to offline recipients","A presence and last-seen mechanism","An OLAP data warehouse sitting on the core message-delivery path"],
    correct:[0,1,2,3],
    why:"Chat needs persistent WebSocket servers, a routing layer so a message reaches whichever server holds the recipient's connection, durable inboxes for offline users, and presence. OLAP is analytics, not the live path.", more:"Redis Pub/Sub (topic per user) is HI's 'great' routing answer — it sidesteps consistent-hashing complexity. Pub/Sub is at-most-once, so durability comes from the inbox + acks + per-chat sequence numbers.", src:"https://www.hellointerview.com/learn/system-design/problem-breakdowns/whatsapp"},
  {id:"q27t0", topic:"Design: Uber", diff:"tricky", level:"Senior", type:"multi",
    q:"Which subsystems are essential for a ride-sharing service like Uber? (select all)",
    options:["A location service with a geospatial index, e.g. Redis geohashing","A ride-matching service with a lock to avoid double-dispatch","A maps, ETA, and fare integration","A push-notification service via APNs and FCM","A full-text search cluster over driver and rider profiles"],
    correct:[0,1,2,3],
    why:"Uber needs high-frequency location ingestion plus proximity search (geospatial index), matching (with a lock so one driver is not double-assigned), maps/fare, and notifications. Full-text search is not core.", more:"Driver location at ~2M writes/sec rules out a disk DB — use an in-memory geospatial store (Redis geohashing). For the unresponsive-driver flow, durable execution (Temporal/Cadence) beats a fragile delay queue.", src:"https://www.hellointerview.com/learn/system-design/problem-breakdowns/uber"},
  {id:"q4vbu", topic:"Design: Ad Click Aggregator", diff:"tricky", level:"Staff", type:"multi",
    q:"Which subsystems are essential for a near-real-time ad click aggregator? (select all)",
    options:["A streaming ingestion layer such as Kafka or Kinesis","A stream processor for windowed aggregation such as Flink","An OLAP store for advertiser analytics queries","A data lake on S3 plus batch Spark jobs for reconciliation","A transactional RDBMS as the primary aggregation store"],
    correct:[0,1,2,3],
    why:"The pipeline is stream ingestion to Flink aggregation to OLAP for queries, plus a batch layer (S3 + Spark) to reconcile and serve as source of truth. A row-store RDBMS cannot absorb the aggregation write rate.", more:"Using one transactional DB for both ingest and analytics is the anti-pattern. The batch layer catches any loss/drift in the fast streaming path — a strong correctness signal.", src:"https://www.hellointerview.com/learn/system-design/problem-breakdowns/ad-click-aggregator"},
  {id:"q16u8", topic:"Design: Web Crawler", diff:"tricky", level:"Senior", type:"multi",
    q:"Which subsystems are essential for a large-scale web crawler? (select all)",
    options:["A frontier queue of URLs to fetch, backed by SQS","Fetcher workers plus a content-extraction stage","Blob storage on S3 for raw HTML and extracted text","A metadata DB for dedup and crawl state","A DNS resolver with caching","A WebSocket server pushing crawl results to connected clients"],
    correct:[0,1,2,3,4],
    why:"A crawler needs a frontier queue, fetch and extract workers, blob storage for content, a metadata DB (URL/content dedup plus state), and DNS resolution. WebSockets serve live clients, not batch crawling.", more:"HI picks SQS (visibility timeout → easy backoff + DLQ) and keeps only the URL pointer in the queue, not raw HTML. DNS can be ~70% of per-thread time, so cache it and use multiple providers. A WebSocket server has no role here.", src:"https://www.hellointerview.com/learn/system-design/problem-breakdowns/web-crawler"},
  {id:"qe2tk", topic:"Design: Google Docs", diff:"tricky", level:"Staff", type:"multi",
    q:"Which subsystems are essential for a collaborative document editor? (select all)",
    options:["Stateful WebSocket document servers holding editor connections","A concurrency-control engine using Operational Transformation","An append-only operations store such as Cassandra","Coordination to route editors of one doc to one server, e.g. a ZooKeeper hash ring","A CDN that serves the live, continuously-edited document to editors"],
    correct:[0,1,2,3],
    why:"Real-time editing needs WebSocket servers, an OT engine to converge concurrent edits, an append-only ops store, and coordination (consistent hashing by docId via ZooKeeper). A CDN cannot serve constantly-mutating live state.", more:"Send edits as operations (insert/delete at position), not the whole doc. Periodically snapshot/compact operations to bound storage and join cost. A CDN serves static assets, not a live collaborative doc.", src:"https://www.hellointerview.com/learn/system-design/problem-breakdowns/google-docs"},
  {id:"qhome", topic:"Design: Payment System", diff:"tricky", level:"Staff", type:"multi",
    q:"Which subsystems are essential for a payment system like Stripe? (select all)",
    options:["An API gateway handling auth and request signing","A payment/intent service plus its database","A transaction service that talks to external payment networks","An append-only event log (event sourcing) for audit and reconciliation","A full-text search cluster over transaction descriptions"],
    correct:[0,1,2,3],
    why:"Payments need a secure gateway, a payment-intent service plus DB, a transaction service to external networks, and an immutable event log enabling audit, reconciliation, and chargebacks. Search is not core.", more:"Idempotency keys + reconciliation against the network are mandatory because async networks make a timeout ambiguous (never assume timeout = failure). Tokenize card data so raw PANs never hit your servers.", src:"https://www.hellointerview.com/learn/system-design/problem-breakdowns/payment-system"},
  {id:"q10sx", topic:"Architecture", diff:"basic", level:"Mid", type:"single",
    q:"Requirement: 'prevent abuse / DDoS before traffic reaches our services'. Which component and where?",
    options:["A cache in front of the database to absorb abusive read traffic","A rate limiter at the edge (API gateway), keyed per user, IP, or API key","A read replica to spread the load that abusive clients generate","A larger load balancer with more capacity to absorb the flood"],
    correct:[1],
    why:"Put a rate limiter at the edge (API gateway/LB) so abusive traffic is rejected before it loads downstream services; key it per user, IP, or API key for fairness.", more:"Token bucket is the usual algorithm (allows bursts up to bucket size). At scale the counter must be centralized (Redis), since per-instance counters each see only a fraction of a client's traffic.", src:"https://www.hellointerview.com/learn/system-design/problem-breakdowns/distributed-rate-limiter"},
  {id:"q11de", topic:"Architecture", diff:"tricky", level:"Senior", type:"single",
    q:"Requirement: 'hold a limited resource (seat, inventory) for a few minutes during checkout'. Which mechanism?",
    options:["Open a long-running database transaction that holds the row until checkout completes","A distributed lock with a TTL, e.g. Redis, that auto-releases if the user abandons","Optimistic concurrency: let anyone proceed and reject the loser at final commit","A status column flipped to reserved, swept back by a periodic cleanup job"],
    correct:[1],
    why:"A distributed lock with a TTL holds the resource for a bounded time and auto-releases if the user abandons. It is the standard reservation pattern (Ticketmaster, Uber dispatch).", more:"Treat the lock as efficiency, not correctness: the authoritative no-oversell guarantee should come from an ACID write or a conditional UPDATE. For hard correctness use fencing tokens or a consensus store.", accept:"A status column with a sweeper can work, but it relies on a separate cleanup job to reclaim abandoned holds; a TTL lock self-expires, which is simpler and more robust.", src:"https://www.hellointerview.com/learn/system-design/patterns/dealing-with-contention"},
  {id:"qltp4", topic:"Architecture", diff:"basic", level:"Mid", type:"single",
    q:"Requirement: 'low-latency two-way realtime messaging'. Which transport?",
    options:["Short polling, where the client re-requests on a fixed interval","Long polling, where the server holds each request open until data arrives","Server-Sent Events, a one-way server-to-client push stream","WebSocket, a single persistent full-duplex connection"],
    correct:[3],
    why:"WebSocket gives full-duplex, low-latency bidirectional messaging over one persistent connection, which is right for chat and collaboration. SSE is one-way; polling adds latency and overhead.", more:"SSE is one-way (server→client) and simpler — good for notifications/feeds. HI advises starting with HTTP polling and only moving to SSE/WebSocket when needed; WebSockets are stateful; an L4 LB cleanly preserves the long-lived connection, though L7 LBs also support WebSocket upgrades.", src:"https://www.hellointerview.com/learn/system-design/patterns/realtime-updates"},
  {id:"q1wrk", topic:"Architecture", diff:"tricky", level:"Senior", type:"single",
    q:"Requirement: 'store user-uploaded videos and serve them globally'. Which storage layout?",
    options:["Store the video bytes as BLOBs in the primary database alongside metadata","Store videos in blob storage (S3) fronted by a CDN, keeping only the URL in the DB","Chunk videos across multiple database rows and reassemble them on read","Hold videos in Redis as binary values and persist with append-only snapshots"],
    correct:[1],
    why:"Large binaries go in blob storage (S3) fronted by a CDN; the DB stores just the URL/reference. Binaries in the DB wreck index and cache efficiency and cost far more, and Redis is volatile memory.", more:"Use presigned URLs for direct client upload/download (multipart for big files), and event notifications to sync DB metadata with the upload's completion.", src:"https://www.hellointerview.com/learn/system-design/patterns/large-blobs"},
  {id:"q1sjo", topic:"Architecture", diff:"tricky", level:"Senior", type:"single",
    q:"Requirement: 'advertisers run analytical queries (sums/group-bys) over billions of events with sub-second latency'. Which store?",
    options:["The transactional row store that already ingests the raw events","An OLAP columnar store such as ClickHouse, Druid, or BigQuery","A key-value cache holding precomputed totals for each advertiser","Blob storage queried directly with on-demand scan jobs per request"],
    correct:[1],
    why:"Analytical aggregation over huge event volumes belongs in an OLAP/columnar store optimized for scans and group-bys, separate from the transactional ingest path. A row store cannot answer these in sub-second time.", more:"Pair it with pre-aggregated rollup tables (daily/weekly) to keep dashboard queries fast. Mixing OLTP ingest and OLAP queries in one store is the anti-pattern HI flags.", src:"https://www.hellointerview.com/learn/system-design/problem-breakdowns/ad-click-aggregator"},
  {id:"qbefs", topic:"Architecture", diff:"tricky", level:"Senior", type:"single",
    q:"Requirement: 'three independent teams must each process the same event stream their own way'. Which technology/feature?",
    options:["SQS, where each message is deleted after a single consumer acks it","Kafka with a separate consumer group per team, each tracking its own offset","A shared database table the teams poll and delete rows from after processing","RabbitMQ with one queue and competing consumers across the three teams"],
    correct:[1],
    why:"Kafka retains the log and lets multiple consumer groups read it independently, each with its own offset. Queue models where a message is consumed once cannot fan the same stream out to three teams.", more:"A broker queue (SQS/RabbitMQ) deletes on ack and suits single-consumer background work; it can't replay or fan a stream to independent consumers.", src:"https://www.hellointerview.com/learn/system-design/deep-dives/kafka"},
  {id:"q80ww", topic:"Architecture", diff:"tricky", level:"Senior", type:"single",
    q:"Requirement: 'find drivers/restaurants within N km, fast, over millions of entities'. Which component?",
    options:["A composite B-tree index on the latitude and longitude columns","A geospatial index such as Redis geo, PostGIS, or Elasticsearch geo-queries","A full-text search index over location names and addresses","A two-step filter: bound by a lat range, then by a long range, then intersect"],
    correct:[1],
    why:"Proximity search needs a geospatial index (geohash or quadtree based). A B-tree (even bounding by each axis separately) cannot efficiently answer 2D radius queries.", more:"Geospatial indexes pay off at hundreds of thousands+ entities; for ~1,000 items a scan beats the index overhead. Queries are usually local to the user, not global.", src:"https://www.hellointerview.com/learn/system-design/patterns/realtime-updates"},
  {id:"q1a18", topic:"Architecture", diff:"tricky", level:"Senior", type:"single",
    q:"Requirement: 'coordinate which server is the leader / keep a consistent shared config across a cluster'. Which component?",
    options:["A relational database with a leader-election table updated under a transaction","A coordination service like ZooKeeper for leader election, config, and failure detection","A message queue where the first consumer to claim a message becomes leader","A shared Redis key with SET NX as the leader lock for the whole cluster"],
    correct:[1],
    why:"Distributed coordination, including leader election, consistent configuration, and failure detection, is ZooKeeper's job, using a hierarchical znode namespace plus watches with strong consistency (ZAB).", more:"Ephemeral znodes give automatic failure detection (they vanish when a session dies), and ephemeral-sequential nodes implement leader election (lowest sequence wins). etcd is a common modern alternative.", accept:"A Redis SET NX lock can elect a leader in simple cases, but it lacks ZooKeeper's failure detection, watches, and strongly-consistent config storage that production coordination needs.", src:"https://www.hellointerview.com/learn/system-design/deep-dives/zookeeper"},
  {id:"qdarr1", topic:"DS: Arrays", diff:"basic", level:"Mid", type:"single",
    q:"Why is append to a dynamic array amortized O(1) rather than always O(1)?",
    options:["Most appends are cheap, but an occasional full buffer triggers an O(n) resize, averaging out","Every append copies the whole array, but copies are fast in practice","The array keeps a linked overflow region so it never resizes","Appends are O(log n) because the buffer grows logarithmically"],
    correct:[0],
    why:"A dynamic array keeps spare capacity; when full it allocates a larger buffer (≈2×) and copies. Resizes are O(n) but rare, so the per-append cost averages to O(1).", src:"ds-arrays.html"},
  {id:"qdarr2", topic:"DS: Arrays", diff:"basic", level:"Mid", type:"single",
    q:"What is the cost of inserting an element at the FRONT of a dynamic array?",
    options:["O(1), the same as appending at the end","O(n), because every existing element must shift over","O(log n), via a binary search for the slot","O(1) amortized, like end-append with doubling"],
    correct:[1],
    why:"Front (or middle) insert/delete shifts all subsequent elements, so it is O(n). If you need fast front ops, use a deque or linked list.", src:"ds-arrays.html"},
  {id:"qdarr3", topic:"DS: Arrays", diff:"tricky", level:"Senior", type:"single",
    q:"Why do contiguous arrays often beat 'asymptotically better' structures for small/medium n?",
    options:["They have lower Big-O complexity for every operation","Cache locality: contiguous memory traverses far faster than pointer-chasing","They are automatically kept sorted for binary search","They avoid all resizing by pre-allocating infinite capacity"],
    correct:[1],
    why:"Contiguous memory gives excellent cache locality, so arrays frequently outperform linked structures in practice despite similar Big-O.", more:"Same reason columnar storage, ring buffers, and append-only logs (Kafka segments, WAL) are array-backed — sequential memory access is cache-friendly.", src:"ds-arrays.html"},
  {id:"qdll1", topic:"DS: Linked Lists", diff:"basic", level:"Mid", type:"single",
    q:"Deleting a node you already hold a reference to in a doubly linked list is…",
    options:["O(n), you must scan from the head to find it first","O(1), you just rewire the neighbors' pointers","O(log n), via the list's balanced index","O(1) only in a singly linked list"],
    correct:[1],
    why:"With a doubly linked node in hand you rewire prev/next in O(1). The expensive part of lists is FINDING a node (O(n)), not removing a known one.", more:"This O(1) removal of a known node is exactly why an LRU cache uses a doubly linked list.", src:"ds-linked-lists.html"},
  {id:"qdll2", topic:"DS: Linked Lists", diff:"tricky", level:"Senior", type:"single",
    q:"How do you detect a cycle in a linked list using O(1) extra space?",
    options:["Floyd's tortoise/hare: a slow and a fast pointer meet inside a cycle","Store every visited node in a hash set and check for repeats","Sort the list and look for an out-of-order pointer","Reverse the list twice and compare the heads"],
    correct:[0],
    why:"Floyd's two-pointer (slow +1, fast +2) meets if and only if there is a cycle, using constant space.", accept:"A visited-node hash set also detects a cycle, but it costs O(n) extra space — Floyd's is preferred when space matters.", src:"ds-linked-lists.html"},
  {id:"qdll3", topic:"DS: Linked Lists", diff:"tricky", level:"Senior", type:"single",
    q:"Why does the canonical O(1) LRU cache pair a hash map with a DOUBLY linked list specifically?",
    options:["Map gives O(1) sort of keys while the list holds insertion order","List gives O(1) key lookup while the map maintains recency order","Singly linked is faster here but the map needs extra memory to index","Map gives O(1) node lookup; doubly linked gives O(1) unlink plus recency"],
    correct:[3],
    why:"The map finds the node in O(1); the doubly linked list lets you unlink that exact node and move it to the head in O(1). Singly linked can't remove a known node in O(1) (no prev pointer).", src:"ds-linked-lists.html"},
  {id:"qdst1", topic:"DS: Stacks", diff:"basic", level:"Mid", type:"single",
    q:"A stack provides which access order?",
    options:["FIFO — first in, first out","LIFO — last in, first out","Sorted by priority on each pop","Random access by index"],
    correct:[1],
    why:"A stack is LIFO: push/pop/peek all act on the top. (FIFO is a queue.)", src:"ds-stacks.html"},
  {id:"qdst2", topic:"DS: Stacks", diff:"tricky", level:"Senior", type:"single",
    q:"Converting deep recursion into an explicit stack primarily protects against…",
    options:["Stack overflow on very deep inputs","Hash collisions in the call table","Cache misses during traversal","Integer overflow in the recursion counter"],
    correct:[0],
    why:"Recursion uses the call stack; very deep recursion can overflow it. An explicit heap-allocated stack removes that limit.", src:"ds-stacks.html"},
  {id:"qdst3", topic:"DS: Stacks", diff:"tricky", level:"Senior", type:"single",
    q:"Which pattern solves 'next greater element' / 'daily temperatures' in O(n)?",
    options:["A monotonic stack popping smaller/larger elements as it scans once","A min-heap holding all elements, polling the smallest each step","Two pointers sweeping over the array after sorting it ascending","Binary search on a prefix-maxima array built in one left-to-right pass"],
    correct:[0],
    why:"A monotonic stack processes each element once, popping smaller/larger ones as it goes — O(n). Recognizing it is a strong signal.", src:"ds-stacks.html"},
  {id:"qdq1", topic:"DS: Queues", diff:"tricky", level:"Senior", type:"single",
    q:"Using a JS array as a queue via array.shift() to dequeue is…",
    options:["O(1) per dequeue, the same constant cost as a tail pop()","O(n) per dequeue, because every remaining element shifts down by one","O(log n) per dequeue, since the array reindexes in tree-like steps","O(1) amortized per dequeue, the same as an appending push()"],
    correct:[1],
    why:"shift() re-indexes the whole array → O(n) per dequeue, a real performance bug. Use a ring buffer or linked list for true O(1).", src:"ds-queues.html"},
  {id:"qdq2", topic:"DS: Queues", diff:"tricky", level:"Senior", type:"single",
    q:"How does a ring buffer give O(1) enqueue and dequeue?",
    options:["It re-sorts elements after each operation","Two indices (head/tail) chase each other over a fixed array, wrapping with modulo","It stores elements in a balanced tree keyed by arrival time","It doubles its capacity on every enqueue"],
    correct:[1],
    why:"A circular buffer advances head/tail with % capacity, so neither end ever shifts elements — O(1) both ends, fixed memory.", more:"This is the shape of thread-pool task queues, socket buffers, and lock-free SPSC queues; overflow policy (reject / overwrite-oldest / block) is the backpressure decision.", src:"ds-queues.html"},
  {id:"qdq3", topic:"DS: Queues", diff:"basic", level:"Mid", type:"single",
    q:"Which traversal uses a queue, and which uses a stack?",
    options:["BFS uses a queue; DFS uses a stack (or recursion)","BFS uses a stack; DFS uses a queue","Both use a stack","Both use a priority queue"],
    correct:[0],
    why:"Breadth-first explores level by level via a FIFO queue; depth-first goes deep via a stack/recursion. Mixing them up is an easy tell.", src:"ds-queues.html"},
  {id:"qdht1", topic:"DS: Hash Tables", diff:"tricky", level:"Senior", type:"single",
    q:"Hash-map lookup is O(1) on average; what is the worst case and why?",
    options:["O(n), when many keys collide into one bucket or during a rehash","O(log n), since balanced tree buckets are guaranteed at all times","O(1) always, because hashing distributes keys with no worst case","O(n log n), from re-sorting every bucket on each insertion"],
    correct:[0],
    why:"Adversarial or unlucky keys can collide into one bucket → O(n) (tree-bucket fallback caps it at O(log n)). 'O(1)' is average and amortized.", src:"ds-hash-tables.html"},
  {id:"qdht2", topic:"DS: Hash Tables", diff:"tricky", level:"Senior", type:"single",
    q:"Your problem needs ordering or range queries. Why is a hash map the wrong choice?",
    options:["Unordered storage can't answer range or ordered queries; use a balanced tree","Lookups grow too slow at scale, so a B-tree index is needed instead","Capacity caps near a few thousand keys, so a tree is needed for more","Resizing silently drops keys, so a sorted set is needed for durability"],
    correct:[0],
    why:"Hashing scatters keys with no order, so range/floor/ceiling/in-order are impossible. Needing ordering means a tree/sorted set (O(log n)). This is the most common structure-selection mistake.", src:"ds-hash-tables.html"},
  {id:"qdht3", topic:"DS: Hash Tables", diff:"tricky", level:"Senior", type:"single",
    q:"What happens when a hash table's load factor crosses its threshold (≈0.75)?",
    options:["Lookups silently start returning stale values","It resizes the bucket array and rehashes all entries — an O(n) operation","It rejects further inserts until keys are deleted","It converts every bucket to a binary tree"],
    correct:[1],
    why:"Crossing the load-factor threshold grows the table and rehashes everything (O(n)), which makes one insert occasionally expensive — amortized O(1) overall.", src:"ds-hash-tables.html"},
  {id:"qdht4", topic:"DS: Hash Tables", diff:"tricky", level:"Staff", type:"single",
    q:"What is HashDoS, and how do real implementations defend against it?",
    options:["Attacker keys forcing collisions into one O(n) bucket; defend with seeded SipHash","A flood of lookups overwhelming the cache layer; defend with request rate limiting","Hash inversion that leaks the original keys; defend with encryption at rest","A storm of resizes thrashing the table; defend by disabling table resizing"],
    correct:[0],
    why:"If an attacker can predict the hash, they can force all keys into one bucket (O(n) per op) and DoS the service. Randomized seeds / SipHash make collisions unpredictable.", src:"ds-hash-tables.html"},
  {id:"qdhp1", topic:"DS: Heaps", diff:"tricky", level:"Senior", type:"single",
    q:"To keep the K largest elements of a stream, which heap do you use?",
    options:["A min-heap of size K — pop the smallest whenever size exceeds K","A max-heap of size K — pop the largest each time","A min-heap holding all n elements","A sorted array rebuilt on every insert"],
    correct:[0],
    why:"A size-K MIN-heap keeps the K largest: its root is the smallest of the top-K, so anything smaller is discarded. Runs in O(n log K), beating a full O(n log n) sort when K ≪ n.", accept:"A max-heap of all n elements then K pops also works, but it's O(n + K log n) and uses O(n) space — the size-K min-heap is the intended answer.", src:"ds-heaps.html"},
  {id:"qdhp2", topic:"DS: Heaps", diff:"basic", level:"Mid", type:"single",
    q:"Why is peek O(1) but pop (extract-min/max) O(log n) on a binary heap?",
    options:["Peek reads the root; pop sifts the new root down to restore the heap","Pop reads the root; peek must scan every leaf to find the extreme","Both are O(1) here, so the stated complexity table is simply wrong","Pop fully re-sorts the backing array while peek reads one element"],
    correct:[0],
    why:"The extreme is always at the root (peek O(1)). Removing it swaps in the last element and sifts it down level by level — O(log n).", src:"ds-heaps.html"},
  {id:"qdhp3", topic:"DS: Heaps", diff:"tricky", level:"Senior", type:"single",
    q:"Which statement about a binary heap's ordering is correct?",
    options:["It is fully sorted, so you can iterate in order for free","It is only partially ordered — the root is the extreme, the rest is not sorted","Both children are always sorted relative to each other","Leaves are sorted but internal nodes are not"],
    correct:[1],
    why:"A heap only guarantees the parent-child relation; siblings/subtrees aren't ordered. You can't iterate sorted without paying O(n log n).", src:"ds-heaps.html"},
  {id:"qdhp4", topic:"DS: Heaps", diff:"tricky", level:"Staff", type:"single",
    q:"What is the cost of building a heap from an unsorted array of n elements?",
    options:["O(n log n), since each of n inserts is O(log n)","O(n), using bottom-up heapify","O(n²), comparing all pairs","O(log n), it only fixes the root"],
    correct:[1],
    why:"Bottom-up build-heap is O(n) — a classic gotcha. Inserting one-by-one would be O(n log n), but heapify in place is linear.", src:"ds-heaps.html"},
  {id:"qdss1", topic:"DS: Sorted Sets/BST", diff:"tricky", level:"Senior", type:"single",
    q:"What happens if you insert already-sorted data into a plain (unbalanced) BST?",
    options:["It stays balanced and gives O(log n) operations","It degenerates into a linked list, making operations O(n)","It automatically rebalances after each insert","It rejects duplicate-ordered inserts"],
    correct:[1],
    why:"Sorted inserts make every node a right child → a degenerate O(n) chain. Production 'tree maps' use self-balancing trees (red-black) to guarantee O(log n).", src:"ds-sorted-sets.html"},
  {id:"qdss2", topic:"DS: Sorted Sets/BST", diff:"tricky", level:"Senior", type:"single",
    q:"What is the core hash-map-vs-sorted-set trade-off?",
    options:["Hash map O(1) unordered; sorted set O(log n) ordered with range queries","Sorted set O(1) ordered; hash map O(log n) and also fully ordered","They are interchangeable, giving identical complexity and ordering guarantees","Hash map answers range queries in O(1) while sorted set cannot at all"],
    correct:[0],
    why:"Pick by need: O(1) unordered membership (hash map) vs O(log n) with ordering, range, floor/ceiling, and rank (balanced tree / skip list). Naming this explicitly is a Staff signal.", src:"ds-sorted-sets.html"},
  {id:"qdss3", topic:"DS: Sorted Sets/BST", diff:"basic", level:"Mid", type:"single",
    q:"A range query returning k results on a balanced BST costs…",
    options:["O(n), it scans every node","O(log n + k): find the start, then walk k in-order","O(k log n), a separate search per result","O(1), ranges are precomputed"],
    correct:[1],
    why:"You locate the low end in O(log n) then traverse k successors — O(log n + k).", src:"ds-sorted-sets.html"},
  {id:"qdss4", topic:"DS: Sorted Sets/BST", diff:"tricky", level:"Staff", type:"single",
    q:"A Redis ZSET (sorted set) and a Java TreeMap are typically backed by…",
    options:["A skip list for Redis ZSET and a red-black tree for Java TreeMap","A hash table in both, with ordering layered on top by iteration","A B+tree on disk in both, paged in for ordered range scanning","A binary heap in both, giving O(1) min with ordered traversal"],
    correct:[0],
    why:"Redis ZSET uses a skip list (+ a hash for O(1) score lookup); TreeMap/std::map use a red-black tree. Both give ordered O(log n) operations.", src:"ds-sorted-sets.html"},
  {id:"qdsk1", topic:"DS: Skip Lists", diff:"tricky", level:"Senior", type:"single",
    q:"How should you describe a skip list's complexity bounds?",
    options:["Guaranteed O(log n) worst case, like an AVL tree","Expected O(log n) (probabilistic); O(n) in the rare unlucky case","Always O(1) due to the express lanes","O(log n) only if inserted in sorted order"],
    correct:[1],
    why:"A skip list is probabilistic: bounds are expected, not guaranteed. Overstating it as a guaranteed-balanced tree is wrong.", src:"ds-skip-lists.html"},
  {id:"qdsk2", topic:"DS: Skip Lists", diff:"tricky", level:"Senior", type:"single",
    q:"How are a skip list's levels assigned to a new node?",
    options:["By the node's value modulo the number of levels","By coin flips: ~50% chance to be promoted one level higher each time","By keeping every level exactly half the size via rebalancing","By the insertion timestamp"],
    correct:[1],
    why:"Each insert flips a coin, promoting the node a level per heads (~50%), so ~half reach level 1, a quarter level 2, etc. — yielding O(log n) expected height.", src:"ds-skip-lists.html"},
  {id:"qdsk3", topic:"DS: Skip Lists", diff:"tricky", level:"Staff", type:"single",
    q:"Where do skip lists show up in real systems?",
    options:["Redis sorted sets and the in-memory memtable of LSM stores like RocksDB","As the persistent on-disk clustered index of relational databases","As the bucket array backing open-addressed hash map implementations","As the call-stack frame allocator inside language runtime interpreters"],
    correct:[0],
    why:"Redis ZSET is a skip list; LSM-tree memtables (LevelDB/RocksDB/Cassandra) use skip lists for the ordered in-memory write buffer (also easier to make concurrent than balanced trees).", src:"ds-skip-lists.html"},
  {id:"qdtr1", topic:"DS: Tries", diff:"tricky", level:"Senior", type:"single",
    q:"A trie operation on a key of length L costs O(L). How does that relate to the number of keys stored?",
    options:["It is independent of how many keys are stored","It grows linearly with the number of keys","It grows logarithmically with the number of keys","It is O(L × number of keys)"],
    correct:[0],
    why:"Cost depends only on key length, not the count of stored keys — the defining property of a trie.", src:"ds-tries.html"},
  {id:"qdtr2", topic:"DS: Tries", diff:"basic", level:"Mid", type:"single",
    q:"When should you choose a trie over a hash set?",
    options:["When you need faster exact-membership checks","When you need prefix queries like 'starts with' or autocomplete","When you want to minimize memory usage","When keys are integers, not strings"],
    correct:[1],
    why:"A hash set gives O(1) exact membership but can't do prefixes. Tries are for prefix operations; memory is their trade-off.", src:"ds-tries.html"},
  {id:"qdtr3", topic:"DS: Tries", diff:"tricky", level:"Staff", type:"single",
    q:"Which real system is the canonical trie use case?",
    options:["IP routing longest-prefix match via a radix trie, plus autocomplete","Relational join processing across two large indexed input tables","Distributed consensus over a replicated log of ordered commands","Lossy image compression by quantizing repeated pixel-block patterns"],
    correct:[0],
    why:"Longest-prefix match in IP routing tables uses radix tries; autocomplete uses tries with cached top-K completions per node.", src:"ds-tries.html"},
  {id:"qdbt1", topic:"DS: B-Trees", diff:"tricky", level:"Senior", type:"single",
    q:"Why use a high-fan-out B+tree instead of a binary search tree for an on-disk index?",
    options:["Binary trees cannot keep sorted data, so range order is lost on disk","High fan-out keeps the tree shallow, so a lookup touches fewer disk blocks","B+trees spend less CPU per key comparison than binary tree traversal","Binary trees cannot answer range queries the way a B+tree leaf walk can"],
    correct:[1],
    why:"A binary tree is too tall → many random disk reads. High fan-out (hundreds of keys/node) makes the tree ~3–4 levels deep, minimizing block I/O — the real cost on disk.", src:"ds-btrees.html"},
  {id:"qdbt2", topic:"DS: B-Trees", diff:"tricky", level:"Senior", type:"single",
    q:"In a B+tree (vs a plain B-tree), where does data live and why does it help range scans?",
    options:["In internal nodes, which stay cached so range scans avoid leaf reads","Only in the leaves, which are linked in sorted order for a fast walk","Spread evenly across all levels so any node can begin a range scan","In a side hash table keyed by row id that the leaves point into"],
    correct:[1],
    why:"B+trees keep values only in leaves and link the leaves, so a range scan is a linear walk along the leaf chain; internal nodes hold routing keys only (higher fan-out).", src:"ds-btrees.html"},
  {id:"qdbt3", topic:"DS: B-Trees", diff:"tricky", level:"Staff", type:"single",
    q:"What is the B+tree vs LSM-tree trade-off?",
    options:["B+trees favor reads and in-place updates; LSM favors writes via compaction","LSM-trees are always faster for reads, writes, and range scans alike","B+trees only work in memory while LSM-trees only work on durable disk","They are the same structure, with names that differ only by vendor"],
    correct:[0],
    why:"B+trees (Postgres/InnoDB) optimize reads and updates; LSM-trees (RocksDB/Cassandra) optimize writes by appending sorted runs and compacting later. Knowing when each wins is a strong signal.", src:"ds-btrees.html"},
  {id:"qdbt4", topic:"DS: B-Trees", diff:"basic", level:"Mid", type:"single",
    q:"What is the default index structure in Postgres and MySQL/InnoDB?",
    options:["A hash index","A B+tree","A skip list","A bloom filter"],
    correct:[1],
    why:"B+tree is the default index in most relational databases — shallow, ordered, and range-friendly.", src:"ds-btrees.html"},
  {id:"qdg1", topic:"DS: Graphs", diff:"tricky", level:"Senior", type:"single",
    q:"What finds the shortest path in an UNWEIGHTED graph?",
    options:["BFS (breadth-first search)","DFS (depth-first search)","In-order traversal","Topological sort"],
    correct:[0],
    why:"BFS explores by distance, so the first time it reaches a node it has the fewest edges. DFS finds A path, not the shortest — a classic error.", accept:"Dijkstra also yields shortest paths but is meant for weighted graphs; on an unweighted graph BFS is simpler and O(V+E).", src:"ds-graphs.html"},
  {id:"qdg2", topic:"DS: Graphs", diff:"tricky", level:"Senior", type:"single",
    q:"What finds the shortest path in a graph with non-negative edge WEIGHTS?",
    options:["BFS with a plain FIFO queue expanding level by level outward","Dijkstra's algorithm expanding the closest node via a min-heap frontier","DFS with backtracking, returning the first complete path it finds","A topological sort over the graph followed by a single relaxation pass"],
    correct:[1],
    why:"Dijkstra expands the closest unvisited node using a min-heap. Plain BFS ignores weights; DFS doesn't minimize.", accept:"Bellman-Ford also computes shortest paths and even handles negative edges, but it's O(V·E) — Dijkstra is preferred when weights are non-negative.", src:"ds-graphs.html"},
  {id:"qdg3", topic:"DS: Graphs", diff:"tricky", level:"Senior", type:"single",
    q:"A topological ordering of tasks exists only when the dependency graph is…",
    options:["A DAG with no cycles, since any cycle blocks a valid ordering","Connected end to end, regardless of whether cycles are present","Undirected, so edges can be traversed in either direction freely","Weighted with strictly positive edges feeding a relaxation pass"],
    correct:[0],
    why:"Topological sort requires a directed ACYCLIC graph; a cycle makes ordering impossible — which is exactly how you detect a build/dependency cycle.", src:"ds-graphs.html"},
  {id:"qdg4", topic:"DS: Graphs", diff:"basic", level:"Mid", type:"single",
    q:"For a sparse graph (few edges), which representation is preferred?",
    options:["Adjacency matrix — O(V²) space, O(1) edge test","Adjacency list — O(V+E) space, efficient for sparse graphs","A single sorted array of all edges","A hash of every possible vertex pair"],
    correct:[1],
    why:"Adjacency lists use O(V+E) and suit most real (sparse) graphs. A matrix is O(V²) — wasteful unless the graph is dense or you constantly test specific edges.", src:"ds-graphs.html"},
  {id:"qduf1", topic:"DS: Union-Find", diff:"tricky", level:"Senior", type:"single",
    q:"Which two optimizations give union-find near-constant time?",
    options:["Path compression and union by rank/size","Memoization and binary search","Lazy deletion and rehashing","Level promotion and coin flips"],
    correct:[0],
    why:"Path compression flattens trees during find; union by rank keeps the shorter tree under the taller. Together they give O(α(n)) — effectively constant.", src:"ds-union-find.html"},
  {id:"qduf2", topic:"DS: Union-Find", diff:"tricky", level:"Senior", type:"single",
    q:"How does union-find detect a cycle while adding edges to an UNDIRECTED graph?",
    options:["If union(a,b) finds a and b already share a root, that edge closes a cycle","If find(a) returns null because the node has not been added to any set","If a tree's rank ever climbs above log n during repeated union calls","It cannot detect cycles at all, so only DFS over the edges can do it"],
    correct:[0],
    why:"Endpoints already in the same set mean adding the edge forms a cycle. (Directed-graph cycles need DFS with a recursion stack instead.)", src:"ds-union-find.html"},
  {id:"qduf3", topic:"DS: Union-Find", diff:"tricky", level:"Staff", type:"single",
    q:"What complexity do path compression + union by rank achieve per operation?",
    options:["O(log n), the height of the tree after union by rank flattening","O(α(n)), inverse Ackermann, effectively constant and under 5 for any n","O(1) strictly guaranteed per operation with no asymptotic caveats","O(√n), since path compression only partially flattens each tree"],
    correct:[1],
    why:"With both optimizations operations run in inverse-Ackermann time — so small it's treated as constant, though not literally O(1).", src:"ds-union-find.html"},
  {id:"qdlru1", topic:"DS: LRU/LFU", diff:"tricky", level:"Senior", type:"single",
    q:"Which structures give an LRU cache O(1) get and put?",
    options:["A hash map plus a doubly linked list","A single array scanned for the oldest entry","A min-heap keyed by last-access time","A balanced BST keyed by key"],
    correct:[0],
    why:"The hash map gives O(1) key→node; the doubly linked list maintains recency (MRU head, LRU tail) and allows O(1) move/evict. 'Array + scan for oldest' is O(n) and misses the bar.", src:"ds-lru-lfu.html"},
  {id:"qdlru2", topic:"DS: LRU/LFU", diff:"tricky", level:"Senior", type:"single",
    q:"Why must the LRU list be DOUBLY linked rather than singly linked?",
    options:["To pack more cached payload into each individual list node","To unlink a known arbitrary node in O(1) using its prev pointer","To enable binary search across the list by walking both directions","To keep the list ordered by key so lookups can stop scanning early"],
    correct:[1],
    why:"On access you unlink a node from the middle and move it to the head; without a prev pointer that removal is O(n). Doubly linked makes it O(1).", src:"ds-lru-lfu.html"},
  {id:"qdlru3", topic:"DS: LRU/LFU", diff:"tricky", level:"Staff", type:"single",
    q:"What is LRU's classic failure mode, and what resists it?",
    options:["A large sequential scan evicts the whole hot set as pollution; LFU resists it","It leaks memory steadily as entries pile up over time; per-key TTLs resist it","It double-counts repeated hits and skews recency; stored checksums resist it","It cannot store string keys without corruption; careful serialization resists it"],
    correct:[0],
    why:"One big scan touches many one-off items and pushes out the long-term hot set. LFU (frequency-based) resists pollution but can keep stale once-popular items — hence aging variants (LRU-K, ARC).", src:"ds-lru-lfu.html"},
  {id:"qdlru4", topic:"DS: LRU/LFU", diff:"basic", level:"Mid", type:"single",
    q:"Which eviction policies does Redis offer for its keyspace?",
    options:["Only plain FIFO eviction of the oldest key written to the store","allkeys-lru, allkeys-lfu, and more, with noeviction as the default","Only uniform random eviction of an arbitrary key when memory fills","None at all, since Redis keeps every key until it is deleted by hand"],
    correct:[1],
    why:"Redis exposes LRU, LFU, random, and TTL-based policies (default is noeviction, which errors on writes when full).", src:"ds-lru-lfu.html"},
  {id:"qdbf1", topic:"DS: Bloom Filters", diff:"tricky", level:"Senior", type:"single",
    q:"What does a Bloom filter guarantee about its answers?",
    options:["No false negatives but possible false positives: definitely-no or maybe-yes","No false positives but possible false negatives: definitely-yes or maybe-no","Exact membership with zero errors, the same as a hash set would give","Errors appear only once the filter is more than half of its bits full"],
    correct:[0],
    why:"If any of the k bits is 0 the item is definitely absent; if all are 1 it's probably present (other elements may have set those bits). Reversing this is an instant tell.", src:"ds-bloom-filters.html"},
  {id:"qdbf2", topic:"DS: Bloom Filters", diff:"tricky", level:"Senior", type:"single",
    q:"Can you delete an element from a standard Bloom filter?",
    options:["Yes, just clear the k bits that the element originally set on insert","No: clearing shared bits can corrupt members; a counting filter is needed","Yes, but reliably only for the single most recently inserted element","No, and even the counting Bloom filter variant cannot support deletes"],
    correct:[1],
    why:"Bits are shared across elements, so clearing them may remove others. A counting Bloom filter (small counters instead of bits) supports deletes at extra space. Standard filters also can't enumerate members.", src:"ds-bloom-filters.html"},
  {id:"qdbf3", topic:"DS: Bloom Filters", diff:"tricky", level:"Staff", type:"single",
    q:"What is the canonical systems use of a Bloom filter?",
    options:["A filter before each SSTable so a read skips disk when a key is absent","Replacing the primary on-disk database entirely to save storage space","Sorting keys into order before running a leaf-level range scan on disk","Encrypting stored keys at rest so absent lookups reveal no information"],
    correct:[0],
    why:"Cassandra/RocksDB/HBase/Bigtable put a Bloom filter before each SSTable: a cheap in-memory bit check turns many would-be disk reads for absent keys into instant misses.", more:"General pattern: 'check the cheap probabilistic filter before the expensive lookup.' Related sketches: Count-Min Sketch (frequencies), HyperLogLog (distinct counts).", src:"ds-bloom-filters.html"},
  {id:"qdbf4", topic:"DS: Bloom Filters", diff:"basic", level:"Mid", type:"single",
    q:"Roughly how much space gives a Bloom filter a ~1% false-positive rate?",
    options:["About 1 bit per element","About 10 bits per element","About 100 bytes per element","The same size as storing the elements themselves"],
    correct:[1],
    why:"~10 bits per element yields ≈1% false positives — far less than storing the actual keys. More bits / optimal k lowers the rate further.", src:"ds-bloom-filters.html"},
  {id:"qcms1", topic:"DS: Count-Min Sketch", diff:"basic", level:"Mid", type:"single",
    q:"What does a Count-Min Sketch estimate, and what is its core guarantee?",
    options:["Set membership only: whether an item has been seen at least once","Per-item frequency; the estimate is never below the true count (it may over-count)","Per-item frequency; the estimate is never above the true count (it may under-count)","The number of distinct items seen, with a small relative error"],
    correct:[1],
    why:"CMS approximates how many times each item appeared. Collisions can only add to counters, so an estimate is always ≥ the true count — it over-counts, never under-counts. Membership is a Bloom filter; distinct count is HyperLogLog.", src:"ds-count-min-sketch.html"},
  {id:"qcms2", topic:"DS: Count-Min Sketch", diff:"tricky", level:"Senior", type:"single",
    q:"A Count-Min Sketch reads d counters on a query and returns the minimum. Why the min specifically?",
    options:["Averaging the rows would be cheaper, but the min is more cache-friendly","Every counter is inflated by other items' collisions, so each row over-counts; the min is the least-inflated, tightest estimate","The min cancels collisions in both directions, making the estimate unbiased","The min is what lets the sketch support safe deletions"],
    correct:[1],
    why:"Each row's counter is the true count plus whatever else collided into that cell — always ≥ true. The minimum row absorbed the fewest collisions, so it is the tightest upper bound. Averaging would not preserve the never-undercount guarantee.", src:"ds-count-min-sketch.html"},
  {id:"qcms3", topic:"DS: Count-Min Sketch", diff:"tricky", level:"Senior", type:"single",
    q:"The CMS bound is est(x) ≤ true(x) + ε·N. What does that imply about accuracy across items?",
    options:["Every item is estimated with the same small percentage error","Rare items are the most accurate; heavy hitters carry the most error","The error term is absolute (ε·N), so heavy hitters stay accurate while low-frequency items can be swamped","Accuracy depends only on the depth d, never on the data distribution"],
    correct:[2],
    why:"ε·N is an absolute error, identical for every item. Next to a heavy hitter's huge count it's negligible; for a rare item it can dwarf the true value. That's exactly why CMS suits heavy-hitter / top-K problems and not accurate tail counts.", more:"If you need the long tail accurately, CMS is the wrong tool — its error floor doesn't shrink for small counts.", src:"ds-count-min-sketch.html"},
  {id:"qcms4", topic:"DS: Count-Min Sketch", diff:"tricky", level:"Staff", type:"single",
    q:"You use a Count-Min Sketch to find the top-K hottest items in a stream. What must you add, and why?",
    options:["Nothing — the sketch can list its highest-count keys directly","A separate min-heap of K candidate keys, because a CMS estimates a key's count but cannot enumerate keys","A Bloom filter, to deduplicate keys before counting them","A second CMS, intersected with the first to recover the keys"],
    correct:[1],
    why:"A CMS stores counters, not keys — you can't ask it 'who are my top items?'. The standard pattern keeps a min-heap of the current top-K: for each event, query its estimate and conditionally update the heap. CMS supplies the counts; the heap remembers the keys.", src:"ds-count-min-sketch.html"},
  {id:"qcms5", topic:"DS: Count-Min Sketch", diff:"tricky", level:"Staff", type:"single",
    q:"Can you decrement or delete from a Count-Min Sketch?",
    options:["Yes, always — just subtract from the d counters exactly like adding","Only on a strictly non-negative stream; arbitrary decrements can push the min below the true count and break the never-undercount guarantee","No — counters are write-once and can never be lowered","Yes, but reliably only for the single most recently added item"],
    correct:[1],
    why:"Subtraction is safe while net counts stay non-negative (e.g. sliding-window removal of things you actually added). With arbitrary decrements the min can read below the truth, destroying the core guarantee — use a signed variant or Count-Mean-Min if you truly need deletes.", src:"ds-count-min-sketch.html"},
  {id:"qcms6", topic:"DS: Count-Min Sketch", diff:"basic", level:"Mid", type:"single",
    q:"Match each sketch to what it approximates: Bloom filter, Count-Min Sketch, HyperLogLog.",
    options:["Membership / frequency / distinct cardinality","Frequency / membership / distinct cardinality","Distinct cardinality / frequency / membership","Membership / distinct cardinality / frequency"],
    correct:[0],
    why:"Bloom answers 'have I seen x?' (membership), Count-Min answers 'how many times?' (frequency), HyperLogLog answers 'how many distinct?' (cardinality). All three are hash-based sketches trading exactness for sublinear space.", src:"ds-count-min-sketch.html"},
  {id:"qcms7", topic:"DS: Count-Min Sketch", diff:"tricky", level:"Senior", type:"multi",
    q:"With a CMS sized as w=⌈e/ε⌉ columns and d=⌈ln(1/δ)⌉ rows, which statements are correct? (select all)",
    options:["Widening w (more columns) reduces the error ε of each estimate","Adding rows d reduces the probability δ that an estimate exceeds the error bound","Space is O(d·w) and is independent of how many distinct keys you insert","Adding more rows lowers the per-estimate error term ε"],
    correct:[0,1,2],
    why:"w trades space for accuracy (smaller ε); d trades space for confidence (smaller δ); total space O(d·w) never grows with the stream or the key count. Rows control the failure probability, not the error magnitude — the last option swaps the roles of w and d.", src:"ds-count-min-sketch.html"},
  {id:"qgrpc1", topic:"gRPC / Protobuf", diff:"basic", level:"Mid", type:"single", q:"What is the most accurate reason gRPC is typically faster than a JSON-over-HTTP/1.1 REST API for internal service-to-service calls?", options:["It binary-serializes with Protobuf and multiplexes calls over HTTP/2","It always runs in the same datacenter, so the network latency is lower","It skips TLS entirely, removing the handshake on every single request","It caches every response by default, so most repeat calls are free"], correct:[0], why:"gRPC's speed comes from compact Protobuf binary encoding plus HTTP/2 multiplexing and header compression (HPACK), which removes per-request connection setup and shrinks bytes on the wire. Co-location, skipping TLS, and caching are not inherent to gRPC.", more:"On small payloads, benchmarks commonly show gRPC cutting latency substantially versus JSON/HTTP1.1; the win is HTTP/2 + Protobuf, not the RPC framing alone."},
  {id:"qgrpc2", topic:"gRPC / Protobuf", diff:"tricky", level:"Senior", type:"single", q:"A browser SPA needs to call your gRPC backend directly. What is the actual constraint you must design around?", options:["Browsers can speak full gRPC, but only when tunneled over WebSockets","Browsers can't frame raw HTTP/2, so you need gRPC-Web behind a proxy","gRPC is permanently blocked by CORS and can never reach any browser","gRPC-Web supports full bidirectional streaming natively in all browsers"], correct:[1], why:"Browsers expose no API to control raw HTTP/2 frames, so the full gRPC wire protocol can't run there. gRPC-Web is the browser-compatible variant and needs a translating proxy (e.g. Envoy). It supports unary and server-streaming only; client/bidirectional streaming is not generally available.", more:"This is why the common pattern is gRPC for east-west (internal) traffic and REST/JSON or gRPC-Web for north-south (browser/partner) traffic."},
  {id:"qgrpc3", topic:"gRPC / Protobuf", diff:"tricky", level:"Senior", type:"single", q:"In Protobuf, which change to a message is SAFE for backward/forward compatibility?", options:["Adding a new optional field that uses a brand-new field number","Reusing the field number of a deleted field for a new field","Renumbering an existing field so it encodes into fewer bytes","Changing an existing field's type from int32 to string in place"], correct:[0], why:"The wire format identifies fields by number, not name. Adding a new field with an unused number is safe: old code ignores it, new code tolerates its absence. Reusing a retired number, renumbering, or changing a field's type corrupts decoding for peers on the old schema.", more:"Best practice when deleting a field is to mark its number (and name) as reserved so it can never be reused, preventing silent corruption."},
  {id:"qgrpc4", topic:"gRPC / Protobuf", diff:"tricky", level:"Senior", type:"single", q:"Which scenario is the WEAKEST fit for gRPC, where REST/JSON is the better default?", options:["A public API consumed by unknown third-party developers and browsers","A high-QPS internal call between two backend services you fully own","A streaming telemetry pipeline running between backend microservices","A latency-sensitive mobile-to-backend RPC over a shared Protobuf contract"], correct:[0], why:"Public, third-party-facing APIs favor REST/JSON: it's human-readable, debuggable with curl, browser-native, and needs no shared .proto or proxy. gRPC shines for internal east-west traffic and streaming where both ends are owned by the same org.", accept:"Mobile-to-backend gRPC is viable (native clients can speak HTTP/2), but the classic 'use REST instead' case is the open public API."},
  {id:"qgrpc5", topic:"gRPC / Protobuf", diff:"tricky", level:"Staff", type:"single", q:"Your team wants real-time server push from a gRPC service to backend consumers. Which gRPC streaming mode fits, and what's the operational catch?", options:["Server-streaming; but long-lived HTTP/2 streams complicate load-balancer draining","Unary calls with polling, because that is the only mode that survives a proxy","Client-streaming, because the server cannot push without a request arriving first","Bidirectional only, because server-streaming can deliver just one message per call"], correct:[0], why:"Server-streaming lets one request yield a stream of responses, ideal for push. The catch is operational: long-lived HTTP/2 connections pin clients to a backend, so L4/L7 load balancing, graceful draining, and rebalancing during deploys need care (often an L7 proxy that understands HTTP/2).", more:"Bidirectional streaming also works but isn't required for pure push; the load-balancing/draining concern is the staff-level signal here."},
  {id:"qvec1", topic:"Vector DBs", diff:"basic", level:"Mid", type:"single", q:"What core problem does a vector database with an ANN index solve that a B-tree or inverted (keyword) index does not?", options:["Finding the nearest items in high-dimensional embedding space by similarity","Returning exact-match rows by primary key with very low read latency","Enforcing ACID transactions and joins across many normalized tables","Compressing cold, rarely-read data to reduce overall storage cost"], correct:[0], why:"Vector DBs answer 'find items similar to this one' via approximate nearest-neighbor search over embeddings, capturing semantic/conceptual similarity. B-trees do ordered exact/range lookups; inverted indexes do keyword/term matching, neither of which understands 'meaning'.", more:"Embeddings place semantically similar items close in a 128-3072-dimensional space; similarity is measured by cosine or dot product, not string overlap."},
  {id:"qvec2", topic:"Vector DBs", diff:"tricky", level:"Senior", type:"single", q:"You must choose between an HNSW and an IVF (inverted-file) index for similarity search. What is the central trade-off?", options:["HNSW gives high recall and fast queries but uses more memory to build","IVF reliably gives higher recall than HNSW at the same memory budget","HNSW requires a GPU to query, whereas IVF runs only on commodity CPU","IVF supports streaming inserts, while HNSW must be fully rebuilt per insert"], correct:[0], why:"HNSW (a navigable graph) gives excellent recall and low query latency and absorbs inserts, but costs notably more memory (often 2-5x IVF) and more to build. IVF partitions vectors into clusters (probe a few) for lower memory and faster build at some recall cost. HNSW does not need a GPU, and it handles incremental inserts.", more:"Most modern vector DBs (Pinecone, Milvus, Qdrant, Weaviate, OpenSearch) default to HNSW; IVF/IVF-PQ shines when memory is the binding constraint at very large scale."},
  {id:"qvec3", topic:"Vector DBs", diff:"tricky", level:"Senior", type:"single", q:"For a few million embeddings alongside an existing Postgres app, what's the pragmatic first choice before reaching for a dedicated vector DB?", options:["pgvector, the Postgres extension, with an HNSW index on the column","Stand up a Milvus cluster on dedicated GPU nodes right from the start","Store vectors as JSON blobs and brute-force scan them on every query","Keep vectors in Redis strings and compute cosine in the app layer"], correct:[0], why:"pgvector adds vector columns and ANN indexes (HNSW/IVFFlat) inside Postgres, so you keep one datastore, transactions, and joins/filters at low operational cost; it matches dedicated DBs around ~1M vectors. Move to a purpose-built DB when you outgrow it (often beyond a handful of millions of vectors).", accept:"A purpose-built DB (Milvus/Pinecone/Qdrant) is the right end-state at large scale, but starting there adds ops cost you don't need yet."},
  {id:"qvec4", topic:"Vector DBs", diff:"tricky", level:"Senior", type:"single", q:"A RAG system must restrict similarity search to one tenant's documents. What's the right way to combine the filter with ANN search?", options:["Use the DB's filtered/hybrid ANN so the predicate applies during traversal","Run ANN over all tenants, then drop other tenants' hits afterward in the app","Build one separate HNSW index per document and merge the per-doc results","Abandon ANN and use keyword search, since ANN cannot filter on metadata"], correct:[0], why:"Post-filtering after ANN can return too few (or zero) on-tenant results because the nearest global neighbors may all be other tenants'. Real vector DBs support filtered/hybrid search that applies the metadata predicate during graph traversal, preserving recall within the allowed set.", more:"This is why metadata (tenant_id, ACLs, source) should be stored with each vector; naive post-filtering is a classic correctness/recall bug."},
  {id:"qvec5", topic:"Vector DBs", diff:"tricky", level:"Staff", type:"single", q:"Pure dense-vector retrieval sometimes misses exact terms (codes, names, rare keywords). What's the standard production fix?", options:["Hybrid retrieval: fuse BM25 keyword and dense vector hits, then re-rank","Keep increasing the embedding dimensions until the exact terms are captured","Drop vector search entirely and fall back to keyword-only retrieval again","Lower the ANN recall target so the engine returns more diverse results"], correct:[0], why:"Bi-encoder embeddings are lossy and can miss exact lexical matches. The proven default is hybrid search: run BM25 and vector search in parallel, fuse with Reciprocal Rank Fusion, then apply a cross-encoder re-ranker. This typically lifts recall 15-30% over either method alone.", more:"Re-ranking (cross-encoder over the top-N) is often the single highest-ROI quality improvement in a retrieval stack."},
  {id:"qllm1", topic:"LLM Serving", diff:"basic", level:"Mid", type:"single", q:"During autoregressive generation, what does the KV cache store and why does it matter?", options:["Attention keys/values for past tokens, so new tokens skip recomputing them","The full model weights, so they are loaded into the GPU only once per request","The user's prompt history across sessions, enabling cross-request personalization","Final logits for every position, so a failed request can be retried instantly"], correct:[0], why:"Each generated token attends to all previous tokens; caching their key/value tensors turns per-token work from quadratic re-computation into reuse. The cost is GPU memory that grows with sequence length and batch size, which becomes the main capacity constraint in serving.", more:"KV-cache memory pressure is exactly what PagedAttention (in vLLM) targets by paging KV blocks like virtual memory to cut fragmentation."},
  {id:"qllm2", topic:"LLM Serving", diff:"tricky", level:"Senior", type:"single", q:"Why does continuous (iteration-level) batching beat static batching for LLM inference throughput?", options:["Finished sequences free their slot each decode step and a waiting request refills it","It places each incoming request on its own GPU so requests never interfere","It pads every request in the batch up to the single longest sequence length","It batches only the prefill stage and then serves the decode phase one-by-one"], correct:[0], why:"Static batching wastes GPU cycles waiting for the slowest request in a batch to finish. Continuous batching schedules at the iteration level: as soon as any sequence completes, a waiting request takes its slot, keeping the GPU full and raising throughput dramatically without per-request GPUs.", more:"This iteration-level scheduling (popularized by Orca and implemented in vLLM/TGI) is what lets a single GPU serve far more concurrent requests."},
  {id:"qllm3", topic:"LLM Serving", diff:"tricky", level:"Senior", type:"single", q:"How should generated tokens be delivered to a web client to minimize perceived latency?", options:["Stream tokens incrementally as they're produced, typically over SSE","Buffer the entire completion and then return it as one JSON response","Poll a status endpoint once per second until the generation is complete","Open a fresh TLS connection per token to keep each one fully isolated"], correct:[0], why:"Streaming tokens as they're generated (commonly Server-Sent Events) lets the user start reading after the first token, so perceived latency tracks time-to-first-token rather than total generation time. Buffering the whole response or polling adds dead wait; per-token connections add absurd overhead.", more:"Time-to-first-token (TTFT) and inter-token latency become the headline SLOs for interactive LLM apps."},
  {id:"qllm4", topic:"LLM Serving", diff:"tricky", level:"Staff", type:"single", q:"In LLM inference, prefill and decode stress hardware differently. What follows from that?", options:["Prefill is compute-bound and batches well; decode is memory-bound, the latency tail","The two phases are identical, so a single shared GPU pool is always optimal here","Decode is the compute-bound phase; prefill is trivial and can essentially be skipped","Prefill is the memory-bound phase, while decode is embarrassingly parallel and cheap"], correct:[0], why:"Prefill processes the whole prompt in parallel (compute-bound, batch-friendly). Decode emits one token at a time, dominated by reading weights/KV from memory (memory-bandwidth-bound) and drives the latency tail; GPUs can sit underutilized during decode. This motivates prefill/decode disaggregation onto separately scaled pools.", more:"Disaggregated prefill/decode is now standard across vLLM, SGLang, TensorRT-LLM and NVIDIA Dynamo, reportedly cutting serving cost ~35-46% versus aggregated configs."},
  {id:"qllm5", topic:"LLM Serving", diff:"tricky", level:"Senior", type:"single", q:"What is the most reliable architectural way to keep an LLM assistant's answers grounded and current without retraining?", options:["Retrieval-augmented generation: fetch relevant context into the prompt","Raise the sampling temperature so the model explores more candidate facts","Fine-tune the base model nightly on every piece of newly arrived data","Increase the max output token budget so it can elaborate in more detail"], correct:[0], why:"RAG retrieves relevant, fresh, possibly-private documents at query time and injects them into the prompt, grounding the model in real data and reducing hallucination, with no retraining. Temperature controls randomness (more, not fewer, hallucinations); nightly fine-tuning is slow, costly, and still goes stale.", more:"Production RAG adds chunking, hybrid retrieval + re-ranking, and guardrails (input/output filtering) around the model."},
  {id:"qllm6", topic:"LLM Serving", diff:"tricky", level:"Staff", type:"single", q:"Speculative decoding speeds up generation. What is the key invariant it must preserve?", options:["A draft model proposes tokens the large model verifies, keeping its distribution","It lets the draft model's proposed tokens ship unverified to save large-model compute","It only functions when the prompt is shorter than the draft model's context window","It permanently replaces the large model once the small draft model has warmed up"], correct:[0], why:"A cheap draft model proposes several tokens ahead; the large model verifies them in one parallel pass and accepts the longest correct prefix. Crucially, the accept/reject step preserves the target model's exact output distribution, so quality is unchanged while latency drops. Unverified draft tokens would change the output.", more:"It's a latency optimization that exploits spare compute in the memory-bound decode phase; throughput gains depend on draft acceptance rate."},
  {id:"qcell1", topic:"Cell-based Arch", diff:"basic", level:"Senior", type:"single", q:"What is the defining property of a 'cell' in cell-based architecture?", options:["A complete, isolated copy of the stack serving a defined subset of customers","A read replica added in front of the primary to scale up query throughput","An in-memory cache tier placed between the service and its backing database","A single stateless microservice that is built and deployed independently"], correct:[0], why:"A cell is a full, self-contained instance of the system (its own compute, storage, deploy pipeline, and observability) that serves a partition of customers. The point is fault isolation: a bad deploy, bad tenant, or failing dependency damages one cell, not the whole fleet.", more:"Cells can be scoped per-AZ, multi-AZ regional, or per-region depending on the failure domains you want to contain."},
  {id:"qcell2", topic:"Cell-based Arch", diff:"tricky", level:"Senior", type:"single", q:"What does cell-based architecture primarily buy you, compared with one large multi-tenant regional deployment?", options:["A bounded blast radius, so a failure hits only a fraction of all customers","Lower total infrastructure cost through aggressively shared, pooled capacity","Stronger global consistency guarantees across every tenant in the system","Elimination of the need for any load balancing in front of the service"], correct:[0], why:"The core win is blast-radius containment: partitioning into isolated cells means an outage, poison request, or bad rollout affects only the customers in that cell. It typically costs more (duplicated stacks) and does not improve global consistency or remove load balancing.", more:"You also gain a safer deploy story: roll out cell-by-cell (canary cells) and halt before a fleet-wide incident."},
  {id:"qcell3", topic:"Cell-based Arch", diff:"tricky", level:"Staff", type:"single", q:"How does shuffle sharding reduce blast radius BEYOND putting each tenant in one cell?", options:["Each tenant gets an overlapping but distinct subset of nodes, so co-failure is rare","It replicates every tenant's data onto every available node for full redundancy","It routes all tenants through one shared FIFO queue to enforce strict fairness","It removes sharding altogether, so there is no shard left that can fail anyone"], correct:[0], why:"Shuffle sharding gives each tenant a random combination of workers from a larger pool. Because two tenants almost never get the identical subset, a noisy or poisoned tenant degrades only the few nodes it shares with any victim, shrinking the fraction of customers any single failure can take down.", more:"With enough nodes the number of unique combinations is huge, so the probability of two customers fully overlapping (and thus co-failing) becomes tiny, the math behind AWS-style isolation."},
  {id:"qcell4", topic:"Cell-based Arch", diff:"tricky", level:"Staff", type:"single", q:"What is the hardest part of operating a cell-based architecture well?", options:["Keeping the cell router and shared dependencies from becoming a fleet-wide SPOF","Writing and maintaining the entire business logic separately for each cell","Keeping every individual cell deployed on a different cloud provider region","Guaranteeing linearizable, strongly-consistent reads spanning all of the cells"], correct:[0], why:"Isolation only holds if the routing layer that maps customers to cells is itself highly available and simple, and if cells share no hidden global dependency (one control plane, one database, one config service) that can fail for everyone. Those shared components quietly reintroduce the blast radius cells were meant to remove.", more:"Keep the router thin and static where possible, and replicate or partition any control-plane dependency so no single cell-spanning component is a SPOF."},
  {id:"qcdc1", topic:"CDC / Outbox", diff:"basic", level:"Senior", type:"single", q:"What is the 'dual-write problem' that the transactional outbox pattern exists to solve?", options:["Writing to a DB and a broker in one step cannot be made atomic across both","Two replicas accepting writes simultaneously produces conflicting row versions","Writing the very same row twice in a request needlessly wastes storage space","A client retrying a timed-out write ends up creating an unwanted duplicate"], correct:[0], why:"When a service must update its DB and publish an event to a broker, there's no shared transaction across the two systems: one can succeed while the other fails, leaving them inconsistent (lost event or phantom event). That non-atomic pair of writes is the dual-write problem.", more:"Two-phase commit across a DB and Kafka is brittle/unsupported in practice, which is why the outbox sidesteps it entirely."},
  {id:"qcdc2", topic:"CDC / Outbox", diff:"tricky", level:"Senior", type:"single", q:"How does the transactional outbox pattern guarantee an event is published iff the business write commits?", options:["Insert the event into an outbox table in the same DB transaction, relay it later","Publish the event to the broker first, and only then write the business DB row","Acquire a distributed lock spanning both the database and the message broker","Write to the broker and the DB in parallel, then reconcile them in a nightly job"], correct:[0], why:"The event row is written to an outbox table inside the same local ACID transaction as the business change, so they commit or roll back together. A separate relay then reads the outbox and publishes to the broker, decoupling the two systems while preserving atomicity at the source.", more:"Consumers must be idempotent, since the relay gives at-least-once delivery (a crash after publish but before marking sent causes a replay)."},
  {id:"qcdc3", topic:"CDC / Outbox", diff:"tricky", level:"Senior", type:"single", q:"For relaying the outbox, what's the trade-off between log-based CDC (e.g. Debezium) and query-based polling?", options:["CDC tails the commit log for low latency and order, but adds ops complexity","Polling alone preserves commit order, whereas CDC reorders events arbitrarily","CDC requires adding a status column, while polling needs no schema change at all","Polling delivers strictly lower latency than CDC once event throughput gets high"], correct:[0], why:"Log-based CDC reads the database's replication/commit log: near-real-time, commit-ordered, and adding little query load, no status column needed because it doesn't read the table. The cost is running and monitoring Debezium + logical replication. Polling a status column is trivial to build but adds latency and constant query load.", more:"Reach for CDC at high event rates or strict latency SLAs; a simple polling relay is fine for modest volumes."},
  {id:"qcdc4", topic:"CDC / Outbox", diff:"tricky", level:"Senior", type:"single", q:"A team wants to invalidate a Redis cache whenever rows change in Postgres, with no app code in the write path. What fits best?", options:["Log-based CDC streaming row changes to a consumer that evicts the cache keys","A nightly batch job that flushes the entire Redis cache and lets it warm again","Dual-writing each change to both Postgres and Redis from the application layer","A database trigger that fires a synchronous HTTP call out to Redis on commit"], correct:[0], why:"CDC tails the WAL and emits change events out-of-band, so a consumer can evict or update the affected cache keys with low latency and zero changes to the application's write path. Dual-writing reintroduces the dual-write problem; nightly flush is too coarse; triggers doing synchronous network calls couple commit latency to Redis and can block transactions.", more:"This is the canonical 'CDC for cache invalidation' pattern: the DB log is the single source of truth for what changed."},
  {id:"qcdc5", topic:"CDC / Outbox", diff:"tricky", level:"Staff", type:"single", q:"With log-based CDC + outbox, what delivery semantics should downstream consumers assume, and how do they cope?", options:["At-least-once, so consumers must be idempotent (dedupe by event id or upsert)","Exactly-once across the whole pipeline for free, so no dedupe is ever required","At-most-once delivery, so the design must tolerate occasional silent event loss","Strictly ordered exactly-once across every partition, handled fully automatically"], correct:[0], why:"A crash between publishing and recording progress (or connector restarts replaying log offsets) means the same change can be delivered more than once, so the practical guarantee is at-least-once. Consumers must be idempotent: dedupe by a unique event id, or apply upserts so replays are harmless.", more:"True end-to-end exactly-once requires extra machinery (transactional sinks/dedupe stores); assuming it for free is a classic mistake."},
  {id:"qgeo1", topic:"Geospatial", diff:"basic", level:"Mid", type:"single", q:"What is the core idea behind geohash for proximity search?", options:["Interleave lat/long bits into a string so a shared prefix implies nearness","Precompute and store each point's exact distance to every other point nearby","Hash the human-readable address text into a bucket to group close places","Build a B-tree indexed on latitude alone and ignore longitude entirely"], correct:[0], why:"Geohash recursively subdivides the globe and interleaves latitude/longitude bits into a base-32 string, so points sharing a longer prefix are (usually) physically close. A range scan on the prefix returns nearby candidates without comparing against every point.", more:"It maps 2D coordinates onto a 1D string that a standard B-tree/prefix index can serve."},
  {id:"qgeo2", topic:"Geospatial", diff:"tricky", level:"Senior", type:"single", q:"What is the classic correctness gotcha with geohash proximity queries, and the usual fix?", options:["Boundary points share no prefix, so you must also query the 8 neighbor cells","Geohashes cannot represent the poles, so very high latitudes must be skipped","Prefixes are case-sensitive, so every code must be lowercased before comparison","Geohash already returns exact distances, so no distance post-filtering is needed"], correct:[0], why:"Two points can be meters apart yet fall in adjacent cells with different prefixes, so a naive prefix query misses them. The standard fix is to compute the query cell plus its 8 neighbors and union the results, then post-filter by true distance. This boundary problem is geohash's signature weakness.", more:"Uber hit exactly this matching riders to drivers across cell edges, and the neighbor-cell search adds query overhead, motivating richer schemes."},
  {id:"qgeo3", topic:"Geospatial", diff:"tricky", level:"Senior", type:"single", q:"Google's S2 differs from a plain geohash grid mainly because it...", options:["Maps Earth onto a cube and orders cells along a Hilbert space-filling curve","Uses hexagonal cells so that every neighbor shares one complete full edge","Stores all of its points purely in RAM and cannot persist them to disk","Indexes locations by their postal code rather than by raw coordinates"], correct:[0], why:"S2 projects the sphere onto six cube faces and numbers cells along a Hilbert space-filling curve, preserving locality as 64-bit cell IDs. Its covering algorithm returns a small mixed-level set of cells approximating any circle/polygon, so a radius query touches only those cell IDs. Hexagons are H3's idea, not S2's.", more:"Hilbert ordering keeps nearby cells close in ID space, which makes range scans and coverings efficient; Google uses S2 for persistent planet-scale indexes."},
  {id:"qgeo4", topic:"Geospatial", diff:"tricky", level:"Senior", type:"single", q:"Why did Uber build H3 (hexagonal cells) rather than reuse square-cell schemes?", options:["Hexagon neighbors are equidistant, so k-ring expansion covers a circle evenly","Hexagons subdivide perfectly into smaller hexagons with absolutely no error","Hexagons are geometrically exact, removing any need for distance post-filtering","Square grids simply cannot represent dense cities, only sparse rural regions"], correct:[0], why:"Every hexagon shares a full edge with all six neighbors at equal center distance, so expanding by k rings approximates a circle uniformly, ideal for Uber's 'supply/demand per cell, refreshed often' analytics. Squares have mixed edge/corner adjacency (4 edges + 4 corners), which distorts neighbor distance.", accept:"H3 hexagons don't tile perfectly across resolutions (there's slight approximation), so the 'perfect subdivision' option is wrong; the uniform-neighbor property is the real reason.", more:"H3 is analytics-first (aggregation per cell) and proximity-second, which is exactly Uber's marketplace-balancing use case."},
  {id:"qgeo5", topic:"Geospatial", diff:"tricky", level:"Staff", type:"single", q:"For transient positions of millions of game players that exist only in memory and update constantly, which spatial index fits best?", options:["An in-memory quadtree, which suits dynamic data and fast region traversal","A persisted geohash B-tree in Postgres, fully re-indexed on every game tick","S2 cell IDs written out to a wide-column store on each position update","A single global HNSW vector index built over the raw 2D coordinates"], correct:[0], why:"A quadtree recursively splits 2D space into quadrants and traverses only branches intersecting the query region, giving sub-millisecond in-memory queries and cheap updates, perfect for fast-changing, RAM-resident positions. Persisting to a DB per tick (geohash/S2) adds write/latency overhead; HNSW is for high-dimensional similarity, not 2D points.", more:"Rule of thumb: quadtree for transient in-memory positions; geohash/S2 for persistent disk-backed indexes; H3 for cell analytics."},
  {id:"qpg6mvcc", topic:"PostgreSQL", diff:"tricky", level:"Senior", type:"single",
    q:"How does Postgres MVCC let readers and writers avoid blocking each other, and what's the maintenance cost?",
    options:["Readers take shared locks that writers must wait on, so reads always win","Each write creates a new row version; readers see a consistent snapshot, and dead tuples must be VACUUMed away","Writers copy the whole table so readers keep the old file open until commit","Reads are served from a replica, so the primary only ever handles writes"],
    correct:[1],
    why:"MVCC keeps multiple row versions: a reader sees a snapshot as of its transaction start while writers create new versions, so reads don't block writes or vice versa. The cost is dead tuples (old versions) that autovacuum must reclaim; neglected vacuum causes table bloat and transaction-ID wraparound risk.",
    more:"A long-running transaction holds back the vacuum horizon (xmin), so dead tuples can't be cleaned and bloat builds up — a classic Postgres production gotcha."},
  {id:"qpg6iso", topic:"PostgreSQL", diff:"tricky", level:"Staff", type:"single",
    q:"To stop two transactions from overselling the last item, what's the real difference between SELECT … FOR UPDATE and SERIALIZABLE isolation?",
    options:["They are two names for the same row-locking mechanism","FOR UPDATE is pessimistic row locking; SERIALIZABLE is optimistic and may abort a transaction with a serialization error you must retry","SERIALIZABLE locks the whole table while FOR UPDATE locks nothing","FOR UPDATE only works inside a SERIALIZABLE transaction"],
    correct:[1],
    why:"SELECT … FOR UPDATE takes an explicit pessimistic lock on matched rows, so a competitor blocks until you commit. SERIALIZABLE (SSI in Postgres) is optimistic: it lets both proceed and aborts one with serialization_failure if they'd violate serial order, so the app must retry. Pick pessimistic for high-contention hotspots, optimistic when conflicts are rare.",
    more:"The common confusion is treating SERIALIZABLE as 'just stronger locking' — it's conflict detection with retries, not a bigger lock."},
  {id:"qpg6pool", topic:"PostgreSQL", diff:"tricky", level:"Senior", type:"single",
    q:"Thousands of app instances each open Postgres connections and the DB falls over. Fix, and why?",
    options:["Raise max_connections into the tens of thousands so every client gets one","Put a pooler like PgBouncer in front; each Postgres connection is a heavyweight backend process","Move every read to a replica so the primary needs no connections","Open a fresh connection per query so none stay held open"],
    correct:[1],
    why:"Each Postgres connection is a separate OS process with real memory overhead, so it doesn't scale to tens of thousands. A pooler (PgBouncer in transaction mode) multiplexes many client connections onto a small pool of real backends. Just raising max_connections trades one bottleneck for memory exhaustion and context-switch thrash.",
    more:"Serverless/Lambda fan-out makes this acute — hundreds of cold starts each grabbing a connection is the canonical way to exhaust Postgres."},
  {id:"qpg6part", topic:"PostgreSQL", diff:"tricky", level:"Senior", type:"single",
    q:"A read-heavy Postgres table keeps growing. What's the right ordering of scaling moves before sharding?",
    options:["Shard across machines first, since one node can never keep up","Indexes/partitioning + read replicas first; native partitioning splits one table within an instance, sharding (e.g. Citus) splits across machines","Add more replicas until writes are also fast","Vertically split every column into its own table before anything else"],
    correct:[1],
    why:"Scale within the box first: proper indexes, declarative partitioning (range/hash) to keep working sets and indexes small, and read replicas for read load. Native partitioning is still one instance; only when a single primary can't hold the write/data volume do you shard across machines (Citus or app-level), which adds cross-shard query and transaction pain.",
    more:"Replicas scale reads, not writes — every write still funnels to the primary, so a write-bound table needs partitioning/sharding, not more replicas."},
  {id:"qpg6wal", topic:"PostgreSQL", diff:"basic", level:"Senior", type:"single",
    q:"What is the write-ahead log (WAL) in Postgres actually for?",
    options:["It caches recent query results to speed up repeated reads","Changes are appended to a durable sequential log BEFORE the data pages, enabling crash recovery and replication","It stores the query-plan cache across restarts","It is the on-disk B-tree index for the primary key"],
    correct:[1],
    why:"WAL is the durability mechanism: a change is appended to the sequential log and fsynced before the random-access heap/index pages are updated, so a crash recovers by replaying the log. The same WAL stream feeds streaming replication and logical replication / CDC.",
    more:"This is why commits are sequential-write fast while data files update lazily at checkpoints — and why CDC tools like Debezium tail the WAL."},
  {id:"qcas6ring", topic:"Cassandra", diff:"tricky", level:"Senior", type:"single",
    q:"How does Cassandra decide which node stores a given partition key?",
    options:["partition = hash(key) mod node_count, recomputed whenever nodes join or leave","A partitioner (Murmur3) hashes the key to a token on a ring; vnodes give each node many token ranges","A central coordinator assigns each key a home and records it in a directory","Keys are range-partitioned alphabetically across nodes in order"],
    correct:[1],
    why:"Cassandra hashes the partition key with a partitioner (Murmur3 by default) to a token, and the node owning that token range on the ring stores it — consistent hashing, NOT modulo. Virtual nodes (num_tokens) give each physical node many small ranges, so adding/removing a node rebalances a bounded slice instead of remapping everything.",
    more:"Saying 'mod number of nodes' is the classic tell: modulo would remap almost every key on a membership change, which is exactly what the token ring avoids."},
  {id:"qcas6model", topic:"Cassandra", diff:"tricky", level:"Senior", type:"single",
    q:"What's the right way to model data in Cassandra for a new access pattern?",
    options:["Normalize like SQL and JOIN the tables at read time","Model query-first: one denormalized table per query, duplicating data, since there are no JOINs","Put everything in one table and filter with ALLOW FILTERING","Add a secondary index on any column you might ever query"],
    correct:[1],
    why:"Cassandra has no JOINs and punishes ad-hoc queries. You design tables around the exact queries you'll run, denormalizing and duplicating data across multiple tables (one per access pattern) so each query is a single-partition read. Writes are cheap, so write the same fact several ways.",
    more:"ALLOW FILTERING and unbounded secondary indexes are anti-patterns — they scan across partitions. If you need them, your data model is wrong for Cassandra."},
  {id:"qcas6tomb", topic:"Cassandra", diff:"tricky", level:"Staff", type:"single",
    q:"A queue-like Cassandra table (insert rows, delete after processing, read the head) gets slower and times out. Why?",
    options:["SSTables are immutable, so deletes are impossible and rows pile up forever","Deletes write tombstones; reading the head scans over thousands of not-yet-purged tombstones until gc_grace_seconds + compaction remove them","Cassandra rejects reads on any partition that has had a delete","The commit log fills because deletes are never logged"],
    correct:[1],
    why:"Deletes are tombstone markers, not in-place removals. A read must scan past all tombstones still present until compaction purges them — and they linger gc_grace_seconds (default 10 days) so deletes can propagate and avoid zombie resurrection. Queue/often-deleted patterns generate tombstone floods that blow up read latency and trip tombstone thresholds.",
    more:"Lesson: don't use Cassandra as a queue. Tombstone build-up on range reads is a signature Cassandra failure mode."},
  {id:"qddb6gsi", topic:"DynamoDB", diff:"tricky", level:"Senior", type:"single",
    q:"Which statement about a DynamoDB Global Secondary Index (GSI) is correct?",
    options:["A GSI lets you query across multiple different tables in one request","A GSI is an alternate-key view of the SAME table, has its own partition/sort key and throughput, and is eventually consistent","A GSI is just a strongly-consistent copy of the base table's primary key","A GSI must share the base table's partition key, like an LSI"],
    correct:[1],
    why:"A GSI indexes one base table under a different partition (and optional sort) key, stored on its own partitions with its own capacity, and is eventually consistent only (no ConsistentRead). It does NOT join or span tables — DynamoDB has no cross-table queries at all.",
    more:"Thinking a GSI is 'cross-table' is a common and costly misconception; model your access patterns within a single table instead."},
  {id:"qddb6hot", topic:"DynamoDB", diff:"tricky", level:"Senior", type:"single",
    q:"A DynamoDB table has a hot partition because one key (a viral item) takes most of the traffic. Standard fix?",
    options:["Raise table-level provisioned capacity until the hot key keeps up","Write-shard the key: add a calculated/random suffix (key#0..N) to spread it across partitions, then scatter-gather on read","Switch the table to strongly consistent reads","Add an LSI on the hot attribute"],
    correct:[1],
    why:"A single partition caps near ~3,000 RCU / ~1,000 WCU, so one hot key throttles no matter how much table capacity you buy. Write sharding appends a suffix so the key's traffic spreads across many partitions; reads fan out across the suffixes and merge. Adaptive capacity helps somewhat but won't save a truly hot single key.",
    more:"Same idea as Kafka / ad-click-aggregator salting — spread a hot key across partitions, then re-aggregate on read."},
  {id:"qddb6single", topic:"DynamoDB", diff:"tricky", level:"Staff", type:"single",
    q:"What is 'single-table design' in DynamoDB, and why is it used?",
    options:["Putting every microservice's data in one shared table to save money","Storing multiple entity types in one table with overloaded generic PK/SK so related items co-locate and one query fetches them together","Always using exactly one GSI per table","Avoiding sort keys so every item is addressed by partition key alone"],
    correct:[1],
    why:"Because DynamoDB has no JOINs, you co-locate related entities in one table using generic, overloaded keys (PK/SK) and item collections, so a single Query can return, say, an order and its line items together. It trades modeling complexity for single-digit-ms multi-entity reads.",
    more:"It's polarizing and access-pattern-specific; for simple apps multiple tables are fine. The point is designing keys around queries, not entities."},
  {id:"qddb6streams", topic:"DynamoDB", diff:"tricky", level:"Senior", type:"multi",
    q:"Which DynamoDB features do what they claim? (select all)",
    options:["DynamoDB Streams emits an ordered change log of item modifications (24h), often triggering Lambda","TTL auto-deletes expired items in the background at no extra write cost","TransactWriteItems gives ACID across up to 100 items in one or more tables","Streams guarantee exactly-once delivery, so consumers need no dedupe"],
    correct:[0,1,2],
    why:"Streams are a 24-hour, per-partition-ordered change feed (great for CDC, search sync, materialized views, fan-out via Lambda). TTL lazily removes expired items without consuming write capacity. TransactWriteItems is ACID across up to 100 items. But Streams are at-least-once, so consumers still must be idempotent.",
    more:"Streams + Lambda is the idiomatic way to keep a search index or aggregate in sync with DynamoDB — the DynamoDB analog of CDC."},
  {id:"qkaf6isr", topic:"Kafka vs Queues", diff:"tricky", level:"Senior", type:"single",
    q:"With acks=all, what actually guarantees a Kafka write survives a broker failure?",
    options:["The leader fsyncs the message to disk before acknowledging","The write is replicated to all in-sync replicas (ISR); with min.insync.replicas=2 the producer errors if the ISR shrinks too far","Every one of the N replicas, in-sync or not, must acknowledge","ZooKeeper stores a second copy of each message as a backup"],
    correct:[1],
    why:"acks=all means the leader waits for all current in-sync replicas (ISR) to replicate before acking. Paired with min.insync.replicas (commonly 2), if too few replicas are caught up the producer gets a NotEnoughReplicas error instead of silently accepting an under-replicated write — that's the durability contract, not fsync alone.",
    more:"acks=1 (leader only) can lose data if the leader dies before a follower replicates; the ISR + min.insync.replicas combo is the real durability lever."},
  {id:"qkaf6eos", topic:"Kafka vs Queues", diff:"tricky", level:"Staff", type:"single",
    q:"Kafka's default delivery is at-least-once. How do you actually get exactly-once?",
    options:["It's automatic; Kafka never delivers a message twice","Enable the idempotent producer (dedupes retries via producer id + sequence) and use transactions with read_committed for atomic multi-partition writes","Set acks=0 so there are no retries to duplicate","Have every consumer commit offsets before it processes the message"],
    correct:[1],
    why:"By default a producer retry can duplicate and a consumer can reprocess, so it's at-least-once. The idempotent producer dedupes retries per partition via a producer id + sequence number; Kafka transactions make a set of writes (and offset commits) atomic, and consumers on read_committed see all-or-nothing — together that's exactly-once within Kafka. Crossing into external systems still needs idempotent consumers.",
    more:"Committing offsets BEFORE processing gives at-most-once (you can lose messages on crash) — the opposite mistake."},
  {id:"qkaf6compact", topic:"Kafka vs Queues", diff:"tricky", level:"Senior", type:"single",
    q:"How does Kafka log compaction differ from time/size-based retention?",
    options:["Compaction zips old segments to save disk but keeps every message","Retention deletes by age/size; compaction keeps the LATEST value per key (a changelog), so the topic can rebuild current state","Compaction merges partitions together to reduce their count","They're the same feature under two names"],
    correct:[1],
    why:"Normal retention drops messages older than a time/size threshold. Compaction instead guarantees at least the most recent value for each key survives, so the topic becomes a replayable snapshot of current state — ideal for changelogs, CDC, and rebuilding caches/KTables. A null-value tombstone marks a key for deletion.",
    more:"Compacted topics back Kafka Streams state stores and the internal consumer-offsets topic."},
  {id:"qes6refresh", topic:"Elasticsearch", diff:"tricky", level:"Senior", type:"single",
    q:"You index a document into Elasticsearch and immediately can't find it in search. Why, and what's the lever?",
    options:["The write failed silently; retry until it appears","ES is near-real-time: a new doc is searchable only after a refresh (default ~1s); raising refresh_interval boosts bulk-indexing throughput","Search only works after a full reindex of the index","You must pass a strong-consistency flag on the search query"],
    correct:[1],
    why:"Elasticsearch is near-real-time, not real-time: an indexed doc becomes searchable only once a refresh writes a new Lucene segment, which by default happens about every second. For heavy bulk loads you raise (or temporarily disable) refresh_interval to cut segment churn and speed indexing, then refresh once at the end.",
    more:"This slight lag is exactly why ES is a secondary search index synced from the source of truth, never the source of truth itself."},
  {id:"qes6denorm", topic:"Elasticsearch", diff:"tricky", level:"Senior", type:"single",
    q:"How should you model relational data for Elasticsearch search?",
    options:["Normalize and JOIN indices at query time like SQL","Denormalize into self-contained documents; nested and parent-child (join) types exist but are expensive and limited","Store each table as a separate index and let ES auto-join on shared ids","Always use parent-child relations to mirror foreign keys"],
    correct:[1],
    why:"Lucene has no efficient cross-document JOIN, so you denormalize the data each search needs into one document. nested fields and the join (parent-child) type exist but cost extra memory/query overhead and don't scale like denormalization, so reach for them only when duplication is truly unworkable.",
    more:"Denormalizing means re-syncing when the source changes (via CDC/Streams) — you trade write amplification for fast reads, the usual search-index bargain."},
  {id:"qes2shards", topic:"Elasticsearch", diff:"basic", level:"Mid", type:"single",
    q:"In Elasticsearch, what's the difference between a primary shard and a replica shard?",
    options:["Primaries handle writes and reads; replicas are cold backups that serve no traffic","Each primary holds a slice of the data and takes writes; replicas are copies that add read throughput and failover","Replicas hold the data while primaries only route queries","Primaries live in memory and replicas are the on-disk copy"],
    correct:[1],
    why:"Data is split across primary shards (each takes writes for its slice); each primary has 0+ replica copies on other nodes. Replicas serve reads (scaling query throughput) and get promoted to primary if a node fails, so they give both HA and read scaling. A replica never sits on the same node as its primary.",
    more:"Replica count is changeable anytime (unlike primary count) — add replicas to scale reads, but each replica multiplies storage and indexing work."},
  {id:"qes2sizing", topic:"Elasticsearch", diff:"tricky", level:"Senior", type:"single",
    q:"What's the pitfall of creating an index with hundreds of tiny shards 'to be safe'?",
    options:["Tiny shards are faster, so there's no real downside","Each shard is a full Lucene index with fixed heap/file-handle/cluster-state overhead, so over-sharding wastes memory and slows the cluster","Elasticsearch merges tiny shards automatically, so the count is irrelevant","Shards under 1GB cannot be queried at all"],
    correct:[1],
    why:"Every shard is a separate Lucene index with its own segments, file handles, and a slice of cluster state on the master, plus per-shard query overhead. Hundreds of tiny shards bloat heap and the master's bookkeeping. Aim for ~10-50GB per shard and size the primary count from your expected data volume.",
    more:"Under-sharding hurts too (one giant shard can't spread load and is slow to recover) — shard sizing is a Goldilocks problem you reason about from the data estimate."},
  {id:"qes2textkw", topic:"Elasticsearch", diff:"tricky", level:"Senior", type:"single",
    q:"You need to aggregate and exact-match on a 'status' field, but it was mapped as text. What's wrong?",
    options:["text is fine; aggregations and exact match work the same on any string","text is analyzed (tokenized/lowercased) for full-text search; for exact match, sorting, and aggregations you need a keyword field","keyword is only for numbers, so text is the only option for strings","You must reindex into a separate cluster to aggregate strings"],
    correct:[1],
    why:"text fields are analyzed — split into lowercased tokens for relevance search — so they don't support exact term match, sorting, or aggregations cleanly (aggregating even needs fielddata, which blows heap). keyword fields are stored verbatim for exact match, sort, and aggregations. The idiomatic mapping is a multi-field: text for search plus a .keyword sub-field for the rest.",
    more:"Default dynamic mapping already does this — a string becomes a text field with a keyword sub-field. text-vs-keyword is the single most common ES gotcha."},
  {id:"qes2analyzer", topic:"Elasticsearch", diff:"tricky", level:"Senior", type:"single",
    q:"A term query for 'Apple' on an analyzed text field returns nothing, though the doc clearly contains it. Why?",
    options:["term is invalid syntax; only match queries exist","The analyzer lowercased the indexed token to 'apple', but term does no analysis and looks up 'Apple' verbatim","Text fields can't be queried at all, only keyword fields","The document must be refreshed before any query can see it"],
    correct:[1],
    why:"At index time the analyzer tokenizes and lowercases, so the inverted index holds 'apple'. match runs the same analyzer on the query (so it finds 'apple'); term does NOT analyze and looks for the exact string 'Apple', which isn't in the index. Use match on analyzed text, term on keyword/exact fields.",
    more:"Analyzer choice (standard, language, edge-ngram for autocomplete) applies at both index and search time and must be consistent — a mismatch is the classic 'why no results' bug."},
  {id:"qes2bm25", topic:"Elasticsearch", diff:"basic", level:"Senior", type:"single",
    q:"How does Elasticsearch rank full-text results by default?",
    options:["By document insertion order, newest first","By BM25 relevance scoring — term frequency, inverse document frequency, and field length","By the alphabetical order of the matched field","Randomly, unless you specify an explicit sort"],
    correct:[1],
    why:"ES scores matches with BM25 (the default similarity since 5.0): a term scores higher when it's frequent in the document (TF), rarer across the corpus (IDF), and in a shorter field. Results return sorted by _score unless you override with an explicit sort.",
    more:"Tune relevance with boosts, function_score, or by re-ranking the top-N — the same 'cheap retrieve, then re-rank' pattern used in vector/hybrid search."},
  {id:"qes2deeppage", topic:"Elasticsearch", diff:"tricky", level:"Senior", type:"single",
    q:"Why does paging to result 100,000 with from=100000&size=10 perform terribly in Elasticsearch?",
    options:["from/size is disabled above page 1","Each shard must collect and sort from+size hits and ship them to the coordinator to merge, so cost grows with the offset; use search_after or scroll","Deep pages hit a different index that isn't cached","Elasticsearch re-indexes the data on every deep page request"],
    correct:[1],
    why:"In query-then-fetch, every shard returns its top from+size results so the coordinator can merge them; deep offsets force each shard to sort huge result sets, and memory/CPU grow with from (default cap index.max_result_window=10000). For deep/live pagination use search_after with a point-in-time; use scroll for batch exports.",
    more:"search_after pages by the sort values of the last hit (a keyset cursor) instead of an offset, so cost stays flat — the ES analog of SQL keyset pagination."},
  {id:"qes2bulk", topic:"Elasticsearch", diff:"basic", level:"Mid", type:"single",
    q:"You must index millions of documents. What's the best-practice ingestion approach?",
    options:["Send one index request per document for maximum reliability","Use the Bulk API to batch many index ops per request, and lower refresh frequency during the load","Write the documents straight into the Lucene files on disk","Disable replicas permanently to speed up writes"],
    correct:[1],
    why:"The Bulk API amortizes network and processing overhead by sending many index/update/delete actions per request — the standard way to get indexing throughput. Pair it with a raised/disabled refresh_interval during bulk loads (fewer segments) and consider temporarily dropping replica count, then restoring it.",
    more:"Right-size batches (a few MB / thousands of docs); too-large batches cause memory pressure and rejections — watch the bulk thread-pool queue."},
  {id:"qes2aggs", topic:"Elasticsearch", diff:"basic", level:"Senior", type:"single",
    q:"Beyond full-text search, what's a primary reason teams reach for Elasticsearch?",
    options:["As a strongly-consistent transactional system of record","Aggregations over large data — metrics and bucketing — powering log/metrics analytics and dashboards (ELK/Kibana)","As a distributed lock manager for coordination","As a message queue between microservices"],
    correct:[1],
    why:"ES's aggregation framework (metric + bucket aggs) makes it a fast analytical engine over big volumes, which is why it anchors observability stacks (logs, metrics, APM via Kibana). It complements search but is still a secondary store synced from a source of truth, not transactional.",
    more:"Aggregations run on doc_values (columnar, on-disk) for keyword/numeric fields — another reason to map aggregatable fields as keyword, not text."},
  {id:"qes2ilm", topic:"Elasticsearch", diff:"tricky", level:"Staff", type:"single",
    q:"You store append-only logs in Elasticsearch and the cluster keeps filling up. What's the right pattern?",
    options:["One enormous index that you periodically prune with delete-by-query","Time-based indices with rollover + Index Lifecycle Management moving data hot to warm to cold to delete","A single index with replicas set to zero to save space","Store all logs in one shard so deletes are cheap"],
    correct:[1],
    why:"For time-series/log data you roll over to a fresh index by age/size/doc count and let ILM migrate indices through hot (fast SSD, indexing) to warm to cold (cheaper hardware, read-only) to delete. Dropping a whole old index is far cheaper than delete-by-query, which writes tombstones and forces merges.",
    more:"Same lesson as Cassandra: don't delete row-by-row in a segment/LSM store — age out whole partitions/indices instead. Data streams package this pattern."},
  {id:"qes2roles", topic:"Elasticsearch", diff:"tricky", level:"Senior", type:"multi",
    q:"Which are real Elasticsearch node roles you'd separate at scale? (select all)",
    options:["Master-eligible nodes that manage cluster state and shard allocation","Data nodes that hold shards and do the indexing/search work","Coordinating nodes that route requests and merge results","Compaction nodes that rewrite SSTables in the background"],
    correct:[0,1,2],
    why:"ES nodes can specialize: dedicated master-eligible nodes (usually 3) keep cluster state stable, data nodes store shards and run queries, ingest nodes run pipelines, and coordinating-only nodes fan out and merge. 'Compaction nodes' aren't a thing — that's LSM/Cassandra terminology; ES merges Lucene segments on the data nodes themselves.",
    more:"Dedicate masters so a heavy query storm on data nodes can't destabilize cluster-state management — a key stability move at scale."},
  {id:"qes2qtf", topic:"Elasticsearch", diff:"tricky", level:"Senior", type:"single",
    q:"How does a search across many shards return a globally correct top-10?",
    options:["The coordinating node queries one shard and trusts its top-10","Query-then-fetch: each shard returns its local top-10 ids+scores, the coordinator merges to the global top-10, then fetches _source for just those","Every shard streams all matching documents to the client, which sorts them","A background job precomputes the answer for every possible query"],
    correct:[1],
    why:"A coordinating node scatters the query to all relevant shards (query phase): each returns lightweight {doc_id, _score} for its local top-K. The coordinator merges these into the global top-K, then runs the fetch phase to pull _source only for the winners. This scatter-gather is why deep pagination is costly and why more shards add merge overhead.",
    more:"Scoring is per-shard by default, so with very few docs relevance can vary slightly across shards (dfs_query_then_fetch fixes this at extra cost)."},
  {id:"qes2mapexpl", topic:"Elasticsearch", diff:"tricky", level:"Senior", type:"single",
    q:"Indexing documents with arbitrary user-supplied JSON keys eventually destabilizes the cluster. Why?",
    options:["Elasticsearch can't store JSON objects at all","Dynamic mapping creates a new field per unique key; unbounded fields bloat the mapping and cluster state (mapping explosion)","Each new key opens a TCP connection that's never closed","JSON keys must be alphabetical or indexing fails"],
    correct:[1],
    why:"With dynamic mapping, every new JSON key becomes a permanently mapped field. User-controlled or high-cardinality keys cause a mapping explosion — thousands of fields bloating cluster state and heap (default limit index.mapping.total_fields.limit=1000). Use strict or dynamic:false mappings, or store such data as flattened/key-value pairs.",
    more:"Cluster state is replicated to every node and updated by the master, so a runaway mapping makes every cluster-state change expensive."},
  {id:"qes2alias", topic:"Elasticsearch", diff:"tricky", level:"Senior", type:"single",
    q:"Primary shard count is fixed at creation, but you must change it on a live index with no downtime. How?",
    options:["Edit the shard-count setting in place and let ES rebalance","Reindex into a new index with the new shard count, then atomically swap an alias the app reads/writes through","Delete and recreate the index during a maintenance window only","Add replica shards, which raises the primary count"],
    correct:[1],
    why:"Since primaries can't change in place, have the app read/write through an alias, reindex into a new index with the desired shard count, then atomically repoint the alias (remove old + add new in one call). Clients never see the switch — the standard zero-downtime reindex.",
    more:"Aliases also enable filtered views and blue/green index rollouts; pair with the Reindex API and ILM rollover for time-series."},
  {id:"qes2docvalues", topic:"Elasticsearch", diff:"tricky", level:"Staff", type:"single",
    q:"Enabling fielddata on a text field so you can sort/aggregate on it risks what?",
    options:["Nothing — fielddata is the recommended way to aggregate text","Loading all of that field's terms into JVM heap, which can OOM the node; use a keyword field with doc_values instead","Permanently corrupting the inverted index","Disabling search on the rest of the index"],
    correct:[1],
    why:"Sorting/aggregating needs a columnar view. Non-text fields use doc_values (on-disk, off-heap, default on). Text fields disable fielddata by default because building it loads every term into heap — on a big field that OOMs the node. The fix is almost never 'enable fielddata' but 'aggregate on the keyword sub-field', which has doc_values.",
    more:"This is the heap-blowup trap behind text-vs-keyword: doc_values are cheap and on-disk; fielddata is expensive and on-heap."},
  {id:"qr2types", topic:"Redis", diff:"basic", level:"Mid", type:"single",
    q:"A candidate treats Redis as 'just a string key-value cache'. What are they missing?",
    options:["Nothing; Redis only stores opaque string values","Rich server-side data types — hashes, lists, sets, sorted sets, bitmaps, HyperLogLog, geo, streams — each with atomic ops, so you model the structure in Redis, not the app","Redis can only store integers and counters","All non-string types require a paid Redis module"],
    correct:[1],
    why:"Redis's power is native data structures with atomic O(1)/O(log n) operations: hashes for objects, lists for queues, sets for membership, sorted sets for leaderboards/ranges, bitmaps and HyperLogLog for compact counting, geo for proximity, streams for logs. Choosing the right type (and avoiding O(N) ops on huge ones) is the real skill.",
    more:"The structure shapes complexity — e.g. a sorted set gives O(log n) ranked inserts and O(log n + k) range reads a plain string can't."},
  {id:"qr2scan", topic:"Redis", diff:"tricky", level:"Senior", type:"single",
    q:"Why is KEYS pattern* dangerous in production, and what do you use instead?",
    options:["KEYS is fine; it's fully indexed and instant","KEYS is O(N) over the whole keyspace and blocks the single thread, stalling every other client; use SCAN, a non-blocking incremental cursor","KEYS only works on a replica, never the primary","KEYS silently returns at most 10 keys, so it's useless"],
    correct:[1],
    why:"KEYS scans the entire keyspace in one shot — O(N) — and because Redis executes commands single-threaded, it freezes all other clients for the duration. SCAN returns keys in small batches via a cursor, never blocking, at the cost of weaker snapshot guarantees (keys may be missed or duplicated across a resize).",
    more:"Same single-thread hazard as SMEMBERS/HGETALL on a huge collection or a big SORT — prefer the cursor variants (SSCAN/HSCAN) and bounded ops."},
  {id:"qr2pipeline", topic:"Redis", diff:"tricky", level:"Senior", type:"single",
    q:"An app makes 1,000 sequential Redis GETs and is slow despite Redis being fast. Best fix?",
    options:["Add more replicas so reads spread out","Pipeline the commands — send them in one batch without waiting for each reply — collapsing 1,000 round trips into ~1","Switch every GET to a cluster-wide broadcast","Raise the client's socket timeout"],
    correct:[1],
    why:"The bottleneck is network round-trip time, not Redis: 1,000 serial commands pay 1,000 RTTs. Pipelining streams many commands before reading replies, so latency drops to roughly one RTT plus server time (MGET also helps for plain GETs). Pipelining is not transactional — use MULTI/EXEC or Lua if you need atomicity.",
    more:"In Redis Cluster the pipelined keys must be routed per node/slot, so client libraries split a pipeline by slot."},
  {id:"qr2persist", topic:"Redis", diff:"tricky", level:"Senior", type:"single",
    q:"For a Redis instance that must minimize data loss on crash, which persistence setup and trade-off?",
    options:["RDB snapshots every few minutes — lowest possible loss","AOF with appendfsync everysec (~1s worst-case loss), optionally hybrid RDB+AOF for fast restart; RDB alone can lose minutes","Disable persistence; replication alone guarantees durability","appendfsync always, with no downside"],
    correct:[1],
    why:"RDB takes point-in-time snapshots (compact, fast restart) but loses everything since the last snapshot on a crash. AOF logs every write: appendfsync everysec (common default) caps loss at ~1s, while always loses nothing but is much slower. Modern Redis can combine them (RDB preamble + AOF tail) for fast restart and a small loss window.",
    more:"Persistence is local durability; it doesn't replace replication/failover — and async replication can still drop the last acked writes on promotion."},
  {id:"qr2sentinel", topic:"Redis", diff:"tricky", level:"Senior", type:"single",
    q:"What's the difference between Redis Sentinel and Redis Cluster?",
    options:["They're the same product under two names","Sentinel gives HA for a single master (monitoring + automatic failover, no sharding); Cluster shards data across many masters via 16384 slots and also fails over","Sentinel shards data; Cluster only does backups","Cluster is single-node; Sentinel is multi-node"],
    correct:[1],
    why:"Sentinel monitors a master+replicas, detects failure, and promotes a replica automatically — high availability for one dataset that still fits on one node (no horizontal scaling). Cluster partitions the keyspace across multiple masters (16384 hash slots), giving sharding for scale plus per-shard failover. Pick Sentinel when you need HA but not sharding.",
    more:"Cluster restricts multi-key ops to one slot (hence hash tags); Sentinel keeps full single-node semantics, simpler if your data fits."},
  {id:"qr2zsetuses", topic:"Redis", diff:"tricky", level:"Senior", type:"multi",
    q:"Which problems is a Redis sorted set (ZSET) a great fit for? (select all)",
    options:["A real-time leaderboard ranked by score","A sliding-window rate limiter keyed on request timestamps","A delayed/scheduled job queue ordered by execute-at time","Storing a 50MB binary blob for fast retrieval"],
    correct:[0,1,2],
    why:"A ZSET orders members by score with O(log n) insert and O(log n + k) range reads: leaderboards (ZADD/ZREVRANGE), sliding-window rate limiting (score = timestamp, ZREMRANGEBYSCORE to drop old entries, ZCARD to count), and delayed queues (score = run-at, poll with ZRANGEBYSCORE). Large blobs belong in object storage, never in any Redis value.",
    more:"The sliding-window limiter is more accurate than fixed-window counters but uses more memory — one entry per request in the window."},
  {id:"qr2bigkey", topic:"Redis", diff:"tricky", level:"Staff", type:"single",
    q:"One Redis key holds a hash with 10 million fields and the instance suffers latency spikes. Why, and the fix?",
    options:["Redis caps hashes at 1M fields, so writes silently fail","A 'big key' makes O(N) ops (HGETALL, DEL, slot migration) block the single thread and skews memory/slot load; shard the value across many keys","Big keys are fine; the spikes must be a network issue","Convert the hash to a string to remove the limit"],
    correct:[1],
    why:"A single huge collection is a 'big key': any O(N) command on it (HGETALL, a big DEL, or slot migration in Cluster) monopolizes the single thread and stalls everyone, and since a key maps to one slot it can't spread across nodes — creating a hot, unbalanced shard. Split it into many smaller keys (bucket by sub-id) and use HSCAN / UNLINK.",
    more:"UNLINK frees big keys asynchronously instead of blocking like DEL; the deeper fix is modeling so no single key grows unbounded."},
  {id:"qk2partcount", topic:"Kafka vs Queues", diff:"tricky", level:"Senior", type:"single",
    q:"What's the best practice and the gotcha when choosing a topic's partition count?",
    options:["Pick any number; you can freely raise or lower it later with no effect","Partitions cap consumer parallelism and throughput, but you can only INCREASE them — and increasing changes hash(key) mod n, breaking per-key ordering/co-location for existing keys","Always use exactly one partition for correctness","More partitions are always strictly better, with no overhead"],
    correct:[1],
    why:"Partition count caps how many consumers in a group can work in parallel (extra consumers idle) and drives throughput, so size it for peak. But you can only add partitions, never remove them, and adding them changes the hash(key) mod partitions mapping, so a given key can move to a new partition — breaking ordering and any 'same key, same partition' assumption for already-produced data.",
    more:"Over-partitioning has real cost: more open files, memory, replication, longer leader elections, and higher end-to-end latency — don't just crank it to thousands."},
  {id:"qk2order", topic:"Kafka vs Queues", diff:"basic", level:"Senior", type:"single",
    q:"What ordering does Kafka actually guarantee?",
    options:["Total global order across the whole topic","Order only within a single partition; across partitions there's no global order","Order only if there's exactly one consumer","Producer-timestamp order, regardless of partition"],
    correct:[1],
    why:"Kafka preserves order only within a partition (the append-only log). To keep events for one entity ordered, give them the same partition key (e.g. user_id) so they land in the same partition. There's no cross-partition ordering — the price of partition-level parallelism.",
    more:"With retries a producer can even reorder within a partition unless max.in.flight is bounded or the idempotent producer is enabled — a subtle ordering gotcha."},
  {id:"qk2rebalance", topic:"Kafka vs Queues", diff:"tricky", level:"Staff", type:"single",
    q:"Why can consumer-group rebalances hurt, and what reduces the pain?",
    options:["Rebalances never affect throughput","Eager rebalancing is stop-the-world (all consumers revoke all partitions, then reassign), pausing consumption; cooperative/incremental rebalancing only moves the changed partitions","Rebalancing permanently duplicates every message","You avoid rebalances by deleting the consumer group"],
    correct:[1],
    why:"When a consumer joins/leaves or partitions change, the group rebalances. Classic eager rebalancing has every consumer give up all partitions and stop while the group reassigns — a stop-the-world pause. Cooperative (incremental) rebalancing revokes only the partitions that actually move, so most consumers keep working. Frequent rebalances often mean slow processing tripping max.poll.interval.ms.",
    more:"Tune session.timeout/heartbeat and use the cooperative-sticky assignor; a consumer that can't poll in time is evicted, triggering yet another rebalance."},
  {id:"qk2lag", topic:"Kafka vs Queues", diff:"basic", level:"Senior", type:"single",
    q:"Your Kafka consumers are falling behind producers. What do you watch, and how do you scale?",
    options:["Watch disk usage; add brokers","Watch consumer lag (log-end-offset minus committed offset); add consumers up to the partition count, then add partitions","Watch CPU only; restart the cluster","Lag isn't measurable in Kafka"],
    correct:[1],
    why:"Consumer lag — the gap between the latest offset and what the group has committed — is the headline health signal. Scale by adding consumers in the group, but only up to the number of partitions (extra consumers sit idle), so persistent lag at max parallelism means adding partitions or speeding up per-message work.",
    more:"Growing lag with idle consumers = too few partitions; growing lag with all consumers busy = processing is the bottleneck (batch, parallelize, or offload)."},
  {id:"qk2offset", topic:"Kafka vs Queues", diff:"tricky", level:"Senior", type:"single",
    q:"With enable.auto.commit=true, a consumer crashes mid-processing. What can go wrong?",
    options:["Nothing; auto-commit guarantees exactly-once","Offsets may be committed before the work finishes, so the crashed messages are skipped (loss); committing after processing gives at-least-once instead","Auto-commit replays the entire topic from the start","Auto-commit blocks the producer until the consumer catches up"],
    correct:[1],
    why:"Auto-commit periodically commits the latest polled offsets on a timer, which can mark messages done before you've actually processed them — so a crash loses that in-flight work (effectively at-most-once). For at-least-once, disable auto-commit and commit offsets only AFTER processing succeeds, then make handlers idempotent to absorb the resulting duplicates.",
    more:"Commit-after-processing + idempotent consumer is the standard at-least-once recipe; committing before processing is the classic message-loss bug."},
  {id:"qk2retention", topic:"Kafka vs Queues", diff:"basic", level:"Senior", type:"single",
    q:"How does Kafka let a brand-new service reprocess last week's events?",
    options:["It can't; consumed messages are deleted immediately","Messages are retained by time/size (retention.ms/bytes), so a consumer can reset its offset (e.g. to-earliest) and replay the log","You must restore the events from a database backup","Only the last message per key is ever kept"],
    correct:[1],
    why:"Kafka keeps messages for a configured retention window independent of consumption, so any consumer group can move its offset back (to-earliest, to a timestamp) and replay history — the core advantage of a log over a delete-on-ack queue. (Log compaction is a separate mode that keeps the latest value per key indefinitely.)",
    more:"This replayability is why Kafka suits event sourcing and bootstrapping new consumers/materialized views from the existing log."},
  {id:"qk2unclean", topic:"Kafka vs Queues", diff:"tricky", level:"Staff", type:"single",
    q:"All in-sync replicas for a partition die. With unclean.leader.election.enable, what's the trade-off?",
    options:["There's no choice to make; Kafka always stays available","Enable=true elects a stale out-of-sync replica as leader (available but loses unreplicated writes); false keeps the partition offline until an ISR returns (consistent but unavailable)","Enable=true guarantees zero data loss","The partition is permanently lost either way"],
    correct:[1],
    why:"This is a CAP-style knob. unclean.leader.election.enable=true lets a lagging, out-of-sync replica become leader so the partition stays available — at the cost of dropping writes it never received. false (the safe default) refuses to elect a stale replica, keeping the partition unavailable until a caught-up replica returns. Durability-critical systems keep it false.",
    more:"It pairs with replication.factor and min.insync.replicas: RF=3 + min.insync=2 + acks=all + unclean=false is the standard durable configuration."},
  {id:"qk2prodtune", topic:"Kafka vs Queues", diff:"tricky", level:"Senior", type:"single",
    q:"Which producer settings raise throughput for a high-volume Kafka pipeline?",
    options:["Smaller batch.size and linger.ms=0 to send each record instantly","Larger batch.size with a small linger.ms to batch records, plus compression (lz4/zstd)","acks=0 with no batching","One producer instance per record"],
    correct:[1],
    why:"Throughput comes from batching: linger.ms lets the producer wait a few ms to fill a batch.size buffer, and compression (lz4/zstd/snappy/gzip) shrinks bytes on the wire and disk — together they amortize per-request overhead massively, at the cost of a little latency. acks/idempotence govern durability separately.",
    more:"linger.ms=0 minimizes latency but wastes throughput; the batch/linger/compression trio is the main producer tuning lever."},
  {id:"qk2kraft", topic:"Kafka vs Queues", diff:"basic", level:"Senior", type:"single",
    q:"What changed about Kafka's dependency on ZooKeeper?",
    options:["Kafka still requires ZooKeeper for all metadata","Kafka moved to KRaft (self-managed Raft-based metadata quorum); ZooKeeper is removed in Kafka 4.0","Kafka now depends on etcd instead","Kafka never used ZooKeeper"],
    correct:[1],
    why:"Historically Kafka used ZooKeeper for cluster metadata, controller election, and ACLs. KRaft moves that into Kafka itself via an internal Raft metadata log run by controller nodes — simpler ops, faster failover, and far higher partition scalability. KRaft is production-ready since 3.3 and ZooKeeper mode is removed in 4.0.",
    more:"Fewer moving parts and no separate ZK ensemble to size/secure; metadata changes propagate as a log the brokers replicate."},
  {id:"qk2dlq", topic:"Kafka vs Queues", diff:"tricky", level:"Senior", type:"single",
    q:"A Kafka consumer keeps hitting a 'poison' message it can't process, blocking the partition. With classic consumer groups, what's the pattern?",
    options:["Kafka auto-moves it to a built-in dead-letter queue","Catch the failure and produce the message to a retry topic (with backoff); after N attempts route it to a dead-letter topic, so the main partition keeps flowing","Skip offset commits so the partition pauses until a human intervenes","Delete the partition and recreate it"],
    correct:[1],
    why:"Classic Kafka has no native retry/DLQ, and because order is per-partition, blocking on a bad message stalls everything behind it. The pattern is to produce failures to a separate retry topic (often tiered by delay) and, after a retry budget, to a dead-letter topic for later inspection — keeping the main consumer moving. SQS gives this out of the box.",
    more:"Kafka 4.x share groups (KIP-932) add broker-side redelivery/DLQ-like semantics, narrowing this long-standing gap."},
  {id:"qcx01", topic:"Cassandra", diff:"basic", level:"Mid", type:"single",
    q:"What does Cassandra's default Murmur3 partitioner produce from a partition key?",
    options:["A 64-bit token mapping the key to a position on the hash ring","A B-tree index entry pointing at the row's exact on-disk location","An auto-increment sequence number assigned by the request coordinator","A range bucket chosen from the alphabetical order of the key value"],
    correct:[0],
    why:"Murmur3Partitioner hashes the partition key to a 64-bit token; the node owning that token range on the ring stores the data. It is consistent hashing, not range or modulo placement.", more:"Murmur3 replaced the old MD5-based RandomPartitioner because it is faster and gives an even token distribution."},
  {id:"qcx02", topic:"Cassandra", diff:"tricky", level:"Senior", type:"single",
    q:"Two different partition keys hash to nearly the same Murmur3 token. What is the consequence?",
    options:["Cassandra rejects the second write to avoid a hard token collision","Their rows co-locate on one node but stay in separate independent partitions","The two rows merge into one partition sharing a single clustering order","A read of either key must scan both partitions on disk to disambiguate"],
    correct:[1],
    why:"Tokens only decide which node/range owns the data. Distinct partition keys remain distinct partitions even if adjacent on the ring; they are stored and read independently. There is no merging or collision rejection.", accept:"The rows likely co-locate on one node, but that is incidental — the load-bearing fact is the partitions stay separate."},
  {id:"qcx03", topic:"Cassandra", diff:"tricky", level:"Senior", type:"single",
    q:"Why do virtual nodes (num_tokens > 1) make adding a new physical node less disruptive?",
    options:["Each node owns many small ranges, so a joiner pulls a thin slice from many peers at once","Vnodes let the joiner take over one large contiguous range from a single adjacent neighbor","Vnodes disable the partitioner so an operator can assign keys to any node by hand","Vnodes replicate every partition onto every node, so no data has to move on a join"],
    correct:[0],
    why:"With many small ranges per node, bootstrapping a new node streams a little data from many existing nodes concurrently, spreading the load and speeding rebalance — versus one node handing off a huge contiguous range.", more:"Modern Cassandra often lowers num_tokens (e.g. 16 with allocate_tokens_for_keyspace) to balance even distribution against repair/streaming overhead from too many ranges."},
  {id:"qcx04", topic:"Cassandra", diff:"basic", level:"Mid", type:"single",
    q:"What problem do virtual nodes (vnodes) primarily solve compared with one-token-per-node?",
    options:["They remove the need to configure a replication factor per keyspace","They provide strong consistency for reads without ever needing QUORUM","They make membership changes rebalance evenly without manual token assignment","They eliminate tombstones so that deletes take effect on disk immediately"],
    correct:[2],
    why:"Single-token rings required hand-picking tokens and rebalanced unevenly. Vnodes auto-assign many ranges per node so load and the cost of join/leave spread evenly across the cluster.", accept:"Vnodes do help with even rebalancing — the other options name unrelated mechanisms (RF, QUORUM, tombstones)."},
  {id:"qcx05", topic:"Cassandra", diff:"tricky", level:"Senior", type:"single",
    q:"Why is NetworkTopologyStrategy preferred over SimpleStrategy for a production multi-rack cluster?",
    options:["It compresses each rack's SSTables independently to cut total disk usage","It places replicas in distinct racks/DCs so one rack or DC loss keeps a copy","It raises the keyspace replication factor automatically as the cluster grows","It routes every read to the physically closest replica regardless of the CL"],
    correct:[1],
    why:"NetworkTopologyStrategy is topology-aware: it walks the ring placing each replica in a different rack (and lets you set RF per datacenter), so a rack/DC outage cannot wipe out every replica of a partition. SimpleStrategy ignores topology.", more:"It relies on the snitch to know which rack/DC each node is in."},
  {id:"qcx06", topic:"Cassandra", diff:"basic", level:"Mid", type:"single",
    q:"What is the role of the snitch in a Cassandra cluster?",
    options:["It maps each node to its datacenter and rack so replicas are placed sensibly","It detects failed nodes via heartbeats and removes them from the ring for good","It runs background compaction across SSTables to reclaim space from tombstones","It computes and assigns each node its Murmur3 token ranges during bootstrap"],
    correct:[0],
    why:"The snitch maps nodes to datacenters and racks. NetworkTopologyStrategy uses it for rack-aware replica placement, and the driver/coordinator uses proximity info for routing reads.", accept:"Failure detection is gossip's job; token assignment is the partitioner's — the snitch is purely about topology."},
  {id:"qcx07", topic:"Cassandra", diff:"tricky", level:"Senior", type:"single",
    q:"With NetworkTopologyStrategy and RF set as {DC1:3, DC2:3}, how many total replicas of each partition exist?",
    options:["3 total, with DC2 holding a read-only mirror of DC1's copies","6 total — three independent full copies kept in each datacenter","3 total, striped across the two datacenters combined as one set","It depends on num_tokens per node, not on the replication factor"],
    correct:[1],
    why:"RF is declared per datacenter. {DC1:3, DC2:3} means three full replicas in DC1 and three in DC2 — six copies total — so each DC can satisfy LOCAL_QUORUM on its own.", more:"This is why multi-DC Cassandra is common for low-latency local reads plus disaster recovery."},
  {id:"qcx08", topic:"Cassandra", diff:"basic", level:"Mid", type:"single",
    q:"What does consistency level ONE mean for a write?",
    options:["The write must be acknowledged by one specific designated leader replica","The coordinator returns success once any single replica acknowledges the write","Only one replica ever stores the data and the remaining replicas are skipped","The write applies in one datacenter and is lazily copied to all the others"],
    correct:[1],
    why:"CL=ONE returns as soon as one of the RF replicas acks. The write is still sent to all replicas (and hints cover any that are down) — only the acknowledgement count required is one.", accept:"All replicas still receive the write; ONE only sets how many acks the coordinator waits for."},
  {id:"qcx09", topic:"Cassandra", diff:"tricky", level:"Senior", type:"single",
    q:"In a {DC1:3, DC2:3} cluster, what does LOCAL_QUORUM require?",
    options:["A majority of the replicas in the coordinator's local datacenter only","A majority taken across all six replicas spanning both of the datacenters","At least one acknowledging replica in each of the two datacenters","All three of the replicas located in the coordinator's local datacenter"],
    correct:[0],
    why:"LOCAL_QUORUM = majority of replicas in the local DC (here 2 of 3). It avoids cross-DC latency while still giving local strong consistency, which is why it is the workhorse for multi-DC deployments.", more:"EACH_QUORUM, by contrast, requires a quorum in every DC and pays full cross-DC latency."},
  {id:"qcx10", topic:"Cassandra", diff:"tricky", level:"Staff", type:"single",
    q:"A multi-DC app uses LOCAL_QUORUM for both reads and writes. A client writes in DC1, then immediately reads the same key in DC2. What can it observe?",
    options:["Always the latest value, since LOCAL_QUORUM is a globally strong level","Possibly a stale value, since the two LOCAL_QUORUM sets sit in different DCs and need not overlap","An error returned by the coordinator, since cross-DC reads are forbidden under LOCAL_QUORUM","The latest value, but only once gc_grace_seconds has elapsed for that row"],
    correct:[1],
    why:"R+W>RF only guarantees overlap when both quorums are drawn from the same replica set. A write quorum in DC1 and a read quorum in DC2 are disjoint, so the DC2 read can miss the write until async cross-DC replication catches up.", more:"If you need read-your-write across DCs you must use EACH_QUORUM (or route the read to the writing DC) — a classic multi-DC consistency gotcha."},
  {id:"qcx11", topic:"Cassandra", diff:"tricky", level:"Mid", type:"single",
    q:"Reads use CL=ONE and writes use CL=ONE with RF=3. What consistency does the client get?",
    options:["Strong consistency, since all three replicas eventually converge anyway","Eventual consistency — a read may hit a replica that has not yet seen the write","Read-your-writes, since the coordinator caches its own recent writes briefly","Linearizable reads, since CL=ONE always picks the single freshest replica"],
    correct:[1],
    why:"With R=1 and W=1, R+W=2 which is not greater than RF=3, so the read and write sets can be disjoint. The read may land on a replica that hasn't seen the write yet — eventual consistency.", accept:"Replicas do converge eventually via hinted handoff/read repair, but at the moment of the read staleness is possible."},
  {id:"qcx12", topic:"Cassandra", diff:"tricky", level:"Senior", type:"single",
    q:"With RF=5, which read/write consistency pair gives strong consistency at the lowest total replica contact?",
    options:["Write at ALL, read at ONE","Write at THREE, read at THREE","Write at TWO, read at THREE","Write at ONE, read at ALL"],
    correct:[1],
    why:"Strong consistency needs R+W>RF, i.e. R+W>5. W=2,R=3 sums to 5 — that is NOT greater than 5, so it fails. W=3,R=3 sums to 6>5 and touches 6 replicas; ALL/ONE pairs touch 6 too but force one operation to wait on all 5. W=3/R=3 is the balanced strong choice.", accept:"WRITE TWO / READ THREE (option 3) is the trap: 2+3=5 is not strictly greater than RF=5, so it does NOT guarantee overlap.", more:"ALL on either side maximizes latency and availability risk; balancing R and W keeps both operations tolerant of node loss while satisfying R+W>RF."},
  {id:"qcx13", topic:"Cassandra", diff:"tricky", level:"Senior", type:"single",
    q:"During a QUORUM read, the coordinator finds two replicas disagree on the value. What is blocking read repair?",
    options:["It drops the read and transparently retries on a fresh set of replicas","It reconciles by timestamp and pushes the newest value to the stale replica before returning","It returns both conflicting values and lets the client decide which one to keep","It schedules a full nodetool repair across the whole partition before answering"],
    correct:[1],
    why:"Blocking (foreground) read repair: when replicas in the read set disagree, the coordinator picks the latest by write timestamp, writes it back to the out-of-date replica, and only then returns the consistent value to the client.", more:"Background read repair (read_repair_chance) was an older, probabilistic best-effort mechanism; modern Cassandra repairs synchronously on mismatch within the read's consistency set."},
  {id:"qcx14", topic:"Cassandra", diff:"tricky", level:"Staff", type:"multi",
    q:"Which statements about read repair are accurate? (select all)",
    options:["It only reconciles the replicas that participated in the current read request","On its own it keeps every replica consistent, so anti-entropy repair is unnecessary","It uses each cell's write timestamp to decide which conflicting value is newest","It can write the latest value back to a lagging replica before returning to the client"],
    correct:[0,2,3],
    why:"Read repair fixes only the replicas touched by a given read, decides freshness by timestamp, and (when blocking) writes back the winner first. It does NOT cover data never read, so periodic anti-entropy (nodetool repair) is still required.", more:"Rarely-read but written data can drift indefinitely without scheduled repairs — read repair alone leaves cold data inconsistent."},
  {id:"qcx15", topic:"Cassandra", diff:"basic", level:"Mid", type:"single",
    q:"A replica is down when a write arrives. What does hinted handoff do?",
    options:["It rejects the incoming write outright until the down replica has returned","The coordinator stores a hint and replays the write to the replica once it returns","It permanently re-replicates the whole partition onto a different live node","It converts the write into a tombstone to be reconciled by the next repair"],
    correct:[1],
    why:"The coordinator records a hint for the unavailable replica and, when that replica rejoins within the hint window, replays the missed mutations to it — improving availability and helping replicas catch up without a full repair.", more:"Hints expire after max_hint_window_ms (default 3 hours); a replica down longer needs anti-entropy repair to converge."},
  {id:"qcx16", topic:"Cassandra", diff:"tricky", level:"Staff", type:"single",
    q:"Does a stored hint count toward satisfying the write's consistency level?",
    options:["Yes, a stored hint counts as an acknowledgement from the down replica","No — a hint is not an ack, so a QUORUM write can still fail if too many replicas are down","Yes, but a hint only counts toward the CL when the level is exactly ONE","It counts only when hinted handoff has been disabled for that keyspace"],
    correct:[1],
    why:"Hints are a best-effort catch-up mechanism, not an acknowledgement. If enough replicas are down that the live ones can't meet the requested CL, the write fails with Unavailable even though hints would be stored for the missing replicas.", more:"This is why people sometimes mistakenly think hints 'satisfy' QUORUM — they don't; they only help convergence afterward."},
  {id:"qcx17", topic:"Cassandra", diff:"tricky", level:"Senior", type:"single",
    q:"How does nodetool repair (anti-entropy) efficiently find differences between replicas?",
    options:["It streams every SSTable in full between the replicas and diffs them byte by byte","Replicas build Merkle hash trees and compare them, streaming only the ranges that differ","It replays each replica's commit log against the others to surface missing writes","It re-reads every partition at CL=ALL to force read repair across the whole keyspace"],
    correct:[1],
    why:"Each replica computes a Merkle (hash) tree over its token ranges; replicas exchange and compare trees, so only the sub-ranges whose hashes differ are streamed. This avoids shipping identical data.", more:"Repair is expensive (CPU for hashing, network for streaming), so it's scheduled off-peak and often run incrementally."},
  {id:"qcx18", topic:"Cassandra", diff:"tricky", level:"Staff", type:"single",
    q:"What does incremental repair change versus full repair?",
    options:["It repairs only one datacenter at a time to limit the cross-DC network cost","It marks already-repaired SSTables so later repairs only hash and stream un-repaired data","It skips building Merkle trees entirely and reconciles replicas by cell timestamp instead","It runs continuously as a background task that needs no scheduled operator action"],
    correct:[1],
    why:"Incremental repair separates repaired from un-repaired SSTables; once a range is repaired it is marked, so subsequent runs only validate and stream newly written (un-repaired) data — drastically less work on large datasets.", more:"Incremental repair has historically had correctness pitfalls (anti-compaction, sstable marking bugs); some operators still prefer full repair or tools like Reaper."},
  {id:"qcx19", topic:"Cassandra", diff:"basic", level:"Mid", type:"single",
    q:"What is the coordinator node for a given request?",
    options:["A permanently elected master node that owns every write for the whole cluster","Whichever node the client connected to for that request; it routes to the replicas","The single node that physically owns the first replica of the target partition","A dedicated stateless proxy tier sitting in front of the data-storage nodes"],
    correct:[1],
    why:"Any node can coordinate. The node the client contacts for a request becomes that request's coordinator, forwarding to the replica set and applying the consistency level. There is no fixed master.", accept:"Token-aware drivers often pick a replica as the coordinator to save a hop, but any node can fill the role per-request."},
  {id:"qcx20", topic:"Cassandra", diff:"basic", level:"Mid", type:"single",
    q:"What is the correct order of a Cassandra write on a replica?",
    options:["Memtable first, then the commit log, then flushed out to an SSTable","Commit log append, then the Memtable, then flushed to an immutable SSTable","Straight to a new SSTable on disk, then later indexed into the Memtable","Commit log, then an SSTable on disk, then cached back into the Memtable"],
    correct:[1],
    why:"The mutation is appended to the commit log (durability/WAL) and applied to the in-memory Memtable; when the Memtable fills it is flushed to a new immutable SSTable on disk. The commit log makes the write recoverable before flush.", accept:"Commit log and Memtable are effectively concurrent, but the durable append precedes acknowledging — SSTable flush happens later."},
  {id:"qcx21", topic:"Cassandra", diff:"tricky", level:"Senior", type:"single",
    q:"Why is the Cassandra write path so fast even though it persists durably?",
    options:["It scatters each write randomly across the disk to spread out device wear","It does a sequential commit-log append plus an in-memory update — no read-before-write","It updates the matching B-tree page in place, which is just a single disk seek","It skips the commit log entirely and leans on replication alone for durability"],
    correct:[1],
    why:"An LSM write is a sequential commit-log append and a memory write. There's no random in-place update and (for non-LWT writes) no read of existing data, so throughput is high and latency low.", more:"The cost is paid at read/compaction time, where multiple SSTables may have to be merged."},
  {id:"qcx22", topic:"Cassandra", diff:"basic", level:"Mid", type:"single",
    q:"What is 'write amplification' in an LSM-tree store like Cassandra?",
    options:["Replication copying each client write out to the RF replicas across the ring","The same data being rewritten repeatedly as compaction merges SSTables over time","A single logical write fanning out into many separate tombstone markers on disk","The commit log keeping a duplicate of every entry already held in the Memtable"],
    correct:[1],
    why:"Because SSTables are immutable, data gets rewritten each time compaction merges the SSTables it lives in. A row may be physically rewritten several times before it stops changing — that repeated rewriting is write amplification.", more:"Leveled compaction trades higher write amplification for lower read amplification; size-tiered does the opposite."},
  {id:"qcx23", topic:"Cassandra", diff:"tricky", level:"Senior", type:"single",
    q:"A read-heavy table needs predictable low read latency and can tolerate more write/compaction work. Which compaction strategy fits best?",
    options:["SizeTieredCompactionStrategy (STCS)","LeveledCompactionStrategy (LCS)","TimeWindowCompactionStrategy (TWCS)","DateTieredCompactionStrategy (DTCS)"],
    correct:[1],
    why:"LCS keeps SSTables in size levels so a partition's data spans few SSTables, bounding the number a read must merge (good read latency) — at the cost of more compaction (write amplification). STCS can leave a key spread across many SSTables.", accept:"STCS is the default and is fine for write-heavy or balanced tables; the question's read-latency priority is exactly LCS's niche."},
  {id:"qcx24", topic:"Cassandra", diff:"tricky", level:"Senior", type:"single",
    q:"Why is SizeTieredCompactionStrategy (STCS) the default, and what is its main read-side downside?",
    options:["It minimizes total disk usage, but it can never actually purge old tombstones","It is cheap on writes but a row's data can spread across many SSTables, hurting reads","It guarantees exactly one SSTable per partition, but it doubles write amplification","It is mandatory for counter tables, but it forces bloom filters to be disabled"],
    correct:[1],
    why:"STCS compacts SSTables of similar size together, which is write-efficient. But updates to a key over time can land in many size tiers, so a read may merge many SSTables — higher read amplification, and free-space spikes during big compactions.", more:"It also needs roughly as much free disk as the largest compaction bucket to run."},
  {id:"qcx25", topic:"Cassandra", diff:"tricky", level:"Staff", type:"single",
    q:"Why is TimeWindowCompactionStrategy (TWCS) ideal for time-series data with TTLs?",
    options:["It compacts freely across all time so old and new rows end up sharing SSTables","It buckets data into time-window SSTables, so whole expired windows drop cheaply on TTL","It rewrites every SSTable in the table each night purely to re-enforce row ordering","It pins the newest data permanently in memory to make recent-window reads faster"],
    correct:[1],
    why:"TWCS buckets SSTables by write-time window and avoids compacting across windows. When an entire window's data expires (TTL), the SSTable is dropped wholesale without merging — minimal compaction and no tombstone scanning for aged-out data.", more:"Anti-pattern with TWCS: out-of-order or updated old data, and explicit deletes, defeat the whole-SSTable-drop optimization."},
  {id:"qcx26", topic:"Cassandra", diff:"tricky", level:"Senior", type:"single",
    q:"What is the default gc_grace_seconds and why does Cassandra wait that long before purging tombstones?",
    options:["3600 seconds, to give the commit log time to flush its segments to disk","864000 seconds (10 days), to let the delete reach all replicas before dropping it","0 seconds, so each delete is purged immediately at the very next compaction","86400 seconds (1 day), purely to bound the disk space consumed by markers"],
    correct:[1],
    why:"gc_grace_seconds defaults to 864000s (10 days). The tombstone must outlive the window in which a down replica could still resurrect the deleted data, so it is kept until the delete has had time to reach every replica (typically via repair).", more:"If you purge tombstones before a lagging replica learns of the delete, that replica re-propagates the old value — a zombie."},
  {id:"qcx27", topic:"Cassandra", diff:"tricky", level:"Staff", type:"single",
    q:"An operator runs repair only every 14 days while gc_grace_seconds is 10 days. What is the risk?",
    options:["Disk fills up over time because the accumulated tombstones are never purged","Deleted data can resurrect because a tombstone may be purged before repair delivers the delete to a lagging replica","Reads gradually slow down because gc_grace blocks compaction from running at all","Writes start failing because the commit log can no longer rotate its segments"],
    correct:[1],
    why:"Tombstones are dropped after gc_grace_seconds. If repair runs less often than gc_grace, a replica that missed the delete may never receive the tombstone before it's purged elsewhere, then re-replicates the old value — a resurrected (zombie) row.", more:"Rule of thumb: run repair more frequently than gc_grace_seconds (e.g. weekly for the 10-day default)."},
  {id:"qcx28", topic:"Cassandra", diff:"tricky", level:"Staff", type:"single",
    q:"A SELECT over a partition fails with TombstoneOverwhelmingException. What threshold tripped, and why does scanning tombstones matter?",
    options:["tombstone_failure_threshold (default 100000) — the read must materialize and skip every tombstone, so too many abort it","The hard 2-billion-cell-per-partition limit was exceeded by this partition's live cells alone","gc_grace_seconds elapsed for the partition, which forces any in-flight read of it to fail","The SSTable bloom filter's false-positive rate climbed above its configured ceiling"],
    correct:[0],
    why:"A read collects tombstones in the scanned range to know which data is deleted. Past tombstone_warn_threshold (1000) it logs warnings; past tombstone_failure_threshold (100000) it aborts with TombstoneOverwhelmingException — protecting the node from a tombstone-flooded read.", more:"Common with queue-like or frequently-deleted/overwritten-with-null patterns; the fix is a data-model change, not raising the threshold."},
  {id:"qcx29", topic:"Cassandra", diff:"tricky", level:"Senior", type:"single",
    q:"Which operation creates tombstones that engineers often overlook?",
    options:["Reading a row at consistency level ALL across all of its replicas","Inserting NULL into a column, or overwriting a whole list/set/map collection","Running nodetool repair over the token range that holds the partition","Flushing a full Memtable out to a new immutable SSTable on disk"],
    correct:[1],
    why:"Writing NULL is a delete (tombstone), and updating a non-frozen collection often inserts a range tombstone to clear the old elements before adding new ones. Bulk collection updates can silently generate many tombstones.", more:"Prefer not writing columns you mean to leave unset, and be cautious with frequent full-collection overwrites."},
  {id:"qcx30", topic:"Cassandra", diff:"basic", level:"Mid", type:"single",
    q:"On a read, what does the bloom filter let a Cassandra node avoid?",
    options:["Replaying the commit log on disk to reconstruct the most recent writes","Touching SSTables that definitely do not contain the requested partition key","Merging tombstones with the surviving live data while serving the read","Contacting any other replicas in order to satisfy the requested consistency level"],
    correct:[1],
    why:"Each SSTable has a bloom filter. A negative answer is definitive ('key not here'), so the node skips that SSTable's index/disk lookups. It can give false positives (occasionally reads an SSTable in vain) but never false negatives.", more:"After the bloom filter, the partition index/summary locates the key's offset within an SSTable that may contain it."},
  {id:"qcx31", topic:"Cassandra", diff:"tricky", level:"Staff", type:"single",
    q:"After the bloom filter says an SSTable might hold the key, how does Cassandra find the row's position on disk?",
    options:["It scans the whole SSTable data file linearly from the very beginning","The partition summary narrows to a region, then the index gives the exact byte offset","It asks the coordinator, which keeps a cache of every key's on-disk offset","It rebuilds a B-tree over the SSTable on the fly to locate the partition"],
    correct:[1],
    why:"The in-memory partition summary is a sparse sample of the on-disk partition index; it points to a small index region, which is read to get the exact byte offset of the partition in the SSTable data file. Key/row caches can short-circuit this.", more:"This summary-to-index-to-data hop is why too many SSTables per read (read amplification) hurts latency."},
  {id:"qcx32", topic:"Cassandra", diff:"tricky", level:"Senior", type:"single",
    q:"Why might a single-row read in Cassandra still have to read several SSTables?",
    options:["Because each of the partition's replicas keeps the row in its own separate SSTable","Because the row's columns may sit across several SSTables that compaction hasn't merged","Because the on-disk commit log has to be consulted on the path of every single read","Because the bloom filter always forces the node to scan all SSTables for the key"],
    correct:[1],
    why:"Updates to a partition over time land in different SSTables (immutability + flushes). Until compaction merges them, a read must reconcile fragments of the same partition across multiple SSTables, picking the latest cell by timestamp.", more:"This read amplification is the LSM trade-off and is what LCS specifically tries to bound."},
  {id:"qcx33", topic:"Cassandra", diff:"tricky", level:"Senior", type:"single",
    q:"Your app must look up users by email AND by user_id. What is the idiomatic Cassandra design?",
    options:["One users table keyed by user_id, plus a native secondary index on the email column","Two tables — users_by_id and users_by_email — each keyed for its query, written on insert","One users table joined against a separate emails lookup table at read time on demand","One users table queried with ALLOW FILTERING on whichever of the two columns you have"],
    correct:[1],
    why:"Query-first modeling: build one table per access pattern, each with the right partition key, and duplicate the row into both on write. Writes are cheap, so two denormalized tables beat a secondary index (which scatters across partitions) or non-existent JOINs.", accept:"A secondary index 'works' for low-cardinality, but for a high-cardinality lookup like email it fans out to all nodes; the dual-table design keeps each read single-partition."},
  {id:"qcx34", topic:"Cassandra", diff:"tricky", level:"Senior", type:"single",
    q:"In PRIMARY KEY ((tenant_id, day), event_time), which part is the partition key?",
    options:["Only tenant_id, with day treated as a clustering column","(tenant_id, day) — the composite in the inner parentheses","Only event_time, because it sets the row order on disk","All three columns combined into one composite partition key"],
    correct:[1],
    why:"The inner parentheses denote a composite partition key: tenant_id AND day together pick the partition. event_time is the clustering column that orders rows within that partition. Both partition-key components are required for an equality lookup.", more:"Without the inner parentheses, only the first column would be the partition key and the rest would be clustering columns."},
  {id:"qcx35", topic:"Cassandra", diff:"basic", level:"Mid", type:"single",
    q:"Which queries can a table with PRIMARY KEY ((user_id), ts) serve efficiently?",
    options:["Filtering by ts across every user in the table at once","Fetching rows for a given user_id, with an optional ts range, in clustering order","Finding the single global maximum ts across all users","Joining users to a separate orders table on user_id"],
    correct:[1],
    why:"Efficient queries must supply the full partition key (user_id) and may then slice/order by the clustering column (ts). Querying by ts alone, finding a global max, or joining are not single-partition operations and are not supported efficiently.", accept:"Querying by ts alone is technically possible with ALLOW FILTERING, but that scans every partition and is an anti-pattern."},
  {id:"qcx36", topic:"Cassandra", diff:"tricky", level:"Senior", type:"single",
    q:"What are the practical guidance limits for a single Cassandra partition?",
    options:["Under ~1 GB and ~10 million rows, with a hard ceiling of 20 billion cells","Under ~100 MB and ~100k rows, with a hard ceiling of ~2 billion cells","No real limit — vnodes let a single partition grow without bound","Under ~10 MB and ~1000 rows, with a hard ceiling of 1 million cells"],
    correct:[1],
    why:"Rule of thumb: keep partitions under ~100 MB and ~100k rows for healthy read/compaction performance; the hard architectural ceiling is ~2 billion cells per partition, but you degrade long before that.", more:"Large partitions cause GC pressure, slow compaction, and read latency spikes — bucket the partition key to bound size."},
  {id:"qcx37", topic:"Cassandra", diff:"tricky", level:"Staff", type:"single",
    q:"All your writes target one partition key (e.g. a global counter keyed by a constant). What is the failure mode?",
    options:["Tombstones build up in that partition and start aborting its reads","A hot partition: one replica set absorbs all the load while the rest sits idle","The cluster-wide bloom-filter false-positive rate spikes for every table","QUORUM can no longer be reached for that one key as the partition grows"],
    correct:[1],
    why:"Cassandra distributes load by partition key. A single hot key sends all traffic to the few nodes owning that token, creating a hotspot and unbounded partition growth while the rest of the cluster is underused.", more:"Fixes: add a sharding/bucketing component to the key (e.g. key % N) to spread the load, then aggregate across buckets on read."},
  {id:"qcx38", topic:"Cassandra", diff:"tricky", level:"Senior", type:"single",
    q:"Why are native secondary indexes usually a poor choice for high-cardinality columns?",
    options:["They are physically incapable of indexing text or large blob columns at all","Each index is local to a node, so a query without the partition key must hit every node","They silently double the replication factor of the base table they belong to","They force the underlying base table to switch to leveled compaction strategy"],
    correct:[1],
    why:"A secondary index is partitioned per node (local), not globally. A lookup that doesn't include the partition key must scatter to all nodes and scatter-gather, which scales poorly — especially for high-cardinality values matching few rows.", more:"Low-cardinality, partition-restricted index queries can be fine; the anti-pattern is using them as a general WHERE-on-any-column substitute."},
  {id:"qcx39", topic:"Cassandra", diff:"tricky", level:"Staff", type:"single",
    q:"What is the main caveat of Cassandra materialized views?",
    options:["They need a periodic JOIN against the base table to stay populated","View consistency with the base table is best-effort and has had bugs, so they're experimental","They can only ever be read at consistency level ALL, never lower","They bypass the commit log, so a crash before flush loses the view"],
    correct:[1],
    why:"Materialized views automate maintaining a base-table-derived view, but keeping the view consistent with the base under failures has proven hard; they've had bugs and are flagged experimental. Many teams hand-maintain a second table via application dual-writes instead.", more:"Manual denormalization gives you control over consistency and repair; MVs hide that complexity but can drift."},
  {id:"qcx40", topic:"Cassandra", diff:"tricky", level:"Staff", type:"single",
    q:"INSERT ... IF NOT EXISTS uses a lightweight transaction. Why is it far costlier than a normal write?",
    options:["It synchronously writes the row to every single replica at consistency level ALL","It runs a Paxos round (several extra round-trips) to make the conditional check linearizable","It rebuilds the bloom filter for the whole partition before applying the write","It takes out a global cluster-wide lock through the coordinator for the duration"],
    correct:[1],
    why:"LWTs use Paxos to make the read-and-conditional-write atomic and linearizable across replicas. That consensus requires several extra round-trips per operation, so LWTs have much higher latency than ordinary eventually-consistent writes.", more:"Use them sparingly (e.g. claiming a unique username); heavy LWT use cripples throughput. SERIAL/LOCAL_SERIAL set the Paxos consistency scope."},
  {id:"qcx41", topic:"Cassandra", diff:"tricky", level:"Staff", type:"single",
    q:"A multi-DC app uses LWTs but wants to avoid cross-DC Paxos latency. Which serial consistency should it use, and what does it give up?",
    options:["SERIAL — keeps full cross-DC linearizability while adding no extra latency cost","LOCAL_SERIAL — runs Paxos in the local DC only, giving up global linearizability for latency","EACH_SERIAL — runs a Paxos quorum in every DC, which is actually the fastest option","ONE — turns Paxos off so the LWT degrades into an ordinary plain write"],
    correct:[1],
    why:"LOCAL_SERIAL confines the Paxos round to the local datacenter, avoiding cross-DC round-trips. The trade-off is that linearizability holds only within that DC, so a concurrent LWT in another DC isn't serialized against it.", more:"SERIAL spans all DCs (safe but slow); choose LOCAL_SERIAL when the conditional uniqueness is scoped to one DC."},
  {id:"qcx42", topic:"Cassandra", diff:"tricky", level:"Senior", type:"single",
    q:"When is a Cassandra BATCH actually a good idea?",
    options:["To insert thousands of rows across many partitions in one round-trip for throughput","To group several writes to the SAME partition so they apply atomically and cheaply","To emulate a SQL transaction spanning several unrelated tables and partitions","To cut write amplification by deferring SSTable compaction on the affected rows"],
    correct:[1],
    why:"A single-partition batch is atomic and cheap because all mutations hit one replica set. Multi-partition (logged) batches exist for atomicity but add coordinator overhead and a batchlog — they are NOT a throughput optimization.", more:"Using big multi-partition batches as a bulk-load speedup is a classic anti-pattern: it overloads the coordinator and the batchlog."},
  {id:"qcx43", topic:"Cassandra", diff:"tricky", level:"Staff", type:"single",
    q:"What does a LOGGED batch guarantee that an UNLOGGED batch does not, and what does it cost?",
    options:["Isolation, so concurrent readers never see partial results, at the cost of a global lock","Atomicity across partitions via a batchlog, at the cost of extra coordinator overhead","Lower write latency overall, achieved by skipping the commit log for those statements","Stronger consistency, by silently forcing CL=ALL on every statement in the batch"],
    correct:[1],
    why:"A LOGGED batch writes the statements to a batchlog first; if the coordinator dies mid-batch, the batchlog is replayed so all partitions eventually get the mutations — atomicity, not isolation. The batchlog and its replication add overhead. UNLOGGED skips this.", more:"Neither batch type provides isolation; concurrent readers can see some mutations applied and others not."},
  {id:"qcx44", topic:"Cassandra", diff:"tricky", level:"Senior", type:"single",
    q:"Which statement about Cassandra counter columns is true?",
    options:["Counter increments are idempotent, so retrying a write after a timeout is always safe","Counter increments are NOT idempotent, so a retry after an unknown failure can double-count","Counters can be freely mixed alongside ordinary value columns in the same table","Counters resolve conflicts with last-write-wins exactly like regular value columns"],
    correct:[1],
    why:"Counters are read-modify-write increments, not idempotent. If a write times out with an unknown outcome, retrying may apply the increment twice. They also can't be reset by overwrite and must live in counter-only tables.", more:"For exact, replay-safe counts under failures, an aggregation pipeline or LWT-backed scheme is safer than raw counters."},
  {id:"qcx45", topic:"Cassandra", diff:"tricky", level:"Senior", type:"single",
    q:"You set a TTL on rows. What happens when the TTL expires?",
    options:["The row is physically removed from disk at the exact expiry instant","The cell turns into a tombstone at expiry, reclaimed later by compaction","The row is migrated to a separate cold-storage SSTable on expiry","The TTL clock simply resets on the next read of that same row"],
    correct:[1],
    why:"TTL expiry turns the data into a tombstone; the bytes are reclaimed only when compaction runs (and after gc_grace for the tombstone). So expired data still occupies disk and can be scanned as tombstones until then.", more:"Pairing TTLs with TWCS lets whole expired time-windows drop as units, avoiding per-cell tombstone scans."},
  {id:"qcx46", topic:"Cassandra", diff:"basic", level:"Mid", type:"single",
    q:"Where does Cassandra sit in the CAP triangle by default?",
    options:["CP — it sacrifices availability to remain consistent during a network partition","AP — it favors availability and partition tolerance with tunable, eventual consistency","CA — it offers consistency and availability but tolerates no network partitions","It is fully ACID and therefore sits entirely outside of the CAP model"],
    correct:[1],
    why:"Cassandra is an AP system: under a network partition it keeps serving reads/writes (availability) and reconciles later. Consistency is tunable per-query via consistency levels rather than guaranteed strong.", accept:"With QUORUM R+W>RF you get strong consistency on the happy path, but the architecture chooses availability under partition — hence AP."},
  {id:"qcx47", topic:"Cassandra", diff:"tricky", level:"Senior", type:"single",
    q:"Why does Cassandra make you write ALLOW FILTERING explicitly, and what does it signal?",
    options:["It opts the query into a faster hidden index path that is disabled by default","It warns the query will scan and filter rows server-side, possibly across all partitions","It is simply required whenever you want to read back more than 100 rows at once","It switches the table to strong consistency for the duration of that one query"],
    correct:[1],
    why:"ALLOW FILTERING lets a query run when it can't be served from the partition/clustering keys, forcing Cassandra to scan and discard rows — possibly cluster-wide. The keyword is a deliberate speed bump signaling an unscalable access pattern.", more:"Seeing it in production usually means the data model is missing a table for that query."},
  {id:"qcx48", topic:"Cassandra", diff:"tricky", level:"Senior", type:"single",
    q:"Why can Cassandra only ORDER BY clustering columns (and only consistent with their defined order)?",
    options:["Because ordering needs a secondary index that exists only on the clustering columns","Because rows are stored physically sorted by clustering columns, so it reads them in that order","Because the partitioner already sorts the partitions globally by their clustering value","Because an ORDER BY clause triggers a Paxos round among replicas to agree on the order"],
    correct:[1],
    why:"Within a partition, rows are stored on disk sorted by the clustering columns. Cassandra serves ORDER BY by reading that physical order (or reversing it) — it won't sort arbitrary columns, since that would require an expensive scan/sort.", more:"Define WITH CLUSTERING ORDER BY (ts DESC) at table creation if your dominant query wants newest-first, so even the reverse read is the natural direction."},
  {id:"qcx49", topic:"Cassandra", diff:"tricky", level:"Staff", type:"single",
    q:"Two clients update the same cell concurrently from nodes with skewed clocks. How does Cassandra resolve the conflict, and what's the danger?",
    options:["It keeps both writes as sibling versions and leaves the app to merge them later","Last-write-wins by cell timestamp, so a clock-fast node can silently shadow a newer write","It rejects the second write outright until the two nodes' clocks resynchronize","It runs a Paxos consensus round between the replicas to order the two writes"],
    correct:[1],
    why:"Conflict resolution is last-write-wins on the per-cell timestamp. If client timestamps come from skewed clocks, the write with the larger timestamp wins even if it actually happened earlier in real time — silent data loss, not an error.", more:"Mitigations: NTP-synced clocks, or supplying explicit application timestamps (USING TIMESTAMP) for ordering-sensitive writes."},
  {id:"qcx50", topic:"Cassandra", diff:"tricky", level:"Senior", type:"multi",
    q:"Which statements about CQL semantics and driver behavior are true? (select all)",
    options:["INSERT and UPDATE are both upserts — neither one checks whether the row already exists","A token-aware driver can route a request straight to a replica owning the key, saving a hop","CQL supports JOINs across two tables as long as they share the same partition key column","Speculative retry can fire a duplicate read to another replica if the first is slow, cutting p99"],
    correct:[0,1,3],
    why:"CQL INSERT/UPDATE are upserts (no existence check unless you add IF). Token-aware drivers compute the token client-side and hit an owning replica directly. Speculative retry fires a second read to a peer when the first lags, trimming p99. CQL has no JOINs.", more:"These three together — upsert semantics, token-aware routing, speculative retry — are why a correct data model plus a good driver gives Cassandra its predictable low latency."},
  {id:"qdx01", topic:"DynamoDB", diff:"basic", level:"Mid", type:"single",
    q:"In DynamoDB, what does the partition (hash) key primarily determine about an item?",
    options:["Which physical partition stores the item, via a hash of the key value","The order in which items are returned by a Query within a partition","Whether the item can exceed the 400KB per-item size limit","How many read capacity units a GetItem on the item will consume"],
    correct:[0],
    why:"DynamoDB hashes the partition key to pick a physical partition (storage node). The sort key orders items within a partition; item size and RCU are independent of the key choice.", accept:"The sort key controls in-partition ordering, but the question asks about the partition key, which selects the partition."},
  {id:"qdx02", topic:"DynamoDB", diff:"basic", level:"Mid", type:"single",
    q:"A DynamoDB table uses a composite primary key (partition key + sort key). What does an 'item collection' refer to?",
    options:["All items in the table that share the same partition key value","All items returned by a single Scan operation in one page","The set of attributes projected into a secondary index","Every item modified within one TransactWriteItems call"],
    correct:[0],
    why:"An item collection is the group of items sharing one partition key value, ordered by sort key and co-located on the same partition. A single Query can efficiently retrieve a slice of it.", more:"Item collections are the basis of single-table design: related entities share a partition key so one Query fetches them together."},
  {id:"qdx03", topic:"DynamoDB", diff:"basic", level:"Mid", type:"single",
    q:"Which DynamoDB operation efficiently retrieves multiple items sharing one partition key value?",
    options:["Query, with the partition key equality and an optional sort key condition","Scan, with a filter expression matching the partition key value","GetItem, passing only the partition key without the sort key","BatchGetItem, which fans the partition key across all partitions"],
    correct:[0],
    why:"Query targets one partition key value and reads only that item collection (optionally sliced by a sort key condition). Scan reads the whole table; GetItem needs the full primary key for a composite-key table.", more:"Query is bounded to a 1MB page and consumes RCU only for items in that collection; Scan consumes RCU across the whole table."},
  {id:"qdx04", topic:"DynamoDB", diff:"basic", level:"Mid", type:"single",
    q:"Roughly how much read throughput does 1 Read Capacity Unit (RCU) provide in DynamoDB?",
    options:["One strongly-consistent read of up to 4KB per second (or two eventually-consistent)","One strongly-consistent read of up to 1KB per second (or two eventually-consistent)","One read of up to 4KB per second, regardless of consistency mode","One eventually-consistent read of up to 4KB per second (or two strong)"],
    correct:[0],
    why:"1 RCU = one strongly-consistent read of up to 4KB/s. An eventually-consistent read of the same size costs half an RCU, so 1 RCU buys two of them.", more:"Writes are sized differently: 1 WCU = one write of up to 1KB/s. Reads round item size up to the next 4KB; writes to the next 1KB."},
  {id:"qdx05", topic:"DynamoDB", diff:"basic", level:"Mid", type:"single",
    q:"An item is 9KB. How many Write Capacity Units does a single PutItem of it consume?",
    options:["9 WCU (item size rounded up to the next 1KB)","3 WCU (item size rounded up to the next 4KB)","1 WCU (writes are charged per item, not per KB)","5 WCU (half of strong-read cost for the same size)"],
    correct:[0],
    why:"Writes are billed per 1KB, rounded up: a 9KB item costs 9 WCU. (Reads, by contrast, round up to 4KB.)", more:"This asymmetry matters for sizing: large items are far more expensive to write than to read per byte."},
  {id:"qdx06", topic:"DynamoDB", diff:"basic", level:"Mid", type:"single",
    q:"When should you generally prefer DynamoDB on-demand capacity mode over provisioned?",
    options:["For spiky, unpredictable, or new workloads where you cannot forecast traffic","For steady, well-understood traffic where you want the lowest cost per request","Whenever the table needs strongly-consistent reads, which provisioned blocks","Only for tables larger than the 10GB per-partition storage limit"],
    correct:[0],
    why:"On-demand auto-scales instantly and bills per request, ideal for unpredictable or new traffic. Provisioned is cheaper per request for steady, forecastable load. Consistency mode is independent of capacity mode.", more:"On-demand instantly serves up to 2x a table's prior peak; beyond that it ramps. Provisioned with auto-scaling fits predictable diurnal patterns at lower cost."},
  {id:"qdx07", topic:"DynamoDB", diff:"basic", level:"Mid", type:"single",
    q:"What is the practical effect of a DynamoDB Scan compared to a Query?",
    options:["Scan reads every item in the table (or index), consuming RCU for all of them","Scan reads only items matching its filter expression, skipping the rest","Scan is the strongly-consistent form of Query and costs the same RCU","Scan reads one partition at a time but stops at the first match found"],
    correct:[0],
    why:"Scan reads the entire table/index and charges RCU for all items read; a filter is applied after the read, so it cuts results returned but not RCU consumed. Query reads only one item collection.", more:"Use Scan sparingly (one-off jobs, small tables). Parallel Scan splits the table into segments to speed it up, but still reads everything."},
  {id:"qdx08", topic:"DynamoDB", diff:"basic", level:"Mid", type:"single",
    q:"A DynamoDB Query returns a LastEvaluatedKey in its response. What does this indicate?",
    options:["More results exist; pass it as ExclusiveStartKey to fetch the next page","The query failed partway and must be retried from the beginning","The result set is complete and the key marks the final item","The partition was throttled and the read should back off and retry"],
    correct:[0],
    why:"A present LastEvaluatedKey means the operation stopped (1MB page limit or Limit reached) with more data available; feed it back as ExclusiveStartKey to paginate. Its absence means you reached the end.", more:"Query and Scan both page at 1MB of read data. Filters are applied within the page, so a page can return zero items yet still have a LastEvaluatedKey."},
  {id:"qdx09", topic:"DynamoDB", diff:"basic", level:"Mid", type:"single",
    q:"Why does HelloInterview recommend storing large blobs (images, video) in S3 rather than in a DynamoDB item?",
    options:["The item size limit is 400KB, so large blobs live in S3 with a pointer in DynamoDB","DynamoDB rejects binary attributes entirely, so blobs must be base64-encoded in S3","S3 enforces strictly stronger read consistency than DynamoDB does for large objects","DynamoDB is unable to index any item that contains a binary (blob) attribute value"],
    correct:[0],
    why:"A DynamoDB item is capped at 400KB including all attributes. Large binaries go to S3; the item stores only the S3 key/URL pointer. This also saves WCU, since writes bill per 1KB.", more:"S3 is ~$0.023/GB/mo vs DynamoDB ~$1.25/GB/mo, so offloading blobs is also far cheaper at rest."},
  {id:"qdx10", topic:"DynamoDB", diff:"basic", level:"Mid", type:"single",
    q:"What does DynamoDB TTL (Time To Live) do when an item's TTL timestamp passes?",
    options:["Asynchronously deletes the expired item in the background at no write-capacity cost","Immediately deletes the item and charges a WCU for the deletion","Marks the item read-only until you manually purge it","Moves the expired item into a separate archive table automatically"],
    correct:[0],
    why:"TTL flags items whose epoch-seconds attribute is in the past and deletes them lazily in the background, free of write capacity. Deletion is not instant.", more:"Expired items can linger and remain readable for up to ~48 hours before the background process removes them; filter on the TTL attribute if you need to hide them immediately. Deletes appear in Streams."},
  {id:"qdx11", topic:"DynamoDB", diff:"basic", level:"Mid", type:"single",
    q:"What is the maximum number of write requests in a single DynamoDB BatchWriteItem call?",
    options:["25 put/delete requests per call","100 put/delete requests per call","10 put/delete requests per call","Unlimited, bounded only by the 1MB response page"],
    correct:[0],
    why:"BatchWriteItem accepts up to 25 put/delete requests (and up to 16MB total). BatchGetItem, by contrast, allows up to 100 read items.", more:"BatchWriteItem is not atomic: individual items can fail and come back in UnprocessedItems, which you must retry with backoff."},
  {id:"qdx12", topic:"DynamoDB", diff:"basic", level:"Mid", type:"single",
    q:"DynamoDB Streams retains item-change records for how long?",
    options:["24 hours of item-level change records","7 days, matching the default Kafka topic retention","Indefinitely, until a consumer explicitly trims the stream","48 hours, the same window as TTL deletion"],
    correct:[0],
    why:"DynamoDB Streams keeps change records for 24 hours. If you need longer retention, fan out to Kinesis Data Streams or persist downstream.", more:"Records are ordered per partition key within a shard and are delivered at-least-once, so consumers must be idempotent."},
  {id:"qdx13", topic:"DynamoDB", diff:"tricky", level:"Senior", type:"single",
    q:"How does a Global Secondary Index (GSI) get its own throughput, and what risk does that create?",
    options:["It has its own capacity; a throttled GSI can back-pressure and throttle base-table writes","It shares the base table's capacity, so it can never throttle independently of the table","It draws capacity only at query time, so under-provisioning a GSI affects only its reads","It auto-scales on its own and is guaranteed never to affect writes on the base table"],
    correct:[0],
    why:"A GSI has its own capacity. Because every base-table write that touches indexed attributes must propagate to the GSI, a throttled GSI applies back-pressure that throttles writes on the base table itself.", more:"This is a classic outage cause: an under-provisioned GSI silently caps your write throughput. Provision GSIs for the write rate, not just the query rate."},
  {id:"qdx14", topic:"DynamoDB", diff:"tricky", level:"Senior", type:"single",
    q:"After writing an item to a base table, you immediately Query a GSI for it and it is missing. Why?",
    options:["GSIs are maintained asynchronously and eventually consistent, so there is replication lag","GSIs require a strongly-consistent read flag that you forgot to set","The item was never indexed because GSIs only index the partition key attribute","GSI writes are transactional with the base write, so a missing item means the write failed"],
    correct:[0],
    why:"GSI propagation is asynchronous; there is a brief lag between the base-table write and the GSI reflecting it. GSIs support eventually-consistent reads only, so you cannot force-read the latest value.", more:"Design for this lag: don't read-your-write through a GSI. If you need read-your-write, query the base table by primary key (which can be strongly consistent)."},
  {id:"qdx15", topic:"DynamoDB", diff:"tricky", level:"Senior", type:"single",
    q:"A Local Secondary Index (LSI) differs from a GSI in one constraint about its lifecycle. Which?",
    options:["An LSI can only be created at table-creation time and cannot be added later","An LSI can be added or dropped at any time, but a GSI cannot","An LSI requires its own partition key distinct from the base table","An LSI supports only eventually-consistent reads, unlike a GSI"],
    correct:[0],
    why:"LSIs must be defined when the table is created and cannot be added afterward; they share the base partition key with an alternate sort key and support strong reads. GSIs can be added/dropped anytime and are eventual-only.", more:"LSIs also impose a 10GB cap per item collection (table + LSIs sharing a partition key); GSIs have no such co-location limit."},
  {id:"qdx16", topic:"DynamoDB", diff:"tricky", level:"Senior", type:"single",
    q:"An LSI introduces a storage limit that a table without one does not have. What is it?",
    options:["Each item collection (items sharing a partition key plus LSI entries) is capped at 10GB","The whole table is capped at 10GB total storage once any LSI is defined","Each individual item is reduced from the usual 400KB down to a 256KB limit","Each partition key may hold at most 1,000 distinct sort-key values"],
    correct:[0],
    why:"With an LSI, an item collection (base items plus LSI projections sharing one partition key) cannot exceed 10GB, because LSIs are co-located on the same partition. Tables without LSIs auto-split partitions and have no per-collection cap.", more:"This makes LSIs risky for high-cardinality sort patterns under a single partition key; a GSI (which re-partitions) avoids the limit."},
  {id:"qdx17", topic:"DynamoDB", diff:"tricky", level:"Senior", type:"single",
    q:"What is a 'sparse index' in DynamoDB and why is it useful?",
    options:["An index holding only items that have the indexed attribute, skipping the rest","An index that stores only the partition key and omits every other attribute to save space","An index that is rebuilt lazily and may therefore be missing the most recent items","An index that is limited to a sparse subset of the table's partitions for cost control"],
    correct:[0],
    why:"DynamoDB only indexes an item in a GSI/LSI if it has the index's key attributes. By writing that attribute only on items you care about (e.g. status='OPEN'), the index stays small and a Query returns just those items.", more:"Sparse indexes are an idiomatic way to query 'the few special items' (open orders, unverified users) cheaply without scanning the whole table."},
  {id:"qdx18", topic:"DynamoDB", diff:"tricky", level:"Senior", type:"single",
    q:"In single-table design, what does 'overloading' a GSI with attributes like GSI1PK and GSI1SK accomplish?",
    options:["Different entity types write different meanings into one set of generic index keys","It compresses several GSIs into one to get past the per-table limit on indexes","It enforces a foreign-key relationship between the entity types stored in the index","It lets a single GSI span two physically separate tables within one query"],
    correct:[0],
    why:"Index overloading reuses generic key attributes (GSI1PK/GSI1SK) across heterogeneous entities, each populating them per its own access pattern, so a single GSI serves multiple query shapes. It is the secondary-index analog of overloading PK/SK.", more:"Combined with overloaded base-table PK/SK, this is how single-table designs serve dozens of access patterns with a handful of indexes."},
  {id:"qdx19", topic:"DynamoDB", diff:"tricky", level:"Senior", type:"single",
    q:"DynamoDB modeling is described as 'access-pattern first'. What does that mean in practice?",
    options:["You enumerate every query the app must serve, then design keys and indexes to satisfy them","You normalize entities into tables first, then add indexes for whatever queries arise later","You let DynamoDB infer indexes automatically from observed query traffic","You start from the entity relationships and derive access patterns from the schema"],
    correct:[0],
    why:"Because DynamoDB has no joins and ad-hoc queries are expensive (Scan), you list all required access patterns up front and shape PK/SK and indexes around them. This is the inverse of relational normalize-then-query design.", more:"Missing an access pattern often means adding a GSI or backfilling a new key attribute, so the enumeration is done before the table is created."},
  {id:"qdx20", topic:"DynamoDB", diff:"tricky", level:"Senior", type:"single",
    q:"How does DynamoDB's adaptive capacity help with an uneven access pattern, and what is its hard limit?",
    options:["It shifts throughput toward hot partitions but cannot exceed the per-partition ceiling","It splits any hot single item across partitions, removing the need for write sharding","It raises the per-partition RCU/WCU ceiling on demand for partitions under pressure","It caches the hot items in memory like DAX so the partition itself sees less load"],
    correct:[0],
    why:"Adaptive capacity shifts a table's throughput toward busy partitions (and can isolate hot ones), smoothing uneven load. But a single partition still tops out near 3,000 RCU / 1,000 WCU, so a truly hot single key still throttles.", more:"For a hot single key you must write-shard (add a suffix) to spread it across partitions; adaptive capacity is not a substitute for key design."},
  {id:"qdx21", topic:"DynamoDB", diff:"tricky", level:"Senior", type:"single",
    q:"You write-shard a hot key by appending a suffix (key#0 .. key#N). What does this require on the read path?",
    options:["Scatter-gather: read all N shards (in parallel) and merge the results in the application","Nothing, because DynamoDB transparently re-merges the shards on read","A GSI on the suffix attribute to reassemble the shards automatically","A strongly-consistent read, which collapses the shards back into one key"],
    correct:[0],
    why:"Sharding spreads writes across N partition-key variants, so a read must query each shard (typically concurrently) and combine the results. You trade read fan-out for write parallelism.", more:"Choose N to clear the hot-key throughput by enough margin without bloating read fan-out. A deterministic suffix (e.g. hash of a sub-key) lets you target specific shards when possible."},
  {id:"qdx22", topic:"DynamoDB", diff:"tricky", level:"Senior", type:"single",
    q:"What does TransactWriteItems guarantee, and at what cost?",
    options:["All-or-nothing ACID across up to 100 items in one or more tables, at roughly 2x the normal write cost","All-or-nothing ACID across an unlimited number of items, at the normal write cost","Eventual consistency across items with automatic retry, at the normal write cost","ACID across up to 25 items within a single partition only, at 2x cost"],
    correct:[0],
    why:"TransactWriteItems is ACID across up to 100 items (and up to 4MB) spanning tables in one region, all-or-nothing. It costs about twice the WCU of the same non-transactional writes because of the two-phase prepare/commit.", more:"Transactions are single-region only; Global Tables replicate the committed result but the transaction itself does not span regions. Each item can carry a ConditionExpression."},
  {id:"qdx23", topic:"DynamoDB", diff:"tricky", level:"Senior", type:"single",
    q:"How do you implement optimistic locking on a DynamoDB item without a transaction?",
    options:["Keep a version attribute and write with ConditionExpression 'version = :expected'","Acquire a pessimistic row lock with SELECT ... FOR UPDATE before issuing the write","Set ConsistentRead=true on the write call so that concurrent writers serialize","Use BatchWriteItem so that the whole 25-item batch is applied atomically as one unit"],
    correct:[0],
    why:"Optimistic concurrency stores a version number on the item; PutItem/UpdateItem includes a ConditionExpression asserting the version is unchanged and bumps it. A concurrent writer's expectation fails (ConditionalCheckFailed), so it retries on fresh data.", more:"This avoids lost updates without a lock. DynamoDB has no SELECT ... FOR UPDATE; ConsistentRead affects reads, not write serialization."},
  {id:"qdx24", topic:"DynamoDB", diff:"tricky", level:"Senior", type:"single",
    q:"A reserved word like 'status' or 'name' appears in your expression and the request fails. What is the fix?",
    options:["Use an ExpressionAttributeNames placeholder such as #s and reference #s in the expression","Quote the attribute name with double quotes inside the expression string","Rename the attribute in the table because reserved words cannot be stored","Switch the call to a Scan, which does not enforce reserved-word rules"],
    correct:[0],
    why:"Attribute names colliding with DynamoDB reserved words must be aliased via ExpressionAttributeNames (#s -> 'status') and referenced by the placeholder. Values use ExpressionAttributeValues (:v) similarly.", more:"You can store reserved-word attribute names fine; the restriction is only on referencing them directly inside expressions."},
  {id:"qdx25", topic:"DynamoDB", diff:"tricky", level:"Senior", type:"single",
    q:"A Query uses a FilterExpression to narrow results. What is the cost implication?",
    options:["RCU is charged for all items read before the filter; the filter only reduces items returned","RCU is charged only for items that pass the filter, so filters are free of cost","The filter pushes down to storage, so unmatched items are never read or billed","FilterExpression converts the Query into a strongly-consistent read at no extra cost"],
    correct:[0],
    why:"A FilterExpression is applied after items are read from the partition, so you pay RCU for everything scanned in the item collection; the filter only shrinks the response payload. To cut RCU, put the predicate into the key condition or a (sparse) index.", more:"This is the same trap as ProjectionExpression: both reduce returned data, neither reduces RCU on the read."},
  {id:"qdx26", topic:"DynamoDB", diff:"tricky", level:"Senior", type:"single",
    q:"A BatchGetItem response contains an UnprocessedKeys field. What does it mean and how should you handle it?",
    options:["Some reads were throttled or hit the size limit; resubmit those keys with exponential backoff","Those keys do not exist in the table and should be dropped from the request","The whole batch failed atomically and must be retried from scratch","Those keys require a strongly-consistent read that the batch could not perform"],
    correct:[0],
    why:"BatchGetItem is best-effort: items that were throttled or pushed past the response size come back in UnprocessedKeys, and you retry just those with backoff. The batch is not atomic and partially succeeds.", more:"BatchWriteItem has the analogous UnprocessedItems. Always loop on these fields rather than assuming a batch fully succeeded."},
  {id:"qdx27", topic:"DynamoDB", diff:"tricky", level:"Senior", type:"single",
    q:"DynamoDB returns a ProvisionedThroughputExceededException (throttling). What is the correct client response?",
    options:["Retry the request with exponential backoff and jitter","Immediately switch the table to strongly-consistent reads to bypass the limit","Retry in a tight loop without delay so the request lands as soon as capacity frees","Fail the request permanently, since throttling means the item is too large"],
    correct:[0],
    why:"Throttling is transient (a partition or table briefly out of capacity). The standard remedy is exponential backoff with jitter; the AWS SDKs do this automatically. Tight-loop retries amplify the overload.", more:"Persistent throttling on one key signals a hot partition (fix with sharding); persistent table-wide throttling signals under-provisioning (raise capacity or use on-demand)."},
  {id:"qdx28", topic:"DynamoDB", diff:"tricky", level:"Senior", type:"single",
    q:"How do Global Tables resolve a conflict when the same item is written in two regions at nearly the same time?",
    options:["Last-writer-wins based on timestamp; the conflicting write may be silently overwritten","The write in the region with the higher region ID always wins, deterministically","DynamoDB blocks the second write until the first replicates, preserving order","It merges the two items field-by-field into a combined item automatically"],
    correct:[0],
    why:"Global Tables are multi-region active-active with asynchronous, eventually-consistent replication and last-writer-wins conflict resolution by timestamp. Concurrent cross-region writes to one item can lose one update.", more:"Design to avoid same-item cross-region contention (e.g. region-affinity or per-region key prefixes) when last-writer-wins is unacceptable."},
  {id:"qdx29", topic:"DynamoDB", diff:"tricky", level:"Senior", type:"single",
    q:"What is the key trade-off when adopting DAX in front of a DynamoDB table?",
    options:["Microsecond cached reads, but direct (non-DAX) writes leave the cache stale until eviction","Strongly-consistent microsecond reads that eliminate any staleness concern entirely","Lower write latency, because DAX buffers writes and flushes them to the table in batches","Free RCU on every cache hit with no risk whatsoever of ever serving stale data to clients"],
    correct:[0],
    why:"DAX is a write-through/read-through cache giving microsecond reads, but it only invalidates entries for writes routed through DAX. A direct DynamoDB write (or a write from another client) leaves DAX serving stale data until the entry's TTL or eviction.", more:"DAX also does not cache strongly-consistent reads (they pass through to DynamoDB) and requires the DAX client SDK."},
  {id:"qdx30", topic:"DynamoDB", diff:"tricky", level:"Senior", type:"single",
    q:"A NoSQL-from-relational migration models a one-to-many relationship (a user with many orders). What is the idiomatic DynamoDB approach?",
    options:["Co-locate under one partition key: PK=USER#id with SK=PROFILE and SK=ORDER#id","Create a separate users table and orders table and JOIN them together at query time","Store all of the user's orders as a single nested list attribute inside the user item","Use a GSI to join the user table and the order table together in one read request"],
    correct:[0],
    why:"With no joins, you place related entities in one item collection (shared PK=USER#id, distinct sort keys), so one Query returns the profile and its orders together. DynamoDB cannot JOIN across tables.", accept:"Nesting orders inside the user item works for small, bounded lists, but it breaks at the 400KB item limit and forces rewriting the whole item per order, so separate items under one PK is preferred.", more:"This is single-table design: model by access pattern, co-locate by partition key, distinguish entity types by sort-key prefix."},
  {id:"qdx31", topic:"DynamoDB", diff:"tricky", level:"Senior", type:"single",
    q:"What does DynamoDB Point-in-Time Recovery (PITR) provide?",
    options:["Continuous backups letting you restore the table to any second within the last 35 days","A single nightly snapshot you can restore from, retained for 35 days","Synchronous replication to a second region for instant failover","Undo of individual item writes via the Streams change log"],
    correct:[0],
    why:"PITR continuously backs up the table and lets you restore to any point in the trailing 35 days, protecting against accidental writes/deletes. It is distinct from on-demand backups (manual snapshots) and from Streams.", more:"Restores create a new table; they do not overwrite in place. Combine PITR with deletion protection for safety."},
  {id:"qdx32", topic:"DynamoDB", diff:"tricky", level:"Senior", type:"single",
    q:"Why are eventually-consistent reads the default in DynamoDB, and when must you opt into strong reads?",
    options:["Eventual reads are cheaper (half an RCU) and lower-latency; opt into strong reads when stale data is unacceptable","Eventual reads are the only option on the base table; strong reads exist solely for GSIs","Strong reads are the default and you opt into eventual reads to save latency","Eventual reads are required for items over 4KB; strong reads handle smaller items"],
    correct:[0],
    why:"Eventual reads may hit a lagging replica but cost half an RCU and are faster, so they're the default. Set ConsistentRead=true (full RCU, leader read) when correctness requires the latest value. GSIs cannot do strong reads at all.", more:"Read-your-write through the base-table primary key needs a strong read; through a GSI it is impossible because GSIs are eventual-only."},
  {id:"qdx33", topic:"DynamoDB", diff:"tricky", level:"Senior", type:"single",
    q:"A ConditionExpression on a PutItem fails with ConditionalCheckFailedException. What happened?",
    options:["The condition was false at write time, so the write was rejected and not applied","The item exceeded 400KB, which conditions enforce before writing","The write succeeded but a follower replica rejected it asynchronously","The table was throttled and the condition could not be evaluated"],
    correct:[0],
    why:"A ConditionExpression makes the write conditional; if the predicate is false (e.g. attribute_not_exists(PK) when the item already exists), DynamoDB rejects it with ConditionalCheckFailedException and applies nothing.", more:"This is how you implement insert-if-absent, optimistic locking, and idempotency keys. A failed condition still consumes capacity for the evaluation."},
  {id:"qdx34", topic:"DynamoDB", diff:"tricky", level:"Senior", type:"single",
    q:"How does provisioned auto-scaling react to a sudden, brief traffic spike above the current setting?",
    options:["It reacts on a delay of minutes, so a short burst can throttle before it catches up","It scales instantly to match the spike, so provisioned tables never throttle on bursts","It pre-warms capacity by predicting the spike, eliminating any cold-start throttling","It silently downgrades reads to eventual consistency to absorb the spike in traffic"],
    correct:[0],
    why:"Auto-scaling adjusts the provisioned target based on CloudWatch metrics, reacting over minutes; a sharp spike can throttle before it catches up. A small pool of burst capacity and adaptive capacity cushion brief overages but not large sustained ones.", more:"On-demand mode reacts far faster (up to 2x prior peak instantly), which is why spiky workloads favor it over provisioned + auto-scaling."},
  {id:"qdx35", topic:"DynamoDB", diff:"tricky", level:"Senior", type:"single",
    q:"Strongly-consistent reads cost twice the RCU of eventual reads. Why?",
    options:["A strong read hits the leader replica and bills 1 RCU per 4KB; eventual bills only 0.5","A strong read returns twice as much data, so it is billed by its larger payload size","A strong read fans the read across two availability zones and is billed for both legs","A strong read holds a read lock for its duration and is billed as two separate operations"],
    correct:[0],
    why:"A strongly-consistent read must hit the authoritative leader and costs the full 1 RCU per 4KB. An eventually-consistent read of the same item may hit any replica and costs half an RCU, so strong reads are 2x the cost.", more:"This is a sizing lever: defaulting reads to eventual roughly halves read capacity when staleness is tolerable."},
  {id:"qdx36", topic:"DynamoDB", diff:"tricky", level:"Staff", type:"single",
    q:"You must model a social graph (followers/following) for efficient bidirectional traversal in DynamoDB. Which pattern fits?",
    options:["Adjacency list: store each edge (PK=USER#a, SK=FOLLOWS#b) and query the inverse via a GSI","Store one item per user holding a single list attribute of all of that user's neighbor IDs","Create a separate table for each user that contains only that one user's outgoing edges","Use a relational-style edges table and traverse it with a recursive self-JOIN at read time"],
    correct:[0],
    why:"The adjacency-list pattern stores each relationship as its own item under a partition key; an inverted GSI (or a stored inverse edge) lets you traverse the other direction. This keeps both 'who does a follow' and 'who follows a' as efficient Queries.", more:"DynamoDB has no recursive joins; graph traversals are modeled as item collections plus inverted indexes, fanning out per hop in the application."},
  {id:"qdx37", topic:"DynamoDB", diff:"tricky", level:"Staff", type:"single",
    q:"An item must hold a value larger than 400KB. What is the standard DynamoDB pattern?",
    options:["Store the large payload in S3 and keep only the S3 key (a pointer) in the DynamoDB item","Compress the payload so it fits, accepting CPU cost on every read and write","Split the payload across multiple items and reassemble with a transaction","Enable a large-item table setting that raises the limit to 1MB"],
    correct:[0],
    why:"The item limit is a hard 400KB. The idiomatic fix is to offload the payload to S3 and store its key/URL in the item; the item stays small (and cheap to write per 1KB). There is no setting to raise the limit.", accept:"Compression can keep some borderline items under 400KB, but it doesn't help payloads that are fundamentally larger and adds per-access CPU, so the S3-pointer pattern is the general solution.", more:"Splitting across items works but loses atomic single-item reads/writes and complicates consistency; S3 offload is simpler and cheaper for true blobs."},
  {id:"qdx38", topic:"DynamoDB", diff:"tricky", level:"Staff", type:"single",
    q:"You need to drive a Lambda from item changes to keep an Elasticsearch index in sync. Which DynamoDB feature and configuration fits?",
    options:["DynamoDB Streams with NEW_AND_OLD_IMAGES triggering an idempotent indexing Lambda","A GSI projected directly into Elasticsearch that DynamoDB keeps in sync automatically","TTL expiry events, which emit the full item to any subscriber for downstream indexing","A scheduled full-table Scan every minute that diffs the table and reindexes the changes"],
    correct:[0],
    why:"Streams emit ordered (per partition key) item-change records; NEW_AND_OLD_IMAGES gives both states so the Lambda can compute the index mutation. Delivery is at-least-once, so the consumer must be idempotent.", more:"This is the DynamoDB analog of CDC: write to DynamoDB, project derived state (search index, materialized view, aggregates) via Streams + Lambda rather than dual-writing."},
  {id:"qdx39", topic:"DynamoDB", diff:"tricky", level:"Staff", type:"single",
    q:"A Scan of a large table is too slow even though capacity is available. What speeds it up without changing what it reads?",
    options:["Parallel Scan: split the table into N segments and scan them concurrently across workers","Switch the Scan to strongly-consistent reads to read all partitions at once","Add a GSI so the Scan can use an index instead of the base table","Increase the page size beyond 1MB so fewer round trips are needed"],
    correct:[0],
    why:"Parallel Scan divides the table into Segments and lets multiple workers scan disjoint segments simultaneously, using available throughput in parallel. It still reads the whole table (and bills for it); it just finishes faster.", more:"Parallel Scan can starve real traffic of capacity, so bound the number of segments or rate-limit. A Query or sparse index is preferable when the access pattern allows."},
  {id:"qdx40", topic:"DynamoDB", diff:"tricky", level:"Staff", type:"single",
    q:"You want each new write to be idempotent so a client retry never double-applies. Which DynamoDB mechanism is the simplest fit?",
    options:["A ConditionExpression attribute_not_exists(PK) keyed on a client idempotency token","Set ConsistentRead=true on the write so that a retry observes the prior write attempt","Wrap every single write in TransactWriteItems, which deduplicates retries automatically","Rely on the per-shard ordering of Streams to drop the duplicate write event downstream"],
    correct:[0],
    why:"Make the idempotency key the item's PK and write with attribute_not_exists(PK): the first write succeeds, a retry fails the condition (ConditionalCheckFailed) and applies nothing. This gives at-most-once apply with no extra infra.", accept:"TransactWriteItems supports a ClientRequestToken that dedupes identical transactions for ~10 minutes, which is valid for transactional writes, but for a single write the conditional-put pattern is simpler and unbounded in time.", more:"Streams are at-least-once, so they cannot themselves guarantee dedupe; the consumer must still be idempotent."},
  {id:"qdx41", topic:"DynamoDB", diff:"tricky", level:"Staff", type:"single",
    q:"A GSI projects ALL attributes versus KEYS_ONLY. What is the core trade-off?",
    options:["ALL avoids a base-table fetch-back but adds storage and write cost; KEYS_ONLY is leaner","KEYS_ONLY costs more storage because it duplicates the whole item; ALL stores only keys","ALL uniquely enables strongly-consistent GSI reads, while KEYS_ONLY allows only eventual","Projection type only affects query latency and has no impact on storage or write cost at all"],
    correct:[0],
    why:"Projecting ALL copies every attribute into the GSI, so queries are self-contained but you pay extra storage and WCU to maintain the index. KEYS_ONLY (or INCLUDE) keeps the GSI small but a query that needs other attributes must read the base table again.", more:"Pick the projection by access pattern: project exactly the attributes the GSI's queries return (INCLUDE) to balance read self-sufficiency against write amplification."},
  {id:"qdx42", topic:"DynamoDB", diff:"tricky", level:"Staff", type:"single",
    q:"Two writers run UpdateItem with 'SET count = count + :n' on the same item concurrently. What is the outcome?",
    options:["Both increments apply: a server-side atomic counter serializes the additions per item","One increment is lost because the client-side read-modify-write on the value races","DynamoDB rejects the second concurrent write with a conflict exception and retries it","The result is non-deterministic and may corrupt the numeric attribute on the item"],
    correct:[0],
    why:"An UpdateItem ADD/SET-with-arithmetic is an atomic counter: DynamoDB applies the increment server-side against the item's current value, serializing per item, so concurrent increments all land. No client read-modify-write race exists.", accept:"If instead you GetItem, add in the client, then PutItem, that read-modify-write does race and loses updates, which is exactly why the server-side atomic counter (or a version ConditionExpression) is preferred.", more:"Atomic counters are not idempotent on retry; if exactly-once counting matters, gate with a conditional version or idempotency token."},
  {id:"qdx43", topic:"DynamoDB", diff:"tricky", level:"Staff", type:"single",
    q:"A leaderboard needs top-N by score with frequent updates. Why is DynamoDB alone awkward for this, and what is a common resolution?",
    options:["No global sorted-by-value query without a hot index; pair it with Redis sorted sets","DynamoDB cannot store numeric score values at all, so scores must be kept only in Redis","DynamoDB sort keys cannot be numbers, so ranking requires a custom string encoding scheme","A DynamoDB Query cannot return more than a single item, which blocks any top-N retrieval"],
    correct:[0],
    why:"Ranking everyone by score needs a single ordered structure; a naive GSI keyed by score concentrates traffic on a hot partition. Teams offload ranking to Redis sorted sets, or shard the score index into buckets and merge, keeping DynamoDB as the source of truth.", more:"This is a recurring 'right tool' signal: DynamoDB is excellent for keyed access, but global ordering/ranking is better served by a sorted structure (Redis ZSET) or a carefully sharded index."},
  {id:"qdx44", topic:"DynamoDB", diff:"tricky", level:"Staff", type:"single",
    q:"You enable Global Tables across 3 regions for an active-active app. What consistency must the application tolerate?",
    options:["Cross-region replication is asynchronous and eventually consistent, with last-writer-wins on conflicts","Cross-region replication is synchronous, so all regions are strongly consistent","Each region is strongly consistent locally and globally serializable across regions","Writes are quorum-acknowledged across all regions before returning"],
    correct:[0],
    why:"Global Tables replicate asynchronously; a write acked in one region propagates to others within (typically) a second or two, and conflicting concurrent writes resolve last-writer-wins. There is no synchronous cross-region quorum.", more:"Within a single region you still get DynamoDB's normal strong/eventual read options; the eventual-consistency caveat is specifically the cross-region replication."},
  {id:"qdx45", topic:"DynamoDB", diff:"tricky", level:"Staff", type:"single",
    q:"An access pattern requires 'all OPEN tickets across all customers', but tickets are partitioned by customer. What is the cleanest DynamoDB solution?",
    options:["A sparse GSI keyed on a status attribute that is only present while a ticket is OPEN","A full-table Scan with a FilterExpression on status = 'OPEN'","An LSI on status, added to the existing table to enable strong reads","Storing all OPEN tickets in a separate table and moving them on close"],
    correct:[0],
    why:"Write the status attribute (or a derived GSI key) only while OPEN and index it in a GSI; closed tickets drop out of the sparse index automatically. A Query on that GSI returns exactly the open tickets cheaply, table-wide.", accept:"A separate hot table also works and is sometimes used for very high-volume queues, but it requires moving items on state change and keeping two stores in sync, whereas a sparse GSI needs only removing one attribute on close.", more:"LSIs can't be added to an existing table and share the customer partition key (so they can't query across customers), making them the wrong tool here."},
  {id:"qdx46", topic:"DynamoDB", diff:"tricky", level:"Staff", type:"multi",
    q:"Which statements about DynamoDB capacity and sizing are correct? (select all)",
    options:["A single physical partition tops out around 3,000 RCU and 1,000 WCU","An eventually-consistent read of a 4KB item costs half an RCU","A 3KB write costs 1 WCU because writes are billed per item","On-demand mode can instantly absorb up to about 2x a table's previous peak"],
    correct:[0,1,3],
    why:"Per-partition ceiling is ~3,000 RCU / ~1,000 WCU; an eventual read of a 4KB item is 0.5 RCU; on-demand instantly serves up to ~2x prior peak. The write claim is wrong: a 3KB write costs 3 WCU (writes bill per 1KB).", more:"These four are the core back-of-envelope numbers for DynamoDB sizing; the per-1KB write billing is the most commonly misremembered."},
  {id:"qdx47", topic:"DynamoDB", diff:"tricky", level:"Staff", type:"multi",
    q:"Which statements correctly describe DynamoDB secondary indexes? (select all)",
    options:["A GSI can define a partition key different from the base table's","An LSI shares the base table's partition key with an alternate sort key","GSIs support strongly-consistent reads when ConsistentRead is set","An LSI must be created at table-creation time and cannot be added later"],
    correct:[0,1,3],
    why:"GSIs re-key on a different partition key (and have separate capacity, eventual-only); LSIs share the partition key with an alternate sort key and support strong reads but must be defined at table creation. The strong-read-on-GSI claim is false.", more:"Mnemonic: GSI = Global (anywhere, anytime, eventual); LSI = Local (same partition, at-creation, strong reads, 10GB collection cap)."},
  {id:"qdx48", topic:"DynamoDB", diff:"tricky", level:"Staff", type:"multi",
    q:"Which DynamoDB operations are best-effort / non-atomic and require partial-failure handling? (select all)",
    options:["BatchWriteItem, which can return UnprocessedItems","BatchGetItem, which can return UnprocessedKeys","TransactWriteItems, which can leave some of its items applied on failure","A throttled GetItem, which can return half of a large item"],
    correct:[0,1],
    why:"BatchWriteItem and BatchGetItem are non-atomic best-effort: throttled/oversized items come back in UnprocessedItems/UnprocessedKeys to retry. TransactWriteItems is all-or-nothing (never partially applied); a throttled GetItem fails wholly, never returns a partial item.", more:"Treat the Batch* APIs as 'submit and reconcile': loop on the unprocessed fields with backoff. Reach for Transact* when you actually need atomicity across items."},
  {id:"qdx49", topic:"DynamoDB", diff:"tricky", level:"Staff", type:"multi",
    q:"Which are valid techniques to mitigate a hot partition in DynamoDB? (select all)",
    options:["Append a write-sharding suffix to spread the key across partitions, then scatter-gather on read","Add a random or calculated prefix/suffix so the hashed key value varies","Cache the hot item in DAX or another cache to absorb read traffic","Switch the table from provisioned to on-demand capacity mode"],
    correct:[0,1,2],
    why:"Write sharding (suffix or prefix) spreads a hot key across partitions; a cache (DAX) offloads hot reads from the partition entirely. Switching to on-demand raises table-level limits but does NOT lift the per-partition ceiling, so a single hot key still throttles.", more:"The per-partition ~3,000 RCU / 1,000 WCU ceiling is the real constraint; on-demand and adaptive capacity help with skew across partitions, not a single concentrated key."},
  {id:"qdx50", topic:"DynamoDB", diff:"tricky", level:"Staff", type:"multi",
    q:"Which statements about DynamoDB transactions and conditional writes are correct? (select all)",
    options:["TransactWriteItems is ACID across up to 100 items and roughly doubles write cost","A ConditionExpression that evaluates false rejects the write with ConditionalCheckFailedException","Transactions span multiple regions, providing global ACID across Global Tables","Each item in a transaction can carry its own ConditionExpression"],
    correct:[0,1,3],
    why:"TransactWriteItems is single-region ACID over up to 100 items at ~2x cost, each item may carry a ConditionExpression, and a false condition raises ConditionalCheckFailedException. Transactions do NOT span regions; Global Tables replicate the committed result asynchronously.", more:"If any item's condition fails, the whole transaction aborts (TransactionCanceledException with per-item reasons) and nothing is applied."},
  {id:"qpx01", topic:"PostgreSQL", diff:"basic", level:"Mid", type:"single",
    q:"In Postgres MVCC, what happens to a row when you UPDATE it?",
    options:["The row is overwritten in place and the old bytes are immediately gone","A new tuple version is written and the old one is marked superseded for cleanup","The row moves to a separate undo segment that readers consult on rollback","The page is locked so no reader can see the row until the writer commits"],
    correct:[1],
    why:"MVCC never overwrites: an UPDATE inserts a new tuple version and stamps the old one's xmax, so existing snapshots can still read the prior version. The dead old tuple is reclaimed later by VACUUM.", more:"Unlike Oracle/MySQL's rollback/undo segments, Postgres keeps old versions inline in the heap — which is why dead-tuple bloat and VACUUM are such a recurring operational theme."},
  {id:"qpx02", topic:"PostgreSQL", diff:"tricky", level:"Senior", type:"multi",
    q:"Which statements about Postgres MVCC are correct? (select all that apply)",
    options:["A plain SELECT never blocks waiting on a concurrent UPDATE of the rows it reads","An UPDATE writes a new tuple version rather than overwriting the row in place","Dead tuples left by updates/deletes are reclaimed by VACUUM, not freed instantly","Two concurrent writers to the same row proceed without ever taking a row lock"],
    correct:[0,1,2],
    why:"Under MVCC reads run against a snapshot so they don't wait on writers; updates create new versions; and the superseded old versions are dead tuples that VACUUM later reclaims. But writers DO take a row lock against each other — concurrent writers of the same row serialize.", more:"The 'readers don't block writers' guarantee is specifically about reads vs writes; write-write conflicts on a single row still block on the row lock."},
  {id:"qpx03", topic:"PostgreSQL", diff:"basic", level:"Mid", type:"single",
    q:"What is the default transaction isolation level in PostgreSQL?",
    options:["Serializable, the strictest level, applied by default for safety","Read Committed, where each statement sees rows committed before it began","Repeatable Read, giving one stable snapshot for the whole transaction","Read Uncommitted, permitting dirty reads in exchange for throughput"],
    correct:[1],
    why:"Postgres defaults to Read Committed: each statement sees a fresh snapshot of data committed before that statement started, so two queries in one transaction can observe different committed states.", more:"Postgres has no true Read Uncommitted — asking for it silently behaves as Read Committed, since MVCC never exposes uncommitted (dirty) data."},
  {id:"qpx04", topic:"PostgreSQL", diff:"tricky", level:"Senior", type:"single",
    q:"At Read Committed you run the same SELECT twice in one transaction and the rows changed because another transaction committed in between. Which anomaly is this?",
    options:["A dirty read of another transaction's uncommitted data","A non-repeatable read of rows you already selected","A phantom read of newly inserted matching rows","A write skew across two overlapping predicates"],
    correct:[1],
    why:"Re-reading the same rows and seeing changed committed values is a non-repeatable read, permitted at Read Committed because each statement takes a new snapshot. Repeatable Read prevents it by freezing one snapshot for the whole transaction.", accept:"Phantom read is tempting, but phantoms specifically concern new rows appearing for a range/predicate, not changed values of rows you already read."},
  {id:"qpx05", topic:"PostgreSQL", diff:"tricky", level:"Staff", type:"single",
    q:"Two on-call engineers each confirm a colleague is still on shift, then each removes themselves — leaving nobody on shift. Both committed under Repeatable Read. What slipped through?",
    options:["A lost update where one write clobbers the other on one row","A phantom read of shift rows another session inserted concurrently","Write skew, disjoint writes that jointly violate an invariant","A dirty read of a shift change that was never actually committed"],
    correct:[2],
    why:"This is the classic write-skew anomaly: each transaction reads an overlapping set, then writes disjoint rows, and the combination violates a constraint (at least one on shift). Snapshot isolation allows it; only Serializable detects it and aborts one.", more:"It isn't a lost update because they write different rows — no single row is clobbered. The fix is SERIALIZABLE, or materializing the invariant so the writes conflict on a shared row."},
  {id:"qpx06", topic:"PostgreSQL", diff:"tricky", level:"Staff", type:"single",
    q:"How does Postgres implement the SERIALIZABLE isolation level?",
    options:["It takes range locks on every row read, so reads block conflicting writers","It uses Serializable Snapshot Isolation, aborting offenders with serialization_failure","It runs transactions strictly one after another, eliminating all concurrency","It promotes each transaction's row locks to table locks until it commits"],
    correct:[1],
    why:"Postgres uses SSI: transactions run concurrently on snapshots, it tracks dangerous read/write dependency structures, and it aborts one offender with a serialization_failure (SQLSTATE 40001) rather than taking heavy locks. The app must catch that and retry.", more:"This is optimistic, not pessimistic — so SERIALIZABLE is great when conflicts are rare but causes retry storms on hot contention, where explicit row locking can be cheaper."},
  {id:"qpx07", topic:"PostgreSQL", diff:"tricky", level:"Staff", type:"multi",
    q:"You sell the last unit and must stop two buyers from both succeeding under concurrency. Which approaches actually prevent the oversell? (select all that apply)",
    options:["SELECT … FOR UPDATE on the row, then check and decrement before COMMIT","Run the purchase under SERIALIZABLE and retry on serialization_failure","Atomic UPDATE … SET qty = qty - 1 WHERE id = ? AND qty > 0, checking rows-affected","Read the quantity at Read Committed, then UPDATE it later in a separate unlocked statement"],
    correct:[0,1,2],
    why:"FOR UPDATE serializes the buyers pessimistically on the row; SERIALIZABLE catches the conflict and aborts one to retry; and a single guarded UPDATE with qty>0 is atomic and checks rows-affected. The plain read-then-write at Read Committed is the textbook oversell bug.", more:"The guarded single-statement UPDATE is often the simplest and fastest — no explicit lock, no retry loop — because the WHERE qty>0 and the decrement happen atomically."},
  {id:"qpxm1", topic:"PostgreSQL", diff:"basic", level:"Senior", type:"single",
    q:"What does DELETE physically do to the target row in Postgres?",
    options:["Removes the tuple from its heap page and compacts the page immediately","Stamps the tuple's xmax with the deleter's XID and leaves it in place for VACUUM","Copies the tuple into an undo segment so concurrent readers can still find it","Marks the page's line pointer unused and hands the space to the next INSERT"],
    correct:[1],
    why:"DELETE only sets xmax on the current version — nothing is moved or erased. Once the deleting transaction commits and no snapshot can still see the tuple, VACUUM reclaims the space.",
    more:"The undo-segment option describes Oracle/InnoDB. Postgres keeps old versions inline in the heap — which is exactly why dead tuples, bloat and VACUUM dominate its operational story.",
    src:"postgres.html"},
  {id:"qpxm2", topic:"PostgreSQL", diff:"tricky", level:"Senior", type:"single",
    q:"The same tuples with the same xmin/xmax are on disk, yet a Read Committed session and a Repeatable Read session return different rows. What actually differs between the two levels?",
    options:["When the snapshot is taken: per statement at Read Committed, once per transaction at Repeatable Read","Which system columns are checked: Read Committed consults only xmin, Repeatable Read also xmax","Repeatable Read takes shared row locks on every row it reads; Read Committed reads without locks","Repeatable Read reads a private copy of the table's pages instead of the shared buffer pool"],
    correct:[0],
    why:"Tuple xmin/xmax never change per reader. Isolation level only decides which snapshot the visibility rule runs against — fresh for every statement (RC) or frozen at the first statement for the whole transaction (RR).",
    more:"Serializable reuses the Repeatable Read snapshot and adds SSI: predicate-lock tracking of read/write dependencies, aborting one transaction in a dangerous cycle.",
    src:"postgres.html"},
  {id:"qpxm3", topic:"PostgreSQL", diff:"tricky", level:"Staff", type:"single",
    q:"A live, fully visible tuple has a non-zero xmax, and it stays visible even after that XID commits. What wrote that xmax?",
    options:["SELECT … FOR UPDATE — the row lock is recorded in xmax with an infomask flag meaning lock, not delete","A DELETE whose WAL record has not yet been flushed to disk by the walwriter process","A HOT update that reused the existing tuple in place instead of chaining a new version","The ctid chain pointer of a concurrent UPDATE that landed on the same heap page"],
    correct:[0],
    why:"Row locks reuse the xmax field: FOR UPDATE/FOR SHARE stamp the locker's XID plus an infomask bit saying 'this is a lock, not a deletion', so visibility is unaffected when the locker commits.",
    more:"This dual use of xmax is why several sessions share-locking one row need multixacts, and why tuple-inspection tools must always read the infomask alongside xmax.",
    src:"postgres.html"},
  {id:"qpxm4", topic:"PostgreSQL", diff:"tricky", level:"Staff", type:"single",
    q:"You ROLLBACK a transaction that inserted a million rows. What happens to those heap tuples at rollback time?",
    options:["Nothing — the XID is marked aborted in pg_xact, the tuples fail visibility checks, and VACUUM removes them later","The engine replays the transaction's WAL backwards, deleting each inserted tuple from its page","They are moved to an undo log and dropped as soon as the last open snapshot releases them","The pages they occupy are truncated from the table file immediately in one O(1) operation"],
    correct:[0],
    why:"Postgres has no undo: abort just flips the XID's status in pg_xact. Tuples whose xmin is aborted are treated as never born by the visibility rule, and their space is reclaimed by VACUUM.",
    more:"That makes ROLLBACK itself O(1) — but a huge aborted load still leaves real bloat behind, a surprise for teams coming from undo-based engines like InnoDB or Oracle.",
    src:"postgres.html"},
  {id:"qpxm5", topic:"PostgreSQL", diff:"basic", level:"Mid", type:"single",
    q:"A typical CRUD web service does single-statement reads and guarded single-statement writes (UPDATE … WHERE …, checking rows-affected). Which isolation level should it run?",
    options:["Read Committed — each statement is atomic, sees the latest committed data, and needs no retry logic","Repeatable Read — every service benefits from stable snapshots and it costs nothing extra to enable","Serializable — anything below it risks anomalies, so correctness demands it as the baseline everywhere","Read Uncommitted — single-statement workloads can safely trade isolation away for extra throughput"],
    correct:[0],
    why:"Single statements are already atomic, and row locks plus EvalPlanQual make guarded updates safe at Read Committed. Raising isolation buys nothing here but adds serialization failures you would then have to handle.",
    more:"Read Uncommitted exists in Postgres syntax but silently behaves as Read Committed — dirty reads are impossible at every level. And Repeatable Read is not free: concurrent updates to the same row start failing with serialization errors that need retries.",
    src:"postgres.html"},
  {id:"qpxm6", topic:"PostgreSQL", diff:"tricky", level:"Senior", type:"single",
    q:"A nightly report runs 15 SELECTs whose numbers must be mutually consistent — totals from different queries have to add up. What's the cheapest correct isolation level?",
    options:["Repeatable Read — one snapshot for the whole transaction, so every query reads the same database state","Read Committed — each SELECT sees only committed data, which is exactly what a financial report needs","Serializable — cross-query consistency is precisely what SSI's read/write dependency tracking provides","Read Committed plus LOCK TABLE … IN SHARE MODE on every table the report touches during its run"],
    correct:[0],
    why:"Repeatable Read freezes one snapshot at the first query, so all 15 SELECTs see the same consistent state — no locks taken, no writers blocked, and a read-only RR transaction can't hit serialization failures.",
    accept:"Serializable also yields consistent results, but it adds predicate-lock tracking and abort risk that a read-only report doesn't need — Repeatable Read gives the same one-snapshot guarantee for free.",
    more:"Read Committed re-snapshots per statement, so commits landing mid-report skew the totals. The LOCK TABLE variant is 'correct' but blocks every writer for the duration — unacceptable on a production OLTP database.",
    src:"postgres.html"},
  {id:"qpxm7", topic:"PostgreSQL", diff:"tricky", level:"Staff", type:"multi",
    q:"A booking service enforces 'max 3 reservations per room per day' with SELECT COUNT(*) then INSERT. Under load, rooms end up with 4-5 bookings. Which fixes actually work? (select all that apply)",
    options:["Run the check-and-insert under SERIALIZABLE and retry transactions that fail with serialization_failure","Lock a common row first (the room row via FOR UPDATE, or an advisory lock) so bookings for one room serialize","Raise the transaction to REPEATABLE READ so the COUNT and the INSERT run against one frozen snapshot","Wrap the COUNT and the INSERT in a single BEGIN … COMMIT block so the two statements execute atomically"],
    correct:[0,1],
    why:"This is write skew on a predicate: two transactions each count 2, each insert, and both commit — Repeatable Read raises no error because they never touch the same row. Either detect it (SERIALIZABLE/SSI) or materialize the conflict by locking a row both must take.",
    more:"Locking the parent row turns an invisible predicate conflict into a visible row conflict — the same idea SSI implements generally with predicate locks. Atomicity (option 4) is irrelevant: both transactions commit 'atomically' and still jointly break the invariant.",
    src:"postgres.html"},
  {id:"qpxm8", topic:"PostgreSQL", diff:"tricky", level:"Staff", type:"single",
    q:"You need a multi-hour, strictly consistent read-only extract from a busy OLTP database — without aborting the OLTP writers or being aborted yourself. Best transaction setup?",
    options:["SERIALIZABLE READ ONLY DEFERRABLE — wait for a provably safe snapshot, then read with no SSI overhead or abort risk","Plain SERIALIZABLE — read-only transactions never participate in dangerous dependency structures anyway","READ COMMITTED with a cursor — each fetch re-reads fresh committed data, keeping the extract maximally current","REPEATABLE READ — a frozen snapshot is by definition serializable as long as the transaction only reads"],
    correct:[0],
    why:"DEFERRABLE waits until it can take a snapshot proven free of serialization anomalies, then runs as a cheap snapshot read: full serializable consistency, zero abort risk, zero predicate-lock overhead — built exactly for pg_dump-style extracts.",
    accept:"Repeatable Read is the pragmatic choice when 'one consistent snapshot' is the real requirement — but strictly, an RR snapshot can observe a state no serial order would produce (the read-only anomaly), and plain SERIALIZABLE both pays SSI tracking and can be chosen as the abort victim.",
    more:"pg_dump --serializable-deferrable uses precisely this mode. The read-only anomaly needs three concurrent transactions and is rare — which is why RR remains the default answer for ordinary reporting.",
    src:"postgres.html"},
  {id:"qpxm9", topic:"PostgreSQL", diff:"tricky", level:"Senior", type:"single",
    q:"After an audit, a team flips their order service from Read Committed to SERIALIZABLE 'for safety' — changing nothing else. What breaks first under production load?",
    options:["Requests start failing with serialization_failure (40001) because no code retries aborted transactions","Throughput collapses because every transaction now takes exclusive locks on all the rows it reads","Deadlocks spike because SSI acquires its predicate locks in a non-deterministic order across sessions","Replication lag grows because serializable transactions must also be replayed serially on the replicas"],
    correct:[0],
    why:"SSI doesn't block — it aborts. Under contention some transactions die with 40001, and code written for Read Committed almost never has retry loops, so users see raw errors. Adopting Serializable safely means adopting retry-on-40001 at the same time.",
    more:"That's the operational contract of optimistic concurrency: fewer blocked transactions, more aborted ones. SIReadLocks don't block anybody, and replicas replay the WAL identically regardless of the writer's isolation level.",
    src:"postgres.html"},
  {id:"qpx08", topic:"PostgreSQL", diff:"tricky", level:"Senior", type:"single",
    q:"In a job-queue table where many workers each claim the next task, which clause lets a worker pass rows another already locked instead of waiting?",
    options:["SELECT … FOR UPDATE NOWAIT, which errors out the moment a row is locked","SELECT … FOR UPDATE SKIP LOCKED, which skips rows already locked elsewhere","SELECT … FOR SHARE, which takes a weaker shared lock on the matched rows","SELECT … FOR UPDATE OF queue, which locks only the named queue table"],
    correct:[1],
    why:"FOR UPDATE SKIP LOCKED locks what it can and silently skips rows already locked by another transaction, so concurrent workers fan out across distinct rows without contending. NOWAIT errors instead of skipping; FOR SHARE doesn't give an exclusive claim.", more:"SKIP LOCKED is the idiom that lets Postgres act as a decent work queue without an external broker for moderate throughput."},
  {id:"qpx09", topic:"PostgreSQL", diff:"tricky", level:"Staff", type:"single",
    q:"You need an application mutex (e.g. only one worker runs a nightly job) not tied to any particular row. What's the idiomatic Postgres mechanism?",
    options:["LOCK TABLE jobs IN ACCESS EXCLUSIVE MODE for the duration of the job","An advisory lock via pg_advisory_lock(key) or pg_try_advisory_lock(key)","SELECT … FOR UPDATE on a designated sentinel row in a config table","SET TRANSACTION ISOLATION LEVEL SERIALIZABLE before running the job"],
    correct:[1],
    why:"Advisory locks (pg_advisory_lock / pg_try_advisory_lock) are arbitrary application-defined locks on an integer key, enforced cooperatively by Postgres and not bound to any table row — exactly the right tool for a named cross-process mutex.", accept:"A FOR UPDATE on a sentinel row works and is sometimes used, but it ties the mutex to a real row and transaction and holds a row lock; advisory locks are purpose-built and can be session- or transaction-scoped."},
  {id:"qpx10", topic:"PostgreSQL", diff:"tricky", level:"Senior", type:"single",
    q:"Two transactions deadlock by locking rows A and B in the opposite order. What does Postgres do?",
    options:["It hangs both indefinitely until a client times out and disconnects","A detector finds the cycle and aborts one with a deadlock_detected error","It escalates both transactions to table locks and lets them both proceed","It silently retries the losing transaction on the application's behalf"],
    correct:[1],
    why:"Postgres has automatic deadlock detection (running after deadlock_timeout): it finds the wait cycle, picks a victim, and aborts it with a deadlock_detected error. The application must catch the error and retry; Postgres does not auto-retry.", more:"Consistent lock ordering across code paths is the standard prevention; the detector is a safety net, not a substitute."},
  {id:"qpx11", topic:"PostgreSQL", diff:"basic", level:"Mid", type:"single",
    q:"What is the primary job of VACUUM in PostgreSQL?",
    options:["It rebuilds every index from scratch to keep each B-tree balanced","It reclaims space from dead tuples, the old MVCC versions, for reuse","It flushes the write-ahead log to disk to guarantee commit durability","It recomputes table statistics so the query planner costs plans well"],
    correct:[1],
    why:"VACUUM reclaims dead tuples left behind by UPDATE/DELETE under MVCC, marking their space reusable so the table doesn't bloat indefinitely. (ANALYZE updates planner statistics; autovacuum conveniently does both.)", more:"Plain VACUUM marks space reusable within the file; it does not return disk to the OS — that's VACUUM FULL, which rewrites the table under an exclusive lock."},
  {id:"qpx12", topic:"PostgreSQL", diff:"tricky", level:"Senior", type:"single",
    q:"An idle-in-transaction session has stayed open for hours. Why does it cause table bloat across the whole database?",
    options:["It holds an exclusive lock on the shared system catalog tables","It pins the xmin horizon, so VACUUM can't reclaim dead tuples it might see","It blocks every checkpoint, so dead tuples never get written out to disk","It disables the autovacuum launcher globally until that session closes"],
    correct:[1],
    why:"VACUUM can only remove tuple versions no longer visible to any snapshot. A long-lived transaction holds back the global xmin horizon, so dead tuples that became dead after it started can't be reclaimed anywhere — bloat accumulates until it ends.", more:"This is why monitoring for 'idle in transaction' sessions and setting idle_in_transaction_session_timeout is standard hygiene at scale."},
  {id:"qpx13", topic:"PostgreSQL", diff:"tricky", level:"Staff", type:"single",
    q:"Why does Postgres run aggressive anti-wraparound autovacuums, and what is the failure mode if they fall behind?",
    options:["To rebalance B-tree indexes before they exceed their maximum depth limit","XIDs are 32-bit and wrap near 2 billion; unfrozen rows force writes to stop","To compact the WAL before it overflows its fixed per-segment size cap","To migrate tuples off pages that have reached their configured fillfactor"],
    correct:[1],
    why:"XIDs are 32-bit (~2^31 usable values before the comparison space wraps). VACUUM must freeze old tuples before that happens; if anti-wraparound vacuum falls too far behind, Postgres refuses new writes to prevent old rows appearing as if from the future.", more:"This is the canonical Postgres-at-scale outage (famously hit Sentry, Mailchimp). Mitigations: monitor datfrozenxid age and tune autovacuum to keep up; freezing is still the mechanism."},
  {id:"qpx14", topic:"PostgreSQL", diff:"tricky", level:"Senior", type:"multi",
    q:"A high-churn table is bloating despite autovacuum running. Which tunings legitimately help it keep up? (select all that apply)",
    options:["Lower autovacuum_vacuum_scale_factor for the table so vacuum triggers sooner","Raise autovacuum_vacuum_cost_limit or lower cost_delay so each round does more","Drop all the indexes on the table so VACUUM has nothing left to clean up","Raise autovacuum_max_workers when many tables compete for the default workers"],
    correct:[0,1,3],
    why:"Lowering the scale factor triggers vacuum at a smaller fraction of dead tuples; raising the cost limit (or lowering the delay) lets each vacuum do more before yielding; more workers help when tables contend. Dropping indexes cripples queries and isn't a vacuum fix.", more:"Per-table storage parameters (ALTER TABLE … SET (autovacuum_vacuum_scale_factor = …)) let you tune the hot table without globally over-vacuuming everything."},
  {id:"qpx15", topic:"PostgreSQL", diff:"tricky", level:"Senior", type:"single",
    q:"You run jsonb containment queries (data @> '{...}') and full-text searches on the same table. Which index type serves both?",
    options:["B-tree, the default, which handles essentially any indexable column","GIN, an inverted index mapping contained elements and lexemes to rows","GiST, the extensible tree used for range overlap and nearest-neighbor","BRIN, the block-range summary index for huge naturally-ordered tables"],
    correct:[1],
    why:"GIN (Generalized Inverted Index) maps each contained element (jsonb keys/values, array elements, tsvector lexemes) to the rows holding it — exactly what containment (@>) and full-text (@@) queries need. B-tree can't index 'contains a value'.", more:"GIN is read-optimized but slower to update; the fastupdate option batches index changes to soften write cost on busy tables."},
  {id:"qpx16", topic:"PostgreSQL", diff:"tricky", level:"Staff", type:"single",
    q:"A geospatial table answers 'find the 10 nearest points' and 'rows whose range overlaps this range'. Which index supports both natively?",
    options:["GIN, the inverted index used for full-text and array containment","GiST, which handles overlap operators and KNN distance ordering","Hash, which is optimized for fast equality on the geometry column","BRIN, which summarizes each block range with a compact min/max pair"],
    correct:[1],
    why:"GiST is the extensible tree behind PostGIS and range types: it answers overlap/containment operators and supports KNN nearest-neighbor ordering via the distance operator (<->). GIN is for inverted, contains-element workloads, not spatial nearest-neighbor.", more:"SP-GiST suits non-balanced partitioning structures (quadtrees, tries) and can also do KNN, but GiST is the standard choice for PostGIS geometry and range overlap."},
  {id:"qpx17", topic:"PostgreSQL", diff:"tricky", level:"Senior", type:"single",
    q:"A 2 TB append-only events table is physically ordered by created_at and queries filter time ranges. Which index gives pruning at a tiny fraction of B-tree size?",
    options:["A B-tree on created_at, which is the obvious default for range scans","A BRIN on created_at, summarizing each block range with a min/max","A GIN on created_at, treating each timestamp as an indexed element","A hash on created_at, chosen mainly for its compact on-disk footprint"],
    correct:[1],
    why:"BRIN stores a tiny min/max summary per block range. When the heap's physical order correlates with the column (append-only by time), BRIN prunes whole block ranges for a range scan while occupying a fraction of a B-tree's size — ideal for huge ordered tables.", more:"BRIN's effectiveness collapses if the heap isn't correlated with the column (heavy random UPDATEs reorder rows), where it can scan far more than expected."},
  {id:"qpx18", topic:"PostgreSQL", diff:"tricky", level:"Senior", type:"single",
    q:"Only 2% of orders are in state 'pending', and all hot queries filter WHERE status='pending'. Which index is most efficient?",
    options:["A full B-tree on status, indexing every order row regardless of state","A partial index on created_at WHERE status='pending', indexing only those","A hash index on status, optimizing the equality match on the value","A multicolumn index on status, created_at, customer_id, and total"],
    correct:[1],
    why:"A partial index only indexes rows matching the predicate, so it's tiny, cheaper to maintain, and the planner uses it precisely for pending-status queries. A full index on a low-cardinality status column is mostly wasted space the planner often skips anyway.", more:"Partial indexes shine for 'hot subset of a big table' patterns (active sessions, unprocessed jobs) — the index stays small even as the table grows."},
  {id:"qpx19", topic:"PostgreSQL", diff:"tricky", level:"Staff", type:"single",
    q:"You added INCLUDE columns to enable an index-only scan, but EXPLAIN still shows heap fetches and little speedup. What's the most likely cause?",
    options:["The INCLUDE columns are not actually stored in the index leaf pages","The visibility map is stale, so the scan visits the heap to check visibility","Index-only scans require a SERIALIZABLE transaction to skip the heap","Covering indexes stay disabled unless enable_indexonlyscan is turned on"],
    correct:[1],
    why:"Index-only scans skip the heap only for pages marked all-visible in the visibility map. If recent writes left pages not-all-visible (VACUUM hasn't updated the map), the scan falls back to heap fetches to confirm visibility — so the gain depends on VACUUM keeping the map current.", more:"This is why a covering index on a write-heavy table underdelivers until autovacuum catches up; the INCLUDE payload is there, but visibility still has to be confirmed."},
  {id:"qpx20", topic:"PostgreSQL", diff:"tricky", level:"Senior", type:"single",
    q:"With an index on (tenant_id, created_at), which query uses it efficiently for both filtering and ordering?",
    options:["WHERE created_at > $1 ORDER BY created_at, ranging on the second column","WHERE tenant_id = $1 ORDER BY created_at, pinning the first, sorting next","WHERE created_at = $1 ORDER BY tenant_id, pinning the second column first","WHERE tenant_id > $1 AND created_at = $2, ranging the leading column"],
    correct:[1],
    why:"A multicolumn B-tree is ordered by its leading column first. Pinning tenant_id with equality, then ordering or ranging on created_at, uses the leftmost-prefix rule perfectly. Queries that skip the leading column can't seek efficiently with this index.", more:"Rule of thumb: equality columns first, then the range/sort column. (tenant_id, created_at) suits 'this tenant, recent first'; reverse the order and the tenant filter degrades."},
  {id:"qpx21", topic:"PostgreSQL", diff:"tricky", level:"Staff", type:"single",
    q:"What conditions make a HOT (Heap-Only Tuple) update possible?",
    options:["The update changes only the primary key, so the index entry is reused","No indexed column changed and the new version fits on the same page","The row is small enough to be stored entirely inside the visibility map","The update runs under SERIALIZABLE, which enables an in-place rewrite"],
    correct:[1],
    why:"A HOT update applies when no indexed column is modified and the new version fits on the same heap page. Postgres then chains the new version on-page and skips inserting into every index — cutting write amplification and index bloat. Changing an indexed column forfeits HOT.", more:"Leaving free space via a lower fillfactor on update-heavy tables increases the chance the new version fits on the page, keeping more updates HOT."},
  {id:"qpx22", topic:"PostgreSQL", diff:"tricky", level:"Senior", type:"single",
    q:"You store occasional large text/jsonb values. How does Postgres handle a value too big for an 8 KB page?",
    options:["It rejects the insert and requires the separate large-object (lob) API","TOAST compresses it and/or stores it out-of-line in a side table, transparently","It splits the row across several pages using a B-tree overflow page chain","It silently truncates the value down to whatever fits in the heap page"],
    correct:[1],
    why:"TOAST (The Oversized-Attribute Storage Technique) kicks in automatically: large field values are compressed and, if still too big, stored out-of-line in an associated TOAST table, with the main tuple holding a pointer. It's transparent to queries.", more:"Because TOASTed columns live elsewhere, a query that doesn't select them avoids reading them — a reason not to SELECT * over wide tables with big blobs."},
  {id:"qpx23", topic:"PostgreSQL", diff:"basic", level:"Mid", type:"single",
    q:"How does the WAL let Postgres make COMMIT fast while staying crash-safe?",
    options:["It writes the affected data pages to disk synchronously on every COMMIT","It fsyncs a sequential log record; data pages flush lazily at checkpoints","It keeps committed data in memory and relies on replicas for durability","It batches commits into the query plan cache until the next checkpoint"],
    correct:[1],
    why:"COMMIT only needs the WAL record durably fsynced — a fast sequential write. The random-access heap/index pages are written later (lazily) at checkpoints; after a crash, replaying WAL from the last checkpoint reconstructs them. That's why commits are sequential-write fast.", more:"synchronous_commit controls how strictly COMMIT waits for the WAL flush; relaxing it trades a small durability window for throughput."},
  {id:"qpx24", topic:"PostgreSQL", diff:"tricky", level:"Staff", type:"single",
    q:"What is a checkpoint in Postgres, and why does it exist?",
    options:["A consistency pass that scans every page checking for on-disk corruption","A flush of all dirty buffers so older WAL is no longer needed for recovery","A point-in-time snapshot taken for each Repeatable Read transaction start","A periodic ANALYZE run that refreshes the planner's table statistics"],
    correct:[1],
    why:"A checkpoint flushes all dirty shared buffers to the data files and records the WAL position, so recovery never has to replay WAL older than the last checkpoint. It bounds recovery time and lets old WAL segments be recycled.", more:"More frequent checkpoints shorten recovery but spread I/O spikes; checkpoint_timeout and max_wal_size tune the trade-off."},
  {id:"qpx25", topic:"PostgreSQL", diff:"tricky", level:"Senior", type:"multi",
    q:"Which statements are true of logical replication (as opposed to physical streaming replication)? (select all that apply)",
    options:["It decodes WAL into row-level changes via pgoutput rather than shipping raw bytes","It can replicate only a chosen subset of tables through a publication and subscription","It can replicate between different major Postgres versions, easing upgrades","It makes the subscriber a byte-for-byte physical copy of the entire primary cluster"],
    correct:[0,1,2],
    why:"Logical replication decodes WAL into logical row changes (pgoutput), so it can target specific tables via publications/subscriptions and even bridge different major versions. The byte-for-byte copy of the whole cluster is physical streaming replication, not logical.", more:"Because logical reconstructs row changes, it powers CDC tools (Debezium reads the replication slot) and can replicate a subset of tables into a differently-structured target."},
  {id:"qpx26", topic:"PostgreSQL", diff:"tricky", level:"Senior", type:"single",
    q:"With async streaming replication, a user updates their profile, reloads, and sees the OLD value off a read replica. What is this, and what fixes it?",
    options:["A logical-decoding bug; the fix is to switch over to physical replication","Replication lag, a read-after-write miss; route that user's reads to primary","A torn-page corruption on the replica; the fix is to enable full_page_writes","A serialization failure on the read; the fix is to retry under SERIALIZABLE"],
    correct:[1],
    why:"Async replicas apply WAL slightly behind the primary, so a just-written value may not have arrived — a read-after-write violation. Common fixes: send a just-wrote user's reads to the primary for a short window, or wait until the replica has applied the write's LSN.", more:"Synchronous replication eliminates the lag for committed data but makes COMMIT wait for the standby, hurting write latency and availability if the standby stalls."},
  {id:"qpx27", topic:"PostgreSQL", diff:"tricky", level:"Staff", type:"single",
    q:"You enable synchronous replication for zero data loss with one sync standby. What is the operational catch?",
    options:["Reads on the primary now block until the standby confirms each query","If the only sync standby goes unreachable, COMMITs on the primary hang","The standby can no longer serve any read queries while it stays in sync","It quietly degrades to asynchronous commit on every individual COMMIT"],
    correct:[1],
    why:"Synchronous commit makes the primary wait for the standby's acknowledgement before COMMIT returns. With a single sync standby, losing it stalls all commits until it recovers or you remove it from synchronous_standby_names — a real availability trade for durability.", more:"Quorum-based synchronous_standby_names (e.g. ANY 1 of N) gives durability without one standby being a single point of write-blocking."},
  {id:"qpx28", topic:"PostgreSQL", diff:"basic", level:"Mid", type:"single",
    q:"How does a Postgres backend serve each client connection?",
    options:["A lightweight thread is spawned per connection inside one shared process","Each connection gets its own dedicated OS process with its own memory","All connections share a single event loop running on one CPU core","Connections are coroutines scheduled cooperatively by the query planner"],
    correct:[1],
    why:"Postgres uses a process-per-connection model: every client connection is served by a separate forked OS process with its own work_mem and overhead. This is why connection count is bounded (a few hundred practical) and why thousands of clients need pooling.", more:"This is unlike MySQL's thread-per-connection model; the per-process cost is exactly what makes PgBouncer-style pooling so important for Postgres."},
  {id:"qpx29", topic:"PostgreSQL", diff:"tricky", level:"Staff", type:"single",
    q:"You run PgBouncer in transaction-pooling mode. Because a backend is assigned only for one transaction, which application behavior breaks?",
    options:["Multi-statement transactions, since BEGIN and COMMIT span one backend","Session state across transactions: SET, session advisory locks, server prepares","Plain read-only SELECT queries, which cannot be multiplexed onto a pool","UPSERT statements, since INSERT ON CONFLICT needs a persistent session"],
    correct:[1],
    why:"In transaction mode a backend is returned at COMMIT, so anything tied to a session rather than a transaction breaks: SET-on-session settings, session-level advisory locks, server-prepared statements, and WITH HOLD cursors. A single transaction still runs intact on one backend.", more:"Session-pooling mode preserves those semantics but holds a backend for the whole client session, sacrificing the high multiplexing that makes transaction mode scale."},
  {id:"qpx30", topic:"PostgreSQL", diff:"tricky", level:"Senior", type:"single",
    q:"A predicate matching ~40% of a large table does a sequential scan instead of using the index. Is the planner wrong?",
    options:["Yes; you should force the index, since indexes always beat a full scan","No; at low selectivity a seq scan avoids scattered random I/O and is cheaper","Yes; re-running ANALYZE on the table would make it pick the index instead","No, but only because the index on that column is most likely corrupt"],
    correct:[1],
    why:"The cost-based planner correctly prefers a sequential scan when a predicate matches a large fraction of rows: chasing thousands of scattered heap pages via an index costs more random I/O than reading the table sequentially. Indexes win for selective predicates, not broad ones.", more:"Postgres has no query hints by design; you steer the planner via statistics, indexes, and cost settings (random_page_cost), not hints."},
  {id:"qpx31", topic:"PostgreSQL", diff:"tricky", level:"Staff", type:"single",
    q:"When does the planner choose a Bitmap Index Scan over a plain Index Scan?",
    options:["Only when the underlying table happens to have no primary key defined","At a medium match count, fetching heap pages in physical order once each","Only for index-only scans that skip touching the heap pages entirely","Whenever the chosen index is a hash index rather than a B-tree index"],
    correct:[1],
    why:"A bitmap scan suits a medium match count: it builds a bitmap of matching tuple IDs from the index, then visits the heap in physical page order (each page once), avoiding the random, possibly repeated page hits of a plain index scan. It can also AND/OR bitmaps from several indexes.", more:"Few matches → plain index scan; many matches → seq scan; the bitmap scan is the planner's middle ground and is how Postgres combines multiple indexes for one query."},
  {id:"qpx32", topic:"PostgreSQL", diff:"tricky", level:"Senior", type:"single",
    q:"EXPLAIN ANALYZE shows estimated rows 12 but actual rows 400,000, and the plan is terrible. Most likely root cause and fix?",
    options:["The query is too complex; rewriting it as a CTE will straighten out the plan","Stale or thin statistics; run ANALYZE, raise targets or add extended stats","The planner ignores indexes on big tables; adding more indexes would help","EXPLAIN ANALYZE is itself inaccurate here; trust the plain EXPLAIN instead"],
    correct:[1],
    why:"A huge gap between estimated and actual rows means the planner's statistics are wrong, so it mis-costs the plan. ANALYZE refreshes the histograms; for correlated predicates, CREATE STATISTICS (extended/multivariate) or a higher default_statistics_target fixes the misestimates.", more:"Correlated columns (e.g. city and zip) are a classic source — Postgres assumes independence unless you create extended statistics, which can blow up multi-predicate estimates."},
  {id:"qpx33", topic:"PostgreSQL", diff:"tricky", level:"Senior", type:"single",
    q:"Events are RANGE-partitioned by month and a query filters WHERE event_time >= '2026-06-01'. What does partition pruning do?",
    options:["It merges all of the monthly partitions into one parent before scanning","It excludes partitions whose bounds can't match, scanning only relevant ones","It replicates the matching month's partition out to a read replica first","It rewrites the query to scan rows stored on the parent table directly"],
    correct:[1],
    why:"Partition pruning lets Postgres skip partitions whose bounds can't satisfy the query's predicate on the partition key, scanning only the relevant child tables. This keeps per-query work and the indexes touched proportional to the data actually queried.", more:"Pruning happens at plan time for constants and at execution time for parameters; a query that doesn't filter on the partition key can't prune and scans every partition."},
  {id:"qpx34", topic:"PostgreSQL", diff:"tricky", level:"Staff", type:"single",
    q:"Native declarative partitioning helps a single large table, but it does NOT provide which capability?",
    options:["Pruning irrelevant partitions to limit the data scanned per query","Distributing partitions across machines to scale write throughput out","Dropping old data cheaply by detaching a whole partition at once","Keeping each partition's indexes smaller than one giant single index"],
    correct:[1],
    why:"Partitioning still lives inside one Postgres instance — it improves pruning, maintenance (DETACH old partitions), and index sizes, but every partition shares the same server. Spreading data across machines for write scaling needs sharding (Citus or app-level), not partitioning.", more:"This is the key Staff-level distinction: partitioning ≠ sharding. Partitioning is intra-node organization; sharding is inter-node distribution."},
  {id:"qpx35", topic:"PostgreSQL", diff:"tricky", level:"Staff", type:"single",
    q:"A single Postgres primary still can't keep up with writes after partitioning and replicas. What does this imply, and what's the path?",
    options:["Add more read replicas, since reads and writes both scale with replicas","Writes don't scale within one node; shard across machines (Citus or app-level)","Switch the workload to SERIALIZABLE so the writes get batched together","Raise max_connections so that many more writers can run at the same time"],
    correct:[1],
    why:"Every write still funnels through the single primary; replicas only scale reads and partitioning only reorganizes one node's data. Scaling writes means sharding across machines (Citus distributes tables, or app-level sharding), which adds cross-shard joins, distributed transactions, and rebalancing pain.", more:"Postgres has no built-in transparent sharding — recognizing that ceiling and naming Citus/app-level sharding (with its costs) is the senior-staff signal."},
  {id:"qpx36", topic:"PostgreSQL", diff:"tricky", level:"Senior", type:"single",
    q:"Why prefer the jsonb type over json for a column you intend to query and index?",
    options:["json can be GIN-indexed for containment, whereas jsonb cannot be indexed","jsonb is stored as parsed binary, is GIN-indexable, and avoids reparsing","jsonb preserves original key order and duplicate keys, which json discards","json is the compact binary format, while jsonb keeps the raw input text"],
    correct:[1],
    why:"jsonb stores a parsed binary representation, so operators like @> (containment) and -> are fast and it can be GIN-indexed for membership queries. Plain json keeps the original text (whitespace, key order, duplicates) and must be reparsed, with no efficient containment indexing.", more:"Trade-off: json is faster to ingest and keeps the exact input bytes; jsonb costs a bit more on write but is the right choice whenever you'll query, filter, or index the document."},
  {id:"qpx37", topic:"PostgreSQL", diff:"tricky", level:"Senior", type:"single",
    q:"For Postgres native full-text search, which combination is correct?",
    options:["Store the text and use LIKE '%term%' with a B-tree index to keep it fast","Convert text to tsvector, match with tsquery via @@, accelerate with GIN","Store a tsquery column and match against it with a GiST equality operator","Build a hash index on the raw text to find any document containing a word"],
    correct:[1],
    why:"Full-text search normalizes documents into a tsvector (lexemes), matches against a tsquery with the @@ operator, and uses a GIN index over the tsvector for fast lookups. LIKE '%term%' can't use a normal index and scans the table; B-tree/hash don't help containment search.", more:"For richer relevance or typo tolerance teams often move to Elasticsearch, but Postgres FTS (tsvector + GIN) is the built-in answer and fine for moderate scale."},
  {id:"qpx38", topic:"PostgreSQL", diff:"tricky", level:"Staff", type:"single",
    q:"In modern Postgres (12+), what is the default behavior of a plain WITH (CTE), and how do you restore the old fence?",
    options:["It is always materialized; add NOT MATERIALIZED to inline it into the query","It can be inlined and optimized; add MATERIALIZED to force a fence again","It is always inlined now, and there is no longer any way to materialize it","It is recomputed once per outer row unless you explicitly add MATERIALIZED"],
    correct:[1],
    why:"Since Postgres 12, a non-recursive, side-effect-free CTE referenced once can be inlined and optimized like a subquery. Adding MATERIALIZED restores the pre-12 behavior of computing the CTE once into a temp result (an optimization fence); NOT MATERIALIZED forces inlining.", more:"Pre-12, every CTE was an implicit fence — a common cause of accidentally slow queries when people used CTEs purely for readability."},
  {id:"qpx39", topic:"PostgreSQL", diff:"basic", level:"Mid", type:"single",
    q:"What does INSERT … ON CONFLICT (key) DO UPDATE accomplish?",
    options:["It deletes the conflicting row and then re-inserts the brand-new one","An atomic upsert: insert when the key is new, otherwise update in place","It always silently ignores any insert that would hit a unique conflict","It locks the entire target table while it checks for a key conflict"],
    correct:[1],
    why:"ON CONFLICT DO UPDATE is Postgres's upsert: it tries the insert and, on a unique/exclusion-constraint conflict for the named target, performs the UPDATE instead — atomically in a single statement, with no read-then-write race.", more:"DO NOTHING is the 'insert-or-ignore' variant; the EXCLUDED pseudo-row exposes the values you tried to insert so the UPDATE can reference them."},
  {id:"qpx40", topic:"PostgreSQL", diff:"tricky", level:"Mid", type:"single",
    q:"SERIAL and GENERATED … AS IDENTITY are both backed by a sequence. Why can their generated values contain gaps?",
    options:["Sequences reset back to 1 automatically after each transaction commits","Sequences are non-transactional, so a rolled-back insert still consumes one","Identity columns deliberately skip every even-numbered value by default","Gaps only ever appear when two concurrent transactions hit a deadlock"],
    correct:[1],
    why:"A sequence hands out the next value outside transactional rollback — so an aborted transaction (or a discarded INSERT) consumes that number and never reuses it. Gaps are expected; sequences guarantee uniqueness and roughly monotonic growth, not a contiguous run.", more:"Per-session caching (CACHE n) widens gaps further. IDENTITY is the SQL-standard, recommended form; SERIAL is the older Postgres-specific shorthand for the same sequence machinery."},
  {id:"qpx41", topic:"PostgreSQL", diff:"tricky", level:"Senior", type:"single",
    q:"You add a foreign key from orders.customer_id to customers.id. Deletes on customers are suddenly slow. Usual cause?",
    options:["The foreign key now forces SERIALIZABLE isolation on both of the tables","No index on the referencing orders.customer_id, so each delete scans orders","The foreign key constraint silently disables HOT updates on customers","Postgres locks both whole tables for every referential integrity check"],
    correct:[1],
    why:"Postgres auto-indexes the referenced (parent) key but NOT the referencing (child) column. Without an index on orders.customer_id, every delete/update of a customer must sequentially scan orders to enforce the FK, which is slow on a big child table.", more:"The fix is a plain index on the referencing column. This is one of the most common 'missing index' surprises because people assume the FK created it for them."},
  {id:"qpx42", topic:"PostgreSQL", diff:"tricky", level:"Senior", type:"single",
    q:"What does a STORED generated column (col GENERATED ALWAYS AS (expr) STORED) give you?",
    options:["It is recomputed on every read of the row, so the value never goes stale","It physically stores a derived value, kept in sync on write and indexable","It lets two different tables share one common reusable column definition","It moves the column out-of-line into TOAST storage to save heap space"],
    correct:[1],
    why:"A STORED generated column persists the result of an expression over other columns of the same row, maintained automatically on insert/update. Because it's materialized, you can index it and read it without recomputation — handy for derived keys, normalized values, or search vectors.", more:"Postgres currently supports only STORED (not VIRTUAL) generated columns; the value is part of the heap tuple and can't reference other rows or volatile functions."},
  {id:"qpx43", topic:"PostgreSQL", diff:"tricky", level:"Senior", type:"single",
    q:"You want to find which queries consume the most total time fleet-wide, with call counts and mean/total duration. Which tool?",
    options:["EXPLAIN ANALYZE, run on each suspect query you can think of, one by one","pg_stat_statements, which aggregates execution stats per normalized query","pg_stat_activity, which only lists the queries currently running right now","The slow-query log, grepped for any statement over your chosen threshold"],
    correct:[1],
    why:"pg_stat_statements aggregates per-normalized-statement metrics (calls, total/mean/stddev time, rows, buffer hits) across the whole server, so you can rank by total time and find the real load drivers. pg_stat_activity is only a live snapshot; the log is unaggregated.", more:"It normalizes constants so 'SELECT … WHERE id = $1' rolls many literal variants into one row — essential for spotting the query that's death-by-a-thousand-calls."},
  {id:"qpx44", topic:"PostgreSQL", diff:"tricky", level:"Staff", type:"single",
    q:"A prepared statement was fast for specific parameters but got slow after several executions. What likely happened?",
    options:["The prepared statement expired from the cache and got re-parsed badly","It switched from custom per-value plans to a generic plan, worse on skew","The plan cache was disabled by an autovacuum run on the involved tables","Prepared statements always re-plan from scratch on every single execution"],
    correct:[1],
    why:"Postgres tries custom plans for the first executions of a prepared statement, then may switch to a single generic (parameter-agnostic) plan if it estimates that's cheaper on average. For skewed data the generic plan can be far worse — the classic generic-plan regression.", more:"plan_cache_mode (force_custom_plan / force_generic_plan) lets you override the heuristic when a workload's parameter skew defeats the default after roughly the sixth execution."},
  {id:"qpx45", topic:"PostgreSQL", diff:"tricky", level:"Staff", type:"single",
    q:"A bloated table needs disk reclaimed and its physical order compacted on a busy production system. Why is pg_repack often preferred over VACUUM FULL?",
    options:["VACUUM FULL cannot reclaim any on-disk space, while pg_repack can do so","VACUUM FULL holds ACCESS EXCLUSIVE the whole time; pg_repack rebuilds online","pg_repack also frees up the WAL on disk, which a VACUUM FULL never does","VACUUM FULL only works on partitioned tables, not ordinary heap tables"],
    correct:[1],
    why:"VACUUM FULL rewrites the table to a new file and returns space to the OS, but it holds an ACCESS EXCLUSIVE lock for the whole operation — unacceptable downtime on a hot table. pg_repack achieves the same compaction online, with only a brief exclusive lock at the swap.", more:"Plain VACUUM never shrinks the file (only marks space reusable); to actually return disk you need VACUUM FULL or pg_repack — and on production the online tool usually wins."},
  {id:"qpx46", topic:"PostgreSQL", diff:"tricky", level:"Senior", type:"single",
    q:"What does Postgres's LISTEN/NOTIFY provide, and what is its key limitation?",
    options:["A durable message queue with at-least-once delivery and full replay support","Lightweight in-DB pub/sub: it is ephemeral, so absent listeners miss messages","A way to subscribe to WAL row changes for cross-replica change-data-capture","A cron-like scheduler that fires named events at the configured wall-clock times"],
    correct:[1],
    why:"LISTEN/NOTIFY is a simple publish/subscribe within a Postgres server: a NOTIFY (optionally with a payload, delivered after commit) wakes sessions that issued LISTEN on that channel. It's ephemeral — no persistence or replay, so a listener that isn't connected misses it.", more:"It's great for cache-invalidation or 'work is ready' nudges; for guaranteed delivery you need a real queue or an outbox table polled with SKIP LOCKED."},
  {id:"qpx47", topic:"PostgreSQL", diff:"tricky", level:"Staff", type:"single",
    q:"You add the pgvector extension and build an HNSW or IVFFlat index for similarity search. What do those indexes trade for speed?",
    options:["They guarantee exact nearest neighbors, but only for the L2 distance metric","They return approximate neighbors, much faster, at a tunable recall loss","They require the vectors to live in a separate dedicated sharded cluster","They only work as a GIN index built over coarsely quantized vector blocks"],
    correct:[1],
    why:"pgvector's HNSW and IVFFlat indexes do approximate nearest-neighbor search: they avoid scanning every vector, trading a small loss in recall for large speedups. Parameters (HNSW's ef_search/m, IVFFlat's lists/probes) tune the recall-versus-latency balance; an exact scan is correct but slow.", more:"This brings vector similarity into the same Postgres that holds your relational data — avoiding a separate vector store for moderate scale, with the usual ANN accuracy/latency knobs."},
  {id:"qpx48", topic:"PostgreSQL", diff:"basic", level:"Senior", type:"single",
    q:"What does CREATE INDEX CONCURRENTLY give you, and what is the cost?",
    options:["It builds the index faster by parallelizing the build across many CPU cores","It builds without a write-blocking lock, but is slower and scans the table twice","It builds the index inside a single transaction so you can cleanly roll it back","It creates the index only on the read replicas to offload work from the primary"],
    correct:[1],
    why:"CREATE INDEX CONCURRENTLY avoids the heavy lock that a normal CREATE INDEX takes (which blocks writes), so the table stays writable. The trade-offs: it's slower, scans the table twice, can't run inside a transaction block, and may leave an invalid index if it fails (drop and retry).", more:"On production you almost always build indexes CONCURRENTLY; a plain CREATE INDEX on a large hot table is a self-inflicted write outage for the duration of the build."},
  {id:"qpx49", topic:"PostgreSQL", diff:"tricky", level:"Senior", type:"multi",
    q:"Which statements about Postgres hot-standby read replicas are correct? (select all that apply)",
    options:["Every write goes to the single primary; the replicas themselves are read-only","They scale read throughput by serving read queries away from the primary","An async replica can lag briefly, so it may serve a stale read-after-write","Adding more replicas raises the cluster's overall write throughput as well"],
    correct:[0,1,2],
    why:"Replicas are read-only: writes funnel to the one primary and stream out via WAL, so replicas scale reads (not writes), and an async replica can lag enough to serve a stale value just after a write. More replicas never lift the write ceiling — that's still the single primary.", more:"This is why a write-bound workload gains nothing from more replicas, which is what eventually pushes you toward partitioning or sharding for write scale."},
  {id:"qpx50", topic:"PostgreSQL", diff:"tricky", level:"Staff", type:"multi",
    q:"Which of these are genuine, defensible reasons to choose Postgres over a NoSQL store in a system-design answer? (select all that apply)",
    options:["You need multi-row ACID transactions and referential integrity across entities","Your access patterns need ad-hoc JOINs and querying you can't predict up front","Postgres always scales writes further than any NoSQL system, in every case","You want rich indexing (partial, expression, GIN/GiST) and SQL the team knows"],
    correct:[0,1,3],
    why:"ACID transactions with referential integrity, ad-hoc JOINs/flexible querying, and rich indexing plus familiar SQL are all legitimate reasons to pick Postgres. The blanket claim that Postgres 'always scales writes further than any NoSQL' is false and exactly the sweeping statement interviewers flag.", more:"The honest framing is trade-offs: Postgres gives integrity and query flexibility on a single primary; horizontally write-scaling NoSQL stores trade those for distribution. 'It depends on the access pattern' beats absolute claims."},
  {id:"qvgcj", topic:"Replication", diff:"tricky", level:"Senior", type:"single",
    q:"Async vs sync replication: what is the actual risk you accept with fully async replicas?",
    options:["Writes acknowledged by the leader can be lost if it dies before replicas catch up","Reads become impossible on replicas until the replication log is fully applied","The leader must wait for every replica, so write latency grows with each node","Replicas can accept conflicting writes that must be merged with vector clocks"],
    correct:[0],
    why:"Async = the leader acks before replicas confirm, so a leader crash can drop acked-but-unreplicated writes on failover. Waiting on replicas describes sync replication; conflicting writes describe multi-leader, not async single-leader.", more:"Middle ground: semi-sync — one replica confirmed synchronously for durability, the rest async for latency."},
  {id:"qm101", topic:"Replication", diff:"tricky", level:"Senior", type:"single",
    q:"Leaderless store, N=3 replicas. Which W/R settings guarantee a read sees the latest acked write?",
    options:["W=2, R=2 — write and read sets must overlap in at least one replica","W=1, R=1 — both operations stay fast and the coordinator resolves staleness","W=3, R=3 — anything less can never return the most recent value written","W=2, R=1 — a majority write makes any single-replica read fully current"],
    correct:[0],
    why:"The rule is W + R > N: 2+2 > 3 forces overlap, so every read set contains at least one replica with the latest write. W=1/R=1 and W=2/R=1 allow stale reads; W=3/R=3 works but is needlessly slow and fragile — the point is overlap, not totality."},
  {id:"q1tnw", topic:"Replication", diff:"tricky", level:"Staff", type:"single",
    q:"After a network partition, two nodes of a single-leader cluster both believe they are the leader. What actually prevents split-brain damage?",
    options:["Quorum-based election plus fencing (epoch) tokens that let storage reject the stale leader","A load balancer health check that stops routing client traffic to the slower leader","Switching replication to synchronous so both leaders stay identical until healing","Tight clock synchronization via NTP so both leaders order their writes consistently"],
    correct:[0],
    why:"Only one side of a partition can hold a majority, so quorum election picks a single leader; fencing tokens make downstream storage reject writes stamped with an old epoch. Health checks, sync mode, and NTP don't stop two nodes from accepting divergent writes."},
  {id:"qg85a", topic:"Replication", diff:"tricky", level:"Senior", type:"multi",
    q:"Users complain: 'I post a comment, refresh, and it's gone' (reads hit lagging replicas). Which fixes genuinely address this? (select all)",
    options:["Route the user's reads to the leader for a short window right after they write","Serve the user from a replica known to have applied their last write (track LSN/offset)","Echo the fresh write back into the user's own view optimistically, client-side","Add more read replicas so that each one receives the write sooner"],
    correct:[0,1,2],
    why:"Read-your-writes is a session guarantee: pin post-write reads to the leader, compare the replica's applied position against the user's last write, or do optimistic UI. Adding replicas doesn't shrink lag — it adds more nodes that can be stale."},
  {id:"q64uh", topic:"Replication", diff:"tricky", level:"Staff", type:"single",
    q:"Two data centers accept writes for the same record (multi-leader). Which conflict-handling claim is right?",
    options:["Last-write-wins by timestamp is simple but silently discards one concurrent update","Synchronous cross-DC locking is the standard, keeping both leaders identical always","Conflicts cannot happen if each DC applies writes in the order it received them","Vector clocks merge conflicting values automatically without application logic"],
    correct:[0],
    why:"LWW is the common default and its price is silent data loss under concurrency. Cross-DC synchronous locking defeats the latency purpose of multi-leader; per-DC ordering doesn't prevent divergence; vector clocks only *detect* concurrency — the merge still needs app logic or CRDTs."},
  {id:"q1x8f", topic:"Replication", diff:"tricky", level:"Staff", type:"multi",
    q:"Which are real risks of fully automatic leader failover? (select all)",
    options:["Acked writes that never reached the promoted replica are simply lost","The old leader wasn't truly dead, and now two nodes accept writes","A flapping network triggers repeated failovers and reconnect storms","Replicas permanently lose the ability to serve reads during promotion"],
    correct:[0,1,2],
    why:"Lost unreplicated writes, split-brain from a not-actually-dead leader, and failover flapping are the classic trio — the reason some teams still page a human for the final call. Replica reads keep working during promotion; that's largely why replicas exist."},
  {id:"q1pax", topic:"Replication", diff:"tricky", level:"Staff", type:"single",
    q:"'Dynamo' the 2007 paper vs DynamoDB the AWS product — which statement is accurate?",
    options:["The paper is leaderless quorum replication; the product uses a leader per partition with Paxos across three AZs","Both are leaderless quorums; the product merely adds a managed control plane and billing on top","The paper used a leader per partition, which the product relaxed into tunable leaderless quorums","They share a storage engine, but the product swapped consistent hashing for range assignment"],
    correct:[0],
    why:"A classic trap. The Dynamo paper describes leaderless replication with sloppy quorums; DynamoDB the product diverged — each partition has a leader replicated via Multi-Paxos across 3 AZs, which is exactly why it can offer strongly consistent reads."},
  {id:"q120y", topic:"Replication", diff:"basic", level:"Senior", type:"single",
    q:"When is multi-leader replication actually the right tool?",
    options:["Multi-region write locality, or offline-capable clients that sync up later","Fast failover — the second leader takes over the instant the first one fails","Read scaling — leaders serve strongly consistent reads in every region","Avoiding quorum overhead while keeping single-copy linearizability intact"],
    correct:[0],
    why:"Multi-leader buys write locality across regions (and models offline devices as leaders that sync later) at the price of conflict resolution. It is not a failover mechanism — that's single-leader with promotion — and it weakens linearizability rather than preserving it."},
  {id:"q71ew", topic:"CAP / PACELC", diff:"tricky", level:"Senior", type:"single",
    q:"During a partition, what does a CP system actually do on the minority side?",
    options:["Refuses or errors requests it can't serve consistently, sacrificing availability","Keeps serving possibly-stale reads and queues writes to replay after healing","Continues fully, but tags each response as potentially inconsistent for clients","Hands its clients off to the majority partition through internal rerouting"],
    correct:[0],
    why:"CP means: when consistency can't be verified, the minority side stops answering — availability is the sacrifice. Serving stale reads or queueing writes is AP behavior; rerouting assumes clients can reach the majority, which a partition doesn't guarantee."},
  {id:"q1j1f", topic:"CAP / PACELC", diff:"tricky", level:"Staff", type:"single",
    q:"Pick the correct PACELC classification pairing.",
    options:["Cassandra/DynamoDB ≈ PA/EL (available under partition, latency-first otherwise); Spanner ≈ PC/EC","Cassandra ≈ PC/EC since quorums make it consistency-first; Spanner ≈ PA/EL thanks to TrueTime","Any AP system is automatically EC, because availability implies steady-state consistency","PACELC classifies only partition behavior; the EL/EC half belongs to the CAP theorem"],
    correct:[0],
    why:"Dynamo-style stores choose availability under partition and low latency in normal operation (PA/EL). Spanner refuses under partition and pays coordination latency for consistency (PC/EC). TrueTime doesn't make Spanner available under partition — it makes external consistency affordable."},
  {id:"q3tjs", topic:"CAP / PACELC", diff:"basic", level:"Mid", type:"single",
    q:"'Eventual consistency' promises specifically that…",
    options:["Replicas converge to the same value once writes stop — a real guarantee, unlike weak consistency","Every read reflects some write from the last few seconds, bounded by replication lag","Reads may return anything at all, with no convergence obligation on the system","Each user always observes their own writes, though other users may lag behind"],
    correct:[0],
    why:"Eventual consistency is a liveness guarantee: no new writes → all replicas converge. Weak consistency makes no convergence promise. Bounded staleness and read-your-writes are different, stronger models — know all three names."},
  {id:"qbmv0", topic:"Load balancing", diff:"tricky", level:"Senior", type:"single",
    q:"You're fronting long-lived WebSocket connections. Why do teams usually reach for an L4 load balancer here?",
    options:["It just forwards TCP — the persistent connection passes through with no per-message HTTP handling","It can read WebSocket frames and route each message to the least-busy backend","It terminates TLS closer to the client, which the WebSocket upgrade requires","It transparently retries failed messages, which L7 proxies are unable to do"],
    correct:[0],
    why:"L4 pins the TCP connection to one backend and stays out of the payload — cheap and natural for long-lived duplex streams. Per-message rerouting isn't how WebSockets work (the socket lives on one server), and TLS termination/retries aren't the differentiator.", accept:"L7 proxies (nginx, Envoy) can proxy WebSockets too — but they hold state per connection, so L4 is the lighter default answer."},
  {id:"qan8b", topic:"Load balancing", diff:"tricky", level:"Senior", type:"single",
    q:"Sticky sessions (L7 affinity) solve one problem and create another. Which pair?",
    options:["Keep a user on the server holding their in-memory state; but load skews and a dead server drops its sessions","Guarantee read-after-write consistency; but every write must now pass through one designated server","Remove the need for session storage entirely; but require clients to send an affinity header","Make deployments zero-downtime; but double the servers needed for identical traffic levels"],
    correct:[0],
    why:"Stickiness keeps a client on the server that holds its state (session, WS connection). The costs: uneven load and lost state on server failure. The cleaner fix is externalizing state (Redis) so any server can serve anyone — then stickiness becomes an optimization, not a correctness need."},
  {id:"q1yrx", topic:"Load balancing", diff:"tricky", level:"Senior", type:"single",
    q:"When does least-connections beat round-robin as the balancing algorithm?",
    options:["When request durations vary widely — long-lived or slow requests pile up unevenly under round-robin","When all requests cost the same, because counting connections is cheaper than rotating a pointer","When the same client must always land on the same backend to preserve cache locality","When backends are heterogeneous, since round-robin has no way to be weighted by capacity"],
    correct:[0],
    why:"Round-robin assumes requests cost roughly the same; with variable durations (SSE streams, slow queries) some servers accumulate long-runners. Least-connections tracks actual in-flight load. Cache locality wants consistent hashing — and round-robin does have a weighted variant."},
  {id:"q1mir", topic:"Load balancing", diff:"basic", level:"Mid", type:"single",
    q:"'TLS termination at the load balancer' means…",
    options:["The LB decrypts traffic, enabling content-based routing and offloading crypto from backends","The LB blocks any request arriving over plain HTTP before it reaches the fleet","The LB re-encrypts every hop using a fresh certificate per backend server","Traffic stays encrypted end-to-end while the LB balances on the TCP layer only"],
    correct:[0],
    why:"Terminating TLS at the L7 LB centralizes certificates, offloads handshake cost, and is what enables routing on URLs/headers/cookies. You can still re-encrypt LB→backend, but that's optional hardening — not what 'termination' means."},
  {id:"qwf39", topic:"Load balancing", diff:"tricky", level:"Staff", type:"single",
    q:"Which situation calls for consistent hashing as the LB algorithm (vs round-robin / least-connections)?",
    options:["Backends keep per-key state or cache — a key should keep landing on its node even as the pool scales","Backends are stateless and short-lived, so requests should spread as evenly as possible","You need strict global FIFO ordering of requests across every backend in the pool","Traffic is spiky and you want the algorithm with the lowest per-request CPU cost"],
    correct:[0],
    why:"Consistent hashing gives affinity that survives pool changes — in-process caches, WebSocket hubs, and per-user shards keep locality, and only ~1/N of keys move when a node joins or dies. For stateless backends it buys nothing over simpler algorithms."},
  {id:"qpzkx", topic:"Load balancing", diff:"tricky", level:"Senior", type:"multi",
    q:"Which health-check behaviors are correct practice for a load balancer? (select all)",
    options:["Actively probe a cheap endpoint and eject a backend only after several consecutive failures","Re-admit a recovered backend gradually (slow start) instead of at its full traffic share","Mark a backend dead on its first failed request to minimize user-visible errors","Make every probe exercise the database too, so no dependency is ever missed"],
    correct:[0,1],
    why:"Eject on consecutive failures (don't flap on one blip) and warm recovered nodes back gradually. One-strike ejection amplifies transient noise; deep per-probe dependency checks turn a DB hiccup into 'the entire fleet is unhealthy' — the classic health-check-induced outage."},
  {id:"q1kpn", topic:"Fan-out", diff:"basic", level:"Mid", type:"single",
    q:"Fan-out-on-read (pull) for a timeline means…",
    options:["At read time, fetch recent posts from everyone the user follows and merge them","On each new post, append it to a precomputed timeline for every follower","Cache the merged timeline once and serve it to all followers of that user","Push new posts over WebSockets so clients assemble timelines locally"],
    correct:[0],
    why:"Pull = do the work at read time: query the followees' recent posts and merge. Cheap writes, expensive reads — the mirror image of push, which precomputes per-follower timelines at write time."},
  {id:"q14fa", topic:"Fan-out", diff:"tricky", level:"Senior", type:"single",
    q:"Why does fan-out-on-write run through a queue and async workers rather than inline in the POST request?",
    options:["Delivering to millions of followers takes far longer than an acceptable API response — buffer, smooth, retry","Queues guarantee every follower's timeline updates in one global order, which inline writes cannot","Timeline writes need distributed transactions, and message brokers provide them natively","It upgrades timeline delivery from at-least-once to exactly-once with no consumer changes"],
    correct:[0],
    why:"Fan-out work is huge and spiky; decoupling keeps post latency low, absorbs celebrity-sized bursts, and gives retries on partial failure. Queues don't provide global order across partitions or distributed transactions — and delivery still ends up at-least-once + idempotent writes."},
  {id:"q1xpe", topic:"Fan-out", diff:"tricky", level:"Staff", type:"single",
    q:"Hybrid timeline model: what happens on read for a user following two celebrities and 300 normal accounts?",
    options:["Their precomputed timeline (pushed by the 300) is merged at read time with the celebrities' recent posts","The whole timeline is rebuilt from all 302 accounts, because celebrities invalidate the cached copy","Celebrity posts arrive via the push path too, just at a lower priority in the fan-out queue","The 300 normal accounts get pulled while the two celebrities get pushed, minimizing writes"],
    correct:[0],
    why:"Hybrid = push for normal accounts (bounded fan-out), pull for celebrities (avoid unbounded fan-out). Read path: take the precomputed list, fetch the few celebrity feeds, merge by time. The last option reverses it — pushing celebrities is exactly the disaster hybrid avoids."},
  {id:"q191t", topic:"Fan-out", diff:"tricky", level:"Senior", type:"single",
    q:"What do you actually store in a Redis-backed precomputed timeline, and why?",
    options:["A few hundred recent post IDs per user (capped list/ZSET), hydrated into full posts on read","Fully rendered post JSON per follower, so reads require no further lookups at all","Only the follower graph — the posts themselves always stay in the database","Deltas since the user's last visit, replayed against a client-side cache"],
    correct:[0],
    why:"Store ~200–800 post IDs per user and hydrate from a post store/cache on read. Duplicating full post bodies per follower explodes memory and makes edits/deletes O(followers); IDs keep timelines small and posts canonical."},
  {id:"qj9dk", topic:"Idempotency", diff:"tricky", level:"Senior", type:"single",
    q:"Server-side, how does an idempotency key actually work?",
    options:["Persist key → result of the first execution; a retry with the same key returns the stored result","Hash the request body and reject any request whose hash was already seen in the past 24 h","Lock the key for the request's duration so concurrent duplicates queue up behind it","Attach the key to the DB transaction so the database deduplicates commits automatically"],
    correct:[0],
    why:"The canonical mechanism: persist the key with the operation's outcome (atomically with the side effect) and replay the saved response on retry. Body-hash rejection breaks legitimate identical requests; a lock alone doesn't survive the crash-after-commit case the key exists for."},
  {id:"q13ef", topic:"Idempotency", diff:"tricky", level:"Senior", type:"single",
    q:"A consumer reads an at-least-once queue and inserts rows. How do you stop redeliveries from duplicating data?",
    options:["Make the insert an idempotent upsert keyed by a stable message/business ID — dedupe at the write","Ack each message before processing it, so the broker never gets a chance to redeliver","Turn on the broker's exactly-once delivery mode and leave the consumer unchanged","Keep an in-memory set of processed message IDs inside each consumer process"],
    correct:[0],
    why:"Dedupe must live at the effect: an upsert/unique-constraint on a stable ID makes redelivery harmless. Ack-before-processing converts duplicates into data loss; broker 'exactly-once' doesn't extend into your database; in-memory sets die with the process — exactly when redelivery happens."},
  {id:"q1rna", topic:"Idempotency", diff:"basic", level:"Mid", type:"single",
    q:"Which HTTP methods can a client retry blindly, per the HTTP contract?",
    options:["GET, PUT, DELETE — idempotent by definition; POST is not","GET and POST — the two most common methods are both safe to repeat","Only GET — anything that writes must never be retried automatically","All of them — retries are handled by TCP retransmission anyway"],
    correct:[0],
    why:"PUT sets a state and DELETE removes it — repeating changes nothing; GET doesn't write. POST creates, so it duplicates on retry — which is why POST endpoints that must be retry-safe take an idempotency key."},
  {id:"q1p2d", topic:"Idempotency", diff:"tricky", level:"Staff", type:"single",
    q:"'We need exactly-once delivery' — the technically honest response is…",
    options:["Delivery is at-least-once or at-most-once; 'exactly-once' = at-least-once plus idempotent processing","Modern brokers (Kafka, SQS FIFO) give true exactly-once end to end, so the ask is trivial","Choose at-most-once, since losing a message is always cheaper than processing twice","TCP already guarantees exactly-once, so the requirement only matters over UDP"],
    correct:[0],
    why:"A sender that doesn't get an ack must choose: resend (at-least-once) or not (at-most-once). 'Exactly-once semantics' = at-least-once delivery + dedup/idempotent effects — which is what Kafka EOS is inside its own ecosystem, too."},
  {id:"q1c81", topic:"Rate limiting", diff:"tricky", level:"Senior", type:"single",
    q:"What's the classic flaw of a fixed-window counter (say, 100 req/min per user)?",
    options:["Up to 2× the limit can pass in a short span straddling the window boundary","It cannot be implemented atomically, so concurrent requests always overcount","Token refills accumulate, letting an idle user burn several windows at once","Memory grows with one counter per request rather than one counter per user"],
    correct:[0],
    why:"100 requests at 0:59 and 100 more at 1:01 = 200 in about two minutes, yet each window is 'within limit'. Sliding-window (log or weighted counter) fixes the boundary; token bucket addresses it differently, via refill rate plus capacity."},
  {id:"qv6jn", topic:"Rate limiting", diff:"tricky", level:"Staff", type:"single",
    q:"Implementing a distributed limiter on Redis with INCR + EXPIRE — the subtle bug and its fix?",
    options:["A failure between INCR and EXPIRE leaves a counter with no TTL — make the pair atomic via Lua","INCR wraps at 32 bits under heavy traffic — switch to a Redis Stream for 64-bit offsets","Two servers can read the same value before writing — wrap the increment in MULTI/EXEC","Replicas can serve stale counters after failover — read limits through a replica quorum"],
    correct:[0],
    why:"The footgun is a counter that never expires (INCR succeeded, EXPIRE never ran) — that key is rate-limited forever. Lua — or setting the TTL only when INCR returns 1 — makes it atomic. INCR itself is already atomic per key and 64-bit, so MULTI adds nothing here."},
  {id:"q1aqq", topic:"Rate limiting", diff:"basic", level:"Senior", type:"single",
    q:"Leaky bucket vs token bucket — the real behavioral difference?",
    options:["Leaky bucket smooths output to a constant drain rate; token bucket permits bursts up to capacity","Token bucket drops requests, while leaky bucket queues everything indefinitely without loss","Leaky bucket runs server-side, while token bucket only makes sense inside the client","None — they are mathematically identical implementations of the same algorithm"],
    correct:[0],
    why:"Leaky bucket forces a steady outflow (good for smoothing toward a fragile downstream); token bucket accumulates capacity while idle, allowing controlled bursts — which is usually what user-facing APIs want."},
  {id:"q9bfu", topic:"Rate limiting", diff:"basic", level:"Mid", type:"single",
    q:"A request gets rate-limited. What should the API return, and what should a good client do?",
    options:["429 with a Retry-After hint; the client backs off with jitter before retrying","503 with no body; the client immediately fails over to a secondary endpoint","200 with an empty payload to keep client code simple; retry on a fixed timer","401, since exceeding a quota usually means the credentials were compromised"],
    correct:[0],
    why:"429 Too Many Requests + Retry-After is the contract; well-behaved clients respect it with jittered backoff — otherwise every throttled client retries in sync and re-spikes the service. 503 signals server failure, not client quota."},
  {id:"q1q0h", topic:"Rate limiting", diff:"tricky", level:"Senior", type:"single",
    q:"What should you key API rate limits on?",
    options:["Layers: per user/API key for fairness, plus a coarser per-IP guard for unauthenticated abuse","Per IP address only — the one identifier that clients can never rotate or spoof","Per endpoint globally, so no single route can exceed its fair share of the fleet","Per region, since limits exist mainly to protect cross-region bandwidth budgets"],
    correct:[0],
    why:"User/API-key limits give per-tenant fairness; IP limits catch pre-auth abuse but false-positive on NATs (one office = one IP) and are rotatable. Real systems layer scopes: user, IP, endpoint, plus global load shedding."},
  {id:"q16is", topic:"Real-time transport", diff:"tricky", level:"Senior", type:"single",
    q:"One operational advantage SSE has over WebSockets is…",
    options:["It's plain HTTP with auto-reconnect and Last-Event-ID resume — proxies, LBs, and auth just work","It delivers binary frames with lower per-message overhead than WebSocket framing","It multiplexes many logical streams over one connection, which WebSockets cannot","Messages are acknowledged end-to-end, upgrading delivery to exactly-once"],
    correct:[0],
    why:"SSE rides ordinary HTTP: middleware, LBs, and auth headers work unchanged, the browser auto-reconnects, and Last-Event-ID resumes the stream. It's text-only, one-way, no acks — the other options describe WebSocket/HTTP2 features or fiction."},
  {id:"q1sxj", topic:"Real-time transport", diff:"tricky", level:"Staff", type:"single",
    q:"A WebSocket chat runs on 20 servers. User A (server 3) messages user B (server 17). What's the standard plumbing?",
    options:["Servers subscribe to a pub/sub backbone (Redis/Kafka); server 3 publishes, server 17 delivers to B's socket","The LB migrates B's connection over to server 3 so the conversation shares one process","Server 3 opens a direct socket to server 17 on demand, forming a peer mesh of servers","All messages flow through a shared database table that every server polls each second"],
    correct:[0],
    why:"Connections are pinned to servers, so cross-server delivery needs a routing layer — pub/sub with per-user/channel subscriptions, or a connection registry plus RPC. LBs can't migrate live sockets; server meshes and DB polling collapse as the fleet grows."},
  {id:"q1wi8", topic:"Real-time transport", diff:"basic", level:"Senior", type:"single",
    q:"When is SSE the better pick than WebSockets?",
    options:["One-way server→client streams — notifications, feeds, progress bars, LLM token output","Any latency-sensitive use, because SSE skips the WebSocket upgrade round-trip","When the clients are mobile apps, which cannot hold WebSocket connections open","When the client also needs to push frequent small updates back upstream"],
    correct:[0],
    why:"If data flows one way, SSE gives you push with HTTP simplicity (reconnect, resume, middleware-friendly). The moment the client must talk back at low latency — chat, games, collaborative editing — you want full duplex, i.e. WebSockets."},
  {id:"qr2hl", topic:"Real-time transport", diff:"basic", level:"Mid", type:"single",
    q:"Long-polling differs from plain polling in that…",
    options:["The server holds each request open until data or timeout; the client re-requests immediately after","The client polls on an adaptive schedule, backing off exponentially while the channel is quiet","The connection stays open permanently and the server writes events onto it as they occur","It requires HTTP/2 multiplexing, whereas plain polling still works over HTTP/1.1"],
    correct:[0],
    why:"Long-polling parks the request server-side until there's something to say — near-realtime latency without wasted empty responses — then the client immediately re-polls. A permanently open event stream describes SSE, not long-polling."},
  {id:"q8sev", topic:"Observability", diff:"basic", level:"Senior", type:"single",
    q:"SLI vs SLO vs SLA — which mapping is right?",
    options:["SLI = the measured signal; SLO = your internal target for it; SLA = the external contract with penalties","SLI = the alert rule; SLO = the dashboard feeding it; SLA = the runbook the alert links to","SLI = availability only; SLO = latency only; SLA = both of them, averaged monthly","SLO = the thing you measure; SLI = the target; SLA = whatever error budget remains"],
    correct:[0],
    why:"Indicator (fraction of requests under 300 ms), Objective (99.9% of them should be), Agreement (what you owe customers if you miss). Error budget = 1 − SLO — spent on incidents and risky launches."},
  {id:"qcwv2", topic:"Observability", diff:"tricky", level:"Senior", type:"single",
    q:"Why do SREs watch p99 latency rather than the average?",
    options:["Averages hide the tail — and with fan-out, many user actions include at least one p99-slow call","p99 is far cheaper to compute than a mean across millions of requests per second","The average is undefined once any request times out, while percentiles stay defined","Because 99% of users experience exactly the p99 latency on every one of their requests"],
    correct:[0],
    why:"A great mean coexists happily with an awful tail — and tails compound: a page fanning out to 10 backends hits the p99 of at least one roughly 10% of the time. Heavy (often most valuable) users make the most requests, so they meet the tail most often."},
  {id:"q1rh2", topic:"Observability", diff:"basic", level:"Senior", type:"single",
    q:"Circuit breaker: walk the states.",
    options:["Closed (normal) → trips Open on error threshold (fail fast) → Half-open probes → success closes it again","Open (normal) → Closed once errors exceed threshold → Half-open logs traffic while it blocks","Closed (blocking) → Open when the downstream recovers → stays Open until ops reset it manually","One state with a sliding error window — 'breaker' refers to shedding a percentage of load"],
    correct:[0],
    why:"Closed = traffic flows, failures counted. Open = fail immediately and give the dependency air to recover (no retry pile-up). Half-open = let a trickle through; success closes, failure re-opens. The naming is an electrical-circuit metaphor — closed circuit conducts."},
  {id:"qxipr", topic:"Observability", diff:"tricky", level:"Staff", type:"single",
    q:"'Backpressure' as a design mechanism means…",
    options:["Bounded queues push the slow-down signal upstream — block, shed, or 429 — instead of buffering forever","The system automatically retries failed downstream calls with exponentially growing delays","Memory pressure makes the GC pause ingestion threads until heap usage drops back down","Consumers pull in larger batches whenever the producer's queue depth starts growing"],
    correct:[0],
    why:"When a consumer can't keep up, unbounded buffering converts overload into OOM and latency collapse a few minutes later. Backpressure makes the limit explicit — bounded queues, blocking producers, shedding at the edge — so overload surfaces where it can be handled."},
  {id:"q1me2", topic:"Observability", diff:"basic", level:"Senior", type:"single",
    q:"Canary release vs blue-green — which statement is accurate?",
    options:["Canary shifts a small % of real traffic and compares metrics before ramping; blue-green swaps 100% at once","Blue-green needs no extra capacity, while canary requires running a full duplicate environment","Canary only works for stateless services; blue-green was designed specifically for databases","They are identical except canary covers config changes and blue-green covers code changes"],
    correct:[0],
    why:"Canary = gradual exposure with metric gates (catches what tests didn't); blue-green = two full environments and a router flip (fast out, fast back). They compose: deploy green, canary a slice of traffic onto it, then cut over."},
  {id:"q1r4c", topic:"Estimation", diff:"basic", level:"Senior", type:"single",
    q:"Average traffic is 1,000 QPS. What number do you actually design for?",
    options:["Peak — typically 2–3× average for steady products, 5×+ for spiky or event-driven ones","Average — capacity planning uses the mean precisely so outliers don't dominate it","10× the average as a universal safety factor, regardless of the traffic shape","The p99 of QPS, which for web traffic sits around 1.2× the average"],
    correct:[0],
    why:"Systems fall over at peak, not at average. Daily cycles put peak around 2–3× the mean; launches, sales, and sports events push far higher. Saying the multiplier out loud — 'so I'll design for ~3k QPS' — is exactly the estimation signal interviewers listen for."},
  {id:"qkapx", topic:"Estimation", diff:"tricky", level:"Senior", type:"single",
    q:"Users upload 10M photos/day at ~500 KB each. Roughly what sustained ingest bandwidth is that?",
    options:["~5 TB/day ≈ 60 MB/s ≈ 0.5 Gbps sustained","~5 TB/day ≈ 600 MB/s ≈ 5 Gbps sustained","~500 GB/day ≈ 6 MB/s ≈ 0.05 Gbps sustained","~50 TB/day ≈ 6 GB/s ≈ 50 Gbps sustained"],
    correct:[0],
    why:"10M × 500 KB = 5 TB/day. Divide by ~10⁵ seconds: ~50–60 MB/s; times 8 ≈ 0.5 Gbps. Comfortably one NIC's worth — running the math often kills 'we obviously need special infrastructure for ingest' reflexes."},
  {id:"q196h", topic:"Estimation", diff:"tricky", level:"Staff", type:"single",
    q:"The service holds 200 GB and takes 2k writes/sec. A colleague proposes sharding Postgres now. The numbers say…",
    options:["No — one tuned Postgres with replicas handles this comfortably; revisit at ~10× the writes or TB-scale","Yes — 2k writes/sec is beyond a single node, so range-shard by user ID before it's too late","Yes, but shard by time rather than user so that writes spread across all shards evenly","No — but move to Cassandra anyway, since relational engines degrade sharply past 100 GB"],
    correct:[0],
    why:"A single Postgres is fine to tens of thousands of writes/sec and single-digit TB. Sharding at 200 GB / 2k wps buys cross-shard queries and resharding pain for zero benefit — the classic premature-sharding trap. (And time-range sharding would concentrate writes on the newest shard.)"},
  {id:"qtwba", topic:"Estimation", diff:"basic", level:"Mid", type:"single",
    q:"Writes arrive at 1k QPS, 1 KB each. Raw storage after 5 years?",
    options:["~150–160 TB","~15–16 TB","~1.5 PB","~500 TB"],
    correct:[0],
    why:"1 KB × 1k/s = 1 MB/s ≈ 86 GB/day ≈ 31.5 TB/year → ~158 TB over five years. With ×3 replication plus index overhead, plan on roughly half a petabyte of raw disk.", more:"The chain to say out loud: per-second → per-day (×86,400 ≈ 10⁵) → per-year (×365) → ×horizon → ×replication."},
  {id:"qwqhy", topic:"SPOF / Reliability", diff:"tricky", level:"Staff", type:"multi",
    q:"Every service is redundant: 3 app servers, DB with replicas, Redis cluster. Which sneaky SPOFs commonly remain? (select all)",
    options:["The single load balancer or single DNS provider sitting in front of everything","One NAT gateway or one availability zone quietly hosting the 'redundant' instances","The deploy pipeline and config service that push one bad change to all replicas at once","The read replicas, since replication makes them fail in lockstep with the primary"],
    correct:[0,1,2],
    why:"Compute redundancy hides SPOFs at the edges: the LB itself (needs a pair with VRRP/anycast, or managed), everything sharing one AZ/NAT, and correlated failure via deploys — identical replicas of a bad config fail together. Replicas failing 'in lockstep with the primary' is the decoy."},
  {id:"qzkg4", topic:"SPOF / Reliability", diff:"tricky", level:"Senior", type:"single",
    q:"Active-active vs active-passive failover — the honest trade-off?",
    options:["Active-active uses all capacity and fails over instantly, but must handle state sync and conflicts","Active-passive is strictly better, because it halves the blast radius of any bad deploy","Active-active works only for stateless services; anything with a database must be active-passive","They differ only in cost — both fail over the same way, through a DNS record flip"],
    correct:[0],
    why:"Active-active buys utilization and instant failover at the price of the hard problems: routing, state replication, conflicts. Active-passive is simpler, but the standby is capacity doing nothing — and untested standbys have a habit of not working the day they're finally needed."}
];
